# not a forecast cadence). The DELIBERATE forecast-lane set is the single authority that every
# forecast-dispatch site reads, so adding the redecision type can never be partially applied
# (one missed site would fail-closed at the strategy classifier raise). Imported as the module's
# canonical constant so the producer (continuous_redecision) and consumer (this adapter) cannot
# drift apart.
from src.events.continuous_redecision import REDECISION_EVENT_TYPE as _EDLI_REDECISION_EVENT_TYPE

_FORECAST_DECISION_EVENT_TYPES: frozenset[str] = frozenset(
    {"FORECAST_SNAPSHOT_READY", _EDLI_REDECISION_EVENT_TYPE}
)

# The day0/same-day event lane (a DAY0_EXTREME_UPDATED prices against an observed
# running extreme). Module-level so qkernel can feed the observed boundary into the
# same family optimizer while the live adapter still applies Day0 authority guards.
_DAY0_LANE_EVENT_TYPES: frozenset[str] = frozenset({"DAY0_EXTREME_UPDATED"})
_DAY0_MAKER_ONLY_REST_POLICY = "REST_DAY0_MAKER_ONLY"
_DAY0_MAKER_ONLY_TAKER_FORBIDDEN_REASON = "DAY0_MAKER_ONLY"


def _is_day0_lane_event_type(event_type: object) -> bool:
    return str(event_type or "").strip() in _DAY0_LANE_EVENT_TYPES


def _day0_maker_only_required(actionable_payload: Mapping[str, object]) -> bool:
    """Current live Day0 entries are maker-only; the proof path must rank that reality."""

    return _is_day0_lane_event_type(actionable_payload.get("event_type"))


def _event_allows_same_family_monitor_owned(event_type: object) -> bool:
    """Return whether an event may manage an already-held family.

    Ordinary forecast entries must not duplicate held family exposure. Continuous
    redecision and Day0 hard-fact events are the live management lanes allowed
    to top up or close-before-open shift an existing family through the
    family_rebalance_intents lease.
    """

    return str(event_type or "") in (
        _EDLI_REDECISION_EVENT_TYPE,
        "DAY0_EXTREME_UPDATED",
    )


def _selection_allows_same_family_monitor_owned(
    *,
    event_allows_same_family_monitor_owned: bool,
    selection_exposure_by_outcome: Mapping[str, float] | None,
) -> bool:
    """Return whether selection may rank same-family management candidates.

    ``_event_allows_same_family_monitor_owned`` stays the trigger-level authority:
    a fresh forecast event cannot create duplicate family exposure just because a
    sibling looks attractive.  But once current position truth proves this family
    is already exposed, the next forecast update is no longer a pure fresh-entry
    decision; it is a position-management decision over fresh belief and fresh
    prices.  In that case the qkernel/legacy selector must be allowed to see the
    same-family sibling/same-token proofs so the downstream D1/D2 lanes can choose
    residual fill-up, hold-by-no-submit, close-before-open shift, or no-trade.
    """

    if event_allows_same_family_monitor_owned:
        return True
    return bool(selection_exposure_by_outcome)


# Decision-triggered targeted snapshot refresh (zero-order wall fix 2026-06-11).
#
# The substrate warm job refreshes executable_market_snapshots on a fair rotating
# cursor whose per-family cadence (~5.4 min live) is far slower than the 30s price-
# freshness window the decision path enforces on the SELECTED bin
# (``_snapshot_price_stale_reason``). On that cadence any family is decidable only
# ~9% of wall-clock time and every retry lands price-stale → the six built maker
# final intents all dead-lettered MONEY_PATH_TRANSIENT_EXHAUSTED (live 2026-06-11).
#
# This callable lets the decision path synchronize the two cadences AT the only
# point that matters: when about to decide and the elected row is price-stale, it
# captures FRESH books for THAT family through the SANCTIONED warm-job capture path
# (Gamma topology reconstruct + CLOB /book + ``snapshot_repo.insert_snapshot``),
# scoped to one family. It is wired in main.py (where the CLOB client lives) — the
# adapter never imports venue code (architecture ban,
# tests/engine/test_event_reactor_no_bypass.py).
#
# LOCK LAW (#95 / INV-37 / three-phase venue-sync): the refresher runs OUTSIDE the
# reactor's trade-DB transaction (the caller drops the read snapshot via
# ``trade_conn.commit()`` BEFORE invoking it) and opens its OWN short-lived write
# connection; the [NET] /book fetch is never wrapped by an open trade-DB txn —
# same posture as the submit-time JIT witness /book fetch.
#
# Returns True if it captured/persisted fresh rows; False/None on a fail-soft skip.
# The freshness CONTRACT is unchanged: after the refresh the core re-elects the
# latest row and STILL rejects with EXECUTABLE_SNAPSHOT_STALE if it remains stale.
FamilySnapshotRefresher = Callable[..., bool]


@dataclass(frozen=True)
class _CandidateProof:
    candidate: MarketTopologyCandidate
    token_id: str
    direction: str
    row: dict[str, Any] | None
    executable_snapshot_id: str | None
    execution_price: ExecutionPrice | None
    q_posterior: float
    q_lcb_5pct: float
    c_cost_95pct: float | None
    p_fill_lcb: float
    trade_score: float
    p_value: float
    passed_prefilter: bool
    native_quote_available: bool
    p_cal_vector_hash: str
    p_live_vector_hash: str
    missing_reason: str | None = None
    # Mainstream-agreement gate verdict (Task #135). None = gate not evaluated
    # (flag OFF or evaluation failed). REFERENCE-ONLY (operator directive
    # 2026-06-03): recorded on the receipt to inform the ARM decision; it does
    # NOT gate production selection (see _selected_candidate_proof). `.passed` is
    # an arm-decision reference signal, never a selection filter.
    mainstream_agreement: dict | None = None
    # #120 (2026-06-04): the calibrator that produced q_posterior for this
    # candidate's family ("emos" | "bias_platt" | "platt"). Read from
    # payload["_edli_q_source"] (set by the ONE-CALIBRATOR SEAM, era.py:3735-3818)
    # at proof construction — instance-safe (same payload threaded by the #149
    # fix). Carried to the receipt so 06-05+ settlement can attribute EMOS-cells
    # vs maze-cells per city (the PROMOTE evidence).
    q_source: str | None = None
    q_lcb_calibration_source: str | None = None
    same_bin_yes_posterior: float | None = None
    # Twin-authority reconciliation #7 (2026-06-11; selected-leg repair 2026-06-30):
    # the settlement-backward coverage VERDICT status for this exact condition+direction
    # ("LICENSED"/"UNLICENSED"/"INSUFFICIENT_DATA"; None on the canonical path).
    # Carried on the proof so the receipt-level twin admission gate evaluates the SAME
    # selected-leg evidence the proof-generation gate saw.
    settlement_coverage_status: str | None = None
    replacement_calibration_credential: dict[str, Any] | None = None
    # H2_E2E (REAUDIT_0_1.md §2/§4): carry the bundle posterior_id +
    # probability_authority from the evidence dict
    # (_replacement_authority_probability_and_fdr_proof :5752-5754) through to the
    # receipt so the fill->posterior link is reconstructable in SQL. None on the
    # canonical path. Observability only — never gates selection.
    posterior_id: int | None = None
    probability_authority: str | None = None
    # FIX C (mode-consistent EV; incident 0b5c305e26524042 / operator directive
    # 2026-06-10): the per-candidate maker/taker mode decision and BOTH EVs travel
    # on the proof so the receipt/settlement loop can recalibrate p_fill_maker and
    # the adverse-selection haircut from fill facts. trade_score IS the chosen
    # mode's EV (the taker-cost x visible-depth-p_fill hybrid is retired).
    execution_mode_intent: str | None = None
    ev_taker: float | None = None
    ev_maker: float | None = None
    maker_limit_price: float | None = None
    relative_spread_at_eval: float | None = None
    taker_forbidden_reason: str | None = None
    maker_fill_probability: float | None = None
    maker_fill_probability_source: str | None = None
    # K4.0 REST-THEN-CROSS: the policy verdict that produced the mode + the
    # escalation deadline for REST decisions (None on legacy one-shot proofs).
    rest_then_cross_policy: str | None = None
    rest_escalation_deadline_minutes: float | None = None
    # DECISION TELEMETRY (pr408 review C1+C2 #2 CRITICAL, 2026-06-14): the
    # unlicensed_tail_coverage_telemetry flag records whether the cheap-tail unlicensed
    # disagreement guard WOULD have fired for this candidate. It is OBSERVABILITY ONLY —
    # it NEVER zeros the score, fails the prefilter, sets a no-trade reason, or alters
    # size. The forbidden one-sided fail-CLOSED tail gate (operator law 3) that killed
    # +edge cheap trades was removed from the live path; this records the signal for
    # settlement-graded study without touching the live decision.
    unlicensed_tail_coverage_telemetry: bool = False
    # qkernel spine execution economics certificate. This is deliberately separate from
    # q_posterior / q_lcb_5pct, which remain receipt-facing selected-side probability
    # fields. When selection_authority_applied == "qkernel_spine", submit sizing
    # consumes this guarded payoff-space economics payload instead of rebuilding
    # stake from proof q_lcb.
    qkernel_execution_economics: dict[str, Any] | None = None
    selection_authority_applied: str | None = None


@dataclass(frozen=True)
class PreSubmitAuthorityWitness:
    quote_seen_at: str
    book_hash: str
    current_best_bid: float | None
    current_best_ask: float | None
    tick_size: float
    min_order_size: float
    neg_risk: bool
    heartbeat_status: str
    user_ws_status: str
    venue_connectivity_status: str
    balance_allowance_status: str
    book_authority_id: str
    book_captured_at: str
    heartbeat_authority_id: str
    heartbeat_checked_at: str
    user_ws_authority_id: str
    user_ws_checked_at: str
    venue_connectivity_authority_id: str
    venue_connectivity_checked_at: str
    balance_allowance_authority_id: str
    balance_allowance_checked_at: str
    checked_at: str | None = None
    max_quote_age_ms: int = 1000


# K=1 STAGE 1 (docs/archive/2026-Q2/operations_historical/k1_final_snapshot_authority_plan_2026-06-11.md §4):
# the fresh submit-time JIT /book fetch (R8) is today ephemeral (witness only).
# Stage 1 gives it a durable, first-class executable_market_snapshots identity so
# the receipt can prove the economics it submitted under. Pure additive
# persistence + provenance — the witness ALSO still flows through the existing
# R9-R15 path untouched. Wave-1 2026-06-12: the former
# k1_persist_presubmit_snapshot_enabled flag is DELETED; the persist is now
# UNCONDITIONAL fail-soft (provenance substrate, never a throttle).
JIT_PRESUBMIT_PROVENANCE_SOURCE = "JIT_PRESUBMIT"
# The fresh JIT book carries the SAME price freshness window as the elected DB
# row's executable window: captured_at + the snapshot freshness window. We mirror
# the elected row's own window rather than fabricate a new constant.
_K1_DEFAULT_PRESUBMIT_FRESHNESS_SECONDS = 30.0


def build_presubmit_snapshot_row(
    elected_snapshot: ExecutableMarketSnapshot,
    *,
    witness: PreSubmitAuthorityWitness,
    decision_time: datetime,
    freshness_window_seconds: float | None = None,
) -> ExecutableMarketSnapshot:
    """Build the Stage-1 JIT-presubmit snapshot row (pure, no I/O).

    Mirror minimally: the elected DB snapshot carries the full family identity
    (gamma/event/condition/question/token map/fee details/hashes) — the JIT fetch
    does NOT. We inherit that identity and overlay ONLY the fresh JIT book:
    best_bid/best_ask, captured_at = the fetch instant (witness observation time),
    a fresh immutable snapshot_id, and a provenance tag ``JIT_PRESUBMIT`` carried
    in the tradeability_status provenance envelope (the schema has no dedicated
    ``source`` column; ``authority_tier`` honestly says CLOB — a live /book read).

    Fitz #4 (data provenance): captured_at is anchored to the fetch instant, NOT
    the elected row's stale captured_at, and the provenance_source field makes the
    row's lineage self-describing.
    """

    import hashlib

    witness_captured_at = _parse_utc(getattr(witness, "book_captured_at", None))
    captured_at = (
        witness_captured_at.astimezone(timezone.utc)
        if witness_captured_at is not None
        else decision_time.astimezone(timezone.utc)
    )
    window = (
        float(freshness_window_seconds)
        if freshness_window_seconds is not None
        else _K1_DEFAULT_PRESUBMIT_FRESHNESS_SECONDS
    )
    freshness_deadline = captured_at + timedelta(seconds=max(0.0, window))

    fresh_bid = (
        Decimal(str(witness.current_best_bid))
        if witness.current_best_bid is not None
        else None
    )
    fresh_ask = (
        Decimal(str(witness.current_best_ask))
        if witness.current_best_ask is not None
        else None
    )

    # raw_orderbook_hash must be a 64-char sha256 hex digest (contract invariant).
    # The witness book_hash is the venue's opaque hash string; sha256 it together
    # with the fresh top-of-book so the row's orderbook-lineage hash is a valid,
    # deterministic digest of exactly the JIT book that was witnessed.
    raw_orderbook_hash = hashlib.sha256(
        f"{JIT_PRESUBMIT_PROVENANCE_SOURCE}|{witness.book_hash}|{fresh_bid}|{fresh_ask}".encode("utf-8")
    ).hexdigest()

    # New immutable identity — never collides with the elected row's snapshot_id.
    snapshot_id = (
        f"jitpresub-{elected_snapshot.snapshot_id}-"
        f"{hashlib.sha256((str(captured_at.isoformat()) + raw_orderbook_hash).encode('utf-8')).hexdigest()[:16]}"
    )

    # Provenance envelope (Fitz #4): inherit the elected row's tradeability facts
    # (the JIT fetch does not re-observe gamma/clob tradeability) and stamp the
    # source so the row is self-describing. provenance_source round-trips through
    # ExecutableTradeabilityStatus.from_mapping/to_json_dict; the book hash and
    # fetch instant are already captured in raw_orderbook_hash / captured_at.
    base_status = elected_snapshot.tradeability_status
    status_payload = dict(base_status.to_json_dict()) if base_status is not None else {}
    status_payload["provenance_source"] = JIT_PRESUBMIT_PROVENANCE_SOURCE

    return dataclass_replace(
        elected_snapshot,
        snapshot_id=snapshot_id,
        orderbook_top_bid=fresh_bid,
        orderbook_top_ask=fresh_ask,
        orderbook_depth_jsonb="{}",
        raw_orderbook_hash=raw_orderbook_hash,
        authority_tier="CLOB",
        captured_at=captured_at,
        freshness_deadline=freshness_deadline,
        # depth/microstructure are not re-derived from the single top-of-book JIT
        # fetch; reset to the neutral defaults rather than carry stale elected depth.
        wide_spread_display_substitution=False,
        depth_at_best_ask=0,
        tradeability_status=status_payload,
    )


def persist_presubmit_jit_snapshot(
    trade_conn: sqlite3.Connection | None,
    elected_snapshot: ExecutableMarketSnapshot | None,
    *,
    witness: PreSubmitAuthorityWitness,
    decision_time: datetime,
    enabled: bool = True,
) -> str | None:
    """Persist exactly ONE JIT-presubmit snapshot row, fail-soft and UNCONDITIONAL.

    Wave-1 2026-06-12: the ``k1_persist_presubmit_snapshot_enabled`` flag is DELETED —
    this persistence is the receipt's provenance substrate (pure additive, fail-soft),
    not a throttle, so it now ALWAYS runs. The vestigial ``enabled`` param defaults True
    and is retained only for call-site/test compatibility; passing False still skips
    (a caller's explicit opt-out), but the live path never sets it.

    Returns the new snapshot_id on a successful write, or ``None`` when inputs are
    missing or the write fails. A failed persist MUST NEVER block or delay the submit
    (§4 Stage 1 fail-soft): the persist is observability / Stage-2 substrate, not a gate.

    §5.2 SQLite discipline: the JIT /book fetch [NET] has ALREADY happened by the
    time this is called (the witness is built from it). The write targets zeus_trades
    (executable_market_snapshots), NOT zeus-world — the #95 world-mutex law is
    untouched. When called from an active live-submit transaction/savepoint, this
    provenance write is skipped instead of joining the money-path lock window; submit
    authority is carried by the in-memory witness and the elected snapshot already
    recorded on the receipt.
    """

    if not enabled:
        return None
    if trade_conn is None or elected_snapshot is None:
        return None
    if bool(getattr(trade_conn, "in_transaction", False)):
        import logging as _logging

        _logging.getLogger(__name__).info(
            "K1 Stage 1 presubmit snapshot persist skipped inside active "
            "submit transaction (non-blocking)"
        )
        return None
    try:
        row = build_presubmit_snapshot_row(
            elected_snapshot,
            witness=witness,
            decision_time=decision_time,
        )
        insert_snapshot(trade_conn, row)
        trade_conn.commit()
        return row.snapshot_id
    except Exception as exc:  # noqa: BLE001 - fail-soft: persistence must never block submit
        import logging as _logging

        _logging.getLogger(__name__).warning(
            "K1 Stage 1 presubmit snapshot persist failed (non-blocking): %s", exc
        )
        return None


def _assert_taker_depth_authority_fresh(
    *,
    snapshot: "ExecutableMarketSnapshot",
    direction: str,
    witness_touch: Decimal,
    tick_size: Decimal,
) -> None:
    """FINDING-A relationship invariant (external review 2026-06-12).

    The final TAKER size is swept from ``snapshot``'s DEPTH while the limit price is
    the FRESH submit-time witness touch. The witness proves PRICE only (it carries no
    depth/size field), so sweeping the snapshot's depth is sound ONLY when that
    snapshot describes the SAME top-of-book the witness witnessed. If the snapshot's
    own top-of-book on THIS side is absent, or diverges from the witness touch by more
    than one tick, the depth that would be swept is STALE relative to the fresh price
    (e.g. a 300-share DB book behind a 5-share live book) — an oversized FOK/FAK or a
    wrong VWAP. Fail CLOSED with the typed TRANSIENT reason ``LIVE_DEPTH_AUTHORITY_MISSING``
    (registered in ``src.events.reactor.TRANSIENT_MONEY_PATH_REASONS``) so the candidate
    requeues with a snapshot refresh, NEVER sizing from the stale depth.

    The tolerance is exactly one tick: a book that moved by a single level is still the
    same depth authority for the FOK sweep; a larger move (or a missing touch) means the
    witness saw a book whose depth we do not hold.
    """
    if direction.startswith("buy_"):
        snap_touch = getattr(snapshot, "orderbook_top_ask", None)
    else:
        snap_touch = getattr(snapshot, "orderbook_top_bid", None)
    if snap_touch is None or abs(Decimal(str(snap_touch)) - witness_touch) > tick_size:
        raise ValueError(
            "LIVE_DEPTH_AUTHORITY_MISSING:"
            f"side={direction}:"
            f"witness_touch={witness_touch}:"
            f"snapshot_touch={snap_touch}:"
            f"tick={tick_size}"
        )


class _LiveOpportunityAlreadyLocked(RuntimeError):
    """Raised when continuous redecision rediscovers an already-locked opportunity."""


_DURABLE_LIVE_CAP_UNKNOWN_CITY = "__unknown_live_cap_city__"


def _adapter_table_exists(conn: sqlite3.Connection, table_name: str) -> bool:
    row = conn.execute(
        "SELECT 1 FROM sqlite_master WHERE type='table' AND name=? LIMIT 1",
        (table_name,),
    ).fetchone()
    if row is not None:
        return True
    try:
        for schema_row in conn.execute("PRAGMA database_list").fetchall():
            schema = schema_row[1] if not isinstance(schema_row, sqlite3.Row) else schema_row["name"]
            if schema in ("main", "temp"):
                continue
            probe = conn.execute(
                f"SELECT 1 FROM {schema}.sqlite_master WHERE type='table' AND name=? LIMIT 1",
                (table_name,),
            ).fetchone()
            if probe is not None:
                return True
    except sqlite3.Error:
        return False
    return False


_DURABLE_LIVE_CAP_TERMINAL_COMMAND_STATES = frozenset(
    {"CANCELLED", "CANCELED", "EXPIRED", "FILLED", "REJECTED", "SUBMIT_REJECTED"}
)
_DURABLE_LIVE_CAP_MATERIALIZED_POSITION_PHASES = frozenset(
    {"active", "day0_window", "pending_exit"}
)
_ENTRY_HELD_POSITION_BLOCKING_PHASES = frozenset(
    {"pending_entry", *_DURABLE_LIVE_CAP_MATERIALIZED_POSITION_PHASES}
)
_ENTRY_HELD_POSITION_REASON_BASE = "OPEN_POSITION_SAME_TOKEN_MONITOR_OWNED"
_ENTRY_HELD_FAMILY_REASON_BASE = "OPEN_POSITION_SAME_FAMILY_MONITOR_OWNED"
_POSITIVE_CHAIN_EXPOSURE_EPS = 1e-6
_CURRENT_MONEY_RISK_CHAIN_STATES = tuple(sorted(CURRENT_MONEY_RISK_CHAIN_STATES))


def _position_phase_or_positive_chain_clause(
    columns: set[str],
    phases: frozenset[str],
) -> tuple[str, tuple[object, ...]]:
    """SQL clause for position rows that are monitor-owned or chain-exposed.

    Local lifecycle labels can lag venue truth. A quarantined row with positive
    chain exposure is still live risk only when chain_state itself asserts
    current money risk. Confirmed chain absence stays reconciliation debt and
    must not enter live family selection.
    """
    if "phase" in columns:
        phase_sql = "phase IN ({})".format(",".join("?" for _ in phases))
        params: list[object] = list(sorted(phases))
    else:
        phase_sql = "1=1"
        params = []
    if "chain_shares" in columns:
        chain_risk_sql = "0"
        chain_params: list[object] = []
        if "chain_state" in columns:
            chain_risk_sql = "chain_state IN ({})".format(
                ",".join("?" for _ in _CURRENT_MONEY_RISK_CHAIN_STATES)
            )
            chain_params = list(_CURRENT_MONEY_RISK_CHAIN_STATES)
        terminal_phase_sql = (
            f"phase = 'quarantined' AND {chain_risk_sql}"
            if "phase" in columns
            else chain_risk_sql
        )
        return (
            f"({phase_sql} OR (COALESCE(chain_shares, 0) > ? "
            f"AND ({terminal_phase_sql})))",
            tuple([*params, _POSITIVE_CHAIN_EXPOSURE_EPS, *chain_params]),
        )
    return phase_sql, tuple(params)


def _is_entry_held_family_reason(reason: object) -> bool:
    return str(reason or "").strip().startswith(_ENTRY_HELD_FAMILY_REASON_BASE)


def _is_entry_held_same_token_reason(reason: object) -> bool:
    """True for the SAME-TOKEN held-position scoping reason.

    D1 fill-up (2026-06-22 lifecycle consult): the same-token held reason
    (``OPEN_POSITION_SAME_TOKEN_MONITOR_OWNED``) is DISTINCT from the same-family
    (different-bin) reason; the held-position selection filter must ADMIT a same-token
    held proof for an EDLI redecision so the fill-up candidate can be selected (the
    downstream decide_fill_up + lease gate is the real safety control). Fresh entries
    never set ``allow_same_family_monitor_owned``, so this never widens the entry path.
    """
    return str(reason or "").strip().startswith(_ENTRY_HELD_POSITION_REASON_BASE)


def _is_entry_held_redecision_reason(reason: object) -> bool:
    """A held-position reason a redecision (fill-up or shift-bin) may keep selectable.

    Either the same-token (fill-up) OR the same-family/different-bin (shift-bin)
    held reason. Used ONLY under ``allow_same_family_monitor_owned`` (the EDLI
    redecision lane), so the fresh-entry selection scope is byte-identical.
    """
    return _is_entry_held_same_token_reason(reason) or _is_entry_held_family_reason(reason)


def _durable_live_cap_final_intent_token(final_intent_id: str) -> str:
    token = str(final_intent_id or "").rsplit(":", 1)[-1].strip()
    return token if token and token != str(final_intent_id or "") else ""


def _durable_live_cap_usage_is_represented_in_trade_truth(
    trade_conn: sqlite3.Connection | None,
    *,
    execution_command_id: str,
    final_intent_id: str,
) -> bool:
    if trade_conn is None:
        return False
    try:
        if execution_command_id and _adapter_table_exists(trade_conn, "venue_commands"):
            row = trade_conn.execute(
                """
                SELECT state
                  FROM venue_commands
                 WHERE decision_id = ?
                   AND intent_kind = 'ENTRY'
                 ORDER BY updated_at DESC, created_at DESC
                 LIMIT 1
                """,
                (execution_command_id,),
            ).fetchone()
            if row is not None:
                state = str(row[0] if not isinstance(row, sqlite3.Row) else row["state"]).strip().upper()
                if state in _DURABLE_LIVE_CAP_TERMINAL_COMMAND_STATES:
                    return True

        token = _durable_live_cap_final_intent_token(final_intent_id)
        if token and _adapter_table_exists(trade_conn, "position_current"):
            columns = _position_current_columns(trade_conn)
            phase_sql, phase_params = _position_phase_or_positive_chain_clause(
                columns,
                _DURABLE_LIVE_CAP_MATERIALIZED_POSITION_PHASES,
            )
            positive_terms = [
                f"COALESCE({name}, 0) > 0"
                for name in ("chain_shares", "shares", "chain_cost_basis_usd", "cost_basis_usd")
                if name in columns
            ]
            if not positive_terms:
                return False
            token_columns = [name for name in ("token_id", "no_token_id") if name in columns]
            if not token_columns:
                return False
            token_sql = " OR ".join(f"NULLIF({name}, '') = ?" for name in token_columns)
            row = trade_conn.execute(
                f"""
                SELECT 1
                  FROM position_current
                 WHERE {phase_sql}
                   AND ({token_sql})
                   AND ({" OR ".join(positive_terms)})
                 LIMIT 1
                """,
                (*phase_params, *(token for _ in token_columns)),
            ).fetchone()
            if row is not None:
                return True
    except Exception as exc:  # noqa: BLE001 - sizing must fail closed on exposure ambiguity.
        raise RuntimeError(
            f"DURABLE_LIVE_CAP_TRADE_TRUTH_UNAVAILABLE:{type(exc).__name__}:{exc}"
        ) from exc
    return False


def _position_current_columns(conn: sqlite3.Connection) -> set[str]:
    try:
        columns = {
            str(row[1] if not isinstance(row, sqlite3.Row) else row["name"])
            for row in conn.execute("PRAGMA table_info(position_current)").fetchall()
        }
        if columns:
            return columns
        for schema_row in conn.execute("PRAGMA database_list").fetchall():
            schema = schema_row[1] if not isinstance(schema_row, sqlite3.Row) else schema_row["name"]
            if schema in ("main", "temp"):
                continue
            columns = {
                str(row[1] if not isinstance(row, sqlite3.Row) else row["name"])
                for row in conn.execute(f"PRAGMA {schema}.table_info(position_current)").fetchall()
            }
            if columns:
                return columns
        return set()
    except Exception as exc:  # noqa: BLE001 - live exposure truth ambiguity is fatal.
        raise RuntimeError(
            f"OPEN_POSITION_TRUTH_UNAVAILABLE:{type(exc).__name__}:{exc}"
        ) from exc


def _entry_held_position_same_token_reason(
    conn: sqlite3.Connection | None,
    *,
    token_id: str,
) -> str | None:
    """Return a selection-exclusion reason when an entry token is already held.

    ``position_current`` is the canonical held-position truth. A held token belongs
    to the monitor/exit/redecision lifecycle, not to the ordinary new-entry
    selector. The executor keeps its duplicate gate as the last boundary, but the
    reactor must not use that boundary as normal control flow.
    """
    token = str(token_id or "").strip()
    if conn is None or not token:
        return None
    try:
        if not _adapter_table_exists(conn, "position_current"):
            return None
        columns = _position_current_columns(conn)
        token_columns = [name for name in ("token_id", "no_token_id") if name in columns]
        if not token_columns:
            return None
        phase_expr = "phase" if "phase" in columns else "''"
        position_id_expr = "position_id" if "position_id" in columns else "''"
        positive_terms = [
            f"COALESCE({name}, 0) > 0"
            for name in ("chain_shares", "shares", "chain_cost_basis_usd", "cost_basis_usd", "size_usd")
            if name in columns
        ]
        positive_sql = " AND (" + " OR ".join(positive_terms) + ")" if positive_terms else ""
        token_sql = " OR ".join(f"NULLIF({name}, '') = ?" for name in token_columns)
        phase_sql, phase_params = _position_phase_or_positive_chain_clause(
            columns,
            _DURABLE_LIVE_CAP_MATERIALIZED_POSITION_PHASES,
        )
        row = conn.execute(
            f"""
            SELECT {position_id_expr} AS position_id, {phase_expr} AS phase
              FROM position_current
             WHERE {phase_sql}
               AND ({token_sql})
               {positive_sql}
             LIMIT 1
            """,
            (
                *phase_params,
                *(token for _ in token_columns),
            ),
        ).fetchone()
        if row is None:
            return None
        position_id = str(row["position_id"] if isinstance(row, sqlite3.Row) else row[0] or "")
        phase = str(row["phase"] if isinstance(row, sqlite3.Row) else row[1] or "")
        return (
            f"{_ENTRY_HELD_POSITION_REASON_BASE}:"
            f"position_id={position_id or 'unknown'}:"
            f"phase={phase or 'unknown'}"
        )
    except Exception as exc:  # noqa: BLE001 - fail closed on exposure truth ambiguity.
        raise RuntimeError(
            f"OPEN_POSITION_TRUTH_UNAVAILABLE:{type(exc).__name__}:{exc}"
        ) from exc


def _entry_family_metric(value: object) -> str:
    metric = str(value or "").strip().lower()
    if metric in {"high", "tmax", "max", "maximum", "highest"}:
        return "high"
    if metric in {"low", "tmin", "min", "minimum", "lowest"}:
        return "low"
    return metric


def _proof_family_fields(proof: "_CandidateProof") -> tuple[str, str, str] | None:
    candidate = getattr(proof, "candidate", None)
    if candidate is None:
        return None
    city = str(getattr(candidate, "city", "") or "").strip()
    target_date = str(getattr(candidate, "target_date", "") or "").strip()
    metric = _entry_family_metric(getattr(candidate, "metric", ""))
    if not (city and target_date and metric):
        return None
    return city, target_date, metric


def _entry_held_position_same_family_reason(
    conn: sqlite3.Connection | None,
    proof: "_CandidateProof",
) -> str | None:
    """Return a selection-exclusion reason when this weather family is held.

    A weather city/date/metric family is a mutually-exclusive partition. Once any
    bin in the family is held, adding another bin through the new-entry selector
    is a position-management decision, not a fresh opportunity. Rebalancing or
    switching belongs in monitor/redecision so it can account for current PnL,
    exit liquidity, and already-submitted orders.
    """
    fields = _proof_family_fields(proof)
    if conn is None or fields is None:
        return None
    city, target_date, metric = fields
    try:
        if not _adapter_table_exists(conn, "position_current"):
            return None
        columns = _position_current_columns(conn)
        if "city" not in columns or "target_date" not in columns:
            return None
        metric_column = "temperature_metric" if "temperature_metric" in columns else "metric" if "metric" in columns else ""
        if not metric_column:
            return None
        phase_expr = "phase" if "phase" in columns else "''"
        position_id_expr = "position_id" if "position_id" in columns else "''"
        bin_label_expr = "bin_label" if "bin_label" in columns else "''"
        condition_id_expr = "condition_id" if "condition_id" in columns else "''"
        positive_terms = [
            f"COALESCE({name}, 0) > 0"
            for name in ("chain_shares", "shares", "chain_cost_basis_usd", "cost_basis_usd", "size_usd")
            if name in columns
        ]
        if not positive_terms:
            return None
        positive_sql = " AND (" + " OR ".join(positive_terms) + ")"
        order_sql = "ORDER BY updated_at DESC" if "updated_at" in columns else ""
        phase_sql, phase_params = _position_phase_or_positive_chain_clause(
            columns,
            _ENTRY_HELD_POSITION_BLOCKING_PHASES,
        )
        rows = conn.execute(
            f"""
            SELECT
                {position_id_expr} AS position_id,
                {phase_expr} AS phase,
                {bin_label_expr} AS bin_label,
                {condition_id_expr} AS condition_id,
                {metric_column} AS temperature_metric
              FROM position_current
             WHERE {phase_sql}
               AND city = ?
               AND target_date = ?
               {positive_sql}
             {order_sql}
            """,
            (
                *phase_params,
                city,
                target_date,
            ),
        ).fetchall()
        for row in rows:
            row_metric = row["temperature_metric"] if isinstance(row, sqlite3.Row) else row[4]
            if _entry_family_metric(row_metric) != metric:
                continue
            position_id = str(row["position_id"] if isinstance(row, sqlite3.Row) else row[0] or "")
            phase = str(row["phase"] if isinstance(row, sqlite3.Row) else row[1] or "")
            bin_label = str(row["bin_label"] if isinstance(row, sqlite3.Row) else row[2] or "")
            condition_id = str(row["condition_id"] if isinstance(row, sqlite3.Row) else row[3] or "")
            return (
                f"{_ENTRY_HELD_FAMILY_REASON_BASE}:"
                f"position_id={position_id or 'unknown'}:"
                f"phase={phase or 'unknown'}:"
                f"bin_label={bin_label or 'unknown'}:"
                f"condition_id={condition_id or 'unknown'}"
            )
    except Exception as exc:  # noqa: BLE001 - fail closed on exposure truth ambiguity.
        raise RuntimeError(
            f"OPEN_POSITION_TRUTH_UNAVAILABLE:{type(exc).__name__}:{exc}"
        ) from exc
    return None


def _entry_held_position_reason_for_proof(
    conn: sqlite3.Connection | None,
    proof: "_CandidateProof",
) -> str | None:
    same_token_reason = _entry_held_position_same_token_reason(
        conn,
        token_id=str(getattr(proof, "token_id", "") or ""),
    )
    if same_token_reason is not None:
        return same_token_reason
    return _entry_held_position_same_family_reason(conn, proof)


def _durable_unmaterialized_live_cap_reservations(
    conn: sqlite3.Connection | None,
    *,
    trade_conn: sqlite3.Connection | None = None,
) -> tuple[tuple[str, str, float], ...]:
    """Return durable live-cap exposure not yet represented by position truth.

    ``position_current`` is the canonical open-position truth after a
    ``UserTradeObserved`` bridge. Between venue submit and user-channel/bridge
    materialization, however, the submitted notional is real in-flight capital.
    Seed that cross-cycle exposure into the same Kelly reservation ledger so a
    later reactor cycle cannot over-size while waiting for fills to arrive.
    """
    if conn is None:
        return ()
    try:
        if not (
            _adapter_table_exists(conn, "edli_live_cap_usage")
            and _adapter_table_exists(conn, "edli_live_order_events")
        ):
            return ()
        rows = conn.execute(
            """
            WITH live_cap AS (
                SELECT
                    usage_id,
                    event_id,
                    final_intent_id,
                    execution_command_id,
                    reserved_notional_usd,
                    event_id || ':' || COALESCE(final_intent_id, '') AS aggregate_id
                FROM edli_live_cap_usage
                WHERE reservation_status IN ('RESERVED', 'CONSUMED')
                  AND reserved_notional_usd > 0
            ),
            observed AS (
                SELECT DISTINCT aggregate_id
                FROM edli_live_order_events
                WHERE event_type = 'UserTradeObserved'
                  AND json_extract(payload_json, '$.fill_authority_state') = 'FILL_CONFIRMED'
            ),
            absence_reconciled AS (
                SELECT DISTINCT aggregate_id
                FROM edli_live_order_events
                WHERE event_type = 'Reconciled'
                  AND (
                    json_extract(payload_json, '$.cap_transition_recommendation') = 'RELEASED'
                    OR json_type(payload_json, '$.authenticated_absence_proof') IS NOT NULL
                  )
            ),
            pre_submit AS (
                SELECT aggregate_id, payload_json
                FROM edli_live_order_events
                WHERE event_type = 'PreSubmitRevalidated'
            ),
            decision_audit AS (
                SELECT aggregate_id, payload_json
                FROM edli_live_order_events
                WHERE event_type = 'DecisionProofAccepted'
            )
            SELECT
                live_cap.usage_id,
                live_cap.final_intent_id,
                live_cap.execution_command_id,
                COALESCE(
                    NULLIF(json_extract(pre_submit.payload_json, '$.city'), ''),
                    NULLIF(json_extract(decision_audit.payload_json, '$.decision_audit.city'), ''),
                    ?
                ) AS city,
                live_cap.reserved_notional_usd
            FROM live_cap
            LEFT JOIN observed ON observed.aggregate_id = live_cap.aggregate_id
            LEFT JOIN absence_reconciled ON absence_reconciled.aggregate_id = live_cap.aggregate_id
            LEFT JOIN pre_submit ON pre_submit.aggregate_id = live_cap.aggregate_id
            LEFT JOIN decision_audit ON decision_audit.aggregate_id = live_cap.aggregate_id
            WHERE observed.aggregate_id IS NULL
              AND absence_reconciled.aggregate_id IS NULL
            ORDER BY live_cap.usage_id
            """,
            (_DURABLE_LIVE_CAP_UNKNOWN_CITY,),
        ).fetchall()
    except Exception as exc:  # noqa: BLE001 - sizing must fail closed on exposure ambiguity.
        import logging

        logging.getLogger("zeus.edli_portfolio").warning(
            "durable live-cap exposure seed unavailable: %s: %s",
            type(exc).__name__,
            exc,
        )
        raise RuntimeError(
            f"DURABLE_LIVE_CAP_EXPOSURE_SEED_UNAVAILABLE:{type(exc).__name__}:{exc}"
        ) from exc
    out: list[tuple[str, str, float]] = []
    for row in rows:
        usage_id = str(row[0] if not isinstance(row, sqlite3.Row) else row["usage_id"])
        final_intent_id = str(row[1] if not isinstance(row, sqlite3.Row) else row["final_intent_id"] or "")
        execution_command_id = str(row[2] if not isinstance(row, sqlite3.Row) else row["execution_command_id"] or "")
        city = str(row[3] if not isinstance(row, sqlite3.Row) else row["city"])
        reserved = float(row[4] if not isinstance(row, sqlite3.Row) else row["reserved_notional_usd"])
        if _durable_live_cap_usage_is_represented_in_trade_truth(
            trade_conn,
            execution_command_id=execution_command_id,
            final_intent_id=final_intent_id,
        ):
            continue
        if usage_id and reserved > 0.0:
            out.append((f"durable_live_cap:{usage_id}", city, reserved))
    return tuple(out)


def _same_token_pending_entry_usd(
    conn: sqlite3.Connection | None,
    *,
    token_id: str,
    trade_conn: sqlite3.Connection | None = None,
) -> float:
    """Sum durable in-flight ENTRY notional for the SAME token not yet materialized.

    D1 fill-up residual sizing (consult [HIGH] fill-up sizing): the residual to the
    fresh target nets a live SAME-token pending entry from a prior cycle that has not
    yet reached ``position_current`` — without this a fill-up could re-add capital
    already in flight for the same leg. Reuses the existing durable-live-cap reducer
    (``_durable_unmaterialized_live_cap_reservations``) and filters to the rows whose
    ``final_intent_id`` token suffix equals the selected token. Fails CLOSED: any read
    error raises (the caller treats sizing-truth ambiguity as a no-fill-up), never
    silently returns 0 and over-sizes.
    """
    token = str(token_id or "").strip()
    if conn is None or not token:
        return 0.0
    total = 0.0
    if not (
        _adapter_table_exists(conn, "edli_live_cap_usage")
        and _adapter_table_exists(conn, "edli_live_order_events")
    ):
        return 0.0
    # Per-token in-flight sum: reserved live-cap rows for THIS token not yet
    # represented in trade truth. The city-keyed _durable_unmaterialized_live_cap_
    # reservations tuple is not token-scoped, so re-derive directly from the live-cap
    # rows and filter by the final_intent_id token suffix, reusing the SAME
    # represented-in-trade-truth check the city reducer uses (no parallel exposure
    # calc).
    rows = conn.execute(
        """
        SELECT final_intent_id, execution_command_id, reserved_notional_usd
          FROM edli_live_cap_usage
         WHERE reservation_status IN ('RESERVED', 'CONSUMED')
           AND reserved_notional_usd > 0
        """
    ).fetchall()
    for row in rows:
        final_intent_id = str(
            row[0] if not isinstance(row, sqlite3.Row) else row["final_intent_id"] or ""
        )
        execution_command_id = str(
            row[1] if not isinstance(row, sqlite3.Row) else row["execution_command_id"] or ""
        )
        reserved = float(
            row[2] if not isinstance(row, sqlite3.Row) else row["reserved_notional_usd"]
        )
        if _durable_live_cap_final_intent_token(final_intent_id) != token:
            continue
        if _durable_live_cap_usage_is_represented_in_trade_truth(
            trade_conn or conn,
            execution_command_id=execution_command_id,
            final_intent_id=final_intent_id,
        ):
            continue
        if reserved > 0.0:
            total += reserved
    return total


def _read_old_leg_exit_inputs(
    conn: sqlite3.Connection | None,
    *,
    old_token_id: str,
) -> tuple[float, float, float | None, dict[str, object]] | None:
    """Read the OLD leg's shares + a sell price + snapshot identity for an exit.

    Returns (shares, current_price, best_bid, snapshot_identity) from canonical
    ``position_current`` + the latest executable snapshot for the old token, or None
    when the old leg is no longer held (proven closed) or truth is unavailable.

    The price is the latest executable-snapshot best-bid/ask for the old token; it is
    only a SEED. ``execute_exit_order`` re-runs the executable-snapshot gate + identity
    check and fails CLOSED on a stale/mismatched snapshot, so a stale seed price never
    becomes a false/bad exit — the exit is gated and the SHIFT_BIN lease stays blocking
    for a legitimate retry next cycle (close-before-open holds either way).
    """
    token = str(old_token_id or "").strip()
    if conn is None or not token:
        return None
    if not _adapter_table_exists(conn, "position_current"):
        return None
    cols = _position_current_columns(conn)
    token_cols = [c for c in ("token_id", "no_token_id") if c in cols]
    share_terms = [c for c in ("chain_shares", "shares") if c in cols]
    if not token_cols or not share_terms:
        return None
    phase_sql, phase_params = _position_phase_or_positive_chain_clause(
        cols,
        _ENTRY_HELD_POSITION_BLOCKING_PHASES,
    )
    token_sql = " OR ".join(f"NULLIF({c}, '') = ?" for c in token_cols)
    selected_columns = (
        "chain_shares",
        "shares",
        "token_id",
        "no_token_id",
        "direction",
        "condition_id",
    )
    select_cols = [c if c in cols else f"NULL AS {c}" for c in selected_columns]
    select_idx = {name: idx for idx, name in enumerate(selected_columns)}
    order_sql = "ORDER BY updated_at DESC" if "updated_at" in cols else ""
    sql = (
        f"SELECT {', '.join(select_cols)} FROM position_current "
        f"WHERE {phase_sql} AND ({token_sql}) {order_sql} LIMIT 1"
    )
    params: list[object] = []
    params.extend(phase_params)
    params.extend(token for _ in token_cols)
    try:
        row = conn.execute(sql, tuple(params)).fetchone()
    except sqlite3.Error:
        return None
    if row is None:
        return None  # old leg no longer held → proven closed

    def _g(name: str):
        try:
            if isinstance(row, sqlite3.Row):
                return row[name]
            idx = select_idx.get(name)
            return row[idx] if idx is not None else None
        except (IndexError, KeyError):
            return None

    shares = 0.0
    for value in (_g("chain_shares"), _g("shares")):
        try:
            v = float(value) if value is not None else 0.0
        except (TypeError, ValueError):
            v = 0.0
        if v > 0.0:
            shares = v
            break
    if shares <= 0.0:
        return None

    # Seed price + snapshot identity from the latest executable snapshot for the old
    # token (the SAME source the monitor exit lane seeds from before its fresh capture).
    try:
        from src.execution.exit_lifecycle import (
            _latest_exit_snapshot_context,
            _latest_exit_snapshot_identity_seed,
        )
        snap_ctx = _latest_exit_snapshot_context(conn, token) or {}
        _identity = _latest_exit_snapshot_identity_seed(conn, token) or {}
    except Exception:  # noqa: BLE001 — missing snapshot helpers → no exit this cycle.
        return None
    snap_ctx = dict(snap_ctx)
    if _identity:
        snap_ctx["_exit_identity_seed"] = dict(_identity)
    snap_ctx["_position_yes_token_id"] = str(_g("token_id") or "")
    snap_ctx["_position_no_token_id"] = str(_g("no_token_id") or "")
    snap_ctx["_position_direction"] = str(_g("direction") or "")
    snap_ctx["_position_condition_id"] = str(_g("condition_id") or "")

    # Best-bid as the conservative sell-touch seed. Prefer the fresh executable
    # snapshot when present; otherwise use the latest stale snapshot only as a
    # price seed. The executor still requires a fresh snapshot context before it
    # can submit.
    best_bid: float | None = None
    current_price = 0.0
    try:
        from src.state.snapshot_repo import get_snapshot
        snap_id = str(snap_ctx.get("executable_snapshot_id") or "")
        snap = get_snapshot(conn, snap_id) if snap_id else None
    except Exception:  # noqa: BLE001
        snap = None
    if snap is None:
        try:
            saved_factory = conn.row_factory
            conn.row_factory = sqlite3.Row
            stale_row = conn.execute(
                """
                SELECT snapshot_id, orderbook_top_bid
                  FROM executable_market_snapshots
                 WHERE selected_outcome_token_id = ?
                 ORDER BY captured_at DESC, snapshot_id DESC
                 LIMIT 1
                """,
                (token,),
            ).fetchone()
        except sqlite3.Error:
            stale_row = None
        finally:
            with contextlib.suppress(Exception):
                conn.row_factory = saved_factory
        if stale_row is not None:
            try:
                v = stale_row["orderbook_top_bid"]
                if v is not None and float(v) > 0.0:
                    best_bid = float(v)
            except (TypeError, ValueError, IndexError, KeyError):
                best_bid = None
    if snap is not None:
        # The executable snapshot dataclass exposes the touch as ``orderbook_top_bid``
        # (the SAME attribute the existing exit lane reads — see the witness/exit
        # snapshot handling). The earlier (best_bid/selected_outcome_best_bid) names do
        # not exist on the snapshot object, so without orderbook_top_bid first the seed
        # stayed 0.0 and the old-leg exit DEFERRED every cycle (shift-bin never fired —
        # safe but inert). Real attribute first, the others kept as harmless fallbacks.
        for attr in ("orderbook_top_bid", "best_bid", "selected_outcome_best_bid"):
            v = getattr(snap, attr, None)
            try:
                if v is not None and float(v) > 0.0:
                    best_bid = float(v)
                    break
            except (TypeError, ValueError):
                continue
    if best_bid is not None:
        current_price = best_bid
    if current_price <= 0.0:
        # No usable seed price; defer to a later cycle (lease stays blocking).
        return None
    return shares, current_price, best_bid, dict(snap_ctx)


def _shift_exit_has_durable_command(
    conn: sqlite3.Connection | None,
    *,
    decision_id: str,
) -> bool:
    if conn is None or not str(decision_id or "").strip():
        return False
    try:
        if not _adapter_table_exists(conn, "venue_commands"):
            return False
        row = conn.execute(
            """
            SELECT 1
              FROM venue_commands
             WHERE decision_id = ?
               AND intent_kind = 'EXIT'
             LIMIT 1
            """,
            (str(decision_id),),
        ).fetchone()
        return row is not None
    except sqlite3.Error:
        return False


def _shift_exit_rejection_requires_retry(reason: str) -> bool:
    """Whether a rejected old-leg exit is infrastructure/auth, not strategy finality."""

    normalized = " ".join(str(reason or "").lower().split())
    if not normalized:
        return False
    return (
        "invalid poly_gnosis_safe signature" in normalized
        or "venue_auth_invalid_signature_400" in normalized
    )


_SHIFT_EXIT_TERMINAL_COMMAND_STATES = frozenset({
    "CANCELLED",
    "CANCELED",
    "EXPIRED",
    "FILLED",
    "REJECTED",
    "SUBMIT_REJECTED",
})


def _latest_shift_exit_inflight_command(
    conn: sqlite3.Connection,
    *,
    decision_id: str,
    old_token_id: str,
) -> dict[str, str] | None:
    """Return an existing non-terminal old-leg exit command for this shift, if any."""

    token = str(old_token_id or "").strip()
    if not (decision_id and token):
        return None
    terminal_placeholders = ",".join("?" for _ in _SHIFT_EXIT_TERMINAL_COMMAND_STATES)
    try:
        row = conn.execute(
            f"""
            SELECT command_id,
                   COALESCE(state, '') AS state,
                   COALESCE(venue_order_id, '') AS venue_order_id
              FROM venue_commands
             WHERE decision_id = ?
               AND intent_kind = 'EXIT'
               AND token_id = ?
               AND UPPER(COALESCE(state, '')) NOT IN ({terminal_placeholders})
             ORDER BY updated_at DESC, created_at DESC
             LIMIT 1
            """,
            (decision_id, token, *sorted(_SHIFT_EXIT_TERMINAL_COMMAND_STATES)),
        ).fetchone()
    except sqlite3.Error:
        return None
    if row is None:
        return None
    try:
        command_id = str(row["command_id"] or "")
        state = str(row["state"] or "")
        venue_order_id = str(row["venue_order_id"] or "")
    except (TypeError, KeyError, IndexError):
        command_id = str(row[0] or "")
        state = str(row[1] or "")
        venue_order_id = str(row[2] or "")
    if not command_id:
        return None
    return {"command_id": command_id, "state": state, "venue_order_id": venue_order_id}


def _shift_exit_lease_status_for_command(state: str) -> str:
    normalized = str(state or "").upper()
    if normalized == "PARTIAL":
        return "EXIT_PARTIAL"
    if normalized in {"UNKNOWN", "SUBMIT_UNKNOWN_SIDE_EFFECT", "REVIEW_REQUIRED"}:
        return "EXIT_UNKNOWN"
    return "EXIT_SUBMITTED"


def _latest_chain_ctf_token_balance_micro(
    conn: sqlite3.Connection,
    *,
    token_id: str,
) -> int | None:
    """Latest CHAIN total CTF balance for a token, independent of sell reservations."""

    token = str(token_id or "").strip()
    if not token:
        return None
    try:
        row = conn.execute(
            """
            SELECT ctf_token_balances_json
              FROM collateral_ledger_snapshots
             WHERE authority_tier = 'CHAIN'
             ORDER BY captured_at DESC, id DESC
             LIMIT 1
            """
        ).fetchone()
    except sqlite3.Error:
        return None
    if row is None:
        return None
    try:
        raw = row["ctf_token_balances_json"]
    except (TypeError, KeyError, IndexError):
        raw = row[0]
    try:
        payload = json.loads(raw or "{}")
    except (TypeError, json.JSONDecodeError):
        return None
    try:
        return int(payload.get(token, 0) or 0)
    except (TypeError, ValueError):
        return None


def _shift_exit_collateral_proves_old_leg_closed(
    conn: sqlite3.Connection,
    exc: BaseException,
    *,
    old_token_id: str,
) -> bool:
    """Whether CHAIN collateral truth proves the old SHIFT_BIN leg is already gone.

    ``ctf_tokens_insufficient ... available=0`` is not proof by itself: the token can
    still be held while fully reserved by an already-ACKED sell. Only the latest CHAIN
    total balance being zero proves the old leg is gone.
    """

    normalized = " ".join(str(exc or "").lower().split())
    token = str(old_token_id or "").strip().lower()
    if not token:
        return False
    if not (
        "ctf_tokens_insufficient" in normalized
        and f"token_id={token}" in normalized
        and "available=0" in normalized
    ):
        return False
    balance = _latest_chain_ctf_token_balance_micro(conn, token_id=old_token_id)
    return balance is not None and balance <= 0


def _submit_shift_bin_old_leg_exit(
    conn: sqlite3.Connection,
    *,
    payload: dict[str, object],
    decision_time: datetime,
) -> None:
    """Submit the reduce-only exit for a SHIFT_BIN old leg via the existing exit path.

    Reads the old leg's shares + seed price (``_read_old_leg_exit_inputs``), builds an
    ``ExitOrderIntent``, and calls ``execute_exit_order`` (idempotent, ExitMutex, full
    pre-submit gate chain, self-built client). Advances the SHIFT_BIN lease by the exit
    OrderResult.status:
      - "pending"             → EXIT_SUBMITTED (sell acked at venue; family stays
                                blocking until the residual is proven zero/dust).
      - "unknown_side_effect" → EXIT_UNKNOWN (block the family; reconciliation owns it;
                                NO counter-entry, NO replacement).
      - "rejected"            → ABORTED for clean pre-venue rejection; auth/signature
                                infrastructure rejects with a durable command stay
                                EXIT_UNKNOWN so the old-leg retry is not terminalized
                                as a strategy failure.
    Any read miss (old leg already closed, no seed price) leaves the lease unchanged
    (EXIT_SUBMITTED) so the next cycle re-attempts — close-before-open is preserved.
    """
    intent_id = payload.get("intent_id")
    old_position_id = str(payload.get("old_position_id") or "")
    old_token_id = str(payload.get("old_token_id") or "")
    now_iso = decision_time.isoformat() if hasattr(decision_time, "isoformat") else str(decision_time)
    if not (intent_id and old_position_id and old_token_id):
        return
    decision_id = f"shift_bin_exit:{old_position_id}"
    inputs = _read_old_leg_exit_inputs(conn, old_token_id=old_token_id)
    if inputs is None:
        # Old leg not readable / already closed / no seed price — leave the lease in
        # EXIT_SUBMITTED (blocking) so the next redecision cycle re-evaluates.
        return
    shares, current_price, best_bid, snap_ctx = inputs
    existing_exit = _latest_shift_exit_inflight_command(
        conn,
        decision_id=decision_id,
        old_token_id=old_token_id,
    )
    if existing_exit is not None:
        _shift_bin_wiring.record_exit_submitted(
            conn,
            intent_id,
            now_iso=now_iso,
            old_exit_command_id=existing_exit["command_id"],
            status=_shift_exit_lease_status_for_command(existing_exit["state"]),
            reason=(
                "SHIFT_BIN_EXIT_ALREADY_IN_FLIGHT:"
                f"{existing_exit['state']}:{existing_exit['command_id']}"
            ),
        )
        return
    if not str(snap_ctx.get("executable_snapshot_id") or "").strip():
        identity = snap_ctx.get("_exit_identity_seed")
        if isinstance(identity, Mapping):
            try:
                from types import SimpleNamespace
                from src.data.polymarket_client import PolymarketClient
                from src.execution.exit_lifecycle import _latest_or_capture_exit_snapshot_context

                position_stub = SimpleNamespace(
                    trade_id=old_position_id,
                    market_id=str(
                        identity.get("market_id")
                        or identity.get("condition_id")
                        or snap_ctx.get("_position_condition_id")
                        or ""
                    ),
                    condition_id=str(
                        identity.get("condition_id")
                        or snap_ctx.get("_position_condition_id")
                        or ""
                    ),
                    token_id=str(
                        identity.get("token_id")
                        or snap_ctx.get("_position_yes_token_id")
                        or ""
                    ),
                    no_token_id=str(
                        identity.get("no_token_id")
                        or snap_ctx.get("_position_no_token_id")
                        or ""
                    ),
                    direction=str(snap_ctx.get("_position_direction") or ""),
                )
                with PolymarketClient(public_http_timeout=15) as clob:
                    fresh_ctx = _latest_or_capture_exit_snapshot_context(
                        conn,
                        clob,
                        position_stub,
                        old_token_id,
                        now=decision_time,
                    )
                if fresh_ctx:
                    snap_ctx.update(fresh_ctx)
            except Exception as exc:  # noqa: BLE001
                import logging as _logging

                _logging.getLogger(__name__).warning(
                    "SHIFT_BIN old-leg fresh exit snapshot capture failed: %s: %s",
                    type(exc).__name__,
                    exc,
                )
    try:
        from src.execution.exit_lifecycle import place_sell_order
        result = place_sell_order(
            trade_id=old_position_id,
            token_id=old_token_id,
            shares=float(shares),
            current_price=float(current_price),
            best_bid=best_bid,
            executable_snapshot_id=str(snap_ctx.get("executable_snapshot_id") or ""),
            executable_snapshot_hash=str(snap_ctx.get("executable_snapshot_hash") or ""),
            executable_snapshot_min_tick_size=snap_ctx.get("executable_snapshot_min_tick_size"),
            executable_snapshot_min_order_size=snap_ctx.get("executable_snapshot_min_order_size"),
            executable_snapshot_neg_risk=snap_ctx.get("executable_snapshot_neg_risk"),
            decision_id=decision_id,
        )
    except Exception as exc:  # noqa: BLE001 — venue boundary unknown → block the family.
        reason = f"SHIFT_BIN_EXIT_EXCEPTION:{type(exc).__name__}:{exc}"
        if _shift_exit_collateral_proves_old_leg_closed(conn, exc, old_token_id=old_token_id):
            _shift_bin_wiring.exit_only_complete(
                conn,
                intent_id,
                now_iso=now_iso,
                reason=f"SHIFT_BIN_OLD_LEG_CHAIN_ZERO_COLLATERAL:{reason}",
            )
            import logging as _logging

            _logging.getLogger(__name__).warning(
                "SHIFT_BIN old-leg exit released: chain collateral proves zero old-token "
                "balance token_id=%s reason=%s",
                old_token_id,
                exc,
            )
            return
        existing_exit = _latest_shift_exit_inflight_command(
            conn,
            decision_id=decision_id,
            old_token_id=old_token_id,
        )
        if existing_exit is not None:
            _shift_bin_wiring.record_exit_submitted(
                conn,
                intent_id,
                now_iso=now_iso,
                old_exit_command_id=existing_exit["command_id"],
                status=_shift_exit_lease_status_for_command(existing_exit["state"]),
                reason=(
                    "SHIFT_BIN_EXIT_EXCEPTION_EXISTING_COMMAND:"
                    f"{existing_exit['state']}:{existing_exit['command_id']}:{reason}"
                ),
            )
            import logging as _logging

            _logging.getLogger(__name__).warning(
                "SHIFT_BIN old-leg exit reattached existing command after exception: "
                "command_id=%s state=%s reason=%s",
                existing_exit["command_id"],
                existing_exit["state"],
                exc,
            )
            return
        lease_status = "EXIT_UNKNOWN"
        if not _shift_exit_has_durable_command(conn, decision_id=decision_id):
            _shift_bin_wiring.abort_shift_bin_lease(
                conn, intent_id, now_iso=now_iso, reason=f"{reason}:NO_DURABLE_COMMAND"
            )
            lease_status = "ABORTED_NO_DURABLE_COMMAND"
        else:
            _shift_bin_wiring.record_exit_submitted(
                conn, intent_id, now_iso=now_iso, status="EXIT_UNKNOWN", reason=reason
            )
        import logging as _logging
        _logging.getLogger(__name__).warning(
            "SHIFT_BIN old-leg exit raised (lease_status=%s): %s: %s",
            lease_status, type(exc).__name__, exc,
        )
        return
    status = str(getattr(result, "status", "") or "")
    command_id = str(getattr(result, "order_id", "") or getattr(result, "external_order_id", "") or "")
    if status == "pending":
        _shift_bin_wiring.record_exit_submitted(
            conn, intent_id, now_iso=now_iso,
            old_exit_command_id=command_id or None, status="EXIT_SUBMITTED",
        )
    elif status == "unknown_side_effect":
        reason = str(getattr(result, "reason", "") or "unknown_side_effect")
        if command_id or _shift_exit_has_durable_command(conn, decision_id=decision_id):
            _shift_bin_wiring.record_exit_submitted(
                conn, intent_id, now_iso=now_iso,
                old_exit_command_id=command_id or None, status="EXIT_UNKNOWN",
                reason=f"SHIFT_BIN_EXIT_UNKNOWN:{reason}",
            )
        else:
            _shift_bin_wiring.abort_shift_bin_lease(
                conn, intent_id, now_iso=now_iso,
                reason=f"SHIFT_BIN_EXIT_UNKNOWN_NO_DURABLE_COMMAND:{reason}",
            )
    else:
        reason = str(getattr(result, "reason", "") or status)
        has_command = bool(command_id) or _shift_exit_has_durable_command(
            conn, decision_id=decision_id
        )
        if has_command and _shift_exit_rejection_requires_retry(reason):
            _shift_bin_wiring.record_exit_submitted(
                conn,
                intent_id,
                now_iso=now_iso,
                old_exit_command_id=command_id or None,
                status="EXIT_UNKNOWN",
                reason=f"SHIFT_BIN_EXIT_RETRYABLE_REJECTED:{reason}",
            )
            return
        # Clean pre-venue rejection (mutex held, collateral, snapshot gate, malformed
        # price, shares→0): no side effect. Release the lease for a legitimate retry.
        _shift_bin_wiring.abort_shift_bin_lease(
            conn, intent_id, now_iso=now_iso,
            reason=f"SHIFT_BIN_EXIT_REJECTED:{reason}",
        )


def _seed_portfolio_reservations_from_durable_live_cap(
    ledger: PortfolioReservationLedger,
    conn: sqlite3.Connection | None,
    *,
    trade_conn: sqlite3.Connection | None = None,
) -> int:
    seeded = 0
    for reservation_id, city, reserved_usd in _durable_unmaterialized_live_cap_reservations(
        conn,
        trade_conn=trade_conn,
    ):
        ledger.seed_committed(reservation_id, city, reserved_usd)
        seeded += 1
    return seeded


def _event_bound_strategy_key(
    *,
    event_type: str,
    direction: str | None,
    metric: str | None,
    require_metric_live: bool = False,
) -> str:
    """Classify the EDLI event-bound entry strategy without mixing live lanes."""

    direction_value = getattr(direction, "value", direction)
    normalized_direction = str(direction_value or "").strip().lower()
    if normalized_direction in {"yes", "direction.yes"}:
        normalized_direction = "buy_yes"
    elif normalized_direction in {"no", "direction.no"}:
        normalized_direction = "buy_no"
    normalized_metric = str(metric or "").strip().lower()
    if event_type == "DAY0_EXTREME_UPDATED":
        if normalized_direction == "buy_no":
            strategy = "settlement_capture"
        elif normalized_direction == "buy_yes":
            strategy = "day0_nowcast_entry"
        else:
            raise ValueError(f"EDLI_STRATEGY_DIRECTION_UNKNOWN:{event_type}:{normalized_direction}")
    elif event_type in _FORECAST_DECISION_EVENT_TYPES:
        if normalized_direction not in {"buy_yes", "buy_no"}:
            raise ValueError(f"EDLI_STRATEGY_DIRECTION_UNKNOWN:{event_type}:{normalized_direction}")
        strategy = "forecast_qkernel_entry"
    else:
        raise ValueError(f"EDLI_STRATEGY_UNSUPPORTED_EVENT_TYPE:{event_type}")

    from src.strategy.strategy_profile import try_get

    profile = try_get(strategy)
    if profile is None or not profile.is_runtime_live():
        raise ValueError(f"EDLI_STRATEGY_NOT_RUNTIME_LIVE:{strategy}")
    if normalized_direction and not profile.is_direction_allowed(normalized_direction):
        raise ValueError(
            f"EDLI_STRATEGY_DIRECTION_BLOCKED:{strategy}:direction={normalized_direction}"
        )
    if require_metric_live and normalized_metric and not profile.metric_is_live(normalized_metric):
        raise ValueError(f"EDLI_STRATEGY_METRIC_BLOCKED:{strategy}:metric={normalized_metric}")
    return strategy


def _assert_event_bound_strategy_live_admitted(
    *,
    strategy_key: str | None,
    direction: str | None,
    metric: str | None,
) -> None:
    """Fail closed before the executor boundary if registry semantics reject the receipt."""

    from src.strategy.strategy_profile import try_get

    normalized_strategy = str(strategy_key or "").strip()
    normalized_direction = str(direction or "").strip().lower()
    normalized_metric = str(metric or "").strip().lower()
    profile = try_get(normalized_strategy)
    if profile is None or not profile.is_runtime_live():
        raise ValueError(f"EDLI_STRATEGY_NOT_RUNTIME_LIVE:{normalized_strategy or 'missing'}")
    if normalized_direction and not profile.is_direction_allowed(normalized_direction):
        raise ValueError(
            f"EDLI_STRATEGY_DIRECTION_BLOCKED:{normalized_strategy}:direction={normalized_direction}"
        )
    if normalized_metric and not profile.metric_is_live(normalized_metric):
        raise ValueError(f"EDLI_STRATEGY_METRIC_BLOCKED:{normalized_strategy}:metric={normalized_metric}")


def _event_bound_strategy_live_quality_floors(strategy_key: str | None) -> dict[str, float]:
    """Return strategy-owned final-submit economic floors for event-bound orders."""

    from src.strategy.strategy_profile import try_get

    profile = try_get(str(strategy_key or "").strip())
    return {
        "min_entry_price": float(
            getattr(profile, "min_entry_price", 0.05)
            if profile is not None
            else 0.05
        ),
        "min_expected_profit_usd": float(
            getattr(profile, "min_expected_profit_usd", 0.05)
            if profile is not None
            else 0.05
        ),
        "min_submit_edge_density": float(
            getattr(profile, "min_submit_edge_density", 0.02)
            if profile is not None
            else 0.02
        ),
    }


def _event_bound_effective_live_quality_floors(
    actionable_payload: Mapping[str, object],
) -> dict[str, float]:
    """Current registry floors, never weakened by older durable receipt payloads."""

    strategy_key = str(actionable_payload.get("strategy_key") or "").strip()
    if not strategy_key:
        event_type = str(actionable_payload.get("event_type") or "").strip()
        try:
            strategy_key = _event_bound_strategy_key(
                event_type=event_type,
                direction=str(actionable_payload.get("direction") or ""),
                metric=str(actionable_payload.get("metric") or ""),
            )
        except Exception:  # noqa: BLE001
            strategy_key = ""
    registry_floors = _event_bound_strategy_live_quality_floors(strategy_key)

    def _max_floor(field: str) -> float:
        payload_value = _optional_float(actionable_payload.get(field))
        registry_value = float(registry_floors[field])
        if payload_value is None:
            return registry_value
        return max(float(payload_value), registry_value)

    return {
        "min_entry_price": _max_floor("min_entry_price"),
        "min_expected_profit_usd": _max_floor("min_expected_profit_usd"),
        "min_submit_edge_density": _max_floor("min_submit_edge_density"),
    }


def _assert_event_bound_calibration_live_admitted(calibration: DecisionCertificate) -> None:
    """Require executable calibration evidence before real live entry commands."""

    payload = calibration.payload
    authority = str(payload.get("authority") or "").strip().upper()
    coverage_status = str(payload.get("coverage_status") or "").strip()
    n_samples_raw = payload.get("n_samples")
    try:
        n_samples = int(n_samples_raw) if n_samples_raw is not None else None
    except (TypeError, ValueError):
        n_samples = None
    if authority == "IDENTITY_FALLBACK_NO_PLATT_BUCKET":
        raise ValueError("EDLI_LIVE_CALIBRATION_AUTHORITY_BLOCKED:IDENTITY_FALLBACK_NO_PLATT_BUCKET")
    # CERT BRIDGE (2026-06-10, funnel #1 unlock; corrected 2026-06-30) — the
    # replacement credential has two live forms:
    #   * settlement-coverage licensed when enough claim-days exist;
    #   * conservative fused-bootstrap q_lcb when claim-history is still thin.
    # Missing/unknown coverage remains non-live; thin data is not allowed to masquerade
    # as settlement coverage and is not allowed to default-deny the bootstrap bound.
    if authority == FUSED_BOOTSTRAP_COVERAGE_UNEVALUATED_AUTHORITY:
        raise ValueError(
            "EDLI_LIVE_CALIBRATION_AUTHORITY_BLOCKED:FUSED_BOOTSTRAP_COVERAGE_UNEVALUATED"
        )
    if authority == DAY0_OBSERVATION_CALIBRATION_AUTHORITY:
        raise ValueError(
            "EDLI_LIVE_CALIBRATION_AUTHORITY_BLOCKED:"
            "DAY0_LIVE_OBSERVATION_HARD_FACT"
        )
    if authority == DAY0_REMAINING_WINDOW_CALIBRATION_AUTHORITY:
        from src.events.day0_authority import Day0AuthorityError, assert_live_day0_probability_authority

        try:
            assert_live_day0_probability_authority(payload)
        except Day0AuthorityError as exc:
            raise ValueError(f"EDLI_LIVE_CALIBRATION_DAY0_REMAINING_WINDOW_BLOCKED:{exc}") from None
        return
    if authority == FUSED_BOOTSTRAP_CONSERVATIVE_QLCB_AUTHORITY:
        if coverage_status != "INSUFFICIENT_DATA":
            raise ValueError(
                "EDLI_LIVE_CALIBRATION_COVERAGE_BLOCKED:"
                f"{coverage_status or 'missing'}"
            )
        if payload.get("q_lcb_basis") != _FUSED_BOOTSTRAP_QLCB_BASIS:
            raise ValueError("EDLI_LIVE_CALIBRATION_Q_LCB_BASIS_BLOCKED")
        try:
            bootstrap_draws = int(payload.get("bootstrap_draws"))
        except (TypeError, ValueError):
            bootstrap_draws = 0
        if bootstrap_draws < _FUSED_BOOTSTRAP_MIN_BOOTSTRAP_DRAWS:
            raise ValueError(
                "EDLI_LIVE_CALIBRATION_BOOTSTRAP_DRAW_FLOOR_BLOCKED:"
                f"draws={bootstrap_draws}:min_draws={_FUSED_BOOTSTRAP_MIN_BOOTSTRAP_DRAWS}"
            )
        return
    if authority == FUSED_BOOTSTRAP_CALIBRATION_AUTHORITY:
        if coverage_status == "INSUFFICIENT_DATA":
            raise ValueError(
                "EDLI_LIVE_CALIBRATION_COVERAGE_INSUFFICIENT:"
                f"n_samples={n_samples if n_samples is not None else 'missing'}:"
                f"min_samples={_FUSED_BOOTSTRAP_MIN_LIVE_SAMPLES}"
            )
        if n_samples is None or n_samples < _FUSED_BOOTSTRAP_MIN_LIVE_SAMPLES:
            raise ValueError(
                "EDLI_LIVE_CALIBRATION_SAMPLE_FLOOR_BLOCKED:"
                f"authority={authority or 'missing'}:"
                f"n_samples={n_samples if n_samples is not None else 'missing'}:"
                f"min_samples={_FUSED_BOOTSTRAP_MIN_LIVE_SAMPLES}"
            )
        if coverage_status not in _FUSED_BOOTSTRAP_CERT_COVERAGE_STATUSES:
            raise ValueError(
                "EDLI_LIVE_CALIBRATION_COVERAGE_BLOCKED:"
                f"{coverage_status or 'missing'}"
            )
        return


def _assert_event_bound_receipt_live_authority(receipt: EventSubmissionReceipt) -> None:
    """Real submit needs the family-selection provenance shown in receipts."""

    if str(receipt.q_source or "").strip() == "":
        raise ValueError("EDLI_LIVE_Q_SOURCE_MISSING")
    book = receipt.opportunity_book
    if not isinstance(book, dict):
        raise ValueError("EDLI_LIVE_OPPORTUNITY_BOOK_MISSING")
    selected = str(book.get("selected_candidate_id") or "").strip()
    actual = str(book.get("actual_receipt_selected_candidate_id") or "").strip()
    if not selected:
        raise ValueError("EDLI_LIVE_OPPORTUNITY_BOOK_SELECTED_MISSING")
    if actual and actual != selected:
        raise ValueError(
            "EDLI_LIVE_OPPORTUNITY_BOOK_SELECTION_MISMATCH:"
            f"selected={selected}:actual={actual}"
        )
    receipt_candidate_id = _opportunity_book_candidate_id_for_receipt(book, receipt)
    if not receipt_candidate_id:
        raise ValueError(
            "EDLI_LIVE_OPPORTUNITY_BOOK_RECEIPT_CANDIDATE_MISSING:"
            f"condition_id={receipt.condition_id}:token_id={receipt.token_id}:direction={receipt.direction}"
        )
    if receipt_candidate_id != selected:
        raise ValueError(
            "EDLI_LIVE_OPPORTUNITY_BOOK_RECEIPT_NOT_SELECTED:"
            f"selected={selected}:receipt_candidate={receipt_candidate_id}:"
            f"condition_id={receipt.condition_id}:token_id={receipt.token_id}:direction={receipt.direction}"
        )
    _assert_receipt_qkernel_execution_economics(receipt, book, selected)


def _valid_qkernel_execution_economics_payload(
    cert: Any,
    *,
    direction: str | None = None,
) -> Mapping[str, Any] | None:
    if not isinstance(cert, Mapping):
        return None
    if not _QKERNEL_EXECUTION_ECONOMICS_REQUIRED_KEYS.issubset(cert.keys()):
        return None
    if str(cert.get("source") or "") != "qkernel_spine":
        return None
    if not str(cert.get("candidate_id") or "").strip():
        return None
    route_id = str(cert.get("route_id") or "").strip()
    if not route_id:
        return None
    side = str(cert.get("side") or "").strip().upper()
    native_side = _native_curve_side_for_direction(str(direction or ""))
    if side and native_side is not None and side != native_side:
        return None
    if route_id.startswith("DIRECT_YES:") and native_side not in {None, "YES"}:
        return None
    if route_id.startswith("DIRECT_NO:") and native_side not in {None, "NO"}:
        return None
    if not (route_id.startswith("DIRECT_YES:") or route_id.startswith("DIRECT_NO:")):
        return None
    for key in (
        "payoff_q_point",
        "payoff_q_lcb",
        "edge_lcb",
        "delta_u_at_min",
        "optimal_delta_u",
        "cost",
    ):
        try:
            value = float(cert.get(key))
        except (TypeError, ValueError):
            return None
        if not math.isfinite(value):
            return None
    try:
        optimal_stake = float(cert.get("optimal_stake_usd"))
    except (TypeError, ValueError):
        return None
    if not math.isfinite(optimal_stake):
        return None
    try:
        false_edge_rate = float(cert.get("false_edge_rate"))
    except (TypeError, ValueError):
        return None
    if not (
        math.isfinite(false_edge_rate)
        and 0.0 < false_edge_rate <= _qkernel_max_false_edge_rate()
    ):
        return None
    try:
        payoff_q_point = float(cert.get("payoff_q_point"))
        payoff_q_lcb = float(cert.get("payoff_q_lcb"))
        cost = float(cert.get("cost"))
        edge_lcb = float(cert.get("edge_lcb"))
        delta_u_at_min = float(cert.get("delta_u_at_min"))
        optimal_delta_u = float(cert.get("optimal_delta_u"))
    except (TypeError, ValueError):
        return None
    if not (0.0 <= payoff_q_point <= 1.0):
        return None
    if not (0.0 <= payoff_q_lcb <= 1.0):
        return None
    if payoff_q_lcb > payoff_q_point:
        return None
    if "q_dot_payoff" in cert:
        try:
            q_dot_payoff = float(cert.get("q_dot_payoff"))
        except (TypeError, ValueError):
            return None
        if not math.isfinite(q_dot_payoff):
            return None
        if not math.isclose(
            q_dot_payoff,
            payoff_q_point,
            rel_tol=1e-9,
            abs_tol=1e-9,
        ):
            return None
    if not (0.0 < cost < 1.0):
        return None
    if (
        edge_lcb <= 0.0
        or delta_u_at_min <= 0.0
        or optimal_delta_u <= 0.0
        or optimal_stake <= 0.0
    ):
        return None
    if not math.isclose(payoff_q_lcb, cost + edge_lcb, rel_tol=1e-9, abs_tol=1e-9):
        return None
    if not _qkernel_cert_direction_admitted(cert, direction=direction):
        return None
    if cert.get("coherence_allows") is not True:
        return None
    selection_guard_basis = str(cert.get("selection_guard_basis") or "").strip()
    if not selection_guard_basis or selection_guard_basis == "SIDE_NOT_ARMED":
        return None
    if _qkernel_day0_guard_rejection_reason(cert) is not None:
        return None
    raw_selection_guard_abstained = cert.get("selection_guard_abstained")
    if isinstance(raw_selection_guard_abstained, bool):
        selection_guard_abstained = raw_selection_guard_abstained
    else:
        raw_text = str(raw_selection_guard_abstained).strip().lower()
        if raw_text in {"0", "false", "no"}:
            selection_guard_abstained = False
        elif raw_text in {"1", "true", "yes"}:
            selection_guard_abstained = True
        else:
            return None
    if selection_guard_abstained:
        return None
    try:
        selection_guard_q_safe = float(cert.get("selection_guard_q_safe"))
    except (TypeError, ValueError):
        return None
    if not (math.isfinite(selection_guard_q_safe) and selection_guard_q_safe > 0.0):
        return None
    if not _qkernel_roi_frontier_useful_cert(
        side=side,
        cost=cost,
        payoff_q_lcb=payoff_q_lcb,
        edge_lcb=edge_lcb,
        stake=optimal_stake,
        delta_u_at_min=delta_u_at_min,
    ):
        return None
    return cert


def _qkernel_selection_economics_rejection_reason(
    cert: Any,
    *,
    direction: str | None = None,
) -> str:
    """Classify why a qkernel economics certificate is not selectable.

    This mirrors ``_valid_qkernel_execution_economics_payload`` without relaxing
    it.  A candidate with an honest negative/zero robust edge is different from
    malformed execution evidence, and the live regret surface must preserve that
    distinction for redecision/debugging.
    """

    if not isinstance(cert, Mapping):
        return "QKERNEL_EXECUTION_ECONOMICS_INVALID"
    missing = sorted(_QKERNEL_EXECUTION_ECONOMICS_REQUIRED_KEYS.difference(cert.keys()))
    if missing:
        return "QKERNEL_EXECUTION_ECONOMICS_MISSING_FIELDS:fields=" + ",".join(missing)
    if str(cert.get("source") or "") != "qkernel_spine":
        return "QKERNEL_EXECUTION_ECONOMICS_INVALID_SOURCE"
    if not str(cert.get("candidate_id") or "").strip():
        return "QKERNEL_EXECUTION_ECONOMICS_MISSING_CANDIDATE_ID"
    route_id = str(cert.get("route_id") or "").strip()
    if not route_id:
        return "QKERNEL_EXECUTION_ECONOMICS_MISSING_ROUTE_ID"
    side = str(cert.get("side") or "").strip().upper()
    native_side = _native_curve_side_for_direction(str(direction or ""))
    if side not in {"YES", "NO"}:
        return f"QKERNEL_EXECUTION_ECONOMICS_INVALID_SIDE:side={side or 'UNKNOWN'}"
    if native_side is not None and side != native_side:
        return (
            "QKERNEL_EXECUTION_ECONOMICS_SIDE_MISMATCH:"
            f"side={side}:direction={direction or 'UNKNOWN'}"
        )
    if route_id.startswith("DIRECT_YES:") and native_side not in {None, "YES"}:
        return (
            "QKERNEL_EXECUTION_ECONOMICS_ROUTE_SIDE_MISMATCH:"
            f"route_side=YES:direction={direction or 'UNKNOWN'}"
        )
    if route_id.startswith("DIRECT_NO:") and native_side not in {None, "NO"}:
        return (
            "QKERNEL_EXECUTION_ECONOMICS_ROUTE_SIDE_MISMATCH:"
            f"route_side=NO:direction={direction or 'UNKNOWN'}"
        )
    if not (route_id.startswith("DIRECT_YES:") or route_id.startswith("DIRECT_NO:")):
        return f"QKERNEL_EXECUTION_ECONOMICS_INVALID_ROUTE:route_id={route_id}"

    numeric: dict[str, float] = {}
    for key in (
        "payoff_q_point",
        "payoff_q_lcb",
        "edge_lcb",
        "delta_u_at_min",
        "optimal_delta_u",
        "cost",
        "optimal_stake_usd",
        "false_edge_rate",
    ):
        try:
            value = float(cert.get(key))
        except (TypeError, ValueError):
            return f"QKERNEL_EXECUTION_ECONOMICS_NON_NUMERIC:key={key}"
        if not math.isfinite(value):
            return f"QKERNEL_EXECUTION_ECONOMICS_NONFINITE:key={key}"
        numeric[key] = value

    false_edge_rate = numeric["false_edge_rate"]
    if not (0.0 < false_edge_rate <= 1.0):
        return f"QKERNEL_EXECUTION_ECONOMICS_FALSE_EDGE_RATE_INVALID:value={false_edge_rate:.6f}"
    max_false_edge_rate = _qkernel_max_false_edge_rate()
    if false_edge_rate > max_false_edge_rate:
        return (
            "QKERNEL_EXECUTION_ECONOMICS_FALSE_EDGE_RATE_BLOCKS:"
            f"value={false_edge_rate:.6f}:alpha={max_false_edge_rate:.6f}"
        )
    payoff_q_point = numeric["payoff_q_point"]
    payoff_q_lcb = numeric["payoff_q_lcb"]
    cost = numeric["cost"]
    edge_lcb = numeric["edge_lcb"]
    delta_u_at_min = numeric["delta_u_at_min"]
    optimal_delta_u = numeric["optimal_delta_u"]
    optimal_stake = numeric["optimal_stake_usd"]
    if not (0.0 <= payoff_q_point <= 1.0):
        return f"QKERNEL_EXECUTION_ECONOMICS_Q_POINT_BOUNDS:value={payoff_q_point:.6f}"
    if not (0.0 <= payoff_q_lcb <= 1.0):
        return f"QKERNEL_EXECUTION_ECONOMICS_Q_LCB_BOUNDS:value={payoff_q_lcb:.6f}"
    if payoff_q_lcb > payoff_q_point:
        return (
            "QKERNEL_EXECUTION_ECONOMICS_Q_LCB_EXCEEDS_POINT:"
            f"payoff_q_lcb={payoff_q_lcb:.6f}:payoff_q_point={payoff_q_point:.6f}"
        )
    if "q_dot_payoff" in cert:
        try:
            q_dot_payoff = float(cert.get("q_dot_payoff"))
        except (TypeError, ValueError):
            return "QKERNEL_EXECUTION_ECONOMICS_NON_NUMERIC:key=q_dot_payoff"
        if not math.isfinite(q_dot_payoff):
            return "QKERNEL_EXECUTION_ECONOMICS_NONFINITE:key=q_dot_payoff"
        if not math.isclose(
            q_dot_payoff,
            payoff_q_point,
            rel_tol=1e-9,
            abs_tol=1e-9,
        ):
            return (
                "QKERNEL_EXECUTION_ECONOMICS_Q_DOT_PAYOFF_MISMATCH:"
                f"q_dot_payoff={q_dot_payoff:.6f}:payoff_q_point={payoff_q_point:.6f}"
            )
    if not (0.0 < cost < 1.0):
        return f"QKERNEL_EXECUTION_ECONOMICS_COST_BOUNDS:cost={cost:.6f}"
    if edge_lcb <= 0.0:
        return (
            "QKERNEL_EDGE_LCB_NON_POSITIVE:"
            f"edge_lcb={edge_lcb:.6f}:payoff_q_lcb={payoff_q_lcb:.6f}:cost={cost:.6f}"
        )
    if optimal_delta_u <= 0.0:
        return (
            "QKERNEL_DELTA_U_NON_POSITIVE:"
            f"optimal_delta_u={optimal_delta_u:.9f}:edge_lcb={edge_lcb:.6f}:"
            f"stake={optimal_stake:.6f}"
        )
    if delta_u_at_min <= 0.0:
        return (
            "QKERNEL_DELTA_U_AT_MIN_NON_POSITIVE:"
            f"delta_u_at_min={delta_u_at_min:.9f}:edge_lcb={edge_lcb:.6f}:"
            f"stake={optimal_stake:.6f}"
        )
    if optimal_stake <= 0.0:
        return f"QKERNEL_STAKE_NON_POSITIVE:stake={optimal_stake:.6f}:edge_lcb={edge_lcb:.6f}"
    if not math.isclose(payoff_q_lcb, cost + edge_lcb, rel_tol=1e-9, abs_tol=1e-9):
        return (
            "QKERNEL_EXECUTION_ECONOMICS_EDGE_IDENTITY_MISMATCH:"
            f"payoff_q_lcb={payoff_q_lcb:.6f}:cost={cost:.6f}:edge_lcb={edge_lcb:.6f}"
        )
    if not _qkernel_cert_direction_admitted(cert, direction=direction):
        return f"QKERNEL_DIRECTION_LAW_REJECTED:side={side or 'UNKNOWN'}"
    if cert.get("coherence_allows") is not True:
        return f"QKERNEL_MARKET_COHERENCE_BLOCKED:side={side or 'UNKNOWN'}"
    selection_guard_basis = str(cert.get("selection_guard_basis") or "").strip()
    if not selection_guard_basis:
        return "QKERNEL_SELECTION_GUARD_MISSING"
    if selection_guard_basis == "SIDE_NOT_ARMED":
        return f"QKERNEL_SELECTION_SIDE_NOT_ARMED:side={side or 'UNKNOWN'}"
    day0_guard_reason = _qkernel_day0_guard_rejection_reason(cert)
    if day0_guard_reason is not None:
        return day0_guard_reason
    raw_selection_guard_abstained = cert.get("selection_guard_abstained")
    if isinstance(raw_selection_guard_abstained, bool):
        selection_guard_abstained = raw_selection_guard_abstained
    else:
        raw_text = str(raw_selection_guard_abstained).strip().lower()
        if raw_text in {"0", "false", "no"}:
            selection_guard_abstained = False
        elif raw_text in {"1", "true", "yes"}:
            selection_guard_abstained = True
        else:
            return "QKERNEL_SELECTION_GUARD_ABSTAINED_INVALID"
    if selection_guard_abstained:
        return "QKERNEL_SELECTION_GUARD_ABSTAINED"
    try:
        selection_guard_q_safe = float(cert.get("selection_guard_q_safe"))
    except (TypeError, ValueError):
        return "QKERNEL_EXECUTION_ECONOMICS_NON_NUMERIC:key=selection_guard_q_safe"
    if not (math.isfinite(selection_guard_q_safe) and selection_guard_q_safe > 0.0):
        return (
            "QKERNEL_SELECTION_GUARD_Q_SAFE_INVALID:"
            f"selection_guard_q_safe={selection_guard_q_safe:.6f}"
        )
    if not _qkernel_roi_frontier_useful_cert(
        side=side,
        cost=cost,
        payoff_q_lcb=payoff_q_lcb,
        edge_lcb=edge_lcb,
        stake=optimal_stake,
        delta_u_at_min=delta_u_at_min,
    ):
        return (
            "QKERNEL_EXECUTION_ECONOMICS_ROI_FRONTIER_NOT_USEFUL:"
            f"edge_lcb={edge_lcb:.6f}:stake={optimal_stake:.6f}:"
            f"delta_u_at_min={delta_u_at_min:.9f}"
        )
    return "QKERNEL_EXECUTION_ECONOMICS_INVALID_FOR_SELECTION"


def _qkernel_near_day0_cert_rejection_reason(cert: Mapping[str, Any] | None) -> str | None:
    if not isinstance(cert, Mapping):
        return None
    verdict = cert.get("near_day0_raw_extrema_consistency")
    if not isinstance(verdict, Mapping):
        return None
    if verdict.get("passed") is False:
        reason = str(verdict.get("reason") or "").strip()
        return reason or "ADMISSION_NEAR_DAY0_RAW_EXTREMA_CONSISTENCY_FAILED"
    return None


def _qkernel_cert_direction_admitted(
    cert: Mapping[str, Any],
    *,
    direction: str | None = None,
) -> bool:
    """Mirror FamilyDecisionEngine._direction_admitted for serialized certs."""

    if cert.get("direction_law_ok") is not True:
        return False
    native_side = _native_curve_side_for_direction(str(direction or ""))
    side = str(cert.get("side") or "").strip().upper()
    if side not in {"YES", "NO"}:
        return False
    if native_side is not None and side != native_side:
        return False
    return True


def _selected_opportunity_book_candidate(
    book: Mapping[str, object],
    selected_candidate_id: str,
) -> Mapping[str, Any] | None:
    candidates = book.get("candidates")
    if not isinstance(candidates, list):
        return None
    for candidate in candidates:
        if not isinstance(candidate, Mapping):
            continue
        if str(candidate.get("candidate_id") or "").strip() == selected_candidate_id:
            return candidate
    return None


def _assert_receipt_qkernel_execution_economics(
    receipt: EventSubmissionReceipt,
    book: Mapping[str, object],
    selected_candidate_id: str,
) -> Mapping[str, Any] | None:
    q_source = str(receipt.q_source or "").strip()
    if receipt.qkernel_execution_economics is None:
        if q_source == "qkernel_spine":
            raise ValueError("EDLI_LIVE_QKERNEL_EXECUTION_ECONOMICS_INVALID")
        return None
    receipt_cert = _valid_qkernel_execution_economics_payload(
        receipt.qkernel_execution_economics,
        direction=receipt.direction,
    )
    if receipt_cert is None:
        raise ValueError("EDLI_LIVE_QKERNEL_EXECUTION_ECONOMICS_INVALID")
    selected_candidate = _selected_opportunity_book_candidate(book, selected_candidate_id)
    if selected_candidate is None:
        raise ValueError("EDLI_LIVE_QKERNEL_SELECTED_BOOK_CANDIDATE_MISSING")
    if selected_candidate.get("live_decision_selected") is not True:
        raise ValueError("EDLI_LIVE_OPPORTUNITY_BOOK_SELECTED_NOT_LIVE_DECISION")
    if str(selected_candidate.get("live_selection_authority") or "").strip() != "qkernel_spine":
        raise ValueError("EDLI_LIVE_OPPORTUNITY_BOOK_SELECTED_NOT_QKERNEL_AUTHORITY")
    book_cert = _valid_qkernel_execution_economics_payload(
        selected_candidate.get("qkernel_execution_economics"),
        direction=receipt.direction,
    )
    if book_cert is None:
        raise ValueError("EDLI_LIVE_QKERNEL_BOOK_EXECUTION_ECONOMICS_INVALID")
    if stable_hash(dict(book_cert)) != stable_hash(dict(receipt_cert)):
        raise ValueError("EDLI_LIVE_QKERNEL_EXECUTION_ECONOMICS_MISMATCH")
    if not _qkernel_direct_route_matches_receipt_probability(receipt, receipt_cert):
        raise ValueError("EDLI_LIVE_QKERNEL_RECEIPT_PROBABILITY_SPLIT")
    return receipt_cert


def _qkernel_direct_route_matches_receipt_probability(
    receipt: EventSubmissionReceipt,
    cert: Mapping[str, Any],
) -> bool:
    route_id = str(cert.get("route_id") or "")
    if not route_id.startswith(("DIRECT_YES:", "DIRECT_NO:")):
        return True
    try:
        payoff_q_point = float(cert.get("payoff_q_point"))
        payoff_q_lcb = float(cert.get("payoff_q_lcb"))
        receipt_q_point = float(receipt.q_live)
        receipt_q_lcb = float(receipt.q_lcb_5pct)
    except (TypeError, ValueError):
        return False
    if not all(
        math.isfinite(value)
        for value in (payoff_q_point, payoff_q_lcb, receipt_q_point, receipt_q_lcb)
    ):
        return False
    if not math.isclose(payoff_q_point, receipt_q_point, rel_tol=1e-9, abs_tol=1e-6):
        return False
    if not math.isclose(payoff_q_lcb, receipt_q_lcb, rel_tol=1e-9, abs_tol=1e-6):
        return False
    return True


def _opportunity_book_candidate_id_for_receipt(
    book: Mapping[str, object],
    receipt: EventSubmissionReceipt,
) -> str | None:
    candidates = book.get("candidates")
    if not isinstance(candidates, list):
        return None
    condition_id = str(receipt.condition_id or "").strip()
    token_id = str(receipt.token_id or "").strip()
    direction = str(receipt.direction or "").strip()
    if not condition_id or not token_id or not direction:
        return None
    for candidate in candidates:
        if not isinstance(candidate, Mapping):
            continue
        if str(candidate.get("condition_id") or "").strip() != condition_id:
            continue
        if str(candidate.get("token_id") or "").strip() != token_id:
            continue
        if str(candidate.get("direction") or "").strip() != direction:
            continue
        candidate_id = str(candidate.get("candidate_id") or "").strip()
        return candidate_id or None
    return None


def build_event_reactor(
    store: EventStore,
    *,
    source_truth_gate,
    executable_snapshot_gate,
    riskguard_gate,
    final_intent_submit,
    reject,
    config: ReactorConfig | None = None,
    regret_ledger=None,
) -> OpportunityEventReactor:
    return OpportunityEventReactor(
        store,
        source_truth_gate=source_truth_gate,
        executable_snapshot_gate=executable_snapshot_gate,
        riskguard_gate=riskguard_gate,
        final_intent_submit=final_intent_submit,
        reject=reject,
        config=config,
        regret_ledger=regret_ledger,
    )


# Known forecast-snapshot completeness vocabulary (single authority:
# src/events/forecast_completeness.ForecastCompletenessStatus). An event whose
# label is outside this set has unparseable producer state and stays blocked.
_FORECAST_COMPLETENESS_VOCAB = frozenset(get_args(ForecastCompletenessStatus))


def edli_source_truth_gate(event: OpportunityEvent) -> bool:
    """Fail closed unless an EDLI event is source-eligible for a live cycle."""

    payload = _payload(event)
    if event.event_type in _FORECAST_DECISION_EVENT_TYPES:
        # EDLI_REDECISION_PENDING carries the SAME FSR-shaped payload (it re-decides a forecast
        # family on a fresh price) and is gated identically — structural identity only.
        # Coverage labels are ADVISORY at the event gate (serving-authority
        # ruling, incident 2026-06-11T16:33:51Z — see the FSR pass-through block
        # in src/events/reactor.py): the bundle the money path trades on is
        # chosen by the SERVING AUTHORITY keyed by (city, target_date, metric),
        # never pinned to this trigger event's run, and the adapter rejects
        # honestly (REPLACEMENT_0_1_LIVE_BUNDLE_BLOCKED) when nothing
        # eligible is servable. Binding the event's own completeness label here
        # was the same serve-freshest rule re-implemented (wrongly) at a second
        # site: live 2026-06-11T18:20Z+ all six live-eligible cities' low
        # families (HK/London/Miami/NYC/Paris/Shanghai) were SOURCE_TRUTH_BLOCKED
        # on the newest run's PARTIAL_BLOCKED window label while COMPLETE
        # LIVE_ELIGIBLE bundles from the prior cycle were servable.
        # The gate binds ONLY structural identity: a parseable causal snapshot,
        # required identity fields present, and a label from the known
        # vocabulary (single authority: src/events/forecast_completeness).
        # required_fields_present=False also covers the time-violation
        # classifications (AVAILABLE_AT_IN_FUTURE etc.), which stay blocked.
        return (
            bool(event.causal_snapshot_id)
            and payload.get("completeness_status") in _FORECAST_COMPLETENESS_VOCAB
            and payload.get("required_fields_present") is True
        )
    if event.event_type == "DAY0_EXTREME_UPDATED":
        return (
            payload.get("source_match_status") == "MATCH"
            and payload.get("local_date_status") == "MATCH"
            and payload.get("station_match_status") == "MATCH"
            and payload.get("dst_status") == "UNAMBIGUOUS"
            and payload.get("metric_match_status") == "MATCH"
            and payload.get("rounding_status") == "MATCH"
            and payload.get("source_authorized_status", "AUTHORIZED") == "AUTHORIZED"
            and payload.get("live_authority_status") == "live"
        )
    return False


def executable_snapshot_gate_from_trade_conn(
    trade_conn: sqlite3.Connection,
    *,
    now: datetime | None = None,
    topology_conn: sqlite3.Connection | None = None,
) -> Callable[[OpportunityEvent, datetime], bool]:
    """Return a gate requiring a fresh executable snapshot bound to the event."""

    fallback_checked_at = now.astimezone(UTC) if now is not None else None

    def _gate(event: OpportunityEvent, decision_time: datetime) -> bool:
        if topology_conn is None:
            return False
        checked_at = (
            decision_time.astimezone(UTC)
            if decision_time.tzinfo is not None and decision_time.utcoffset() is not None
            else fallback_checked_at
        )
        if checked_at is None:
            return False
        if not _table_exists(trade_conn, "executable_market_snapshots"):
            return False
        columns = _table_columns(trade_conn, "executable_market_snapshots")
        required = {"freshness_deadline", "yes_token_id", "no_token_id"}
        if not required <= columns:
            return False
        payload = _payload(event)
        family_topology_rows = _event_family_market_topology_rows(topology_conn, payload)
        if not family_topology_rows:
            return False
        condition_ids = tuple(str(row.get("condition_id") or "") for row in family_topology_rows)
        rows = _latest_snapshot_rows_for_event_family(
            trade_conn,
            event,
            condition_ids=condition_ids,
            fresh_at=checked_at,
            require_fresh=False,  # entry gate proves market identity; price-freshness is enforced at submission
        )
        if not rows:
            return False
        # Entry gate: at least one sibling snapshot present AND the event's own selected
        # bin has a snapshot. The full-family q/FDR proof is enforced inside
        # build_event_bound_no_submit_receipt; here we only need to know the market
        # family is partially live and the selected bin is executable. Illiquid tail
        # bins absent from executable_market_snapshots are non-tradeable but still part
        # of the full MECE topology — exact-set-equality is the wrong predicate here.
        return _selected_snapshot_row_for_event(rows, payload) is not None

    return _gate


def riskguard_allows_new_entries(*, get_current_level: Callable[[], RiskLevel]) -> Callable[[OpportunityEvent], bool]:
    """Return a reactor gate that preserves RiskGuard's entry-blocking law."""

    def _gate(_event: OpportunityEvent) -> bool:
        return get_current_level() == RiskLevel.GREEN

    return _gate


def _adapter_sql_identifier(name: str) -> str:
    return '"' + str(name).replace('"', '""') + '"'


def _adapter_attached_schema_names(conn: sqlite3.Connection) -> tuple[str, ...]:
    rows = conn.execute("PRAGMA database_list").fetchall()
    names: list[str] = []
    for row in rows:
        name = row[1] if not isinstance(row, sqlite3.Row) else row["name"]
        if name:
            names.append(str(name))
    return tuple(names) or ("main",)


def _adapter_table_or_view_exists(conn: sqlite3.Connection, schema: str, name: str) -> bool:
    schema_sql = _adapter_sql_identifier(schema)
    row = conn.execute(
        f"SELECT 1 FROM {schema_sql}.sqlite_master "
        "WHERE type IN ('table', 'view') AND name = ? LIMIT 1",
        (name,),
    ).fetchone()
    return row is not None


def _entry_pause_blocks_live_submit(conn: sqlite3.Connection | None) -> str | None:
    """Return a control-plane pause reason before live-cap/command materialization.

    The executor keeps the same gate as a final defense, but EDLI must read it
    before reserving live cap or appending ``ExecutionCommandCreated``. Otherwise
    an operator pause still creates durable command/cap artifacts and depends on
    post-facto release recovery.
    """

    try:
        from src.state.db import get_world_connection, query_control_override_state

        world_conn = get_world_connection()
        try:
            state = query_control_override_state(world_conn)
        finally:
            world_conn.close()
    except Exception as exc:  # noqa: BLE001
        return f"entries_pause_control_unreadable:{type(exc).__name__}"
    if state.get("status") != "ok":
        return f"entries_pause_control_unreadable:{state.get('status', 'unknown')}"
    if bool(state.get("entries_paused", False)):
        return str(state.get("entries_pause_reason") or "entries_paused")
    return None


def edli_trade_score_gate(event: OpportunityEvent) -> bool:
    """TradeScore is generated inside the event-bound no-submit adapter.

    Forecast and Day0 events are causal facts; they must not carry q/c/FDR/Kelly
    proof fields as event-authoritative payload data.
    """

    return event.event_type in (_FORECAST_DECISION_EVENT_TYPES | {"DAY0_EXTREME_UPDATED"})


def _resolve_replacement_forecast_adapter_hook(
    *,
    replacement_forecast_hook: Callable[["_CandidateProof", OpportunityEvent, datetime], ReplacementForecastReactorHookResult | None] | None,
    replacement_forecast_runtime_flags: Mapping[str, object] | None,
    replacement_forecast_baseline_bundle_provider: Callable[["_CandidateProof", OpportunityEvent, datetime], object | None] | None,
    replacement_forecast_world_tables: tuple[str, ...],
    replacement_forecast_source_fact_status: str,
    replacement_forecast_data_fact_status: str,
    replacement_forecast_refit_decision: ReplacementForecastRefitDecision | None,
    replacement_forecast_promotion_evidence: ReplacementForecastPromotionEvidence | None,
    replacement_forecast_capital_objective_evidence: ReplacementForecastCapitalObjectiveEvidence | None,
    forecast_conn: sqlite3.Connection | None,
    trade_conn: sqlite3.Connection,
) -> Callable[["_CandidateProof", OpportunityEvent, datetime], ReplacementForecastReactorHookResult | None] | None:
    if replacement_forecast_hook is not None or replacement_forecast_runtime_flags is None:
        return replacement_forecast_hook
    if forecast_conn is None:
        def _missing_forecast_conn_hook(
            proof: _CandidateProof,
            _event: OpportunityEvent,
            _decision_time: datetime,
        ) -> ReplacementForecastReactorHookResult:
            return ReplacementForecastReactorHookResult(
                status="BLOCKED",
                reason_codes=("REPLACEMENT_FORECAST_HOOK_FORECAST_CONNECTION_MISSING",),
                effective_direction=proof.direction,
                effective_q_posterior=proof.q_posterior,
                effective_q_lcb=proof.q_lcb_5pct,
                effective_kelly_fraction=0.0,
            )

        return _missing_forecast_conn_hook
    from src.engine.replacement_forecast_hook_factory import (
        ReplacementForecastHookFactoryInput,
        build_replacement_forecast_event_hook,
    )

    return build_replacement_forecast_event_hook(
        ReplacementForecastHookFactoryInput(
            forecast_conn=forecast_conn,
            trade_conn=trade_conn,
            runtime_flags=replacement_forecast_runtime_flags,
            baseline_bundle_provider=replacement_forecast_baseline_bundle_provider,
            refit_decision=replacement_forecast_refit_decision,
            promotion_evidence=replacement_forecast_promotion_evidence,
            capital_objective_evidence=replacement_forecast_capital_objective_evidence,
            world_tables=replacement_forecast_world_tables,
            source_fact_status=replacement_forecast_source_fact_status,
            data_fact_status=replacement_forecast_data_fact_status,
        )
    )


def replacement_forecast_baseline_bundle_provider_from_forecast_conn(
    forecast_conn: sqlite3.Connection,
) -> Callable[["_CandidateProof", OpportunityEvent, datetime], object | None]:
    """Build the B0 executable forecast provider used by replacement live veto."""

    def _provider(
        proof: _CandidateProof,
        event: OpportunityEvent,
        decision_time: datetime,
    ) -> object | None:
        from src.data.executable_forecast_reader import SOURCE_TRANSPORT, read_executable_forecast

        payload = _payload(event)
        candidate = proof.candidate
        city = str(payload.get("city") or candidate.city)
        target_date_text = str(payload.get("target_date") or candidate.target_date)
        metric = str(payload.get("metric") or candidate.metric)
        source_run_id = str(payload.get("source_run_id") or "")
        source_id = str(payload.get("source_id") or "")
        track = str(payload.get("track") or "")
        if not city or not target_date_text or metric not in {"high", "low"} or not source_run_id:
            return None
        table_ref = _authority_table_ref(forecast_conn, "source_run_coverage")
        if table_ref is None:
            return None
        columns = _table_ref_columns(forecast_conn, table_ref)
        required = {
            "source_run_id",
            "city",
            "target_local_date",
            "temperature_metric",
            "data_version",
            "source_id",
            "track",
            "computed_at",
        }
        if not required.issubset(columns):
            return None
        predicates = [
            "source_run_id = ?",
            "city = ?",
            "target_local_date = ?",
            "temperature_metric = ?",
        ]
        params: list[object] = [source_run_id, city, target_date_text, metric]
        if source_id:
            predicates.append("source_id = ?")
            params.append(source_id)
        if track:
            predicates.append("track = ?")
            params.append(track)
        row = forecast_conn.execute(
            f"""
            SELECT *
            FROM {table_ref}
            WHERE {' AND '.join(predicates)}
            ORDER BY computed_at DESC, recorded_at DESC
            LIMIT 1
            """,
            params,
        ).fetchone()
        if row is None:
            return None
        coverage = dict(row)
        city_id = str(coverage.get("city_id") or city)
        city_timezone = str(coverage.get("city_timezone") or getattr(runtime_cities_by_name().get(city), "timezone", "UTC"))
        final_source_id = str(coverage.get("source_id") or source_id)
        source_transport = str(coverage.get("source_transport") or SOURCE_TRANSPORT)
        data_version = str(coverage.get("data_version") or "")
        final_track = str(coverage.get("track") or track)
        if not final_source_id or not data_version or not final_track:
            return None
        result = read_executable_forecast(
            forecast_conn,
            city_id=city_id,
            city_name=str(coverage.get("city") or city),
            city_timezone=city_timezone,
            target_local_date=date.fromisoformat(target_date_text),
            temperature_metric=metric,
            source_id=final_source_id,
            source_transport=source_transport,
            data_version=data_version,
            track=final_track,
            strategy_key="entry_forecast",
            market_family=str(candidate.condition_id or ""),
            condition_id=str(candidate.condition_id or ""),
            decision_time=decision_time,
            require_entry_readiness=False,
        )
        return result.bundle if result.ok and result.bundle is not None else None

    return _provider


# SUBMIT-LANE STAMP (silent-trade-kill antibody 2026-06-12; root cause
# /tmp/allpass_nosubmit_rootcause.md). Canonical lane labels written onto every
# EventSubmissionReceipt at adapter construction so a full-pass no-submit can never
# be mistaken for a genuine decision-declined no-submit.
SUBMIT_LANE_LIVE = "LIVE"
SUBMIT_LANE_SUBMIT_DISABLED = "SUBMIT_DISABLED"
SUBMIT_LANE_NO_SUBMIT_ADAPTER = "NO_SUBMIT_ADAPTER"

# The default no-submit reason hardcoded by the serializer. Honest ONLY where no
# control-blocked live-submit selector drove this lane (test/replay). On the
# NO_SUBMIT_ADAPTER lane a full-pass receipt carrying THIS reason is the
# silent-kill signature, so the lane stamp rewrites it to name the live block.
_DEFAULT_NO_SUBMIT_REASON = "event_bound_final_intent_no_submit"


def _stamp_no_submit_adapter_lane(
    receipt: EventSubmissionReceipt, *, live_block_cause: str
) -> EventSubmissionReceipt:
    """Stamp submit_lane=NO_SUBMIT_ADAPTER and, for a full-pass receipt carrying the
    DEFAULT no-submit reason, derive a named block reason from the selector's typed
    cause (single source of truth, mirrors _SUBMIT_ABORT_RECEIPT_REASON).

    The default literal is the silent-kill signature on this lane (a full-pass
    candidate that WOULD have submitted on the live lane, consumed with a reason
    indistinguishable from a genuine decline). For such receipts the reason becomes
    ``NO_SUBMIT_ADAPTER_LANE:<live_block_cause>`` so the receipt itself names why the
    live lane was dark this cycle. Receipts that already carry a SPECIFIC reason (a
    gate rejection — TRADE_SCORE_NON_POSITIVE, FDR_REJECTED, etc.) keep it: those are
    honest no-edge declines, not a lane-selection block, and are only lane-stamped.

    ``live_block_cause`` is REQUIRED and must be non-empty — the no-submit adapter is
    only ever selected because live submit is blocked (live_submit_effective False /
    operator_arm None), so a full-pass on this lane MUST be able to name it. An empty
    cause makes the named block unconstructable and raises.
    """
    if not live_block_cause:
        raise ValueError(
            "NO_SUBMIT_ADAPTER lane requires a non-empty live_block_cause; a full-pass "
            "receipt on this lane must name why the live lane was dark"
        )
    is_full_pass_default = (
        receipt.proof_accepted is True
        and receipt.side_effect_status == "NO_SUBMIT"
        and (receipt.reason or _DEFAULT_NO_SUBMIT_REASON) == _DEFAULT_NO_SUBMIT_REASON
    )
    if is_full_pass_default:
        return dataclass_replace(
            receipt,
            submit_lane=SUBMIT_LANE_NO_SUBMIT_ADAPTER,
            reason=f"NO_SUBMIT_ADAPTER_LANE:{live_block_cause}",
        )
    return dataclass_replace(receipt, submit_lane=SUBMIT_LANE_NO_SUBMIT_ADAPTER)


def _stamp_live_adapter_lane(
    receipt: EventSubmissionReceipt, *, real_order_submit_enabled: bool
) -> EventSubmissionReceipt:
    """Stamp the live adapter's lane onto a receipt it produced.

    Production live receipts have no non-live lane. They are stamped LIVE when real
    submission is armed, otherwise SUBMIT_DISABLED for non-production tests or
    explicit adapter-level dry runs.
    """
    if receipt.submit_lane is not None:
        return receipt
    lane = SUBMIT_LANE_LIVE if real_order_submit_enabled else SUBMIT_LANE_SUBMIT_DISABLED
    return dataclass_replace(receipt, submit_lane=lane)


def event_bound_no_submit_adapter_from_trade_conn(
    trade_conn: sqlite3.Connection,
    *,
    get_current_level: Callable[[], RiskLevel],
    forecast_conn: sqlite3.Connection | None = None,
    topology_conn: sqlite3.Connection | None = None,
    calibration_conn: sqlite3.Connection | None = None,
    live_cap_conn: sqlite3.Connection | None = None,
    bankroll_usd_provider: Callable[[], float | None] | None = None,
    free_cash_usd_provider: Callable[[], float | None] | None = None,
    portfolio_state_provider: "Callable[[], Any] | None" = None,
    replacement_forecast_hook: Callable[["_CandidateProof", OpportunityEvent, datetime], ReplacementForecastReactorHookResult | None] | None = None,
    replacement_forecast_runtime_flags: Mapping[str, object] | None = None,
    replacement_forecast_baseline_bundle_provider: Callable[["_CandidateProof", OpportunityEvent, datetime], object | None] | None = None,
    replacement_forecast_world_tables: tuple[str, ...] = (),
    replacement_forecast_source_fact_status: str = "STALE_FOR_LIVE",
    replacement_forecast_data_fact_status: str = "STALE_FOR_LIVE",
    replacement_forecast_refit_decision: ReplacementForecastRefitDecision | None = None,
    replacement_forecast_promotion_evidence: ReplacementForecastPromotionEvidence | None = None,
    replacement_forecast_capital_objective_evidence: ReplacementForecastCapitalObjectiveEvidence | None = None,
    family_snapshot_refresher: "FamilySnapshotRefresher | None" = None,
    live_block_cause: str = "live_lane_unselected",
) -> Callable[[OpportunityEvent, datetime], EventSubmissionReceipt]:
    """Build a proof-only final-intent receipt adapter for EDLI events.

    SUBMIT-LANE STAMP (silent-trade-kill antibody 2026-06-12): ``live_block_cause`` is the
    TYPED reason the main.py selector chose this no-submit adapter over the live lane
    (e.g. ``live_submit_effective_false:<sub-reason>`` or ``operator_arm_none``). Every
    receipt this adapter emits is stamped submit_lane=NO_SUBMIT_ADAPTER, and a full-pass
    receipt that would otherwise carry the DEFAULT no-submit reason has its reason
    rewritten to ``NO_SUBMIT_ADAPTER_LANE:<live_block_cause>`` so a full-pass entry consumed
    on the no-submit lane names why the live lane was dark — never the default literal that
    is byte-identical to a genuine decline. The default ``"live_lane_unselected"`` keeps
    test/replay construction working; main.py threads the real cause.

    Task #107 (portfolio/multi Kelly): ``portfolio_state_provider`` (mirrors
    ``bankroll_usd_provider``) lets Kelly size against the bankroll NET of
    correlation-weighted committed capital. The per-cycle in-flight reservation
    accumulator (INV-K7) is CLOSURE-held here — NOT module-global — so parallel
    cycles / tests stay isolated. One adapter instance == one reactor cycle, so
    the accumulator is fresh per cycle by construction."""

    # INV-K7 reservation ledger: closure-held (test-isolation safe), fresh per
    # adapter instance (== per reactor cycle). FIX B (2026-06-05): rollback-aware
    # ledger (not a bare list) so a candidate rejected downstream of Kelly is
    # rolled back by the reactor before the next sequential event reads it.
    portfolio_reservation = PortfolioReservationLedger()
    _seed_portfolio_reservations_from_durable_live_cap(
        portfolio_reservation,
        live_cap_conn,
        trade_conn=trade_conn,
    )
    resolved_replacement_forecast_hook = _resolve_replacement_forecast_adapter_hook(
        replacement_forecast_hook=replacement_forecast_hook,
        replacement_forecast_runtime_flags=replacement_forecast_runtime_flags,
        replacement_forecast_baseline_bundle_provider=replacement_forecast_baseline_bundle_provider,
        replacement_forecast_world_tables=replacement_forecast_world_tables,
        replacement_forecast_source_fact_status=replacement_forecast_source_fact_status,
        replacement_forecast_data_fact_status=replacement_forecast_data_fact_status,
        replacement_forecast_refit_decision=replacement_forecast_refit_decision,
        replacement_forecast_promotion_evidence=replacement_forecast_promotion_evidence,
        replacement_forecast_capital_objective_evidence=replacement_forecast_capital_objective_evidence,
        forecast_conn=forecast_conn,
        trade_conn=trade_conn,
    )

    def _submit(event: OpportunityEvent, decision_time: datetime) -> EventSubmissionReceipt:
        # CATEGORY ANTIBODY (2026-06-08, "database is locked" HOLDER-side kill):
        # same trade-DB lock-hold disease as the live adapter — the reactor's single
        # per-cycle trade_conn is read/written here via build_event_bound_no_submit_
        # receipt and committed NOWHERE in process_pending (only closed at cycle end),
        # so the implicit transaction pins the trade-DB WAL lock / read-mark across
        # the whole multi-event cycle and starves concurrent trade-DB writers
        # (substrate warm, log_trade_exit, CollateralLedger heartbeat). Commit
        # trade_conn per event in a finally to release the lock and end the WAL-floor-
        # pinning read txn each event (mirrors the live adapter + reactor world-DB
        # per-event windows). In-memory reservation ledger is unaffected; no gate or
        # decision semantics change — this only bounds the lock-hold.
        try:
            receipt = build_event_bound_no_submit_receipt(
                event,
                trade_conn=trade_conn,
                decision_time=decision_time,
                forecast_conn=forecast_conn,
                topology_conn=topology_conn,
                calibration_conn=calibration_conn,
                get_current_level=get_current_level,
                bankroll_usd_provider=bankroll_usd_provider,
                free_cash_usd_provider=free_cash_usd_provider,
                portfolio_state_provider=portfolio_state_provider,
                portfolio_reservation=portfolio_reservation,
                locked_opportunity_conn=live_cap_conn or trade_conn,
                replacement_forecast_hook=resolved_replacement_forecast_hook,
                replacement_forecast_promotion_evidence=replacement_forecast_promotion_evidence,
                replacement_forecast_capital_objective_evidence=replacement_forecast_capital_objective_evidence,
                family_snapshot_refresher=family_snapshot_refresher,
            )
            # SUBMIT-LANE STAMP: this adapter is the control-blocked no-submit lane. Stamp every receipt
            # NO_SUBMIT_ADAPTER and rewrite a full-pass default reason to name the
            # live block that drove the selector here (single source of truth).
            return _stamp_no_submit_adapter_lane(receipt, live_block_cause=live_block_cause)
        finally:
            try:
                trade_conn.commit()
            except Exception:  # noqa: BLE001 - commit is a lock-release boundary; never mask the real result/raise
                pass

    # Expose the per-cycle ledger so the reactor can commit/rollback provisional
    # reservations in its post-submit phase (FIX B). The reactor reads this
    # attribute off the injected submit callable; absent it falls back to the
    # legacy append-only behavior (no commit/rollback).
    _submit.reservation_ledger = portfolio_reservation  # type: ignore[attr-defined]
    return _submit


def event_bound_live_adapter_from_trade_conn(
    trade_conn: sqlite3.Connection,
    *,
    get_current_level: Callable[[], RiskLevel],
    forecast_conn: sqlite3.Connection | None = None,
    topology_conn: sqlite3.Connection | None = None,
    calibration_conn: sqlite3.Connection | None = None,
    live_cap_conn: sqlite3.Connection | None = None,
    bankroll_usd_provider: Callable[[], float | None] | None = None,
    free_cash_usd_provider: Callable[[], float | None] | None = None,
    portfolio_state_provider: "Callable[[], Any] | None" = None,
    replacement_forecast_hook: Callable[["_CandidateProof", OpportunityEvent, datetime], ReplacementForecastReactorHookResult | None] | None = None,
    replacement_forecast_runtime_flags: Mapping[str, object] | None = None,
    replacement_forecast_baseline_bundle_provider: Callable[["_CandidateProof", OpportunityEvent, datetime], object | None] | None = None,
    replacement_forecast_world_tables: tuple[str, ...] = (),
    replacement_forecast_source_fact_status: str = "STALE_FOR_LIVE",
    replacement_forecast_data_fact_status: str = "STALE_FOR_LIVE",
    replacement_forecast_refit_decision: ReplacementForecastRefitDecision | None = None,
    replacement_forecast_promotion_evidence: ReplacementForecastPromotionEvidence | None = None,
    replacement_forecast_capital_objective_evidence: ReplacementForecastCapitalObjectiveEvidence | None = None,
    real_order_submit_enabled: bool = False,
    executor_submit: Callable[[DecisionCertificate, DecisionCertificate], EventBoundExecutorSubmitResult] | None = None,
    pre_submit_authority_provider: Callable[[DecisionCertificate, DecisionCertificate, datetime], PreSubmitAuthorityWitness] | None = None,
    durable_submit_outbox_enabled: bool = False,
    operator_arm: "OperatorArm | None" = None,
    edli_live_scope: str = "forecast_plus_day0",
    family_snapshot_refresher: "FamilySnapshotRefresher | None" = None,
) -> Callable[[OpportunityEvent, datetime], EventSubmissionReceipt]:
    """Build the event-bound live certificate chain up to the executor boundary.

    This live adapter creates the durable proof shape that submits through the
    existing executor seam whenever real submit is armed.

    Task #107 (portfolio/multi Kelly): ``portfolio_state_provider`` (mirrors
    ``bankroll_usd_provider``) lets Kelly size against the bankroll NET of
    correlation-weighted committed capital. The INV-K7 per-cycle in-flight
    reservation accumulator is CLOSURE-held (test-isolation safe), fresh per
    adapter instance (== per reactor cycle).
    """

    # Live production scope is forecast_plus_day0 only. Forecast and Day0 events
    # both use this same execution adapter; unknown events fail closed before the
    # candidate pipeline. There is no non-live/no-submit scope inside production.

    # FIX-4 (P2): per-cycle live submit call counter. Incremented ONLY when
    # executor_submit() is actually called (i.e., real_order_submit_enabled and
    # all gates pass). Exposed on the adapter callable so main.py can read it
    # after process_pending and populate live_submit_attempts accurately.
    # No-submit / submit-blocked cycles always read 0.
    _live_submit_count: list[int] = [0]

    # FIX-4 venue_acks: per-cycle counter of actual venue ACKs (successful
    # place_limit_order responses).  Incremented when venue_ack_received is
    # True on the submit result.  Exposed on the adapter callable for main.py.
    _live_ack_count: list[int] = [0]

    # INV-K7 reservation ledger: closure-held, fresh per reactor cycle. FIX B
    # (2026-06-05): rollback-aware so a candidate rejected downstream of Kelly is
    # rolled back by the reactor before the next sequential event reads it.
    portfolio_reservation = PortfolioReservationLedger()
    _seed_portfolio_reservations_from_durable_live_cap(
        portfolio_reservation,
        live_cap_conn,
        trade_conn=trade_conn,
    )
    resolved_replacement_forecast_hook = _resolve_replacement_forecast_adapter_hook(
        replacement_forecast_hook=replacement_forecast_hook,
        replacement_forecast_runtime_flags=replacement_forecast_runtime_flags,
        replacement_forecast_baseline_bundle_provider=replacement_forecast_baseline_bundle_provider,
        replacement_forecast_world_tables=replacement_forecast_world_tables,
        replacement_forecast_source_fact_status=replacement_forecast_source_fact_status,
        replacement_forecast_data_fact_status=replacement_forecast_data_fact_status,
        replacement_forecast_refit_decision=replacement_forecast_refit_decision,
        replacement_forecast_promotion_evidence=replacement_forecast_promotion_evidence,
        replacement_forecast_capital_objective_evidence=replacement_forecast_capital_objective_evidence,
        forecast_conn=forecast_conn,
        trade_conn=trade_conn,
    )

    def _submit_inner(event: OpportunityEvent, decision_time: datetime) -> EventSubmissionReceipt:
        # FINAL ADAPTER BOUNDARY SCOPE GATE. Production supports one scope:
        # forecast_plus_day0. Both forecast and Day0 events continue into the
        # same candidate proof/submit path; unknown event types are rejected.
        import logging as _logging

        event_type = getattr(event, "event_type", None)
        # FINAL ADAPTER BOUNDARY SCOPE GATE forecast-lane set — DELIBERATELY includes
        # EDLI_REDECISION_PENDING (continuous re-decision resurrection 2026-06-12): a price-driven
        # re-decision of a forecast family is forecast-lane and may submit under
        # production scope exactly as an FSR does. Unknown types remain fail-closed below.
        _FORECAST_LANE_EVENT_TYPES: frozenset[str] = _FORECAST_DECISION_EVENT_TYPES
        is_forecast_lane = event_type in _FORECAST_LANE_EVENT_TYPES
        is_day0_lane = event_type in _DAY0_LANE_EVENT_TYPES

        if edli_live_scope != "forecast_plus_day0":
            return EventSubmissionReceipt(
                False,
                event.event_id,
                event.causal_snapshot_id,
                reason=f"UNSUPPORTED_EDLI_LIVE_SCOPE:{edli_live_scope}",
                proof_accepted=False,
            )
        if not is_forecast_lane and not is_day0_lane:
            _logging.getLogger(__name__).error(
                "EVENT_TYPE_OUT_OF_LIVE_SCOPE: unknown event_type=%r rejected at live boundary",
                event_type,
            )
            return EventSubmissionReceipt(
                False,
                event.event_id,
                event.causal_snapshot_id,
                reason="EVENT_TYPE_OUT_OF_LIVE_SCOPE",
                proof_accepted=False,
            )
        no_submit_receipt = build_event_bound_no_submit_receipt(
            event,
            trade_conn=trade_conn,
            decision_time=decision_time,
            forecast_conn=forecast_conn,
            topology_conn=topology_conn,
            calibration_conn=calibration_conn,
            get_current_level=get_current_level,
            bankroll_usd_provider=bankroll_usd_provider,
            free_cash_usd_provider=free_cash_usd_provider,
            portfolio_state_provider=portfolio_state_provider,
            portfolio_reservation=portfolio_reservation,
            locked_opportunity_conn=live_cap_conn or trade_conn,
            replacement_forecast_hook=resolved_replacement_forecast_hook,
            replacement_forecast_promotion_evidence=replacement_forecast_promotion_evidence,
            replacement_forecast_capital_objective_evidence=replacement_forecast_capital_objective_evidence,
            family_snapshot_refresher=family_snapshot_refresher,
        )
        # D2 SHIFT-BIN CLOSE-BEFORE-OPEN — old-leg exit submission (2026-06-22 consult
        # §"Shift-bin sequencing" step 3). A SHIFT_BIN EXIT_OLD_LEG receipt is a TYPED
        # no-submit for the NEW bin (proof_accepted=False) that carries the lease + the
        # old-leg identity. When real submit is enabled, submit the reduce-only exit for
        # the OLD held token THROUGH THE EXISTING exit path (execute_exit_order: builds
        # idempotency from decision_id/token/SELL/price/size, runs the executable-snapshot
        # gate + heartbeat/ws-gap/collateral, acquires ExitMutex, self-builds the client)
        # — bypassing NO gate. The lease advances by the exit OrderResult: EXIT_SUBMITTED
        # on a placed/acked sell, EXIT_PARTIAL on a partial, EXIT_UNKNOWN on an unknown
        # side effect, ABORTED on a clean pre-venue rejection (releases the family for a
        # legitimate retry). NO new-bin entry is built. No-op for every non-shift receipt.
        _shift_exit_payload = no_submit_receipt.shift_bin_lease_payload
        if (
            _shift_exit_payload is not None
            and str(_shift_exit_payload.get("phase") or "") == "EXIT_OLD_LEG"
            and real_order_submit_enabled
        ):
            _submit_shift_bin_old_leg_exit(
                trade_conn,
                payload=_shift_exit_payload,
                decision_time=decision_time.astimezone(UTC),
            )
            return no_submit_receipt
        if no_submit_receipt.proof_accepted is not True or no_submit_receipt.decision_proof_bundle is None:
            return no_submit_receipt
        # Wave-1 2026-06-12: the legacy submit throttle is DELETED. The real
        # gates remain the operator arm + real-submit flag + durable outbox +
        # executor boundary below. Live submit proceeds whenever those are present.
        if real_order_submit_enabled and not durable_submit_outbox_enabled:
            return EventSubmissionReceipt(
                False,
                event.event_id,
                event.causal_snapshot_id,
                reason="EDLI_DURABLE_SUBMIT_OUTBOX_REQUIRED",
                proof_accepted=False,
            )
        if real_order_submit_enabled and executor_submit is None:
            return EventSubmissionReceipt(
                False,
                event.event_id,
                event.causal_snapshot_id,
                reason="EXECUTOR_BOUNDARY_MISSING",
                proof_accepted=False,
            )
        # FIX-2b (PR_SPEC.md §2) OPERATOR ARM GATE: every real submit on the EDLI
        # boundary requires the operator-arm capability token, regardless of mode.
        # The token is constructible ONLY in main.py via
        # ``require_operator_arm`` after asserting ``edli_live_operator_authorized is
        # True``. Absent the token this fails closed BEFORE the live-order build /
        # executor seam. This is an UPSTREAM guard on the EDLI adapter only; the
        # mainline convergence node never constructs this adapter, so the 293-order
        # mainline is unaffected.
        if real_order_submit_enabled and operator_arm is None:
            return EventSubmissionReceipt(
                False,
                event.event_id,
                event.causal_snapshot_id,
                reason="OPERATOR_ARM_REQUIRED",
                proof_accepted=False,
            )
        # OPERATOR LAW (2026-06-04, Rule-4 antibody): mainstream is OBSERVATIONAL /
        # DISPLAY-ONLY — it is NEVER a decision input. The former submit-time mainstream
        # enforce branch (which rejected an armed submit on a missing/failed mainstream
        # verdict) is DELETED so mainstream has NO code path to gate / reject / skip /
        # alter direction, q, q_lcb, trade_score, selection, or submit. The verdict is
        # computed + annotated on the receipt for the operator's ARM review only; it can
        # never change a decision. This makes "mainstream changes a decision"
        # UNCONSTRUCTABLE (not merely flag-OFF). The dead config key is left inert.
        # Wave-1 2026-06-12: the legacy force-taker KNOB is DELETED entirely
        # (twin-authority disease: a knob that force-flips the proof's mode to
        # TAKER competes with the single mode authority). The proof's
        # execution_mode_intent (REST-then-cross policy) is the SOLE mode
        # authority; the build chain no longer carries a force-taker override.
        _live_order_build_phase = "not_started"
        command_certificates: tuple[DecisionCertificate, ...] = ()
        command: DecisionCertificate | None = None
        certificate_decision_time = decision_time.astimezone(UTC)
        command_certificates_persisted = False
        submit_result: EventBoundExecutorSubmitResult | None = None
        try:
            if real_order_submit_enabled:
                build_conn = live_cap_conn or trade_conn
                entries_pause_reason = _entry_pause_blocks_live_submit(build_conn)
                if entries_pause_reason is not None:
                    return dataclass_replace(
                        no_submit_receipt,
                        submitted=False,
                        side_effect_status="NO_SUBMIT",
                        reason=f"entries_paused:{entries_pause_reason}",
                        proof_accepted=False,
                    )
                # D1 FILL-UP PRE-SUBMIT REREAD (2026-06-22 lifecycle consult §"final
                # gate"): for an APPROVED same-token fill-up, before any command build /
                # venue call, re-read family exposure on fresh truth. If a NEW unowned /
                # unknown same-family entry appeared between admission and submit, abort
                # (advance the lease ABORTED) and emit NO order — the only safe response
                # to the over-exposure hazard reappearing mid-flight. No-op for every
                # non-fill-up receipt (fill_up_lease_payload is None → entry path
                # byte-identical).
                _fill_up_lease = no_submit_receipt.fill_up_lease_payload
                if _fill_up_lease is not None:
                    _reread_abort = _fill_up_wiring.presubmit_reread_aborts(
                        trade_conn,
                        city=str(_fill_up_lease.get("city") or ""),
                        target_date=str(_fill_up_lease.get("target_date") or ""),
                        temperature_metric=str(_fill_up_lease.get("metric") or ""),
                        owned_position_id=str(_fill_up_lease.get("owned_position_id") or ""),
                        owned_token_id=str(_fill_up_lease.get("owned_token_id") or ""),
                    )
                    if _reread_abort is not None:
                        _fill_up_wiring.abort_fill_up_lease(
                            trade_conn,
                            _fill_up_lease.get("intent_id"),
                            now_iso=decision_time.astimezone(UTC).isoformat(),
                            reason=_reread_abort,
                        )
                        return EventSubmissionReceipt(
                            False,
                            event.event_id,
                            event.causal_snapshot_id,
                            reason=f"FILL_UP_PRESUBMIT_REREAD_ABORT:{_reread_abort}",
                            proof_accepted=False,
                        )
                _live_order_build_phase = "building_live_order_certificates"
                command_certificates = _build_live_execution_command_certificates(
                    event=event,
                    receipt=no_submit_receipt,
                    decision_time=decision_time.astimezone(UTC),
                    live_cap_conn=build_conn,
                    trade_conn=trade_conn,
                    pre_submit_authority_provider=pre_submit_authority_provider,
                )
                _live_order_build_phase = "live_order_certificates_built"
                final_intent = _required_cert(command_certificates, claims.FINAL_INTENT)
                command = _required_cert(command_certificates, claims.EXECUTION_COMMAND)
                certificate_decision_time = command.header.decision_time
                _persist_live_command_certificates_before_executor_submit(
                    build_conn,
                    command_certificates,
                )
                command_certificates_persisted = True
                _live_order_build_phase = "live_order_command_persisted"
                assert executor_submit is not None
                _live_order_build_phase = "calling_executor_submit"
                submit_result = _normalize_event_bound_executor_submit_result(
                    executor_submit(final_intent, command)
                )
                _live_order_build_phase = "executor_submit_completed"
                if submit_result.venue_call_started:
                    _append_venue_submit_attempted_aggregate_event(
                        live_cap_conn or trade_conn,
                        command,
                        decision_time=certificate_decision_time,
                    )
                    _live_submit_count[0] += 1
                if submit_result.venue_ack_received:
                    _live_ack_count[0] += 1  # FIX-4 venue_acks: count actual ACKs
                # D1 FILL-UP lease terminal advance: COMPLETE on a venue ack, ABORTED
                # otherwise (a non-ack submit result means no resting order materialized
                # for this fill-up, so release the family for the next legitimate
                # rebalance). No-op for non-fill-up receipts.
                if _fill_up_lease is not None:
                    _now_iso = certificate_decision_time.isoformat() if hasattr(
                        certificate_decision_time, "isoformat"
                    ) else decision_time.astimezone(UTC).isoformat()
                    if submit_result.venue_ack_received:
                        _fill_up_wiring.complete_fill_up_lease(
                            trade_conn,
                            _fill_up_lease.get("intent_id"),
                            now_iso=_now_iso,
                            new_entry_command_id=str(
                                getattr(getattr(command, "header", None), "certificate_id", "") or ""
                            ),
                        )
                    else:
                        _fill_up_wiring.abort_fill_up_lease(
                            trade_conn,
                            _fill_up_lease.get("intent_id"),
                            now_iso=_now_iso,
                            reason=f"FILL_UP_SUBMIT_NO_ACK:{submit_result.status}",
                        )
                # D2 SHIFT-BIN ENTER_NEW_BIN lease terminal advance: this submit IS the
                # counter-entry (old leg already proven closed). COMPLETE on a venue ack,
                # ABORTED otherwise (no resting counter-entry materialized → release the
                # family). No-op for every non-shift / EXIT_OLD_LEG receipt.
                _shift_entry_lease = no_submit_receipt.shift_bin_lease_payload
                if (
                    _shift_entry_lease is not None
                    and str(_shift_entry_lease.get("phase") or "") == "ENTER_NEW_BIN"
                ):
                    _now_iso_sb = certificate_decision_time.isoformat() if hasattr(
                        certificate_decision_time, "isoformat"
                    ) else decision_time.astimezone(UTC).isoformat()
                    if submit_result.venue_ack_received:
                        _shift_bin_wiring.complete_shift_bin_lease(
                            trade_conn,
                            _shift_entry_lease.get("intent_id"),
                            now_iso=_now_iso_sb,
                            new_entry_command_id=str(
                                getattr(getattr(command, "header", None), "certificate_id", "") or ""
                            ),
                        )
                    else:
                        _shift_bin_wiring.abort_shift_bin_lease(
                            trade_conn,
                            _shift_entry_lease.get("intent_id"),
                            now_iso=_now_iso_sb,
                            reason=f"SHIFT_BIN_ENTRY_SUBMIT_NO_ACK:{submit_result.status}",
                        )
                receipt_cert = build_execution_receipt_certificate(
                    execution_command_cert=command,
                    decision_time=certificate_decision_time,
                    status=submit_result.status,
                    reason_code=submit_result.reason_code,
                    submit_started_at=submit_result.submit_started_at,
                    submit_finished_at=submit_result.submit_finished_at,
                    venue_order_id=submit_result.venue_order_id,
                    raw_response=submit_result.raw_response,
                    raw_response_hash=submit_result.raw_response_hash,
                    reconciliation_followup_required=submit_result.reconciliation_followup_required,
                    venue_call_started=submit_result.venue_call_started,
                    venue_ack_received=submit_result.venue_ack_received,
                    side_effect_known=submit_result.side_effect_known,
                )
                _append_submit_terminal_aggregate_event(
                    live_cap_conn or trade_conn,
                    command,
                    receipt_cert,
                    submit_result=submit_result,
                    decision_time=certificate_decision_time,
                )
                _live_order_build_phase = "submit_terminal_appended"
                transition_cert = _transition_live_cap_after_submit(
                    command_certificates,
                    live_cap_conn or trade_conn,
                    command,
                    receipt_cert,
                    submit_result,
                    decision_time=certificate_decision_time,
                )
                certificates = command_certificates + (receipt_cert, transition_cert)
                side_effect_status = submit_result.status
                submitted = submit_result.status in {"SUBMITTED"}
                reason = submit_result.reason_code
            else:
                build_conn = live_cap_conn or trade_conn
                certificates = _run_live_order_build_savepoint(
                    build_conn,
                    lambda: _build_submit_disabled_live_certificates(
                        event=event,
                        receipt=no_submit_receipt,
                        decision_time=decision_time.astimezone(UTC),
                        live_cap_conn=build_conn,
                        trade_conn=trade_conn,
                        pre_submit_authority_provider=pre_submit_authority_provider,
                    ),
                    savepoint_name="edli_submit_disabled_live_order_build",
                )
                side_effect_status = "SUBMIT_DISABLED"
                submitted = False
                reason = "real_order_submit_disabled"
        except _LiveOpportunityAlreadyLocked as exc:
            return dataclass_replace(
                no_submit_receipt,
                side_effect_status="NO_SUBMIT",
                reason=str(exc),
                proof_accepted=False,
            )
        except _SubmitAbortedModeFlipped as exc:
            # Fresh book evidence invalidated the previously built intent before
            # the venue boundary. No venue side effect exists and the final intent
            # is no longer accepted; the reactor classifies the typed reason and
            # re-decides from fresh evidence when it is transient.
            return dataclass_replace(
                no_submit_receipt,
                side_effect_status="NO_SUBMIT",
                reason=(
                    f"{_SUBMIT_ABORT_RECEIPT_REASON[CandidateLifecycleState.SUBMIT_ABORTED_MODE_FLIPPED]}"
                    f":{exc}"
                ),
                proof_accepted=False,
            )
        except Exception as exc:
            if _live_order_build_phase == "building_live_order_certificates":
                try:
                    _fill_up_lease = no_submit_receipt.fill_up_lease_payload
                    if _fill_up_lease is not None:
                        _fill_up_wiring.abort_fill_up_lease(
                            trade_conn,
                            _fill_up_lease.get("intent_id"),
                            now_iso=decision_time.astimezone(UTC).isoformat(),
                            reason=(
                                "FILL_UP_PRE_VENUE_BUILD_FAILED:"
                                f"{type(exc).__name__}:{exc}"
                            ),
                        )
                    _shift_entry_lease = no_submit_receipt.shift_bin_lease_payload
                    if (
                        _shift_entry_lease is not None
                        and str(_shift_entry_lease.get("phase") or "") == "ENTER_NEW_BIN"
                    ):
                        _shift_bin_wiring.abort_shift_bin_lease(
                            trade_conn,
                            _shift_entry_lease.get("intent_id"),
                            now_iso=decision_time.astimezone(UTC).isoformat(),
                            reason=(
                                "SHIFT_BIN_ENTRY_PRE_VENUE_BUILD_FAILED:"
                                f"{type(exc).__name__}:{exc}"
                            ),
                        )
                except Exception:  # noqa: BLE001 - preserve the original build failure.
                    pass
            _strategy_floor_abort = _presubmit_strategy_floor_abort_reason(exc)
            if _strategy_floor_abort is not None:
                return dataclass_replace(
                    no_submit_receipt,
                    submitted=False,
                    side_effect_status="NO_SUBMIT",
                    reason=_strategy_floor_abort,
                    proof_accepted=False,
                )
            _price_moved_abort = _submit_price_moved_abort_reason(exc)
            if _price_moved_abort is not None:
                return dataclass_replace(
                    no_submit_receipt,
                    submitted=False,
                    side_effect_status="NO_SUBMIT",
                    reason=_price_moved_abort,
                    proof_accepted=False,
                )
            if (
                real_order_submit_enabled
                and command_certificates_persisted
                and command is not None
                and _live_order_build_phase != "submit_terminal_appended"
            ):
                try:
                    terminal_result = submit_result
                    if terminal_result is None:
                        terminal_result = _fallback_submit_result_after_live_command_failure(
                            exc,
                            phase=_live_order_build_phase,
                            decision_time=certificate_decision_time,
                        )
                    if terminal_result.venue_call_started:
                        _append_venue_submit_attempted_aggregate_event(
                            live_cap_conn or trade_conn,
                            command,
                            decision_time=certificate_decision_time,
                        )
                    receipt_cert = build_execution_receipt_certificate(
                        execution_command_cert=command,
                        decision_time=certificate_decision_time,
                        status=terminal_result.status,
                        reason_code=terminal_result.reason_code,
                        submit_started_at=terminal_result.submit_started_at,
                        submit_finished_at=terminal_result.submit_finished_at,
                        venue_order_id=terminal_result.venue_order_id,
                        raw_response=terminal_result.raw_response,
                        raw_response_hash=terminal_result.raw_response_hash,
                        reconciliation_followup_required=terminal_result.reconciliation_followup_required,
                        venue_call_started=terminal_result.venue_call_started,
                        venue_ack_received=terminal_result.venue_ack_received,
                        side_effect_known=terminal_result.side_effect_known,
                    )
                    _append_submit_terminal_aggregate_event(
                        live_cap_conn or trade_conn,
                        command,
                        receipt_cert,
                        submit_result=terminal_result,
                        decision_time=certificate_decision_time,
                    )
                    transition_cert = _transition_live_cap_after_submit(
                        command_certificates,
                        live_cap_conn or trade_conn,
                        command,
                        receipt_cert,
                        terminal_result,
                        decision_time=certificate_decision_time,
                    )
                    return dataclass_replace(
                        no_submit_receipt,
                        submitted=terminal_result.status == "SUBMITTED",
                        side_effect_status=terminal_result.status,
                        reason=terminal_result.reason_code,
                        proof_accepted=True,
                        decision_proof_bundle=command_certificates + (receipt_cert, transition_cert),
                    )
                except Exception as terminal_exc:  # noqa: BLE001
                    return dataclass_replace(
                        no_submit_receipt,
                        submitted=False,
                        side_effect_status="NO_SUBMIT",
                        reason=(
                            "EDLI_LIVE_COMMAND_TERMINALIZATION_FAILED:"
                            f"{type(terminal_exc).__name__}:{terminal_exc}"
                        ),
                        proof_accepted=False,
                    )
            return dataclass_replace(
                no_submit_receipt,
                submitted=False,
                side_effect_status="NO_SUBMIT",
                reason=f"EDLI_LIVE_CERTIFICATE_BUILD_FAILED:{exc}",
                proof_accepted=False,
            )
        return EventSubmissionReceipt(
            submitted=submitted,
            event_id=no_submit_receipt.event_id,
            causal_snapshot_id=no_submit_receipt.causal_snapshot_id,
            city=no_submit_receipt.city,
            target_date=no_submit_receipt.target_date,
            metric=no_submit_receipt.metric,
            condition_id=no_submit_receipt.condition_id,
            token_id=no_submit_receipt.token_id,
            outcome_label=no_submit_receipt.outcome_label,
            candidate_id=no_submit_receipt.candidate_id,
            executable_snapshot_id=no_submit_receipt.executable_snapshot_id,
            family_id=no_submit_receipt.family_id,
            bin_label=no_submit_receipt.bin_label,
            direction=no_submit_receipt.direction,
            q_live=no_submit_receipt.q_live,
            q_lcb_5pct=no_submit_receipt.q_lcb_5pct,
            c_fee_adjusted=no_submit_receipt.c_fee_adjusted,
            c_cost_95pct=no_submit_receipt.c_cost_95pct,
            p_fill_lcb=no_submit_receipt.p_fill_lcb,
            trade_score=no_submit_receipt.trade_score,
            native_quote_available=no_submit_receipt.native_quote_available,
            source_status=no_submit_receipt.source_status,
            family_complete=no_submit_receipt.family_complete,
            trade_score_positive=no_submit_receipt.trade_score_positive,
            fdr_pass=no_submit_receipt.fdr_pass,
            fdr_family_id=no_submit_receipt.fdr_family_id,
            fdr_hypothesis_count=no_submit_receipt.fdr_hypothesis_count,
            kelly_pass=no_submit_receipt.kelly_pass,
            kelly_execution_price_type=no_submit_receipt.kelly_execution_price_type,
            kelly_price_fee_deducted=no_submit_receipt.kelly_price_fee_deducted,
            kelly_size_usd=no_submit_receipt.kelly_size_usd,
            kelly_cost_basis_id=no_submit_receipt.kelly_cost_basis_id,
            kelly_decision_id=no_submit_receipt.kelly_decision_id,
            risk_decision_id=no_submit_receipt.risk_decision_id,
            final_intent_id=no_submit_receipt.final_intent_id,
            neg_risk=no_submit_receipt.neg_risk,
            side_effect_status=side_effect_status,
            reason=reason,
            proof_accepted=True,
            decision_proof_bundle=certificates,
            mainstream_agreement_pass=no_submit_receipt.mainstream_agreement_pass,
            mainstream_agreement_fail_reason=no_submit_receipt.mainstream_agreement_fail_reason,
            mainstream_point=no_submit_receipt.mainstream_point,
            mainstream_delta=no_submit_receipt.mainstream_delta,
            mainstream_bin_label=no_submit_receipt.mainstream_bin_label,
            mainstream_source=no_submit_receipt.mainstream_source,
            mainstream_fetched_at_utc=no_submit_receipt.mainstream_fetched_at_utc,
            alpha_gap=no_submit_receipt.alpha_gap,
            q_source=no_submit_receipt.q_source,
            strategy_key=no_submit_receipt.strategy_key,
            opportunity_book=no_submit_receipt.opportunity_book,
            replacement_forecast=no_submit_receipt.replacement_forecast,
            unit=no_submit_receipt.unit,
            # P0 mode-authority: carry the proven proof mode + maker limit forward onto
            # the submit-outcome receipt for settlement attribution (operator 2026-06-10).
            execution_mode_intent=no_submit_receipt.execution_mode_intent,
            maker_limit_price=no_submit_receipt.maker_limit_price,
            # FIX (third-path input starvation, 2026-06-11): same_bin_yes_posterior and
            # settlement_coverage_status were omitted here, so the buy_no gate in
            # _receipt_money_path_blocker always received None → ADMISSION_BUY_NO_INDEPENDENT_
            # YES_POSTERIOR_MISSING → receipt.reason set, trade_score_positive=False,
            # rejection_stage=TRADE_SCORE. Thread them unconditionally from no_submit_receipt
            # (single authority: same field names, same values set by _generate_candidate_proofs).
            # Also carry q_lcb_calibration_source, posterior_id, probability_authority for
            # provenance completeness — same omission category.
            q_lcb_calibration_source=no_submit_receipt.q_lcb_calibration_source,
            same_bin_yes_posterior=no_submit_receipt.same_bin_yes_posterior,
            settlement_coverage_status=no_submit_receipt.settlement_coverage_status,
            posterior_id=no_submit_receipt.posterior_id,
            probability_authority=no_submit_receipt.probability_authority,
        )

    def _submit(event: OpportunityEvent, decision_time: datetime) -> EventSubmissionReceipt:
        # CATEGORY ANTIBODY (2026-06-08, "database is locked" HOLDER-side kill):
        # the reactor opens ONE trade connection per cycle (main.py:5231) and hands
        # it here; sqlite3 isolation_level="" makes the first read/write inside
        # _submit_inner open an implicit transaction that takes the trade-DB WAL
        # write lock (on the live-order build INSERTs) / pins the WAL read-mark, and
        # NOTHING in process_pending commits trade_conn until cycle-end close().
        # Across a multi-event cycle (each event doing a venue HTTP POST inside the
        # executor) that lock is held continuously, so the substrate-warm cycle,
        # log_trade_exit, and the CollateralLedger heartbeat all block out their
        # busy_timeout and record "database is locked" (live 2026-06-08 09:43-09:52).
        #
        # Fix (mirrors the reactor's WORLD-DB per-event commit windows in
        # events/reactor.py and the harvester per-event commit in
        # ingest/harvester_truth_writer): commit trade_conn at the END of EVERY
        # _submit — accept, gate-reject, or raise — in a finally. This releases the
        # trade-DB write lock AND ends the WAL-floor-pinning read transaction per
        # event, so concurrent trade-DB writers get a write window each event and
        # the WAL can checkpoint. The executor already commits its own venue-command
        # write units durably; this commits the remaining adapter-level trade_conn
        # writes (durable, intended) + closes the read txn. The provisional
        # PortfolioReservationLedger is IN-MEMORY (sizing/portfolio_reservation.py),
        # so the reactor's post-submit commit/rollback of reservations is unaffected
        # by a trade_conn.commit() here. No gate is weakened: the commit only
        # bounds the lock-hold; it changes no decision, gate, or submit semantics.
        try:
            receipt = _submit_inner(event, decision_time)
            # SUBMIT-LANE STAMP: the live adapter ran. Every receipt it returns is
            # stamped with the live-adapter lane so the persist boundary can tell a
            # genuine live-lane decision from a control-blocked no-submit. This lane
            # is the operator's truth: the live adapter never produces a full-pass
            # NO_SUBMIT carrying the default reason, so a LIVE-stamped
            # proof_accepted NO_SUBMIT is the silent-kill signature the reactor
            # invariant rejects.
            return _stamp_live_adapter_lane(
                receipt, real_order_submit_enabled=real_order_submit_enabled
            )
        finally:
            try:
                trade_conn.commit()
            except Exception:  # noqa: BLE001 - commit is a lock-release boundary; never mask the real result/raise
                pass

    # FIX B: expose the per-cycle ledger so the reactor commits/rolls back
    # provisional reservations in its post-submit phase.
    _submit.reservation_ledger = portfolio_reservation  # type: ignore[attr-defined]
    # FIX-4: expose the live submit call counter so main.py can read it after
    # process_pending to populate live_submit_attempts in the status pulse.
    _submit._live_submit_count = _live_submit_count  # type: ignore[attr-defined]
    # FIX-4 venue_acks: expose the ACK counter alongside submit counter.
    _submit._live_ack_count = _live_ack_count  # type: ignore[attr-defined]
    return _submit


def _run_live_order_build_savepoint(
    conn: sqlite3.Connection,
    build: Callable[[], tuple[DecisionCertificate, ...]],
    *,
    savepoint_name: str = "edli_live_order_build",
) -> tuple[DecisionCertificate, ...]:
    if not savepoint_name.replace("_", "").isalnum():
        raise ValueError("live order build savepoint name must be alphanumeric/underscore")
    retry_delays = _live_order_build_lock_retry_delays()
    saved_busy_timeout_ms = _sqlite_busy_timeout_ms(conn)
    build_busy_timeout_ms = _live_order_build_busy_timeout_ms()
    try:
        _set_sqlite_busy_timeout_ms(conn, build_busy_timeout_ms)
        for attempt in range(1, len(retry_delays) + 2):
            conn.execute(f"SAVEPOINT {savepoint_name}")
            try:
                result = build()
            except sqlite3.OperationalError as exc:
                _rollback_release_live_order_build_savepoint(conn, savepoint_name=savepoint_name)
                if not _is_sqlite_lock_error(exc) or attempt > len(retry_delays):
                    raise
                logging.getLogger(__name__).warning(
                    "live order certificate build hit sqlite lock; rolled back savepoint "
                    "and retrying in %.1fs (attempt %d/%d, busy_timeout_ms=%d): %s",
                    retry_delays[attempt - 1],
                    attempt,
                    len(retry_delays) + 1,
                    build_busy_timeout_ms,
                    exc,
                )
                _time.sleep(retry_delays[attempt - 1])
                continue
            except Exception as exc:
                try:
                    _rollback_release_live_order_build_savepoint(conn, savepoint_name=savepoint_name)
                except sqlite3.OperationalError:
                    logging.getLogger(__name__).exception(
                        "live order build savepoint rollback failed after build error; "
                        "preserving original build exception: %r",
                        exc,
                    )
                raise
            try:
                conn.execute(f"RELEASE SAVEPOINT {savepoint_name}")
            except sqlite3.OperationalError as exc:
                if "no such savepoint" not in str(exc).lower():
                    raise
                logging.getLogger(__name__).warning(
                    "live order build savepoint %s was already released after a successful build",
                    savepoint_name,
                )
            return result
    finally:
        _set_sqlite_busy_timeout_ms(conn, saved_busy_timeout_ms)
    raise RuntimeError("unreachable live order build retry state")


def _release_live_order_build_stale_transaction(conn: sqlite3.Connection, *, phase: str) -> None:
    """End an old read/write transaction before the final live-order write unit.

    The live reactor uses one trade connection across many reads before it appends the
    live-order aggregate and live-cap rows. In WAL mode, a stale read snapshot cannot
    always be upgraded into a writer after sidecars have committed newer trade rows; the
    upgrade fails immediately as ``database is locked`` and retrying the same snapshot is
    useless. The live-order write unit has its own savepoint below, so release any older
    transaction first and write from a fresh snapshot.
    """

    if not bool(getattr(conn, "in_transaction", False)):
        return
    logging.getLogger(__name__).info(
        "live order build releasing stale sqlite transaction before %s", phase
    )
    conn.commit()


def _rollback_release_live_order_build_savepoint(
    conn: sqlite3.Connection,
    *,
    savepoint_name: str,
) -> None:
    try:
        conn.execute(f"ROLLBACK TO SAVEPOINT {savepoint_name}")
    finally:
        conn.execute(f"RELEASE SAVEPOINT {savepoint_name}")


def _persist_live_command_certificates_before_executor_submit(
    conn: sqlite3.Connection,
    certificates: tuple[DecisionCertificate, ...],
) -> None:
    """Durably expose the live command proof before the executor boundary."""

    DecisionCertificateLedger(conn).persist_all(certificates)
    conn.commit()


def _is_sqlite_lock_error(exc: sqlite3.OperationalError) -> bool:
    lock_codes = {
        getattr(sqlite3, "SQLITE_BUSY", 5),
        getattr(sqlite3, "SQLITE_LOCKED", 6),
    }
    code = getattr(exc, "sqlite_errorcode", None)
    if code is not None and code in lock_codes:
        return True
    message = str(exc).lower()
    return (
        "database is locked" in message
        or "database table is locked" in message
        or "database is busy" in message
    )


def _sqlite_busy_timeout_ms(conn: sqlite3.Connection) -> int | None:
    try:
        row = conn.execute("PRAGMA busy_timeout").fetchone()
        return int(row[0]) if row is not None else None
    except Exception:  # noqa: BLE001
        return None


def _set_sqlite_busy_timeout_ms(conn: sqlite3.Connection, value: int | None) -> None:
    if value is None:
        return
    conn.execute("PRAGMA busy_timeout = %d" % max(1, int(value)))


def _live_order_build_busy_timeout_ms() -> int:
    raw = os.environ.get("ZEUS_LIVE_ORDER_BUILD_BUSY_TIMEOUT_MS", "8000")
    try:
        timeout_ms = int(float(raw))
    except (TypeError, ValueError):
        timeout_ms = 8000
    return max(250, min(timeout_ms, 20000))


def _live_order_build_lock_retry_delays() -> tuple[float, ...]:
    raw = os.environ.get("ZEUS_LIVE_ORDER_BUILD_LOCK_RETRY_SECONDS", "0.25,0.75,1.5")
    delays: list[float] = []
    for item in raw.split(","):
        item = item.strip()
        if not item:
            continue
        try:
            delay = float(item)
        except ValueError:
            continue
        if delay > 0:
            delays.append(min(delay, 10.0))
    return tuple(delays)


# --------------------------------------------------------------------------- #
# Forecast-lane market-phase admission gate (#98).
#
# The forecast lane is blind to observation: the instant a market's target LOCAL
# DAY begins, its daily extremum starts realizing and a forecast-only decision
# can land on the already-observed (losing) side — the Paris 2026-06-01 buy_no
# on observed low=14°C incident. Category-killing rule (STRONGER than
# DAY0_OBSERVATION_WRONGSIDE_ROOT §4.1; see DESIGN_CRITIC_2026-06-01 MAJOR-4):
# admit ONLY MarketPhase.PRE_SETTLEMENT_DAY (the whole target local day still
# in the future). SETTLEMENT_DAY / POST_TRADING / RESOLVED / unknown all reject
# fail-closed. Same-day edge belongs to the disjoint day0 observation-aware
# lane, never the forecast lane. Authority: src/strategy/market_phase.py.
#
# WAVE-1 W1-T1: the admit-set and the predicate are now the SHARED canonical
# objects from src.strategy.market_phase (FORECAST_ONLY_ADMIT_PHASES /
# market_phase_admits), imported at module top. The reactor keeps this
# evidence-building backstop (it needs the typed evidence for the
# EVENT_BOUND_MARKET_PHASE_CLOSED rejection reason); the admit verdict cannot
# diverge from the intake filter because both consult the same frozenset.
# --------------------------------------------------------------------------- #


def _edli_forecast_lane_phase_evidence(
    *,
    city: str,
    target_date: str,
    decision_time: datetime,
    selected_market_row: Mapping[str, Any] | None,
    uma_resolved_source: str | None = None,
) -> "_market_phase_evidence.MarketPhaseEvidence":
    """Phase evidence for a forecast-lane family at decision_time.

    Fail-closed: when the city has no resolvable timezone the phase is
    undeterminable and the returned evidence carries phase=None (the caller then
    rejects). The selected snapshot row supplies an explicit endDate when
    present; otherwise the F1 12:00-UTC fallback applies (per market_phase.py).
    """
    city_config = runtime_cities_by_name().get(city)
    tz = getattr(city_config, "timezone", None) if city_config is not None else None
    if not tz:
        return _market_phase_evidence.MarketPhaseEvidence(
            phase=None,
            phase_source="unknown",
            market_start_at=None,
            market_end_at=None,
            settlement_day_entry_utc=None,
            failure_reason=f"city_timezone_missing:{city}",
        )
    market = dict(selected_market_row) if selected_market_row else {}
    return _market_phase_evidence.from_market_dict(
        market=market,
        city_timezone=tz,
        target_date_str=str(target_date),
        decision_time_utc=decision_time.astimezone(UTC),
        uma_resolved_source=uma_resolved_source,
    )


def _forecast_lane_phase_admits(evidence: "_market_phase_evidence.MarketPhaseEvidence") -> bool:
    """True iff the family may be admitted in the forecast lane: ONLY when the
    whole target local day is still future (PRE_SETTLEMENT_DAY). Fail-closed."""
    return evidence.phase in _FORECAST_ONLY_ADMIT_PHASES


def _selection_pi_min() -> float:
    """Fixed telemetry threshold for the selection-shrinkage receipt fields.

    This value is intentionally not configurable from live settings. The live
    selection gate remains the BH/FDR pass; the shrinkage quantities are recorded
    for later attribution and cannot change the selected order.
    """
    return _SELECTION_DIAGNOSTIC_PI_MIN


@dataclass(frozen=True)
class _SelectionShrinkageVerdict:
    """Telemetry output of the C2 EB-shrinkage selection attribution stage."""

    lfsr: float | None
    edge_shrunk: float | None
    edge_shrunk_posterior_sd: float | None
    selection_authority: str
    eb_licensed: bool | None  # None when not computable (no executable universe)


def _compute_selection_shrinkage(
    *,
    proofs: "list[_CandidateProof]",
    selected_token_id: str,
    selected_q_posterior: float,
    selected_price: float,
    authority_on: bool,
) -> _SelectionShrinkageVerdict:
    """Compute the C2 posterior lfsr + EB-shrunk edge for the SELECTED candidate.

    The candidate universe is the family's executable bins (mutually-exclusive →
    one family cluster, so EB tau^2 is family-clustered per the Fable refinement).
    Per-candidate edge ê = q_lcb_5pct − price; the per-candidate posterior SD is
    derived from the one-sided 5% LCB gap s ≈ (q_posterior − q_lcb_5pct)/z_{0.95}.

    Returns telemetry quantities plus the EB license verdict when an executable
    universe exists. The live order selection does not branch on this result.
    Fail-soft: any construction error leaves the quantities None and authority
    "BH_FDR" so the live BH path is never disturbed by attribution computation.
    """
    from src.strategy.selection_shrinkage import (
        eb_shrink_edges,
        lfsr as _lfsr,
        select_license,
    )

    authority = "EB_SHRINKAGE" if authority_on else "BH_FDR"
    try:
        z95 = 1.6448536269514722  # Phi^{-1}(0.95): the 5% one-sided LCB z
        e_hat: list[float] = []
        s_each: list[float] = []
        token_order: list[str] = []
        for cp in proofs:
            if cp.execution_price is None:
                continue
            price = float(cp.execution_price.value)
            edge = float(cp.q_lcb_5pct) - price
            gap = float(cp.q_posterior) - float(cp.q_lcb_5pct)
            # SD proxy from the one-sided 5% LCB gap; floored so a degenerate
            # zero-width bound does not divide-by-zero or claim infinite certainty.
            sd = max(gap / z95, 1e-4)
            e_hat.append(edge)
            s_each.append(sd)
            token_order.append(cp.token_id)
        if selected_token_id not in token_order:
            # The selected bin had no executable price in the universe — cannot
            # shrink. Telemetry quantities stay None; edge-FDR remains the authority.
            return _SelectionShrinkageVerdict(None, None, None, "BH_FDR", None)
        sel_idx = token_order.index(selected_token_id)
        res = eb_shrink_edges(e_hat, s_each)  # single family → family-clustered tau^2
        edge_shrunk = float(res.shrunk_mean[sel_idx])
        edge_shrunk_sd = float(res.posterior_sd[sel_idx])
        # lfsr on the SHRUNK posterior edge (normal approx N(m, V_jj)).
        sign_rate = float(_lfsr(e_hat=edge_shrunk, s=max(edge_shrunk_sd, 1e-9)))
        lic = select_license(
            edge_shrunk=edge_shrunk,
            edge_shrunk_posterior_sd=edge_shrunk_sd,
            q_posterior=float(selected_q_posterior),
            price=float(selected_price),
            e_min=0.0,
            pi_min=_selection_pi_min(),
        )
        return _SelectionShrinkageVerdict(
            lfsr=sign_rate,
            edge_shrunk=edge_shrunk,
            edge_shrunk_posterior_sd=edge_shrunk_sd,
            selection_authority=authority,
            eb_licensed=bool(lic.licensed),
        )
    except Exception:
        # Fail-soft: telemetry computation must never disturb the live edge-FDR gate.
        return _SelectionShrinkageVerdict(None, None, None, "BH_FDR", None)


def _fdr_maps_with_selected_authority(
    *,
    family_id: str,
    proofs: tuple["_CandidateProof", ...],
    selected_proof: "_CandidateProof",
    selected_token_id: str,
) -> tuple[dict[str, float], dict[str, bool]]:
    """Build FDR maps, replacing the selected hypothesis with its live authority.

    qkernel_spine returns an overlaid selected proof carrying the route
    false-edge-rate and conservative edge prefilter. The sibling ``proofs``
    tuple remains the unmodified submission substrate, so selected authority must
    be overlaid into the FDR maps explicitly.
    """

    p_values = {
        f"{family_id}:{proof.token_id}": proof.p_value
        for proof in proofs
    }
    prefilter = {
        f"{family_id}:{proof.token_id}": proof.passed_prefilter
        for proof in proofs
    }
    selected_hypothesis_id = f"{family_id}:{selected_token_id}"
    p_values[selected_hypothesis_id] = selected_proof.p_value
    prefilter[selected_hypothesis_id] = selected_proof.passed_prefilter
    return p_values, prefilter


def _qkernel_selected_route_fdr_proof(
    *,
    family_id: str,
    all_hypothesis_ids: tuple[str, ...],
    selected_hypothesis_id: str,
    selected_proof: "_CandidateProof",
) -> object | None:
    """Return a qkernel-native FDR proof for a selected spine route.

    The qkernel spine selects one coherent family payoff route, not an
    independent scalar bin hypothesis. Its empirical false-edge rate is computed
    from the same band samples and payoff vector that produced the selected
    route's conservative edge. Re-running legacy full-family BH over sibling
    binary hypotheses double-counts the old hypothesis denominator and can
    reject the qkernel-selected route using unrelated legacy p-values.

    Return ``None`` for non-qkernel proofs so the legacy BH path remains
    byte-for-byte responsible for legacy selections.
    """

    cert = _qkernel_execution_economics(selected_proof)
    if cert is None:
        return None
    try:
        false_edge_rate = float(cert.get("false_edge_rate"))
    except (TypeError, ValueError):
        return None
    if not math.isfinite(false_edge_rate):
        return None
    from src.events.money_path_adapters import FdrProof
    from src.strategy.fdr_filter import DEFAULT_FDR_ALPHA

    passed = bool(selected_proof.passed_prefilter) and false_edge_rate <= float(DEFAULT_FDR_ALPHA)
    return FdrProof(
        fdr_family_id=family_id,
        attempted_hypotheses=len(all_hypothesis_ids),
        selected_hypotheses=(selected_hypothesis_id,),
        selected_post_fdr=(selected_hypothesis_id,) if passed else tuple(),
        passed=passed,
    )


def _day0_selected_route_fdr_proof(
    *,
    event_type: str,
    family_id: str,
    all_hypothesis_ids: tuple[str, ...],
    selected_hypothesis_id: str,
    selected_proof: "_CandidateProof",
) -> object | None:
    """Return a Day0 route-level FDR proof for the selected observation path.

    Day0 absorption is a single settlement-family route conditioned on observed
    same-day facts, not 22 independent sibling wagers.  Applying legacy BH across
    every YES/NO sibling denominator can reject a selected route whose own
    hard-fact lower-bound evidence clears the live FDR budget, exactly the same
    route-vs-sibling mismatch the qkernel spine already avoids.
    """

    if str(event_type or "") not in _DAY0_LANE_EVENT_TYPES:
        return None
    from src.events.money_path_adapters import FdrProof
    from src.strategy.fdr_filter import DEFAULT_FDR_ALPHA

    def _proof(passed: bool) -> FdrProof:
        return FdrProof(
            fdr_family_id=family_id,
            attempted_hypotheses=len(all_hypothesis_ids),
            selected_hypotheses=(selected_hypothesis_id,),
            selected_post_fdr=(selected_hypothesis_id,) if passed else tuple(),
            passed=passed,
        )

    if str(getattr(selected_proof, "probability_authority", "") or "").strip() != (
        "day0_absorbing_hard_fact"
    ):
        return _proof(False)
    try:
        q_lcb = float(selected_proof.q_lcb_5pct)
        price = float(selected_proof.execution_price.value)  # type: ignore[union-attr]
        trade_score = float(selected_proof.trade_score)
    except (TypeError, ValueError):
        return _proof(False)
    if not (math.isfinite(q_lcb) and math.isfinite(price) and math.isfinite(trade_score)):
        return _proof(False)
    false_edge_rate = max(0.0, 1.0 - q_lcb)

    passed = (
        bool(getattr(selected_proof, "passed_prefilter", False))
        and getattr(selected_proof, "missing_reason", None) is None
        and 0.0 <= q_lcb <= 1.0
        and 0.0 < price < 1.0
        and q_lcb > price
        and trade_score > 0.0
        and false_edge_rate <= float(DEFAULT_FDR_ALPHA)
    )
    return _proof(passed)


def _fdr_rejection_reason(
    *,
    event_type: object,
    fdr: object,
    selected_proof: "_CandidateProof",
) -> str:
    """Typed FDR reject reason with enough live evidence to diagnose the gate.

    The reactor buckets by the ``FDR_REJECTED`` prefix.  The suffix is evidence
    only: it lets Day0/qkernel live receipts answer why an otherwise selected
    route did not pass FDR without changing the pass/fail decision.
    """

    try:
        from src.strategy.fdr_filter import DEFAULT_FDR_ALPHA

        alpha = float(DEFAULT_FDR_ALPHA)
    except Exception:  # noqa: BLE001
        alpha = float("nan")
    selected_post = getattr(fdr, "selected_post_fdr", ()) or ()
    attempted = getattr(fdr, "attempted_hypotheses", None)
    pieces = [
        "FDR_REJECTED",
        f"event_type={str(event_type or 'unknown')}",
        f"attempted={attempted}",
        f"selected_post_fdr={len(tuple(selected_post))}",
        f"alpha={alpha:.6f}" if math.isfinite(alpha) else "alpha=unknown",
        f"passed_prefilter={bool(getattr(selected_proof, 'passed_prefilter', False))}",
    ]
    q_lcb = _optional_float(getattr(selected_proof, "q_lcb_5pct", None))
    q_live = _optional_float(getattr(selected_proof, "q_posterior", None))
    price = _optional_float(
        getattr(getattr(selected_proof, "execution_price", None), "value", None)
    )
    trade_score = _optional_float(getattr(selected_proof, "trade_score", None))
    if q_live is not None:
        pieces.append(f"q_live={q_live:.6f}")
    if q_lcb is not None:
        pieces.append(f"q_lcb={q_lcb:.6f}")
    if price is not None:
        pieces.append(f"price={price:.6f}")
    if trade_score is not None:
        pieces.append(f"trade_score={trade_score:.6f}")
    if str(event_type or "") in _DAY0_LANE_EVENT_TYPES:
        false_edge_rate = None if q_lcb is None else max(0.0, 1.0 - q_lcb)
        if false_edge_rate is not None:
            pieces.append(f"day0_false_edge_rate={false_edge_rate:.6f}")
        pieces.append(
            "probability_authority="
            f"{str(getattr(selected_proof, 'probability_authority', '') or 'missing')}"
        )
        pieces.append(
            "missing_reason="
            f"{str(getattr(selected_proof, 'missing_reason', None) or 'none')}"
        )
    else:
        p_value = _optional_float(getattr(selected_proof, "p_value", None))
        if p_value is not None:
            pieces.append(f"p_value={p_value:.6f}")
    return ":".join(pieces)


def _qkernel_selection_fact_family_id(
    *,
    family_id: str,
    decision_id: str,
    receipt_hash: str,
) -> str:
    return "qkernel_family:" + stable_hash(
        {
            "family_id": family_id,
            "decision_id": decision_id,
            "receipt_hash": receipt_hash,
        }
    )[:32]


def _qkernel_selection_hypothesis_id(
    *,
    fact_family_id: str,
    candidate_id: str,
    side: str,
) -> str:
    return "qkernel_hypothesis:" + stable_hash(
        {
            "family_id": fact_family_id,
            "candidate_id": candidate_id,
            "side": side,
        }
    )[:32]


def _record_qkernel_selection_family_facts(
    conn: sqlite3.Connection | None,
    *,
    family: EventBoundCandidateFamily,
    decision: Any | None,
    event: OpportunityEvent,
    decision_time: datetime,
    decision_snapshot_id: str | None,
) -> dict[str, Any]:
    """Persist qkernel family-selection facts to canonical world DB only.

    The qkernel path bypasses the legacy evaluator FDR writer by design; the
    spine is the selector. This writer records the spine candidates without
    rerunning legacy BH/FDR, and requires attached ``world`` tables so live
    selected trades cannot proceed with only local ghost facts.
    """

    if conn is None:
        return {"status": "skipped_no_connection", "families": 0, "hypotheses": 0}
    if decision is None:
        return {"status": "skipped_no_decision", "families": 0, "hypotheses": 0}

    candidate_decisions = tuple(getattr(decision, "candidate_decisions", ()) or ())
    if not candidate_decisions:
        return {"status": "skipped_no_candidates", "families": 0, "hypotheses": 0}

    decision_id = str(getattr(decision, "decision_id", "") or "")
    receipt_hash = str(getattr(decision, "receipt_hash", "") or "")
    fact_family_id = _qkernel_selection_fact_family_id(
        family_id=str(getattr(family, "family_id", "") or ""),
        decision_id=decision_id,
        receipt_hash=receipt_hash,
    )
    selected_candidate_id = str(getattr(getattr(decision, "selected", None), "candidate_id", "") or "")
    bin_label_by_id = {
        str(getattr(bin_obj, "bin_id", "") or ""): str(getattr(bin_obj, "label", "") or "")
        for bin_obj in tuple(getattr(getattr(decision, "omega", None), "bins", ()) or ())
    }

    from src.engine.qkernel_spine_bridge import qkernel_candidate_economics_by_bin_side
    from src.state.db import log_selection_family_fact, log_selection_hypothesis_fact

    economics_by_key = qkernel_candidate_economics_by_bin_side(decision)
    rows: list[dict[str, Any]] = []
    selected_strategy_key = ""
    for candidate_decision in candidate_decisions:
        route = getattr(candidate_decision, "route", None)
        economics = getattr(candidate_decision, "economics", None)
        if route is None or economics is None:
            continue
        side = str(getattr(route, "side", "") or "").strip().upper()
        bin_id = str(getattr(route, "bin_id", "") or "").strip()
        candidate_id = str(getattr(economics, "candidate_id", "") or "").strip()
        if side not in {"YES", "NO"} or not bin_id or not candidate_id:
            continue
        payload = dict(economics_by_key.get((bin_id, side), {}) or {})
        direction = "buy_yes" if side == "YES" else "buy_no"
        strategy_key = ""
        try:
            strategy_key = _event_bound_strategy_key(
                event_type=str(getattr(event, "event_type", "") or ""),
                direction=direction,
                metric=str(getattr(family, "metric", "") or ""),
            )
        except Exception:
            strategy_key = ""
        edge_lcb = _optional_float(payload.get("edge_lcb"))
        q_point = _optional_float(payload.get("payoff_q_point"))
        q_lcb = _optional_float(payload.get("payoff_q_lcb"))
        optimal_delta_u = _optional_float(payload.get("optimal_delta_u"))
        passed_prefilter = bool(
            payload.get("direction_law_ok") is True
            and payload.get("coherence_allows") is True
            and edge_lcb is not None
            and edge_lcb > 0.0
            and optimal_delta_u is not None
            and optimal_delta_u > 0.0
        )
        selected_post_fdr = bool(candidate_id and candidate_id == selected_candidate_id)
        if selected_post_fdr:
            selected_strategy_key = strategy_key
        rejection_stage = None
        rejection_detail = None
        if not selected_post_fdr:
            if payload.get("direction_law_ok") is not True:
                rejection_stage = "DIRECTION_LAW_REJECTED"
                rejection_detail = "direction_law_ok_not_true"
            elif payload.get("coherence_allows") is not True:
                rejection_stage = "MARKET_COHERENCE_REJECTED"
                rejection_detail = "coherence_allows_not_true"
            elif not passed_prefilter:
                if edge_lcb is None:
                    rejection_detail = "edge_lcb_missing"
                elif edge_lcb <= 0.0:
                    rejection_detail = "edge_lcb_nonpositive"
                elif optimal_delta_u is None:
                    rejection_detail = "optimal_delta_u_missing"
                elif optimal_delta_u <= 0.0:
                    rejection_detail = "optimal_delta_u_nonpositive"
                else:
                    rejection_detail = "prefilter_unknown"
                rejection_stage = "QKERNEL_PREFILTER_REJECTED"
            else:
                rejection_stage = "QKERNEL_NOT_SELECTED"
                rejection_detail = "positive_edge_not_rank_winner"
        rows.append(
            {
                "hypothesis_id": _qkernel_selection_hypothesis_id(
                    fact_family_id=fact_family_id,
                    candidate_id=candidate_id,
                    side=side,
                ),
                "candidate_id": candidate_id,
                "range_label": bin_label_by_id.get(bin_id) or bin_id,
                "direction": direction,
                "p_value": None,
                "q_value": q_point,
                "ci_lower": q_lcb,
                "ci_upper": None,
                "edge": edge_lcb,
                "tested": True,
                "passed_prefilter": passed_prefilter,
                "selected_post_fdr": selected_post_fdr,
                "rejection_stage": rejection_stage,
                "meta": {
                    "source": "qkernel_spine",
                    "event_id": event.event_id,
                    "event_type": event.event_type,
                    "decision_id": decision_id,
                    "receipt_hash": receipt_hash,
                    "rejection_detail": rejection_detail,
                    "route_id": str(payload.get("route_id") or getattr(economics, "route_id", "") or ""),
                    "side": side,
                    "bin_id": bin_id,
                    "strategy_key": strategy_key,
                    "qkernel_execution_economics": payload,
                },
            }
        )

    if not rows:
        return {"status": "skipped_no_hypotheses", "families": 0, "hypotheses": 0}

    recorded_at = decision_time.astimezone(UTC).isoformat()
    family_meta = {
        "source": "qkernel_spine",
        "event_id": event.event_id,
        "event_type": event.event_type,
        "decision_id": decision_id,
        "receipt_hash": receipt_hash,
        "spine_family_id": str(getattr(family, "family_id", "") or ""),
        "tested_hypotheses": len(rows),
        "passed_prefilter": sum(1 for row in rows if bool(row["passed_prefilter"])),
        "selected_post_fdr": sum(1 for row in rows if bool(row["selected_post_fdr"])),
        "selected_candidate_id": selected_candidate_id,
        "no_trade_reason": str(getattr(decision, "no_trade_reason", "") or ""),
    }
    family_result = log_selection_family_fact(
        conn,
        family_id=fact_family_id,
        cycle_mode="qkernel_spine",
        created_at=recorded_at,
        meta=family_meta,
        decision_snapshot_id=decision_snapshot_id,
        city=family.city,
        target_date=family.target_date,
        strategy_key=selected_strategy_key,
        discovery_mode=event.event_type,
        decision_time_status="live",
        require_attached_world=True,
    )
    if family_result.get("status") != "written":
        return {
            "status": str(family_result.get("status") or "family_write_failed"),
            "families": 0,
            "hypotheses": 0,
        }

    hypothesis_writes = 0
    first_failure: str | None = None
    for row in rows:
        result = log_selection_hypothesis_fact(
            conn,
            hypothesis_id=row["hypothesis_id"],
            family_id=fact_family_id,
            city=family.city,
            target_date=family.target_date,
            range_label=row["range_label"],
            direction=row["direction"],
            recorded_at=recorded_at,
            meta=row["meta"],
            decision_id=decision_id,
            candidate_id=row["candidate_id"],
            p_value=row["p_value"],
            q_value=row["q_value"],
            ci_lower=row["ci_lower"],
            ci_upper=row["ci_upper"],
            edge=row["edge"],
            tested=bool(row["tested"]),
            passed_prefilter=bool(row["passed_prefilter"]),
            selected_post_fdr=bool(row["selected_post_fdr"]),
            rejection_stage=row["rejection_stage"],
            require_attached_world=True,
        )
        if result.get("status") == "written":
            hypothesis_writes += 1
        elif first_failure is None:
            first_failure = str(result.get("status") or "hypothesis_write_failed")

    if hypothesis_writes <= 0:
        return {
            "status": first_failure or "hypothesis_write_failed",
            "families": 1,
            "hypotheses": 0,
        }
    return {
        "status": "written",
        "families": 1,
        "hypotheses": hypothesis_writes,
        "family_id": fact_family_id,
    }


def _build_event_bound_no_submit_receipt_core(
    event: OpportunityEvent,
    *,
    trade_conn: sqlite3.Connection,
    decision_time: datetime,
    get_current_level: Callable[[], RiskLevel],
    forecast_conn: sqlite3.Connection | None = None,
    topology_conn: sqlite3.Connection | None = None,
    calibration_conn: sqlite3.Connection | None = None,
    bankroll_usd_provider: Callable[[], float | None] | None = None,
    free_cash_usd_provider: Callable[[], float | None] | None = None,
    portfolio_state_provider: "Callable[[], Any] | None" = None,
    portfolio_reservation: "PortfolioReservationLedger | list[tuple[str, float]] | None" = None,
    locked_opportunity_conn: sqlite3.Connection | None = None,
    replacement_forecast_hook: Callable[["_CandidateProof", OpportunityEvent, datetime], ReplacementForecastReactorHookResult | None] | None = None,
    replacement_forecast_promotion_evidence: ReplacementForecastPromotionEvidence | None = None,
    replacement_forecast_capital_objective_evidence: ReplacementForecastCapitalObjectiveEvidence | None = None,
    provenance_capture: dict[str, Any] | None = None,
    family_snapshot_refresher: "FamilySnapshotRefresher | None" = None,
) -> EventSubmissionReceipt:
    """Produce a typed no-submit EDLI proof without running the cycle runner.

    Task #107 (portfolio/multi Kelly): ``portfolio_state_provider`` (mirrors
    ``bankroll_usd_provider``) supplies the current PortfolioState snapshot so
    Kelly sizes against the bankroll NET of correlation-weighted committed
    capital. ``portfolio_reservation`` is the per-cycle in-flight ledger
    (``PortfolioReservationLedger``, iterable as ``(city, usd)``); the builder
    reads it as ``extra_reserved`` for INV-K7 and PROVISIONALLY reserves this
    event's stake (``reserve``) so the next same-cycle event nets it. FIX B
    (2026-06-05): the reactor commits/rolls back that provisional reserve in its
    post-submit phase, so a candidate rejected downstream of Kelly never inflates
    later candidates. A plain ``list`` is still accepted (legacy append-only
    behavior). When either provider/ledger is None the sizing reduces EXACTLY to
    pre-#107 single-Kelly (no regression for unwired callers/tests)."""

    decision_time = decision_time.astimezone(UTC)
    payload = _payload(event)
    allow_same_family_monitor_owned = _event_allows_same_family_monitor_owned(
        event.event_type
    )
    if forecast_conn is None:
        return EventSubmissionReceipt(False, event.event_id, event.causal_snapshot_id, reason="FORECAST_AUTHORITY_CONNECTION_MISSING")
    if topology_conn is None:
        return EventSubmissionReceipt(False, event.event_id, event.causal_snapshot_id, reason="TOPOLOGY_AUTHORITY_CONNECTION_MISSING")
    if calibration_conn is None:
        return EventSubmissionReceipt(False, event.event_id, event.causal_snapshot_id, reason="CALIBRATION_AUTHORITY_CONNECTION_MISSING")
    source_conn = forecast_conn
    topology_authority_conn = topology_conn
    family_topology_rows = _event_family_market_topology_rows(topology_authority_conn, payload)
    if not family_topology_rows:
        return EventSubmissionReceipt(False, event.event_id, event.causal_snapshot_id, reason="EVENT_BOUND_MARKET_TOPOLOGY_MISSING")
    family_condition_ids = tuple(str(row.get("condition_id") or "") for row in family_topology_rows)
    family_rows = _latest_snapshot_rows_for_event_family(
        trade_conn,
        event,
        condition_ids=family_condition_ids,
        fresh_at=decision_time,
        require_fresh=False,  # FDR proves family identity/completeness; price-freshness is enforced at submission
    )
    if not family_rows:
        return EventSubmissionReceipt(False, event.event_id, event.causal_snapshot_id, reason="EVENT_BOUND_EXECUTABLE_SNAPSHOT_MISSING")
    snapshot_token_maps = _snapshot_token_maps_by_condition(family_rows)
    # Full-family topology: the family domain is ALWAYS the complete market_events
    # partition (MECE, all bins). Bins WITH a snapshot are tradeable; bins WITHOUT a
    # snapshot are non-tradeable (executable_mask=False) but still carry their bin so
    # q/FDR are computed over the full MECE family. Removing any bin would renormalize
    # q over the subset (~1.2× inflation at 3/11 missing) and shrink fdr_hypothesis_count
    # from 22 to 16 — both unsafe. The selected-bin gate below handles the only fatal
    # case: the event's own target bin has no snapshot.
    #
    # For non-tradeable bins (no snapshot in executable_market_snapshots) we use the
    # market_events.token_id (YES token only) as identity; no_token_id is None. The
    # executable_mask in _generate_candidate_proofs already falls back to
    # executable_mask=False when native_costs has no price for a condition (line ~3877).
    try:
        topology = tuple(
            _topology_candidate_from_market_event(
                row,
                snapshot_token_maps.get(str(row.get("condition_id") or "")),
                payload,
            )
            for row in family_topology_rows
        )
    except ValueError as exc:
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=f"EVENT_BOUND_MARKET_TOPOLOGY_INVALID:{exc}",
        )
    row = _selected_snapshot_row_for_event(family_rows, payload)
    # DecisionProvenanceEnvelope (operator law 2026-06-11): record the EXACT executable
    # snapshot row this decision binds to (book + market_end_at + captured_at). The wrapper
    # assembles the envelope from this capture for EVERY receipt — including every rejection
    # raised after this point. Observability only; never read back into a gate.
    if provenance_capture is not None and row is not None:
        provenance_capture["snapshot_row"] = row
    if row is None:
        return EventSubmissionReceipt(False, event.event_id, event.causal_snapshot_id, reason="EVENT_BOUND_SELECTED_SNAPSHOT_MISSING")
    selected_stale_reason = _snapshot_price_stale_reason(row, decision_time=decision_time)
    # DECISION-TRIGGERED TARGETED REFRESH (zero-order wall fix 2026-06-11).
    # The warm job's per-family cadence (~5.4min) is far slower than this 30s price-
    # freshness window, so the elected row is price-stale ~91% of wall-clock time and
    # every transient requeue lands stale again → MONEY_PATH_TRANSIENT_EXHAUSTED. When
    # the elected row is stale AND a sanctioned family refresher is wired, capture FRESH
    # books for THIS family NOW (one family ≈ 11 CLOB books, 1-2s) through the warm-job
    # capture path, then re-elect the latest row. This is a BUG FIX (fetch fresh data
    # instead of failing on stale data), NOT a gate weakening: the freshness contract is
    # UNCHANGED — if the refresh fails or the re-elected row is STILL stale, the existing
    # EXECUTABLE_SNAPSHOT_STALE fail-closed path below stands.
    #
    # LOCK LAW (#95 / INV-37): the refresher does its OWN [NET] /book fetch + short-lived
    # zeus_trades write on its OWN connection. We drop this core's trade-DB read snapshot
    # (commit/rollback) BEFORE invoking it so (a) the refresher's NET fetch is never
    # wrapped by an open trade-DB txn and (b) the subsequent re-read SEES the refresher's
    # committed rows (a held read snapshot would not). Fail-soft: any refresher exception
    # logs and falls through to the unchanged stale rejection.
    #
    # SCOPE (selected-row-vs-family): the stale datum is the elected row's executable
    # price, so the synchronous decision-time refresh scopes its network work to that
    # condition's YES/NO sides. Full-family identity/proof still comes from
    # family_condition_ids and is re-read after refresh; sibling catch-up belongs to
    # the warm/confirmation producer lanes so one stale selected row cannot make the
    # live reactor wait on every sibling's CLOB request.
    if selected_stale_reason is not None and family_snapshot_refresher is not None:
        refreshed = False
        try:
            selected_condition_id = str(row.get("condition_id") or "")
            refresh_condition_ids = (
                (selected_condition_id,) if selected_condition_id else family_condition_ids
            )
            # Drop the read snapshot so the NET fetch holds no trade-DB txn and the
            # re-read observes the refresher's committed rows (WAL visibility).
            try:
                trade_conn.commit()
            except Exception:  # noqa: BLE001 — commit here is only a lock-release boundary
                pass
            refreshed = bool(
                family_snapshot_refresher(
                    city=str(payload.get("city") or ""),
                    target_date=str(payload.get("target_date") or ""),
                    metric=str(payload.get("metric") or payload.get("temperature_metric") or ""),
                    condition_ids=refresh_condition_ids,
                    selected_token_id=str(payload.get("token_id") or "") or None,
                )
            )
        except Exception as exc:  # noqa: BLE001 — refresh is fail-soft; stale rejection stands
            import logging as _logging

            _logging.getLogger(__name__).warning(
                "decision-triggered family snapshot refresh failed (non-blocking, "
                "falling through to stale rejection): %s",
                exc,
            )
            refreshed = False
        if refreshed:
            # Re-elect the latest row and REBUILD every downstream consumer of the
            # pre-refresh rows (snapshot_token_maps + topology feed the decision engine;
            # family_rows feeds _generate_candidate_proofs). Verify consistency before
            # re-running the staleness gate.
            # POST-REFRESH RE-ELECT — fresh_at=None (NOT decision_time). The targeted
            # refresher above just did a live NET CLOB fetch and inserted rows with
            # captured_at ≈ now() > decision_time. Passing fresh_at=decision_time would
            # apply the `captured_at <= decision_time` ceiling (_latest_snapshot_rows_
            # for_event_family L12921) and EXCLUDE the very rows we just fetched, re-electing
            # the stale pre-refresh row → _snapshot_price_stale_reason fires again → permanent
            # STALE requeue loop (dead-decision-loop root cause, 2026-06-14: 0 receipts since
            # 06-12 while the refresher kept landing fresher books the re-elect could not see).
            # The captured_at ceiling guards NO-LOOK-AHEAD for replay/identity callers; here the
            # refresh deliberately advances the book past decision_time, so the latest row IS the
            # honest one. No-look-ahead is still enforced: the stale recheck below grades the
            # re-elected row's freshness_deadline against the unchanged decision_time.
            refreshed_family_rows = _latest_snapshot_rows_for_event_family(
                trade_conn,
                event,
                condition_ids=family_condition_ids,
                fresh_at=None,
                require_fresh=False,
            )
            if refreshed_family_rows:
                family_rows = refreshed_family_rows
                snapshot_token_maps = _snapshot_token_maps_by_condition(family_rows)
                try:
                    topology = tuple(
                        _topology_candidate_from_market_event(
                            topology_row,
                            snapshot_token_maps.get(str(topology_row.get("condition_id") or "")),
                            payload,
                        )
                        for topology_row in family_topology_rows
                    )
                except ValueError as exc:
                    return EventSubmissionReceipt(
                        False,
                        event.event_id,
                        event.causal_snapshot_id,
                        reason=f"EVENT_BOUND_MARKET_TOPOLOGY_INVALID:{exc}",
                    )
                refreshed_row = _selected_snapshot_row_for_event(family_rows, payload)
                if refreshed_row is not None:
                    row = refreshed_row
                    if provenance_capture is not None:
                        provenance_capture["snapshot_row"] = row
                    selected_stale_reason = _snapshot_price_stale_reason(row, decision_time=decision_time)
    if selected_stale_reason is not None:
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=selected_stale_reason,
        )
    # DELETED 2026-06-12 (operator no-caps law; gate inventory D1): the 24h
    # market-age ban for buy_no had no truth basis — an aged market with
    # positive conservative EV is still +EV. Fired 0x in 7 live days. Sizing
    # by opening-tick age belongs to Kelly's phase-aware multiplier; EV
    # admission belongs to TRADE_SCORE / capital-efficiency.
    decision = EventBoundDecisionEngine().evaluate(
        EventBoundDecisionRequest(
            event=event,
            market_topology=topology,
            decision_time=decision_time,
            market_topology_source="executable_market_snapshots",
        )
    )
    if decision.status != "CANDIDATE_FAMILY_READY" or decision.candidate_family is None:
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=decision.rejection_reason or "EVENT_BOUND_CANDIDATE_BINDING_FAILED",
        )
    family = decision.candidate_family
    # Forecast-lane market-phase admission gate (#98): reject families whose
    # target local day has begun or whose market has closed — forecast lane is
    # blind to the already-realizing/observed extremum (wrong-side risk, Paris
    # 2026-06-01). Scoped to the forecast decision lane (FSR + EDLI_REDECISION_PENDING,
    # which re-decides a forecast family); the day0 observation-aware scope owns same-day.
    # Placed before scoring so closed families never reach q/FDR/Kelly. A redecision must
    # obey the SAME phase gate (a redecision into an already-realizing day is the exact
    # wrong-side risk the gate exists to stop).
    if event.event_type in _FORECAST_DECISION_EVENT_TYPES:
        _phase_evidence = _edli_forecast_lane_phase_evidence(
            city=family.city,
            target_date=family.target_date,
            decision_time=decision_time,
            selected_market_row=row,
        )
        if not _forecast_lane_phase_admits(_phase_evidence):
            return EventSubmissionReceipt(
                False,
                event.event_id,
                event.causal_snapshot_id,
                reason=(
                    "EVENT_BOUND_MARKET_PHASE_CLOSED:"
                    f"{(_phase_evidence.phase.value if _phase_evidence.phase else 'unknown')}:"
                    f"{_phase_evidence.phase_source}"
                ),
                city=family.city,
                target_date=family.target_date,
                metric=family.metric,
                family_id=family.family_id,
                source_status="MATCH",
                family_complete=True,
            )
    try:
        proofs = _generate_candidate_proofs(
            event=event,
            payload=payload,
            family=family,
            snapshot_rows=family_rows,
            trade_conn=trade_conn,
            forecast_conn=source_conn,
            calibration_conn=calibration_conn,
            decision_time=decision_time,
            promotion_evidence=replacement_forecast_promotion_evidence,
            capital_objective_evidence=replacement_forecast_capital_objective_evidence,
            provenance_capture=provenance_capture,
        )
    except ValueError as exc:
        missing_reason = str(exc)
        if missing_reason == "DAY0_REMAINING_DAY_MEMBERS_UNAVAILABLE":
            return EventSubmissionReceipt(
                False,
                event.event_id,
                event.causal_snapshot_id,
                reason="DAY0_REMAINING_DAY_MEMBERS_UNAVAILABLE",
                city=family.city,
                target_date=family.target_date,
                metric=family.metric,
                family_id=family.family_id,
                source_status="MATCH",
                family_complete=True,
            )
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=f"LIVE_INFERENCE_INPUTS_MISSING:{missing_reason}",
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            family_id=family.family_id,
            source_status="MATCH",
            family_complete=True,
        )
    # S4 (operator directive 2026-06-08): the pre-selection scalar-Kelly sizing
    # (_candidate_selection_kelly_size_usd_by_id) is RETIRED. Exposure-aware sizing
    # now comes from RobustCandidateScore.optimal_stake_usd inside the marginal-
    # utility ranker (the size authority, computed post-selection on the WINNING
    # leg with the family payoff matrix + existing exposure). The opportunity_book
    # per-candidate kelly_size_usd is a display field only; it is no longer fed by a
    # parallel scalar-Kelly pass (one sizing surface, no alternate path).
    #
    # === Q-KERNEL FORECAST DECISION AUTHORITY ====================================
    # Forecast-family entry decisions require the rebuilt q-kernel spine
    # (src/decision/family_decision_engine via src/engine/qkernel_spine_bridge):
    # predictive_distribution -> joint_q ->
    # joint_q_band -> family_book -> market_coherence -> negrisk_routes ->
    # payoff_vector -> filter[native side, coherence, edge_lcb>0 & delta_u>0] ->
    # argmax robust utility density. If the qkernel flag is off or unavailable for a
    # forecast event, the lane no-trades with a typed reason instead of falling back to
    # the legacy scalar selector. That legacy selector is not live forecast authority.
    _spine_no_trade_reason: str | None = None
    from src.engine.qkernel_spine_bridge import (
        decide_family_via_spine,
        qkernel_candidate_economics_by_bin_side,
        qkernel_spine_enabled,
    )

    # DAY0 is the same family optimizer with an observed-boundary input. The qkernel
    # bridge now reads DAY0_EXTREME_UPDATED payload authority into a Day0ObservationState
    # and consumes the reactor-served Day0 q/q_lcb proof surface, so it must not fall
    # back to the legacy scalar selector. Forecast/Day0 events with the qkernel flag
    # OFF emit QKERNEL_SPINE_REQUIRED.
    _spine_flag_on = qkernel_spine_enabled()
    _is_day0_event = event.event_type in _DAY0_LANE_EVENT_TYPES
    _spine_eligible_event = event.event_type in (
        _FORECAST_DECISION_EVENT_TYPES | _DAY0_LANE_EVENT_TYPES
    )
    _spine_candidate_economics_by_key: dict[tuple[str, str], dict[str, Any]] = {}
    # Fix #4 generalized: pass REAL current per-bin family exposure into the
    # ΔU SELECTION before the instrument is chosen. A flat/empty baseline can
    # pick a leg the account is already heavy in; re-sizing after selection
    # cannot repair a wrong instrument choice.
    _selection_exposure = _family_existing_exposure_for_selection_by_bin_id(
        proofs=proofs,
        portfolio_state_provider=portfolio_state_provider,
        held_position_conn=trade_conn,
        family=family,
    )
    _selection_scope_allows_same_family_monitor_owned = (
        _selection_allows_same_family_monitor_owned(
            event_allows_same_family_monitor_owned=allow_same_family_monitor_owned,
            selection_exposure_by_outcome=_selection_exposure,
        )
    )
    if _spine_eligible_event and not _spine_flag_on:
        proof = None
        _spine_no_trade_reason = "QKERNEL_SPINE_REQUIRED"
    elif _spine_flag_on and _spine_eligible_event:
        _spine_entry_proofs = _selection_scoped_proofs(
            proofs=proofs,
            locked_opportunity_conn=locked_opportunity_conn,
            held_position_conn=trade_conn,
            strategy_policy_conn=trade_conn,
            strategy_policy_event_type=event.event_type,
            decision_time=decision_time,
            allow_same_family_monitor_owned=_selection_scope_allows_same_family_monitor_owned,
            honor_admission_rejections=False,
            enforce_win_rate_floor=False,
        )
        _pre_day0_low_block_reason = payload.get("_edli_spine_pre_day0_low_block_reason")
        if _pre_day0_low_block_reason is not None:
            proof = None
            _spine_no_trade_reason = str(_pre_day0_low_block_reason)
        elif not _spine_entry_proofs:
            proof = None
            _spine_no_trade_reason = None
        else:
            _active_spine_entry_proofs = tuple(_spine_entry_proofs)
            _actionability_exclusions: list[str] = []
            _spine_result = None
            _spine_fact_decision = None
            while True:
                _spine_result = decide_family_via_spine(
                    family=family,
                    payload=payload,
                    proofs=proofs,
                    selection_proofs=_active_spine_entry_proofs,
                    decision_time=decision_time,
                    native_side_candidate_from_proof=_native_side_candidate_from_proof,
                    candidate_bin_id=_candidate_bin_id,
                    payoff_matrix_over_bins=utility_ranker.FamilyPayoffMatrix.over_bins,
                    exposure_builder=_robust_marginal_utility_exposure,
                    baseline_usd_provider=_robust_marginal_utility_baseline_usd,
                    per_bin_yes_q_lcb=_per_bin_yes_q_lcb(proofs),
                    extra_exposure_by_bin_id=(_selection_exposure or None),
                )
                proof = _spine_result.selected_proof
                _spine_no_trade_reason = _spine_result.no_trade_reason
                _spine_fact_decision = _spine_result.decision
                _spine_candidate_economics_by_key = qkernel_candidate_economics_by_bin_side(
                    _spine_result.decision
                )
                _spine_candidate_economics_by_key = (
                    _qkernel_economics_with_near_day0_consistency(
                        _spine_candidate_economics_by_key,
                        event=event,
                        family=family,
                        payload=payload,
                        decision_time=decision_time,
                    )
                )
                proof = _proof_with_near_day0_qkernel_consistency(
                    proof,
                    qkernel_economics_by_bin_side=_spine_candidate_economics_by_key,
                )
                _near_day0_qkernel_reason = (
                    _qkernel_near_day0_cert_rejection_reason(
                        getattr(proof, "qkernel_execution_economics", None)
                    )
                    if proof is not None
                    else None
                )
                if _near_day0_qkernel_reason is not None:
                    proof = None
                    _spine_fact_decision = None
                    _spine_no_trade_reason = _near_day0_qkernel_reason
                    break
                _fill_up_unactionable_reason = None
                if proof is not None and _selection_scope_allows_same_family_monitor_owned:
                    _fill_up_unactionable_reason = (
                        _qkernel_same_token_fill_up_selection_rejection_reason(
                            proof=proof,
                            held_position_conn=trade_conn,
                            locked_opportunity_conn=locked_opportunity_conn,
                        )
                    )
                if _fill_up_unactionable_reason is None:
                    break
                _excluded_candidate_id = _candidate_evaluation_id(proof)
                _actionability_exclusions.append(
                    f"{_excluded_candidate_id}:{_fill_up_unactionable_reason}"
                )
                _next_spine_entry_proofs = tuple(
                    candidate_proof
                    for candidate_proof in _active_spine_entry_proofs
                    if _candidate_evaluation_id(candidate_proof) != _excluded_candidate_id
                )
                if len(_next_spine_entry_proofs) == len(_active_spine_entry_proofs):
                    proof = None
                    _spine_fact_decision = None
                    _spine_candidate_economics_by_key = {}
                    _spine_no_trade_reason = (
                        "FILL_UP_SELECTION_NOT_ACTIONABLE:"
                        f"{_fill_up_unactionable_reason}"
                    )
                    break
                if not _next_spine_entry_proofs:
                    proof = None
                    _spine_fact_decision = None
                    _spine_candidate_economics_by_key = {}
                    _spine_no_trade_reason = (
                        "FILL_UP_SELECTION_NOT_ACTIONABLE:"
                        + ";".join(_actionability_exclusions)
                    )
                    break
                _active_spine_entry_proofs = _next_spine_entry_proofs
            _selection_fact_result = _record_qkernel_selection_family_facts(
                trade_conn,
                family=family,
                decision=_spine_fact_decision,
                event=event,
                decision_time=decision_time,
                decision_snapshot_id=event.causal_snapshot_id,
            )
            if proof is not None and _selection_fact_result.get("status") != "written":
                proof = None
                _spine_candidate_economics_by_key = {}
                _spine_no_trade_reason = (
                    "QKERNEL_SELECTION_FACT_PERSISTENCE_FAILED:"
                    f"{_selection_fact_result.get('status') or 'unknown'}"
                )
    else:
        proof = _selected_candidate_proof(
            payload,
            proofs,
            locked_opportunity_conn=locked_opportunity_conn,
            held_position_conn=trade_conn,
            strategy_policy_conn=trade_conn,
            strategy_policy_event_type=event.event_type,
            decision_time=decision_time,
            allow_same_family_monitor_owned=_selection_scope_allows_same_family_monitor_owned,
            extra_exposure_by_bin_id=(_selection_exposure or None),
        )
    opportunity_book = _opportunity_book_from_proofs(
        event_id=event.event_id,
        family_id=family.family_id,
        proofs=proofs,
        selected_proof=proof,
        locked_opportunity_conn=locked_opportunity_conn,
        held_position_conn=trade_conn,
        strategy_policy_conn=trade_conn,
        strategy_policy_event_type=event.event_type,
        decision_time=decision_time,
        allow_same_family_monitor_owned=_selection_scope_allows_same_family_monitor_owned,
        qkernel_economics_by_bin_side=_spine_candidate_economics_by_key,
        selection_exposure_by_outcome=_selection_exposure,
        enforce_win_rate_floor=not (_spine_flag_on and _spine_eligible_event),
    )
    if proof is None:
        # MAJOR2 fix (#135): when ALL candidates fail the mainstream-agreement gate,
        # persist the best-scoring family's mainstream verdict on the MISSING receipt so
        # demotions are auditable (not an invisible hole). Pull from payload verdicts
        # dict; attach the verdict for the highest trade_score proof that was evaluated.
        _missing_mav_fields: dict[str, object] = {}
        _all_verdicts: dict[tuple[str, str], dict] = payload.get("_mainstream_agreement_verdicts", {})  # type: ignore[assignment]
        if _all_verdicts:
            best_proof = max(proofs, key=lambda p: p.trade_score, default=None)
            if best_proof is not None:
                _best_v = _all_verdicts.get(
                    (str(best_proof.candidate.condition_id or ""), best_proof.direction)
                )
                if _best_v is not None:
                    _missing_mav_fields = {
                        "mainstream_agreement_pass": _best_v.get("mainstream_agreement_pass"),
                        "mainstream_agreement_fail_reason": _best_v.get("mainstream_agreement_fail_reason"),
                        "mainstream_point": _optional_float(_best_v.get("mainstream_point")),
                        "mainstream_delta": _optional_float(_best_v.get("forecast_delta")),
                        "mainstream_bin_label": _best_v.get("mainstream_bin_label"),
                        "mainstream_source": _best_v.get("mainstream_source"),
                        "mainstream_fetched_at_utc": _best_v.get("mainstream_fetched_at_utc"),
                    }
        # REJECTION-LABEL TRUTH (operator law 2026-06-11). The selector returned no
        # live primary. Two structurally distinct causes share this site:
        #   (1) proofs were generated but EVERY priced candidate was gate-rejected
        #       (the efficient-market normal state) AND no bookless proof existed to
        #       surface as a fallback -> the honest label is ALL_CANDIDATES_REJECTED
        #       carrying the per-class counts + the closest-to-tradeable leg.
        #   (2) NO candidate proofs were produced at all (zero-proof family) -> the
        #       bare SELECTED_CANDIDATE_MISSING, now annotated with the diagnosed
        #       structural precondition (Ankara repro: family_candidates / proofs /
        #       priced counts) so a queried receipt says WHICH precondition emptied it.
        _all_rejected_reason = _family_all_candidates_rejected_reason(opportunity_book)
        if _spine_no_trade_reason is not None:
            # Q-KERNEL REBUILD WAVE 5B: the spine computed the decision and it was a
            # no-trade (or a typed reconstruction-gap / wiring fault). Surface the
            # spine's own typed reason so the receipt names the spine gate that emptied
            # the survivor set (PREDICTIVE_DISTRIBUTION_NOT_LIVE_ELIGIBLE /
            # MARKET_INCOHERENT_BLOCK_LIVE / NO_DIRECTION_LAW_CANDIDATE /
            # NO_POSITIVE_EDGE_CANDIDATE / SPINE_INPUTS_UNAVAILABLE / ...).
            _selected_missing_reason = f"QKERNEL_SPINE_NO_TRADE:{_spine_no_trade_reason}"
        elif _all_rejected_reason is not None:
            _selected_missing_reason = _all_rejected_reason
        else:
            _priced_proofs = sum(1 for p in proofs if p.execution_price is not None)
            _selected_missing_reason = (
                "EVENT_BOUND_SELECTED_CANDIDATE_MISSING:"
                f"family_candidates={len(getattr(family, 'candidates', ()) or ())}"
                f":proofs={len(proofs)}:priced={_priced_proofs}"
            )
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=_selected_missing_reason,
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            family_id=family.family_id,
            source_status="MATCH",
            family_complete=True,
            opportunity_book=(
                _json_finite(opportunity_book.to_receipt_dict())
                if opportunity_book is not None
                else None
            ),
            **_missing_mav_fields,  # type: ignore[arg-type]
        )
    candidate = proof.candidate
    selected_token_id = proof.token_id
    direction = proof.direction
    execution_price = proof.execution_price
    receipt_q_live, receipt_q_lcb = _event_bound_execution_probability_pair(proof)
    if execution_price is None:
        # REJECTION-LABEL TRUTH (operator law 2026-06-11). A non-executable proof was
        # surfaced as the best-belief fallback. EXECUTABLE_NATIVE_ASK_MISSING is the
        # HONEST label ONLY when the family genuinely lacked books on every bin. When
        # the family ALSO had priced candidates that were all gate-rejected (the
        # measured Beijing 2026-06-12 lie: 7/8 bins had live two-sided NO books, yet
        # the receipt claimed NATIVE_ASK_MISSING), the truth is ALL_CANDIDATES_REJECTED
        # with the per-class counts — the fallback bin's q_lcb on an askless bin is not
        # a decision. _family_all_candidates_rejected_reason returns None iff NO priced
        # candidate exists, which is exactly the genuine-no-books case.
        _all_rejected_reason = _family_all_candidates_rejected_reason(opportunity_book)
        _native_ask_reason = (
            _all_rejected_reason
            if _all_rejected_reason is not None
            else f"EXECUTABLE_NATIVE_ASK_MISSING:{proof.missing_reason or 'native executable quote unavailable'}"
        )
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=_native_ask_reason,
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            condition_id=str(candidate.condition_id or ""),
            token_id=selected_token_id,
            executable_snapshot_id=proof.executable_snapshot_id,
            family_id=family.family_id,
            bin_label=candidate.bin.label,
            direction=direction,
            q_live=receipt_q_live,
            q_lcb_5pct=receipt_q_lcb,
            c_fee_adjusted=None,
            c_cost_95pct=proof.c_cost_95pct,
            p_fill_lcb=proof.p_fill_lcb,
            trade_score=proof.trade_score,
            native_quote_available=False,
            source_status="MATCH",
            family_complete=True,
            opportunity_book=(
                _json_finite(opportunity_book.to_receipt_dict())
                if opportunity_book is not None
                else None
            ),
        )
    untradeable_limit_reason = _candidate_limit_price_untradeable_reason(proof)
    if untradeable_limit_reason is not None:
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=untradeable_limit_reason,
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            condition_id=str(candidate.condition_id or ""),
            token_id=selected_token_id,
            executable_snapshot_id=proof.executable_snapshot_id,
            family_id=family.family_id,
            bin_label=candidate.bin.label,
            direction=direction,
            q_live=receipt_q_live,
            q_lcb_5pct=receipt_q_lcb,
            c_fee_adjusted=execution_price.value,
            c_cost_95pct=proof.c_cost_95pct,
            p_fill_lcb=proof.p_fill_lcb,
            trade_score=proof.trade_score,
            native_quote_available=True,
            source_status="MATCH",
            family_complete=True,
        )
    replacement_forecast_receipt_tag: dict[str, Any] | None = None
    if replacement_forecast_hook is not None and not _replacement_primary_authority_already_applied(proof):
        replacement_hook_result = replacement_forecast_hook(proof, event, decision_time)
        if replacement_hook_result is not None:
            if replacement_hook_result.status == "BLOCKED":
                replacement_forecast_receipt_tag = replacement_hook_result.as_receipt_tag()
                return EventSubmissionReceipt(
                    False,
                    event.event_id,
                    event.causal_snapshot_id,
                    reason="REPLACEMENT_FORECAST_HOOK_BLOCKED:" + ",".join(replacement_hook_result.reason_codes),
                    city=family.city,
                    target_date=family.target_date,
                    metric=family.metric,
                    condition_id=str(candidate.condition_id or ""),
                    token_id=selected_token_id,
                    executable_snapshot_id=proof.executable_snapshot_id,
                    family_id=family.family_id,
                    bin_label=candidate.bin.label,
                    direction=direction,
                    q_live=proof.q_posterior,
                    q_lcb_5pct=proof.q_lcb_5pct,
                    c_fee_adjusted=execution_price.value,
                    c_cost_95pct=proof.c_cost_95pct,
                    p_fill_lcb=proof.p_fill_lcb,
                    trade_score=proof.trade_score,
                    native_quote_available=True,
                    source_status="MATCH",
                    family_complete=True,
                    replacement_forecast=replacement_forecast_receipt_tag,
                )
            if replacement_hook_result.status == REPLACEMENT_EXECUTION_LIVE_STATUS:
                replacement_forecast_receipt_tag = replacement_hook_result.as_receipt_tag()
                effective_proof = _replacement_live_authority_proof_for_direction(
                    proofs=proofs,
                    baseline_proof=proof,
                    effective_direction=replacement_hook_result.effective_direction,
                )
                if effective_proof is None:
                    return EventSubmissionReceipt(
                        False,
                        event.event_id,
                        event.causal_snapshot_id,
                        reason="REPLACEMENT_FORECAST_LIVE_DIRECTION_PROOF_MISSING",
                        city=family.city,
                        target_date=family.target_date,
                        metric=family.metric,
                        condition_id=str(candidate.condition_id or ""),
                        token_id=selected_token_id,
                        executable_snapshot_id=proof.executable_snapshot_id,
                        family_id=family.family_id,
                        bin_label=candidate.bin.label,
                        direction=direction,
                        q_live=proof.q_posterior,
                        q_lcb_5pct=proof.q_lcb_5pct,
                        c_fee_adjusted=execution_price.value,
                        c_cost_95pct=proof.c_cost_95pct,
                        p_fill_lcb=proof.p_fill_lcb,
                        trade_score=proof.trade_score,
                        native_quote_available=True,
                        source_status="MATCH",
                        family_complete=True,
                        replacement_forecast=replacement_forecast_receipt_tag,
                    )
                proof = effective_proof
                candidate = proof.candidate
                selected_token_id = proof.token_id
                direction = proof.direction
                execution_price = proof.execution_price
                row = proof.row
                opportunity_book = _opportunity_book_from_proofs(
                    event_id=event.event_id,
                    family_id=family.family_id,
                    proofs=proofs,
                    selected_proof=proof,
                    locked_opportunity_conn=locked_opportunity_conn,
                    held_position_conn=trade_conn,
                    strategy_policy_conn=trade_conn,
                    strategy_policy_event_type=event.event_type,
                    decision_time=decision_time,
                    allow_same_family_monitor_owned=_selection_scope_allows_same_family_monitor_owned,
                    qkernel_economics_by_bin_side=_spine_candidate_economics_by_key,
                    selection_exposure_by_outcome=_selection_exposure,
                    enforce_win_rate_floor=not (_spine_flag_on and _spine_eligible_event),
                )
                if execution_price is None or row is None:
                    return EventSubmissionReceipt(
                        False,
                        event.event_id,
                        event.causal_snapshot_id,
                        reason="REPLACEMENT_FORECAST_LIVE_EXECUTABLE_PROOF_MISSING",
                        city=family.city,
                        target_date=family.target_date,
                        metric=family.metric,
                        condition_id=str(candidate.condition_id or ""),
                        token_id=selected_token_id,
                        executable_snapshot_id=proof.executable_snapshot_id,
                        family_id=family.family_id,
                        bin_label=candidate.bin.label,
                        direction=direction,
                        q_live=proof.q_posterior,
                        q_lcb_5pct=proof.q_lcb_5pct,
                        c_fee_adjusted=None,
                        c_cost_95pct=proof.c_cost_95pct,
                        p_fill_lcb=proof.p_fill_lcb,
                        trade_score=proof.trade_score,
                        native_quote_available=False,
                        source_status="MATCH",
                        family_complete=True,
                        replacement_forecast=replacement_forecast_receipt_tag,
                    )
                effective_q_posterior = replacement_hook_result.effective_q_posterior
                effective_q_lcb = replacement_hook_result.effective_q_lcb
                effective_trade_score = _robust_trade_score_from_generated_inputs(
                    q_posterior=effective_q_posterior,
                    q_lcb_5pct=effective_q_lcb,
                    execution_price=execution_price,
                    c_cost_95pct=proof.c_cost_95pct,
                    p_fill_lcb=proof.p_fill_lcb,
                )
                proof = dataclass_replace(
                    proof,
                    q_posterior=effective_q_posterior,
                    q_lcb_5pct=effective_q_lcb,
                    trade_score=effective_trade_score,
                )
            else:
                return EventSubmissionReceipt(
                    False,
                    event.event_id,
                    event.causal_snapshot_id,
                    reason=f"REPLACEMENT_FORECAST_HOOK_UNSUPPORTED:{replacement_hook_result.status}",
                    city=family.city,
                    target_date=family.target_date,
                    metric=family.metric,
                    condition_id=str(candidate.condition_id or ""),
                    token_id=selected_token_id,
                    executable_snapshot_id=proof.executable_snapshot_id,
                    family_id=family.family_id,
                    bin_label=candidate.bin.label,
                    direction=direction,
                    q_live=proof.q_posterior,
                    q_lcb_5pct=proof.q_lcb_5pct,
                    c_fee_adjusted=execution_price.value,
                    c_cost_95pct=proof.c_cost_95pct,
                    p_fill_lcb=proof.p_fill_lcb,
                    trade_score=proof.trade_score,
                    native_quote_available=True,
                    source_status="MATCH",
                    family_complete=True,
                    replacement_forecast=replacement_forecast_receipt_tag,
                )
    if provenance_capture is not None and proof.row is not None:
        provenance_capture["snapshot_row"] = proof.row
    # Replacement hooks can swap the selected proof after the early unpriced branch.
    # Recompute once at the executable boundary so every later receipt/sizing path
    # consumes the final proof's single execution probability pair.
    receipt_q_live, receipt_q_lcb = _event_bound_execution_probability_pair(proof)
    trade_score = proof.trade_score
    if trade_score <= 0.0:
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason="TRADE_SCORE_NON_POSITIVE",
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            condition_id=str(candidate.condition_id or ""),
            token_id=selected_token_id,
            executable_snapshot_id=proof.executable_snapshot_id,
            family_id=family.family_id,
            bin_label=candidate.bin.label,
            direction=direction,
            q_live=receipt_q_live,
            q_lcb_5pct=receipt_q_lcb,
            c_fee_adjusted=execution_price.value,
            c_cost_95pct=proof.c_cost_95pct,
            p_fill_lcb=proof.p_fill_lcb,
            trade_score=trade_score,
            native_quote_available=True,
            source_status="MATCH",
            family_complete=True,
        )
    hypothesis_id = f"{family.family_id}:{selected_token_id}"
    # C2 (task #60): compute the posterior lfsr + EB-shrunk selected edge over the
    # family's executable bins as attribution only. The BH/FDR pass is the
    # unconditional live selection gate; ``authority_on=False`` pins the receipt
    # stamp to selection_authority="BH_FDR" while lfsr / edge_shrunk remain
    # available for later winner's-curse analysis.
    _shrink = _compute_selection_shrinkage(
        proofs=proofs,
        selected_token_id=selected_token_id,
        selected_q_posterior=receipt_q_live,
        selected_price=execution_price.value,
        authority_on=False,
    )

    def _with_shrink(receipt: EventSubmissionReceipt) -> EventSubmissionReceipt:
        """Stamp the C2 selection-shrinkage attribution columns onto a post-gate receipt.

        Every receipt produced at or after the selection gate carries the
        quantities so settlement grading can run the winner's-curse slope
        telemetry. Pure dataclass_replace; never alters the decision.
        """
        return dataclass_replace(
            receipt,
            lfsr=_shrink.lfsr,
            edge_shrunk=_shrink.edge_shrunk,
            edge_shrunk_posterior_sd=_shrink.edge_shrunk_posterior_sd,
            selection_authority=_shrink.selection_authority,
        )

    all_hypothesis_ids = tuple(
        f"{family.family_id}:{token}" for token in family.yes_token_ids + family.no_token_ids
    )
    try:
        fdr_p_values, fdr_prefilter = _fdr_maps_with_selected_authority(
            family_id=family.family_id,
            proofs=proofs,
            selected_proof=proof,
            selected_token_id=selected_token_id,
        )
        fdr = _day0_selected_route_fdr_proof(
            event_type=event.event_type,
            family_id=family.family_id,
            all_hypothesis_ids=all_hypothesis_ids,
            selected_hypothesis_id=hypothesis_id,
            selected_proof=proof,
        )
        if fdr is None:
            fdr = _qkernel_selected_route_fdr_proof(
                family_id=family.family_id,
                all_hypothesis_ids=all_hypothesis_ids,
                selected_hypothesis_id=hypothesis_id,
                selected_proof=proof,
            )
        if fdr is None:
            fdr = evaluate_fdr_full_family(
                family_id=family.family_id,
                all_hypothesis_ids=all_hypothesis_ids,
                selected_hypothesis_ids=(hypothesis_id,),
                hypothesis_p_values=fdr_p_values,
                passed_prefilter=fdr_prefilter,
            )
    except (TypeError, ValueError) as exc:
        return _with_shrink(EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=f"FDR_FULL_FAMILY_PROOF_MISSING:{exc}",
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            condition_id=str(candidate.condition_id or ""),
            token_id=selected_token_id,
            executable_snapshot_id=proof.executable_snapshot_id,
            family_id=family.family_id,
            bin_label=candidate.bin.label,
            direction=direction,
            q_live=receipt_q_live,
            q_lcb_5pct=receipt_q_lcb,
            c_fee_adjusted=execution_price.value,
            c_cost_95pct=proof.c_cost_95pct,
            p_fill_lcb=proof.p_fill_lcb,
            trade_score=trade_score,
            native_quote_available=True,
            source_status="MATCH",
            family_complete=False,
        ))
    # GATE DECISION: the BH/FDR pass is the unconditional live selection authority
    # (the EB-shrinkage decision-replacement flag was REMOVED 2026-06-13).
    # Selection-shrinkage telemetry is stamped on the receipt regardless.
    _gate_passed = fdr.passed
    _gate_reject_reason = _fdr_rejection_reason(
        event_type=event.event_type,
        fdr=fdr,
        selected_proof=proof,
    )
    if not _gate_passed:
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=_gate_reject_reason,
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            condition_id=str(candidate.condition_id or ""),
            token_id=selected_token_id,
            executable_snapshot_id=proof.executable_snapshot_id,
            family_id=family.family_id,
            bin_label=candidate.bin.label,
            direction=direction,
            q_live=receipt_q_live,
            q_lcb_5pct=receipt_q_lcb,
            c_fee_adjusted=execution_price.value,
            c_cost_95pct=proof.c_cost_95pct,
            p_fill_lcb=proof.p_fill_lcb,
            trade_score=trade_score,
            native_quote_available=True,
            source_status="MATCH",
            family_complete=True,
            fdr_pass=False,
            fdr_family_id=fdr.fdr_family_id,
            fdr_hypothesis_count=fdr.attempted_hypotheses,
            q_source=proof.q_source,
            qkernel_execution_economics=_json_finite(proof.qkernel_execution_economics),
            selection_authority_applied=proof.selection_authority_applied,
            q_lcb_calibration_source=proof.q_lcb_calibration_source,
            same_bin_yes_posterior=proof.same_bin_yes_posterior,
            settlement_coverage_status=proof.settlement_coverage_status,
            posterior_id=proof.posterior_id,
            probability_authority=proof.probability_authority,
            opportunity_book=(
                _json_finite(opportunity_book.to_receipt_dict())
                if opportunity_book is not None
                else None
            ),
            execution_mode_intent=proof.execution_mode_intent,
            maker_limit_price=proof.maker_limit_price,
            rest_then_cross_policy=proof.rest_then_cross_policy,
            rest_escalation_deadline_minutes=proof.rest_escalation_deadline_minutes,
            lfsr=_shrink.lfsr,
            edge_shrunk=_shrink.edge_shrunk,
            edge_shrunk_posterior_sd=_shrink.edge_shrunk_posterior_sd,
            selection_authority=_shrink.selection_authority,
        )
    kelly_cost_basis_id = f"edli_cost:{event.event_id}:{selected_token_id}"
    try:
        bankroll_usd = (
            _bankroll_usd_from_provider(bankroll_usd_provider)
            if bankroll_usd_provider is not None
            else _runtime_bankroll_usd(cached_only=True)
        )
        # FREE-CASH ONE-TIME BOUND (operator single-Kelly directive 2026-06-10, spec
        # point 2): ``bankroll_usd`` above is now TOTAL portfolio equity (the sizing
        # basis, applied once); free available cash bounds the chosen stake ONCE in the
        # kernel (min, never a multiplicative haircut).
        #
        # FINDING-B FIX (external review 2026-06-12): the prior code set
        # ``free_cash_usd=None`` WHENEVER a bankroll provider was injected, so the cash
        # bound VANISHED under an injected bankroll — a strong-edge stake could exceed
        # available free cash with no clamp. The fix threads a COMPANION
        # ``free_cash_usd_provider`` alongside the bankroll provider:
        #   - bankroll provider + free-cash provider present: use the provider's value.
        #     A live free-cash AUTHORITY that returns None is a TYPED FAULT
        #     (BANKROLL_FREE_CASH_MISSING, transient) — never a silent no-clamp.
        #   - bankroll provider WITHOUT a free-cash provider: legacy proof-only / tool
        #     injection that wired no cash authority -> None (bound no-ops, as before).
        #   - no bankroll provider (live cached path): read the SAME wallet record.
        if bankroll_usd_provider is not None:
            if free_cash_usd_provider is not None:
                _provided_free_cash = free_cash_usd_provider()
                if _provided_free_cash is None:
                    raise ValueError(
                        "BANKROLL_FREE_CASH_MISSING:"
                        "free_cash_usd_provider_returned_none"
                    )
                free_cash_usd = float(_provided_free_cash)
            else:
                free_cash_usd = None
        else:
            free_cash_usd = _runtime_free_cash_usd(cached_only=True)
        kelly_multiplier = _runtime_kelly_multiplier()
        (
            kelly_multiplier,
            _bias_decay_applied,
            _bias_decay_native,
            _bias_decay_reason,
        ) = _maybe_bias_decay_kelly_haircut(
            kelly_multiplier,
            family=family,
            q_source=proof.q_source,
        )
        # S3 (variance-required Kelly, task #103/#111): carry the candidate's
        # posterior CI width and forecast lead into Kelly so a wider-CI edge
        # sizes STRICTLY smaller. The config/bias-decay multiplier above is the
        # BASE; SizingContext adds the CI/lead variance haircut on top. lead_days
        # derivation can raise ValueError (CALIBRATION_AUTHORITY_MISSING) — that
        # routes through the except envelope below to KELLY_PROOF_MISSING
        # fail-closed, never silent.
        _lead_days = _snapshot_lead_days(snapshot=row, family=family, payload=payload)
        # Task #107 (portfolio/multi Kelly): when a PortfolioState provider is
        # wired, carry correlation-weighted and raw committed capital into the
        # Kelly context as SOFT marginal pressure inputs. They shrink the next
        # multiplier but do not subtract from a global budget and hard-zero a
        # positive-edge candidate. The reservation accumulator (closure-held in
        # the adapter factory) carries this cycle's already-emitted-but-unfilled
        # stakes (INV-K7). When no provider is wired (back-compat / tests), fall
        # back to the #103 3-arg context.
        if portfolio_state_provider is not None:
            from src.state.portfolio import correlated_committed_usd, total_exposure_usd

            _portfolio_state = portfolio_state_provider()
            _corr_committed_usd = correlated_committed_usd(
                _portfolio_state,
                new_city=family.city,
                extra_reserved=(
                    list(portfolio_reservation)
                    if portfolio_reservation is not None
                    else None
                ),
            )
            # Raw exposure pressure: total cash deployed across all open
            # positions (no corr weighting) + same-cycle reservation usd. This
            # is not a hard portfolio cap; evaluate_kelly turns it into a
            # continuous marginal Kelly haircut.
            _raw_committed_usd = total_exposure_usd(_portfolio_state) + sum(
                float(usd)
                for _, usd in (portfolio_reservation or [])
            )
            sizing_context = SizingContext.from_candidate_proof_with_portfolio(
                q_posterior=receipt_q_live,
                q_lcb_5pct=receipt_q_lcb,
                lead_days=_lead_days,
                bankroll_usd=bankroll_usd,
                corr_committed_usd=_corr_committed_usd,
                raw_committed_usd=_raw_committed_usd,
            )
        else:
            sizing_context = SizingContext.from_candidate_proof(
                q_posterior=receipt_q_live,
                q_lcb_5pct=receipt_q_lcb,
                lead_days=_lead_days,
            )
        kelly = evaluate_kelly(
            kelly_decision_id=f"edli_kelly:{event.event_id}:{selected_token_id}",
            p_posterior=receipt_q_live,
            execution_price=execution_price,
            bankroll_usd=bankroll_usd,
            sizing_context=sizing_context,
            kelly_multiplier=kelly_multiplier,
        )
        # ROBUST-LOWER-BOUND SIZING + CHOSEN-STAKE PRICE (S4+S5; spec §3/§5.2/§5.3/
        # §14.7/§14.10, money-path iron law).
        # ``evaluate_kelly`` is NO LONGER the size authority: it sizes on
        # ``p_posterior`` (q_point) via the scalar binary-Kelly formula. The
        # bin-selection size authority is the marginal-utility ranker's
        # ``RobustCandidateScore.optimal_stake_usd`` — the log-optimal stake on the
        # candidate's OWN robust q_lcb-based π against the family payoff matrix AND
        # the EXISTING per-outcome exposure (Hidden #10), scaled by the FRACTIONAL-
        # Kelly haircut ``evaluate_kelly`` already derived (CI-width / lead /
        # portfolio-heat — variance is NOT dropped). We keep ``evaluate_kelly`` for
        # the typed-price assert, the receipt fields, and that haircut multiplier;
        # we OVERRIDE the size with the q_lcb-grounded ΔU stake.
        #
        # S5 (operator directive 2026-06-08): we ALSO override ``execution_price``
        # with the CHOSEN-STAKE boundary — ``ExecutableCostCurve.avg_cost(optimal_
        # stake)`` on the selected leg's OWN native curve (typed, fee-deducted,
        # probability_units; passes ``assert_kelly_safe``). Scalar Kelly on the
        # cheap min-order top-ask over-bets into thin levels (Hidden #6); the cost-
        # curve optimizer in ``score_candidate`` already maximized ΔU over the
        # feasible depth-bounded stake interval, so the Kelly cost-of-entry the
        # intent + receipt carry MUST be that same curve at that same stake — the
        # depth-walked cost the order actually pays, not S1's top-of-book scalar.
        _fractional_kelly_mult = float(
            kelly.effective_multiplier
            if kelly.effective_multiplier is not None
            else kelly_multiplier
        )
        # S6 (operator directive 2026-06-08; spec §5 submit pseudocode / §7 / §14.9 /
        # §14.10). THE single fail-closed submit-recapture gate — recompute, not
        # validate, at the no-submit receipt boundary. This call RECOMPUTES the
        # selected leg's fresh ExecutableCostCurve, the chosen fractional-Kelly stake
        # + chosen-stake price on that fresh curve (the S5 kernel, internally), the
        # robust q_lcb, and the family rank, then routes ALL of it through ONE
        # RedecisionEngine.evaluate_submit_recapture. It REPLACES the former scattered
        # inline re-gate (the ``not kelly.passed`` size check that implicitly decided
        # submit eligibility): the three abort branches (price-through-max, edge<=0 /
        # forecast-stale, family-rank reversed) are now first-class lifecycle states.
        # The intent is built ONLY when ``_recapture.may_submit`` is True — no parallel
        # branch, no flag, no alternate path.
        _recapture_exposure = _family_existing_exposure_by_bin_id(
            proofs=proofs,
            selected_proof=proof,
            portfolio_state_provider=portfolio_state_provider,
            portfolio_reservation=portfolio_reservation,
            family=family,
        )
        # Stake-floor provenance collector (2026-06-09 min-order fix). The recapture
        # kernel writes stake_floor="VENUE_MIN_ORDER" here when it bumps a positive-edge
        # candidate's haircut stake up to the venue min order, so the submit receipt
        # records WHY the stake equals the venue floor (the fractional-Kelly risk intent
        # was preserved — min order is << the bankroll cap). Empty on the normal path.
        _stake_floor_provenance: dict[str, object] = {}
        # Wave-1 2026-06-12: the DAY0 family NOTIONAL CAP ($25) is DELETED (operator
        # no-caps law: "不允许设置任何的cap"). Day0 sizing is now governed SOLELY by the
        # same q_lcb + fractional-Kelly + free-cash + concentration machinery as every
        # other lane — no day0-specific notional clamp / headroom bound is computed or
        # threaded into the sizing kernel.
        # Maker/taker fill semantics for the S6 PRICE_MOVED ceiling (2026-06-10).
        # A resting maker order rests at the admitted limit and never chases the
        # recaptured ask, so the price-moved ceiling must NOT abort it (it was
        # producing the live sub-3¢ false-abort churn). A taker order crosses and
        # pays the recaptured cost, so the bounded tolerance ceiling still governs.
        # P0-B (2026-06-10): use the PROOF's execution_mode_intent (the same single
        # authority as the final-command builder), NOT the governor's event-payload
        # inference.  Conservative fail direction: unknown mode → TAKER semantics
        # (full fee + ceiling).  _order_will_rest_at_admitted_price is kept for
        # backward-compat but is no longer called on the money path.
        _order_rests_at_admitted_price = _proof_order_rests_at_admitted_price(proof)
        _recapture, _robust_stake_usd, _chosen_stake_price = (
            _evaluate_submit_recapture_for_selected(
                family_key=str(family.family_id or ""),
                selected_proof=proof,
                all_proofs=proofs,
                extra_exposure_by_bin_id=_recapture_exposure,
                bankroll_usd=float(bankroll_usd),
                kelly_multiplier=_fractional_kelly_mult,
                order_rests_at_admitted_price=_order_rests_at_admitted_price,
                # On this synchronous path the forecast snapshot was validated by the
                # decision engine and (if present) the replacement-forecast hook, both
                # of which already returned a no-submit receipt on any flip/block
                # above — so the proof carried here is forecast-current at recapture.
                forecast_still_current=True,
                # S6 scope-set invariant: the recapture family re-rank must scope the
                # candidate set EXACTLY as selection did (`_selected_candidate_proof` was
                # called with this same conn at selection) — else a locked / below-min-tick
                # leg scoped OUT of selection falsely reverses the chosen leg.
                locked_opportunity_conn=locked_opportunity_conn,
                held_position_conn=trade_conn,
                allow_same_family_monitor_owned=_selection_scope_allows_same_family_monitor_owned,
                stake_floor_out=_stake_floor_provenance,
                free_cash_usd=free_cash_usd,
            )
        )
        # D1/D2 SAME-FAMILY MANAGEMENT (2026-06-30 live fix): this must run for any
        # submit-cleared family selection, not only events already labelled as
        # ``allow_same_family_monitor_owned``. A forecast event that selects a sibling
        # while a live old leg exists is no longer a true fresh entry; it is a position
        # management problem. Same-token selections become residual fill-up, and
        # sibling selections become close-before-open SHIFT_BIN. With no held family
        # exposure both helpers no-op and the fresh-entry path is unchanged.
        #
        # For a freshly-selected winning leg that is the SAME token as an existing held
        # position, the family-total ΔU stake (_robust_stake_usd) is NOT what we submit
        # — we top up the EXISTING position by the RESIDUAL to the fresh target
        # (delta = target - current_live - same_token_pending), gated by the committed
        # decide_fill_up predicate + the family-rebalance lease.
        #
        # Placed AFTER the recapture proved may_submit and BEFORE kelly.size_usd is
        # bound: overriding _robust_stake_usd here keeps the portfolio reservation,
        # cost-basis hash, receipt kelly_size_usd, actionable cert and USD->shares
        # conversion ALL coherent off the one value (consult: the single chokepoint).
        if _recapture.may_submit:
            _family_key = str(family.family_id or "")
            _existing_shift_lease = _shift_bin_wiring.active_shift_lease_for_family(
                trade_conn,
                family_key=_family_key,
            )
            if _existing_shift_lease is not None:
                _min_order_shares = (
                    _float_or_default(row.get("min_order_size"), 1.0)
                    if isinstance(row, Mapping) else 1.0
                )
                _price_for_min = float(getattr(execution_price, "value", 0.0) or 0.0)
                _dust_floor_usd = (
                    _min_order_shares * _price_for_min
                    if _price_for_min > 0.0 else _min_order_shares
                )
                _old_leg_residual = _shift_bin_wiring.read_old_leg_residual_usd(
                    trade_conn,
                    token_id=_existing_shift_lease.held_token_id,
                )
                _old_leg_live = float(_old_leg_residual) > float(_dust_floor_usd)
                if _existing_shift_lease.status in {
                    "EXIT_SUBMITTED",
                    "EXIT_UNKNOWN",
                    "EXIT_PARTIAL",
                }:
                    if _old_leg_live:
                        _day0_shift_block = _day0_shift_old_leg_exit_block_reason(
                            event=event,
                            payload=payload,
                            proof=proof,
                        )
                        if _day0_shift_block is not None:
                            return _with_shrink(EventSubmissionReceipt(
                                False,
                                event.event_id,
                                event.causal_snapshot_id,
                                reason=f"SHIFT_BIN_NO_SUBMIT:{_day0_shift_block}",
                                city=family.city,
                                target_date=family.target_date,
                                metric=family.metric,
                                condition_id=str(candidate.condition_id or ""),
                                token_id=selected_token_id,
                                executable_snapshot_id=proof.executable_snapshot_id,
                                family_id=family.family_id,
                                bin_label=candidate.bin.label,
                                direction=direction,
                                q_live=receipt_q_live,
                                q_lcb_5pct=receipt_q_lcb,
                                c_fee_adjusted=execution_price.value,
                                c_cost_95pct=proof.c_cost_95pct,
                                p_fill_lcb=proof.p_fill_lcb,
                                trade_score=trade_score,
                                native_quote_available=True,
                                source_status="MATCH",
                                family_complete=True,
                            ))
                        return _with_shrink(EventSubmissionReceipt(
                            False,
                            event.event_id,
                            event.causal_snapshot_id,
                            reason="SHIFT_BIN_EXIT_OLD_LEG_PENDING",
                            city=family.city,
                            target_date=family.target_date,
                            metric=family.metric,
                            condition_id=str(candidate.condition_id or ""),
                            token_id=selected_token_id,
                            executable_snapshot_id=proof.executable_snapshot_id,
                            family_id=family.family_id,
                            bin_label=candidate.bin.label,
                            direction=direction,
                            q_live=receipt_q_live,
                            q_lcb_5pct=receipt_q_lcb,
                            c_fee_adjusted=execution_price.value,
                            c_cost_95pct=proof.c_cost_95pct,
                            p_fill_lcb=proof.p_fill_lcb,
                            trade_score=trade_score,
                            native_quote_available=True,
                            source_status="MATCH",
                            family_complete=True,
                            shift_bin_lease_payload={
                                "phase": "EXIT_OLD_LEG",
                                "intent_id": _existing_shift_lease.intent_id,
                                "old_position_id": _existing_shift_lease.held_position_id,
                                "old_token_id": _existing_shift_lease.held_token_id,
                                "city": family.city,
                                "target_date": family.target_date,
                                "metric": family.metric,
                            },
                        ))
                    if str(selected_token_id or "") == _existing_shift_lease.selected_token_id:
                        _shift_bin_wiring.record_entry_submitted(
                            trade_conn,
                            _existing_shift_lease.intent_id,
                            now_iso=decision_time.isoformat(),
                            reason="SHIFT_BIN_OLD_LEG_CLOSED_ENTER_NEW_BIN",
                        )
                        if provenance_capture is not None:
                            provenance_capture["shift_bin_lease"] = {
                                "phase": "ENTER_NEW_BIN",
                                "intent_id": _existing_shift_lease.intent_id,
                                "old_position_id": _existing_shift_lease.held_position_id,
                                "old_token_id": _existing_shift_lease.held_token_id,
                                "city": family.city,
                                "target_date": family.target_date,
                                "metric": family.metric,
                            }
                    else:
                        _shift_bin_wiring.exit_only_complete(
                            trade_conn,
                            _existing_shift_lease.intent_id,
                            now_iso=decision_time.isoformat(),
                            reason="SHIFT_BIN_OLD_LEG_CLOSED_FRESH_SELECTION_CHANGED",
                        )
                        return _with_shrink(EventSubmissionReceipt(
                            False,
                            event.event_id,
                            event.causal_snapshot_id,
                            reason="SHIFT_BIN_EXIT_ONLY_COMPLETE:FRESH_SELECTION_CHANGED",
                            city=family.city,
                            target_date=family.target_date,
                            metric=family.metric,
                            condition_id=str(candidate.condition_id or ""),
                            token_id=selected_token_id,
                            executable_snapshot_id=proof.executable_snapshot_id,
                            family_id=family.family_id,
                            bin_label=candidate.bin.label,
                            direction=direction,
                            q_live=receipt_q_live,
                            q_lcb_5pct=receipt_q_lcb,
                            c_fee_adjusted=execution_price.value,
                            c_cost_95pct=proof.c_cost_95pct,
                            p_fill_lcb=proof.p_fill_lcb,
                            trade_score=trade_score,
                            native_quote_available=True,
                            source_status="MATCH",
                            family_complete=True,
                        ))
                elif _existing_shift_lease.status in {
                    "ENTRY_SUBMITTED",
                    "ENTRY_UNKNOWN",
                    "ENTRY_PARTIAL",
                    "REVIEW_REQUIRED",
                }:
                    return _with_shrink(EventSubmissionReceipt(
                        False,
                        event.event_id,
                        event.causal_snapshot_id,
                        reason=f"SHIFT_BIN_ENTRY_IN_FLIGHT:{_existing_shift_lease.status}",
                        city=family.city,
                        target_date=family.target_date,
                        metric=family.metric,
                        condition_id=str(candidate.condition_id or ""),
                        token_id=selected_token_id,
                        executable_snapshot_id=proof.executable_snapshot_id,
                        family_id=family.family_id,
                        bin_label=candidate.bin.label,
                        direction=direction,
                        q_live=receipt_q_live,
                        q_lcb_5pct=receipt_q_lcb,
                        c_fee_adjusted=execution_price.value,
                        c_cost_95pct=proof.c_cost_95pct,
                        p_fill_lcb=proof.p_fill_lcb,
                        trade_score=trade_score,
                        native_quote_available=True,
                        source_status="MATCH",
                        family_complete=True,
                    ))
            _held_same_token = _fill_up_wiring.read_held_same_token_exposure(
                trade_conn, token_id=str(selected_token_id or "")
            )
            if _held_same_token is not None:
                # Venue minimum in USD: min_order_size (shares) priced at the chosen
                # execution price (the same fee-deducted boundary the order pays).
                # This is the residual floor decide_fill_up uses; a residual below it
                # is denied (RESIDUAL_BELOW_VENUE_MIN). The recapture kernel separately
                # enforces the true venue-min bump, so this is a secondary guard.
                _min_order_shares = (
                    _float_or_default(row.get("min_order_size"), 1.0)
                    if isinstance(row, Mapping) else 1.0
                )
                _price_for_min = float(getattr(execution_price, "value", 0.0) or 0.0)
                _venue_min_usd = (
                    _min_order_shares * _price_for_min
                    if _price_for_min > 0.0 else _min_order_shares
                )
                _same_token_pending = _same_token_pending_entry_usd(
                    locked_opportunity_conn,
                    token_id=str(selected_token_id or ""),
                    trade_conn=trade_conn,
                )
                _fill_up_plan = _fill_up_wiring.plan_fill_up(
                    trade_conn,
                    is_redecision_event=True,
                    family_key=str(family.family_id or ""),
                    event_id=str(event.event_id or ""),
                    selected_token_id=str(selected_token_id or ""),
                    selected_bin_id=_candidate_bin_id(proof),
                    selected_direction=str(direction or ""),
                    held=_held_same_token,
                    q_current_lcb=receipt_q_lcb,
                    target_total_exposure_usd=float(_robust_stake_usd),
                    same_token_pending_entry_usd=float(_same_token_pending),
                    venue_min_increment_usd=float(_venue_min_usd),
                    now_iso=decision_time.isoformat(),
                )
                if _fill_up_plan.kind == "ABORT":
                    # Lease collision OR decide_fill_up denied (at/over target, belief
                    # not strengthened, unowned pending, residual below venue min):
                    # emit NO order. The lease (when acquired) is already advanced
                    # ABORTED inside plan_fill_up.
                    return _with_shrink(EventSubmissionReceipt(
                        False,
                        event.event_id,
                        event.causal_snapshot_id,
                        reason=f"FILL_UP_NO_SUBMIT:{_fill_up_plan.reason}",
                        city=family.city,
                        target_date=family.target_date,
                        metric=family.metric,
                        condition_id=str(candidate.condition_id or ""),
                        token_id=selected_token_id,
                        executable_snapshot_id=proof.executable_snapshot_id,
                        family_id=family.family_id,
                        bin_label=candidate.bin.label,
                        direction=direction,
                        q_live=receipt_q_live,
                        q_lcb_5pct=receipt_q_lcb,
                        c_fee_adjusted=execution_price.value,
                        c_cost_95pct=proof.c_cost_95pct,
                        p_fill_lcb=proof.p_fill_lcb,
                        trade_score=trade_score,
                        native_quote_available=True,
                        source_status="MATCH",
                        family_complete=True,
                    ))
                if _fill_up_plan.kind == "APPLY":
                    # THE residual safety override: submit the residual, never a
                    # second full family-total stake.
                    _robust_stake_usd = float(_fill_up_plan.residual_stake_usd or 0.0)
                    if provenance_capture is not None:
                        provenance_capture["fill_up_lease"] = {
                            "intent_id": _fill_up_plan.lease_intent_id,
                            "owned_position_id": _held_same_token.position_id,
                            "owned_token_id": str(selected_token_id or ""),
                            "city": family.city,
                            "target_date": family.target_date,
                            "metric": family.metric,
                            "residual_stake_usd": _robust_stake_usd,
                        }
                # NOOP falls through with _robust_stake_usd unchanged (entry path).
            else:
                # D2 SHIFT-BIN (2026-06-22 lifecycle consult REQ-20260622-060011): the
                # SIBLING case. The fresh winning leg is NOT the same token as any held
                # position (D1 fill-up NOOP'd: _held_same_token is None) — but it MAY be
                # a DIFFERENT bin in a family that already holds a position. That is the
                # close-before-open hazard: without this branch the sibling falls through
                # to the fresh-entry submit and opens a NEW bin while the OLD leg is still
                # held. Close-before-open: detect the old leg, and either (a) exit it
                # first and emit NO new entry this cycle, or (b) — once the old leg is
                # proven zero/dust on a LATER cycle — admit the counter-entry under the
                # SAME lease. A NON-sibling (no held different-bin family position) is a
                # NOOP here → the candidate is a true fresh entry and runs BYTE-IDENTICAL.
                _held_sibling = _shift_bin_wiring.read_held_sibling_exposure(
                    trade_conn,
                    city=str(family.city or ""),
                    target_date=str(family.target_date or ""),
                    temperature_metric=str(family.metric or ""),
                    selected_token_id=str(selected_token_id or ""),
                    selected_bin_label=str(candidate.bin.label or ""),
                )
                if _held_sibling is None:
                    try:
                        _unresolved_family_reason = _entry_held_position_same_family_reason(
                            trade_conn,
                            proof,
                        )
                    except RuntimeError as exc:
                        _unresolved_family_reason = str(exc)
                    if _unresolved_family_reason is not None:
                        return _with_shrink(EventSubmissionReceipt(
                            False,
                            event.event_id,
                            event.causal_snapshot_id,
                            reason=(
                                "SHIFT_BIN_NO_SUBMIT:HELD_FAMILY_UNRESOLVED:"
                                f"{_unresolved_family_reason}"
                            ),
                            city=family.city,
                            target_date=family.target_date,
                            metric=family.metric,
                            condition_id=str(candidate.condition_id or ""),
                            token_id=selected_token_id,
                            executable_snapshot_id=proof.executable_snapshot_id,
                            family_id=family.family_id,
                            bin_label=candidate.bin.label,
                            direction=direction,
                            q_live=receipt_q_live,
                            q_lcb_5pct=receipt_q_lcb,
                            c_fee_adjusted=execution_price.value,
                            c_cost_95pct=proof.c_cost_95pct,
                            p_fill_lcb=proof.p_fill_lcb,
                            trade_score=trade_score,
                            native_quote_available=True,
                            source_status="MATCH",
                            family_complete=True,
                        ))
                if _held_sibling is not None:
                    # Old-leg residual from canonical truth: 0.0 == proven closed
                    # (no live row for the old token); +inf on ambiguous read (treat as
                    # live → exit first, never falsely enter). The dust floor is the
                    # venue min order in USD (a sub-min remainder can never be sold).
                    _old_leg_residual = _shift_bin_wiring.read_old_leg_residual_usd(
                        trade_conn, token_id=_held_sibling.token_id
                    )
                    _min_order_shares = (
                        _float_or_default(row.get("min_order_size"), 1.0)
                        if isinstance(row, Mapping) else 1.0
                    )
                    _price_for_min = float(getattr(execution_price, "value", 0.0) or 0.0)
                    _dust_floor_usd = (
                        _min_order_shares * _price_for_min
                        if _price_for_min > 0.0 else _min_order_shares
                    )
                    # Any unowned pending/unknown/partial ENTRY in the family fails the
                    # shift closed (reuse the SAME pending-entry truth D1 uses; >0 means
                    # an in-flight same-token-or-sibling entry that is not yet position
                    # truth — ambiguous family exposure).
                    _family_pending_usd = _same_token_pending_entry_usd(
                        locked_opportunity_conn,
                        token_id=_held_sibling.token_id,
                        trade_conn=trade_conn,
                    )
                    if float(_old_leg_residual) > float(_dust_floor_usd):
                        _day0_shift_block = _day0_shift_old_leg_exit_block_reason(
                            event=event,
                            payload=payload,
                            proof=proof,
                        )
                        if _day0_shift_block is not None:
                            return _with_shrink(EventSubmissionReceipt(
                                False,
                                event.event_id,
                                event.causal_snapshot_id,
                                reason=f"SHIFT_BIN_NO_SUBMIT:{_day0_shift_block}",
                                city=family.city,
                                target_date=family.target_date,
                                metric=family.metric,
                                condition_id=str(candidate.condition_id or ""),
                                token_id=selected_token_id,
                                executable_snapshot_id=proof.executable_snapshot_id,
                                family_id=family.family_id,
                                bin_label=candidate.bin.label,
                                direction=direction,
                                q_live=receipt_q_live,
                                q_lcb_5pct=receipt_q_lcb,
                                c_fee_adjusted=execution_price.value,
                                c_cost_95pct=proof.c_cost_95pct,
                                p_fill_lcb=proof.p_fill_lcb,
                                trade_score=trade_score,
                                native_quote_available=True,
                                source_status="MATCH",
                                family_complete=True,
                            ))
                    _shift_plan = _shift_bin_wiring.plan_shift_bin(
                        trade_conn,
                        is_redecision_event=True,
                        family_key=str(family.family_id or ""),
                        event_id=str(event.event_id or ""),
                        selected_token_id=str(selected_token_id or ""),
                        selected_bin_id=_candidate_bin_id(proof),
                        selected_direction=str(direction or ""),
                        held=_held_sibling,
                        old_leg_residual_usd=float(_old_leg_residual),
                        has_unowned_pending_or_unknown_entry=bool(_family_pending_usd > 0.0),
                        now_iso=decision_time.isoformat(),
                        old_leg_dust_floor_usd=float(_dust_floor_usd),
                    )
                    if _shift_plan.kind == "ABORT":
                        # Blocking unowned exposure OR concurrent family lease: emit NO
                        # exit, NO order. The lease (when acquired) is already ABORTED.
                        return _with_shrink(EventSubmissionReceipt(
                            False,
                            event.event_id,
                            event.causal_snapshot_id,
                            reason=f"SHIFT_BIN_NO_SUBMIT:{_shift_plan.reason}",
                            city=family.city,
                            target_date=family.target_date,
                            metric=family.metric,
                            condition_id=str(candidate.condition_id or ""),
                            token_id=selected_token_id,
                            executable_snapshot_id=proof.executable_snapshot_id,
                            family_id=family.family_id,
                            bin_label=candidate.bin.label,
                            direction=direction,
                            q_live=receipt_q_live,
                            q_lcb_5pct=receipt_q_lcb,
                            c_fee_adjusted=execution_price.value,
                            c_cost_95pct=proof.c_cost_95pct,
                            p_fill_lcb=proof.p_fill_lcb,
                            trade_score=trade_score,
                            native_quote_available=True,
                            source_status="MATCH",
                            family_complete=True,
                        ))
                    if _shift_plan.kind == "EXIT_OLD_LEG":
                        # CLOSE-BEFORE-OPEN: the old leg is still live. The submit
                        # wrapper submits the reduce-only exit for the OLD token; NO
                        # new-bin entry is built this cycle. Carry the lease + old-leg
                        # identity so the wrapper drives the exit + lease advance.
                        if provenance_capture is not None:
                            provenance_capture["shift_bin_lease"] = {
                                "phase": "EXIT_OLD_LEG",
                                "intent_id": _shift_plan.lease_intent_id,
                                "old_position_id": _shift_plan.old_position_id,
                                "old_token_id": _shift_plan.old_token_id,
                                "city": family.city,
                                "target_date": family.target_date,
                                "metric": family.metric,
                            }
                        return _with_shrink(EventSubmissionReceipt(
                            False,
                            event.event_id,
                            event.causal_snapshot_id,
                            reason="SHIFT_BIN_EXIT_OLD_LEG_PENDING",
                            city=family.city,
                            target_date=family.target_date,
                            metric=family.metric,
                            condition_id=str(candidate.condition_id or ""),
                            token_id=selected_token_id,
                            executable_snapshot_id=proof.executable_snapshot_id,
                            family_id=family.family_id,
                            bin_label=candidate.bin.label,
                            direction=direction,
                            q_live=receipt_q_live,
                            q_lcb_5pct=receipt_q_lcb,
                            c_fee_adjusted=execution_price.value,
                            c_cost_95pct=proof.c_cost_95pct,
                            p_fill_lcb=proof.p_fill_lcb,
                            trade_score=trade_score,
                            native_quote_available=True,
                            source_status="MATCH",
                            family_complete=True,
                            shift_bin_lease_payload={
                                "phase": "EXIT_OLD_LEG",
                                "intent_id": _shift_plan.lease_intent_id,
                                "old_position_id": _shift_plan.old_position_id,
                                "old_token_id": _shift_plan.old_token_id,
                                "city": family.city,
                                "target_date": family.target_date,
                                "metric": family.metric,
                            },
                        ))
                    if _shift_plan.kind == "ENTER_NEW_BIN":
                        # The old leg is proven closed (zero/dust). This is the LATER
                        # cycle's counter-entry: the reactor's OWN fresh selection on
                        # current books IS the mandatory recompute (no pre-exit sibling
                        # reuse). Fall through to the normal entry submit with
                        # _robust_stake_usd UNCHANGED (the fresh target), carrying the
                        # lease so the wrapper advances it COMPLETE on ack.
                        if provenance_capture is not None:
                            provenance_capture["shift_bin_lease"] = {
                                "phase": "ENTER_NEW_BIN",
                                "intent_id": _shift_plan.lease_intent_id,
                                "old_position_id": _shift_plan.old_position_id,
                                "old_token_id": _shift_plan.old_token_id,
                                "city": family.city,
                                "target_date": family.target_date,
                                "metric": family.metric,
                            }
                    # NOOP (no sibling) falls through with _robust_stake_usd unchanged.
        kelly = dataclass_replace(
            kelly,
            size_usd=float(_robust_stake_usd),
            passed=bool(_recapture.may_submit),
        )
        # Rebind the Kelly cost-of-entry to the chosen-stake boundary when the
        # recapture cleared (so the intent's ``execution_price`` / the receipt's
        # ``c_fee_adjusted`` / the executor limit reflect the depth walk). On any abort
        # the stake is 0.0 / price is None and we leave ``execution_price`` as the S1
        # boundary — the abort receipt below reports it for audit and builds no intent.
        if _recapture.may_submit and _chosen_stake_price is not None:
            execution_price = _chosen_stake_price
    except (TypeError, ValueError) as exc:
        return _with_shrink(EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=f"KELLY_PROOF_MISSING:{exc}",
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            condition_id=str(candidate.condition_id or ""),
            token_id=selected_token_id,
            executable_snapshot_id=proof.executable_snapshot_id,
            family_id=family.family_id,
            bin_label=candidate.bin.label,
            direction=direction,
            q_live=receipt_q_live,
            q_lcb_5pct=receipt_q_lcb,
            c_fee_adjusted=execution_price.value,
            c_cost_95pct=proof.c_cost_95pct,
            p_fill_lcb=proof.p_fill_lcb,
            trade_score=trade_score,
            native_quote_available=True,
            source_status="MATCH",
            family_complete=True,
        ))
    if not _recapture.may_submit:
        # S6: the submit recapture aborted. The receipt reason is DERIVED from the
        # engine's terminal lifecycle state (SUBMIT_ABORTED_PRICE_MOVED /
        # _EDGE_REVERSED / _FAMILY_REVERSED) — one taxonomy, never set independently of
        # the state machine. ``detail`` carries the human-readable trigger; the abort
        # state is in SUBMIT_ABORT_STATES (assertable). No intent is built (fail-closed,
        # spec §5/§7/§13: price-through-max, edge<=0/forecast-stale, or rank reversed
        # without a full re-rank).
        assert _recapture.state in SUBMIT_ABORT_STATES, (
            f"recapture aborted but state {_recapture.state} is not a submit-abort "
            f"state — the gate must land in a first-class abort state (§7)"
        )
        _abort_reason = _SUBMIT_ABORT_RECEIPT_REASON[_recapture.state]
        _abort_detail = _recapture.detail or _abort_reason
        _abort_trade_score = trade_score
        if _recapture.state is CandidateLifecycleState.SUBMIT_ABORTED_EDGE_REVERSED:
            _abort_trade_score = _robust_trade_score_from_generated_inputs(
                q_posterior=receipt_q_live,
                q_lcb_5pct=receipt_q_lcb,
                execution_price=execution_price,
                c_cost_95pct=proof.c_cost_95pct,
                p_fill_lcb=proof.p_fill_lcb,
            )
            if not math.isfinite(float(_abort_trade_score)):
                _abort_trade_score = 0.0
            _abort_trade_score = min(0.0, float(_abort_trade_score))
        return _with_shrink(EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=f"{_abort_reason}:{_abort_detail}",
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            condition_id=str(candidate.condition_id or ""),
            token_id=selected_token_id,
            executable_snapshot_id=proof.executable_snapshot_id,
            family_id=family.family_id,
            bin_label=candidate.bin.label,
            direction=direction,
            q_live=receipt_q_live,
            q_lcb_5pct=receipt_q_lcb,
            c_fee_adjusted=execution_price.value,
            c_cost_95pct=proof.c_cost_95pct,
            p_fill_lcb=proof.p_fill_lcb,
            trade_score=_abort_trade_score,
            native_quote_available=True,
            source_status="MATCH",
            family_complete=True,
            fdr_pass=True,
            fdr_family_id=fdr.fdr_family_id,
            fdr_hypothesis_count=fdr.attempted_hypotheses,
            kelly_pass=False,
            kelly_execution_price_type=execution_price.__class__.__name__,
            kelly_price_fee_deducted=execution_price.fee_deducted,
            kelly_size_usd=kelly.size_usd,
            kelly_cost_basis_id=kelly_cost_basis_id,
        ))
    actual_submit_quality_reason = _qkernel_actual_submit_quality_rejection_reason(
        proof=proof,
        strategy_policy_event_type=event.event_type,
        actual_stake_usd=float(kelly.size_usd),
        actual_cost=float(execution_price.value),
    )
    if actual_submit_quality_reason is not None:
        return _with_shrink(EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=actual_submit_quality_reason,
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            condition_id=str(candidate.condition_id or ""),
            token_id=selected_token_id,
            executable_snapshot_id=proof.executable_snapshot_id,
            family_id=family.family_id,
            bin_label=candidate.bin.label,
            direction=direction,
            q_live=receipt_q_live,
            q_lcb_5pct=receipt_q_lcb,
            c_fee_adjusted=execution_price.value,
            c_cost_95pct=proof.c_cost_95pct,
            p_fill_lcb=proof.p_fill_lcb,
            trade_score=trade_score,
            native_quote_available=True,
            source_status="MATCH",
            family_complete=True,
            fdr_pass=True,
            fdr_family_id=fdr.fdr_family_id,
            fdr_hypothesis_count=fdr.attempted_hypotheses,
            kelly_pass=False,
            kelly_execution_price_type=execution_price.__class__.__name__,
            kelly_price_fee_deducted=execution_price.fee_deducted,
            kelly_size_usd=kelly.size_usd,
            kelly_cost_basis_id=kelly_cost_basis_id,
            q_source=proof.q_source,
            qkernel_execution_economics=_json_finite(proof.qkernel_execution_economics),
            selection_authority_applied=proof.selection_authority_applied,
            q_lcb_calibration_source=proof.q_lcb_calibration_source,
            same_bin_yes_posterior=proof.same_bin_yes_posterior,
            settlement_coverage_status=proof.settlement_coverage_status,
            posterior_id=proof.posterior_id,
            probability_authority=proof.probability_authority,
            opportunity_book=(
                _json_finite(opportunity_book.to_receipt_dict())
                if opportunity_book is not None
                else None
            ),
            execution_mode_intent=proof.execution_mode_intent,
            maker_limit_price=proof.maker_limit_price,
            rest_then_cross_policy=proof.rest_then_cross_policy,
            rest_escalation_deadline_minutes=proof.rest_escalation_deadline_minutes,
        ))
    risk = evaluate_riskguard(
        risk_decision_id=f"edli_risk:{event.event_id}:{selected_token_id}",
        level=get_current_level(),
    )
    if not risk.passed:
        return _with_shrink(
            EventSubmissionReceipt(False, event.event_id, event.causal_snapshot_id, reason="RISK_GUARD_BLOCKED")
        )
    # Task #107 INV-K7 (same-cycle in-flight reservation): this bet has now
    # passed Kelly + RiskGuard. Reserve its stake in the per-cycle ledger so the
    # NEXT event in this reactor cycle nets it — a just-emitted EDLI entry is
    # PENDING_TRACKED without fill authority, so its effective_cost_basis_usd is
    # 0.0 and it is invisible to the portfolio snapshot until reconciled. Without
    # this, two same-cycle bets would both size against the full (un-netted)
    # budget and breach it intra-cycle.
    #
    # FIX B (P1 zero-submit co-cause, 2026-06-05): the reservation is now
    # PROVISIONAL. Passing Kelly + RiskGuard is NOT emission — the receipt can
    # still be REJECTED downstream at DECISION_CERTIFICATE / EXECUTOR_
    # EXPRESSIBILITY in the reactor's post-submit phase. The reactor finalizes
    # this provisional reserve (commit on emit / rollback on reject) BEFORE the
    # next sequential event reads the ledger, so a rejected candidate never
    # inflates corr_committed_usd / raw_committed_usd for later same-cycle
    # candidates. (Plain lists supplied by legacy/test callers keep the old
    # append-only behavior via the shim below.)
    if portfolio_reservation is not None:
        _reserve = getattr(portfolio_reservation, "reserve", None)
        if callable(_reserve):
            _reserve(event.event_id, family.city, float(kelly.size_usd))
        else:
            portfolio_reservation.append((family.city, float(kelly.size_usd)))
    intent = EventBoundFinalIntent(
        final_intent_id=f"edli_intent:{event.event_id}:{selected_token_id}",
        event_id=event.event_id,
        family_id=family.family_id,
        candidate_id=f"{family.family_id}:{candidate.condition_id}",
        condition_id=str(candidate.condition_id or ""),
        token_id=selected_token_id,
        direction=direction,
        executable_snapshot_id=str(proof.executable_snapshot_id or ""),
        execution_price=execution_price,
    )
    typed_receipt = build_event_bound_final_intent_receipt(
        intent=intent,
        causal_snapshot_id=str(event.causal_snapshot_id or ""),
        trade_score_id=f"edli_trade_score:{event.event_id}:{selected_token_id}",
        fdr_family_id=fdr.fdr_family_id,
        kelly_decision_id=kelly.kelly_decision_id,
        risk_decision_id=risk.risk_decision_id,
        live_submit_enabled=False,
    )
    raw_receipt = serialize_event_bound_final_intent_receipt(
        typed_receipt,
        trade_score_positive=True,
        fdr_pass=fdr.passed,
        fdr_hypothesis_count=fdr.attempted_hypotheses,
        kelly_pass=kelly.passed,
        kelly_size_usd=kelly.size_usd,
        kelly_cost_basis_id=kelly_cost_basis_id,
    )
    strategy_key = _event_bound_strategy_key(
        event_type=event.event_type,
        direction=direction,
        metric=family.metric,
    )
    live_quality_floors = _event_bound_strategy_live_quality_floors(strategy_key)
    raw_receipt.update(
        {
            "city": family.city,
            "target_date": family.target_date,
            "metric": family.metric,
            "strategy_key": strategy_key,
            "bin_label": candidate.bin.label,
            "unit": getattr(candidate.bin, "unit", None),
            "outcome_label": "NO" if selected_token_id == candidate.no_token_id else "YES",
            "q_live": receipt_q_live,
            "q_lcb_5pct": receipt_q_lcb,
            "q_lcb_calibration_source": proof.q_lcb_calibration_source,
            # Independently-materialized YES-bin posterior (== yes_q from the
            # q-vector; never a complement). Carried so the post-submit receipt-level
            # buy-NO conservative-evidence gate sees the SAME input the adapter gate
            # did — closing ADMISSION_BUY_NO_INDEPENDENT_YES_POSTERIOR_MISSING.
            "same_bin_yes_posterior": proof.same_bin_yes_posterior,
            # Twin-authority reconciliation #7: the family coverage verdict status,
            # carried the same way same_bin_yes_posterior travels so the receipt-level
            # twin gate (events.reactor._receipt_money_path_blocker) evaluates the
            # SAME settled-record evidence — lockstep, never starved.
            "settlement_coverage_status": proof.settlement_coverage_status,
            "q_source": proof.q_source,  # #120 calibrator provenance
            # B3 authority stamp must ride the receipt round-trip alongside q_source:
            # qkernel_spine_bridge preserves q_source as the probability-track label
            # ("replacement_0_1") and records EXECUTION authority here. Without this
            # the typed reconstruction reverts the stamp to None and the taker-quality
            # gate rejects every spine taker (qkernel_cert_present_without_qkernel_authority_stamp).
            "selection_authority_applied": proof.selection_authority_applied,
            # B3 identity key (2026-06-23): the reactor bin_id hash, byte-identical to
            # the qkernel cert's bin_id, so the taker-quality proof can match the cert
            # to this selected leg across the two candidate_id namespaces.
            "candidate_bin_id": _candidate_bin_id(proof),
            "qkernel_execution_economics": _json_finite(proof.qkernel_execution_economics),
            # H2_E2E: typed posterior link carried to the receipt (None on canonical).
            "posterior_id": proof.posterior_id,
            "probability_authority": proof.probability_authority,
            "c_fee_adjusted": execution_price.value,
            "c_cost_95pct": proof.c_cost_95pct,
            "p_fill_lcb": proof.p_fill_lcb,
            "trade_score": trade_score,
            "min_entry_price": live_quality_floors["min_entry_price"],
            "min_expected_profit_usd": live_quality_floors["min_expected_profit_usd"],
            "min_submit_edge_density": live_quality_floors["min_submit_edge_density"],
            "bias_decay_applied": bool(_bias_decay_applied),
            "bias_decay_bias_native": _bias_decay_native,
            "bias_decay_reason": _bias_decay_reason,
            "bias_decay_kelly_factor": float(settings["edli"].get("bias_decay_kelly_factor", 0.5)) if _bias_decay_applied else 1.0,
            "neg_risk": bool(row.get("neg_risk") or False),
            "native_quote_available": True,
            "source_status": FORECAST_LIVE_ELIGIBLE_STATUS,
            "family_complete": True,
            # P0 mode-authority (operator review 2026-06-10): the SELECTED proof's
            # maker/taker mode and its maker limit price are first-class receipt fields.
            # The recapture above PROVED these under that mode's economics
            # (_proof_order_rests_at_admitted_price(proof)); the final command builder
            # consumes them as the SOLE mode authority and must not re-decide. None on a
            # proof that carries no mode_ev (legacy/priced-without-mode) — the final
            # builder fails closed on a missing mode at the final stage.
            "execution_mode_intent": (
                str(proof.execution_mode_intent).strip().upper()
                if proof.execution_mode_intent is not None
                else None
            ),
            "maker_limit_price": proof.maker_limit_price,
            # K4.0 REST-THEN-CROSS: the policy verdict that produced the mode and
            # the escalation deadline. The final command builder validates this
            # proof mode against the fresh book; it may abort for a re-rank, but it
            # must not inline-flip a proven maker intent into a taker submit.
            "rest_then_cross_policy": proof.rest_then_cross_policy,
            "rest_escalation_deadline_minutes": proof.rest_escalation_deadline_minutes,
        }
    )
    # Stake-floor provenance (2026-06-09 min-order fix): record when the chosen stake
    # was bumped up to the venue min order because the fractional-Kelly haircut shrank
    # it below the floor while the robust edge at min order was strictly positive. Absent
    # on the normal (un-bumped) path. Keeps the receipt honest about why size==min order.
    if _stake_floor_provenance.get("stake_floor"):
        raw_receipt["stake_floor"] = _stake_floor_provenance["stake_floor"]
        if "stake_floor_min_order_usd" in _stake_floor_provenance:
            raw_receipt["stake_floor_min_order_usd"] = _stake_floor_provenance[
                "stake_floor_min_order_usd"
            ]
        if "stake_floor_delta_u_at_min_order" in _stake_floor_provenance:
            raw_receipt["stake_floor_delta_u_at_min_order"] = _stake_floor_provenance[
                "stake_floor_delta_u_at_min_order"
            ]
    # Price-move tolerance provenance (2026-06-10). When the recapture priced
    # STRICTLY WORSE than the admitted ceiling yet the entry proceeded — the maker
    # order rested at the admitted price, or a taker filled within the bounded
    # tolerance — record admitted vs recaptured so settlement attribution can measure
    # whether tolerated/rested entries underperform vs assumption (fill-rate, slippage).
    # Absent on the clean no-move path (receipt stays clean).
    if _recapture.price_moved_within_tolerance:
        raw_receipt["price_moved_within_tolerance"] = True
        raw_receipt["price_move_admitted_price"] = _recapture.admitted_price
        raw_receipt["price_move_recaptured_cost"] = _recapture.recaptured_all_in_cost
        raw_receipt["price_move_tolerance"] = _recapture.price_move_tolerance
        raw_receipt["price_move_order_rests_at_admitted"] = bool(
            _order_rests_at_admitted_price
        )
    if opportunity_book is not None:
        raw_receipt["opportunity_book"] = _json_finite(opportunity_book.to_receipt_dict())
    if replacement_forecast_receipt_tag is not None:
        raw_receipt["replacement_forecast"] = replacement_forecast_receipt_tag
    # Mainstream-agreement gate fields (#135). Added when the verdict is available on the
    # selected proof; absent otherwise (gate OFF or evaluation error — receipt stays clean).
    if proof.mainstream_agreement is not None:
        _mav = proof.mainstream_agreement
        raw_receipt.update(
            {
                "mainstream_agreement_pass": _mav.get("mainstream_agreement_pass"),
                "mainstream_agreement_fail_reason": _mav.get("mainstream_agreement_fail_reason"),
                "mainstream_point": _mav.get("mainstream_point"),
                "mainstream_delta": _mav.get("forecast_delta"),
                "mainstream_bin_label": _mav.get("mainstream_bin_label"),
                "mainstream_source": _mav.get("mainstream_source"),
                "mainstream_fetched_at_utc": _mav.get("mainstream_fetched_at_utc"),
            }
        )
    # WRONG-BOOK / IDENTITY WALL #5 (live incident 2026-06-12, Busan 27°C NO POST_ONLY
    # 0.02 vs real book 0.63/0.65). `row` (= _selected_snapshot_row_for_event(family_rows,
    # payload)) is keyed by the EVENT's *trigger* token (payload.token_id) — the bin that
    # fired the opportunity event — NOT by the candidate the ΔU ranker actually selected
    # (`proof`). When the winning leg is a DIFFERENT bin than the trigger bin (the normal
    # case for a family scan), `row` is a SIBLING bin's snapshot. The replacement-forecast
    # branch already re-binds `row = proof.row`; the canonical path never did, so the
    # QUOTE_FEASIBILITY cert (which reads best_bid/best_ask off selected_snapshot_row)
    # carried the wrong bin's book — e.g. the 30°C-YES book 0.018/0.035 — while the
    # executable-snapshot cert (keyed off proof.executable_snapshot_id) was correct. The
    # maker price then bid-improved that ghost 0.018 bid → a 0.02 limit that can never fill.
    #
    # ROOT FIX (same identity discipline as the executable snapshot: condition_id +
    # selected_outcome_token_id): the proof-evidence bundle MUST describe the SELECTED
    # candidate, so the quote book is the SELECTED proof's NATIVE row (`proof.row`, keyed
    # at generation by (condition_id, direction)). A selected, priced proof ALWAYS has a
    # native row (execution_price is derived from it); fail closed if it does not — never
    # substitute the trigger-bin book.
    selected_snapshot_row = _selected_proof_snapshot_row_or_raise(proof)
    try:
        proof_bundle = _build_no_submit_proof_bundle_from_adapter_evidence(
            event=event,
            payload=payload,
            decision_time=decision_time,
            family=family,
            family_topology_rows=family_topology_rows,
            family_snapshot_rows=family_rows,
            selected_snapshot_row=selected_snapshot_row,
            trade_conn=trade_conn,
            forecast_conn=source_conn,
            calibration_conn=calibration_conn,
            proof=proof,
            raw_receipt=raw_receipt,
            fdr=fdr,
            kelly=kelly,
            risk=risk,
            bankroll_usd=bankroll_usd,
            kelly_multiplier=kelly_multiplier,
        )
    except ValueError as exc:
        missing_reason = str(exc)
        if not missing_reason.startswith("CALIBRATION_AUTHORITY_EVIDENCE_MISSING:"):
            raise
        missing_reason = missing_reason.replace(
            "CALIBRATION_AUTHORITY_EVIDENCE_MISSING:",
            "CALIBRATION_AUTHORITY_MISSING:",
            1,
        )
        return _with_shrink(EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason=f"LIVE_INFERENCE_INPUTS_MISSING:{missing_reason}",
            city=family.city,
            target_date=family.target_date,
            metric=family.metric,
            family_id=family.family_id,
            source_status="MATCH",
            family_complete=True,
        ))
    return _with_shrink(
        _event_submission_receipt_from_typed_receipt_payload(
            raw_receipt,
            event,
            decision_proof_bundle=proof_bundle,
        )
    )


# Per-candidate fate fields carried into the envelope's candidate_book. The decision
# provenance must let an operator query, for a REJECTED family, every candidate's fate
# (operator law 2026-06-11: 每一个做的决策为什么都需要被查阅). The full OpportunityBook
# receipt dict is large and decision-time-noisy; the envelope home is a compact,
# size-capped projection of exactly the fate-relevant fields.
_CANDIDATE_BOOK_FIELDS: tuple[str, ...] = (
    "candidate_id",
    "family_id",
    "condition_id",
    "token_id",
    "bin_label",
    "support_index",
    "bin_id",
    "direction",
    "q_posterior",
    "q_lcb_5pct",
    "execution_price",
    "trade_score",
    "missing_reason",
    "execution_mode_intent",
    "qkernel_execution_economics",
    "admitted",
)
_CANDIDATE_BOOK_STR_CAP = 200


def _json_finite(value: Any) -> Any:
    """Return a JSON-safe copy with non-finite floats removed.

    Certificate hashing correctly uses ``allow_nan=False``. Diagnostic payloads
    must not smuggle Python ``inf``/``nan`` into that boundary.
    """

    if isinstance(value, float):
        return value if math.isfinite(value) else None
    if isinstance(value, Mapping):
        return {str(k): _json_finite(v) for k, v in value.items()}
    if isinstance(value, tuple):
        return [_json_finite(v) for v in value]
    if isinstance(value, list):
        return [_json_finite(v) for v in value]
    return value


def _candidate_book_for_envelope(opportunity_book_dict: Any) -> list[dict[str, Any]] | None:
    """Compact per-candidate fate projection from the receipt's opportunity_book dict.

    Serializes every candidate's (bin_label, direction, q, q_lcb, execution_price,
    missing_reason, trade_score, mode, admitted) with string values truncated to
    _CANDIDATE_BOOK_STR_CAP chars, and flags the fallback the receipt surfaced as the
    decision via ``is_selected_fallback``. Returns None when the book carries no
    candidates. Pure + fail-soft: the envelope can never alter or fail a decision.
    """
    if not isinstance(opportunity_book_dict, Mapping):
        return None
    candidates = opportunity_book_dict.get("candidates")
    if not isinstance(candidates, (list, tuple)) or not candidates:
        return None
    # The book records the ΔU winner (a priced selection) as selected_candidate_id; on
    # a rejection the receipt instead surfaced a best-belief fallback, recorded here as
    # actual_receipt_selected_candidate_id. Flag whichever the receipt actually used.
    selected_id = (
        opportunity_book_dict.get("actual_receipt_selected_candidate_id")
        or opportunity_book_dict.get("selected_candidate_id")
    )

    def _cap(value: Any) -> Any:
        if isinstance(value, str) and len(value) > _CANDIDATE_BOOK_STR_CAP:
            return value[:_CANDIDATE_BOOK_STR_CAP]
        return value

    out: list[dict[str, Any]] = []
    for candidate in candidates:
        if not isinstance(candidate, Mapping):
            continue
        entry: dict[str, Any] = {
            field: _json_finite(_cap(candidate.get(field))) for field in _CANDIDATE_BOOK_FIELDS
        }
        entry["is_selected_fallback"] = bool(
            selected_id is not None and candidate.get("candidate_id") == selected_id
        )
        out.append(entry)
    return out or None


def _build_decision_receipt_spine(
    spine_inputs: dict[str, Any] | None,
    receipt: EventSubmissionReceipt,
) -> "DecisionReceipt | None":
    """Assemble the Stage-0 decision-receipt spine from already-computed live values.

    READ-ONLY / observability-only (q-kernel rebuild Stage 0, consult_build_spec.md:994-1033).
    ``spine_inputs`` is the dict lifted from the THREADED payload onto provenance_capture
    inside ``_generate_candidate_proofs`` (key ``decision_receipt_spine_inputs``). Every input
    is a value the CURRENT live path already produced:
      - mu_native / sigma_native / member arrays / q vector: from the q-build's payload stash.
      - q_source: the receipt's #120 calibrator-provenance field.
      - rounding_rule: the city's settlement-semantics rounding (WMO half-up vs HK truncate)
        — the SAME authority the q integrator uses; read here only to record it.
      - sizing_authority: the receipt's selection_authority (which gate sized the stake).

    The DecisionReceipt builder DERIVES the coherence fields (envelope min/max, q_sum) from
    these arrays, so a spine that misrepresents its own forecast/q is unconstructable — the
    corrected transformation, not a post-hoc detector. Returns None when no q-build spine was
    stashed (gate-reject receipts that never reached q integration); never raises into the
    caller (the caller is already wrapped fail-soft).
    """
    from src.decision.decision_receipt import DecisionReceipt  # lazy: no import cycle

    if not spine_inputs:
        return None
    # The q-build stashes these only when it ran; their absence means this receipt never
    # reached q integration (early gate reject) and there is no forecast spine to emit.
    if (
        "_edli_spine_q_vector" not in spine_inputs
        and "_edli_spine_mu_native" not in spine_inputs
    ):
        return None

    raw_members = spine_inputs.get("_edli_spine_raw_members_native")
    debiased_members = spine_inputs.get("_edli_spine_debiased_members_native")
    q_vector = spine_inputs.get("_edli_spine_q_vector")

    # applied_debias_native: the native-unit mean shift the live correction applied, when it
    # ran. Derived from the raw vs debiased member means (the correction shifts the mean by a
    # constant), so it is consistent with the debiased envelope the receipt also carries.
    applied_debias_native = None
    try:
        if (
            isinstance(raw_members, (list, tuple))
            and isinstance(debiased_members, (list, tuple))
            and raw_members
            and debiased_members
        ):
            _raw_mean = sum(float(m) for m in raw_members) / len(raw_members)
            _deb_mean = sum(float(m) for m in debiased_members) / len(debiased_members)
            applied_debias_native = float(_deb_mean - _raw_mean)
    except Exception:  # noqa: BLE001 — observation only
        applied_debias_native = None

    # q_source: prefer the receipt's #120 field; fall back to the q-build stash (covers
    # receipt paths that have not yet lifted q_source onto the receipt object).
    q_source = receipt.q_source if receipt.q_source is not None else spine_inputs.get("_edli_q_source")

    # rounding_rule: the city's settlement-semantics rounding. Read-only; the q integrator is
    # the authority that USES it, here we only record which rule that family settles under.
    rounding_rule = None
    day0_observed_extreme_native = None
    try:
        city_obj = runtime_cities_by_name().get(str(spine_inputs.get("city") or "")) or None
        if city_obj is not None:
            from src.contracts.settlement_semantics import SettlementSemantics
            rounding_rule = SettlementSemantics.for_city(city_obj).rounding_rule
    except Exception:  # noqa: BLE001 — observation only
        rounding_rule = None
    # day0 observed running extreme, when the live day0 lane recorded one on the payload.
    for _k in (
        "_edli_spine_day0_observed_extreme_native",
        "_edli_day0_observed_extreme_native",
    ):
        _v = spine_inputs.get(_k)
        if _v is not None:
            try:
                day0_observed_extreme_native = float(_v)
            except (TypeError, ValueError):
                day0_observed_extreme_native = None
            break

    return DecisionReceipt.from_q_build(
        q_source=q_source,
        q_vector=q_vector if isinstance(q_vector, (list, tuple)) else None,
        mu_native=spine_inputs.get("_edli_spine_mu_native"),
        sigma_native=spine_inputs.get("_edli_spine_sigma_native"),
        raw_members_native=raw_members if isinstance(raw_members, (list, tuple)) else None,
        debiased_members_native=(
            debiased_members if isinstance(debiased_members, (list, tuple)) else None
        ),
        applied_debias_native=applied_debias_native,
        day0_observed_extreme_native=day0_observed_extreme_native,
        rounding_rule=rounding_rule,
        sizing_authority=getattr(receipt, "selection_authority", None),
    )


def build_event_bound_no_submit_receipt(
    event: OpportunityEvent,
    *,
    trade_conn: sqlite3.Connection,
    decision_time: datetime,
    get_current_level: Callable[[], RiskLevel],
    forecast_conn: sqlite3.Connection | None = None,
    topology_conn: sqlite3.Connection | None = None,
    calibration_conn: sqlite3.Connection | None = None,
    bankroll_usd_provider: Callable[[], float | None] | None = None,
    free_cash_usd_provider: Callable[[], float | None] | None = None,
    portfolio_state_provider: "Callable[[], Any] | None" = None,
    portfolio_reservation: "PortfolioReservationLedger | list[tuple[str, float]] | None" = None,
    locked_opportunity_conn: sqlite3.Connection | None = None,
    replacement_forecast_hook: Callable[["_CandidateProof", OpportunityEvent, datetime], ReplacementForecastReactorHookResult | None] | None = None,
    replacement_forecast_promotion_evidence: ReplacementForecastPromotionEvidence | None = None,
    replacement_forecast_capital_objective_evidence: ReplacementForecastCapitalObjectiveEvidence | None = None,
    family_snapshot_refresher: "FamilySnapshotRefresher | None" = None,
) -> EventSubmissionReceipt:
    """DecisionProvenanceEnvelope wrapper (operator law 2026-06-11) around the receipt core.

    K=1 threading decision: the core has dozens of receipt return sites; instead of patching
    each, the chain (core -> _generate_candidate_proofs -> _live_yes_probabilities ->
    _replacement_authority_probability_and_fdr_proof) records the served replacement bundle and
    the selected executable snapshot row into ONE per-call capture dict at the moment they are
    bound, and this wrapper attaches the assembled envelope to WHATEVER receipt comes back —
    every rejection stage included. Pre-bundle rejections honestly carry
    "UNAVAILABLE: bundle not provided" (no bundle was bound). The reactor merges the final
    rejection {stage, reason} into the envelope at regret-write time.

    Fail-soft and observability-only: any envelope failure returns the core receipt UNCHANGED
    (asserted byte-identical by test); the envelope can never alter a decision.
    """
    provenance_capture: dict[str, Any] = {}
    receipt = _build_event_bound_no_submit_receipt_core(
        event,
        trade_conn=trade_conn,
        decision_time=decision_time,
        get_current_level=get_current_level,
        forecast_conn=forecast_conn,
        topology_conn=topology_conn,
        calibration_conn=calibration_conn,
        bankroll_usd_provider=bankroll_usd_provider,
        free_cash_usd_provider=free_cash_usd_provider,
        portfolio_state_provider=portfolio_state_provider,
        portfolio_reservation=portfolio_reservation,
        locked_opportunity_conn=locked_opportunity_conn,
        replacement_forecast_hook=replacement_forecast_hook,
        replacement_forecast_promotion_evidence=replacement_forecast_promotion_evidence,
        replacement_forecast_capital_objective_evidence=replacement_forecast_capital_objective_evidence,
        provenance_capture=provenance_capture,
        family_snapshot_refresher=family_snapshot_refresher,
    )
    # P1 BELIEF CACHE (continuous re-decision resurrection 2026-06-12): attach the family belief
    # captured deep in the proof chain (provenance_capture["edli_belief"]) onto the receipt so the
    # reactor can persist it through its OWN world conn in Window B (deadlock-free P1). Attached on
    # EVERY return path below. belief_payload is compare=False/repr=False so it can never drift the
    # receipt hash. Absent on gate-reject receipts that never reached candidate-proof generation.
    _belief = provenance_capture.get("edli_belief")
    if _belief is not None and receipt.belief_payload is None:
        receipt = dataclass_replace(receipt, belief_payload=_belief)
    _day0_probability = provenance_capture.get("day0_probability_authority")
    if _day0_probability is not None and receipt.day0_probability_authority is None:
        receipt = dataclass_replace(
            receipt,
            day0_probability_authority=_json_finite(_day0_probability),
        )
    # D1 FILL-UP (2026-06-22 lifecycle consult): carry the acquired fill-up lease
    # context onto the receipt so the live submit wrapper runs the pre-submit family-
    # exposure reread and advances the lease to a terminal status. Only set when the
    # core APPROVED a fill-up (stake overridden to the residual); None otherwise so
    # the fresh-entry path is byte-identical.
    _fill_up_lease = provenance_capture.get("fill_up_lease")
    if _fill_up_lease is not None and receipt.fill_up_lease_payload is None:
        receipt = dataclass_replace(receipt, fill_up_lease_payload=_fill_up_lease)
    # D2 SHIFT-BIN: carry the SHIFT_BIN lease context onto the receipt so the live
    # submit wrapper can drive the close-before-open exit + lease advance. Only the
    # ENTER_NEW_BIN counter-entry reaches this lift (the EXIT_OLD_LEG receipt is a
    # typed no-submit that already set the payload inline at its early return). None on
    # every fresh-entry / fill-up receipt so both paths stay byte-identical.
    _shift_bin_lease = provenance_capture.get("shift_bin_lease")
    if _shift_bin_lease is not None and receipt.shift_bin_lease_payload is None:
        receipt = dataclass_replace(receipt, shift_bin_lease_payload=_shift_bin_lease)
    # === Q-KERNEL REBUILD STAGE 0 — emit the decision-receipt spine (2026-06-14) =========
    # READ-ONLY, observability-only: assemble the DecisionReceipt spine from the inputs the
    # live q-build already lifted onto provenance_capture (decision_receipt_spine_inputs) plus
    # the receipt's own q_source / sizing provenance, and attach the flattened 19-column row
    # to provenance_capture so the spine is reconstructable forecast -> q -> route -> size
    # (consult_build_spec.md:994-1033). This NEVER mutates the receipt that drives the
    # decision/size/submit. Fail-soft: any error leaves the decision untouched (mirrors the
    # envelope wrapper's contract).
    try:
        _spine = _build_decision_receipt_spine(
            provenance_capture.get("decision_receipt_spine_inputs"), receipt
        )
        if _spine is not None:
            provenance_capture["decision_receipt_spine"] = _spine.to_row()
    except Exception:  # noqa: BLE001 — observability must never alter or fail a decision
        pass
    if receipt.envelope_json is not None:
        return receipt
    try:
        from src.contracts.decision_provenance import (  # noqa: PLC0415 — lazy, no import cycle
            build_decision_provenance_envelope,
            envelope_to_json,
        )

        payload = _payload(event)
        mainstream = None
        if receipt.mainstream_agreement_pass is not None or receipt.mainstream_point is not None:
            mainstream = {
                "agreement_pass": receipt.mainstream_agreement_pass,
                "agreement_fail_reason": receipt.mainstream_agreement_fail_reason,
                "point": receipt.mainstream_point,
                "delta": receipt.mainstream_delta,
                "bin_label": receipt.mainstream_bin_label,
                "source": receipt.mainstream_source,
                "fetched_at_utc": receipt.mainstream_fetched_at_utc,
            }
        envelope = build_decision_provenance_envelope(
            forecast_conn,
            trade_conn,
            bundle=provenance_capture.get("replacement_bundle"),
            decision_time=decision_time,
            condition_id=receipt.condition_id or (str(payload.get("condition_id") or "") or None),
            token_id=receipt.token_id or (str(payload.get("token_id") or "") or None),
            executable_snapshot_row=provenance_capture.get("snapshot_row"),
            economics={
                "q_live": receipt.q_live,
                "q_lcb_5pct": receipt.q_lcb_5pct,
                "c_fee_adjusted": receipt.c_fee_adjusted,
                "trade_score": receipt.trade_score,
                "kelly_size_usd": receipt.kelly_size_usd,
            },
            direction=receipt.direction,
            mainstream=mainstream,
            rejection=None,  # the reactor merges the final {stage, reason} at regret-write
            city=receipt.city or (str(payload.get("city") or "") or None),
            target_date=receipt.target_date or (str(payload.get("target_date") or "") or None),
        )
        # Persist the per-candidate fates (operator law 2026-06-11: every candidate's
        # rejection reason queryable). The full OpportunityBook rides on the receipt for
        # ACCEPTED + every relabeled rejection; project its compact fate view into the
        # envelope's candidate_book. envelope_json is the home — it is EXCLUDED from
        # receipt_json/receipt_hash (no_submit_receipts._receipt_json) so adding this can
        # never drift the money-path receipt hash. Fail-soft: absent book -> key omitted.
        candidate_book = _candidate_book_for_envelope(receipt.opportunity_book)
        if candidate_book is not None:
            envelope["candidate_book"] = candidate_book
        if receipt.qkernel_execution_economics is not None:
            envelope["qkernel_execution_economics"] = _json_finite(
                receipt.qkernel_execution_economics
            )
        return dataclass_replace(receipt, envelope_json=envelope_to_json(envelope))
    except Exception:  # noqa: BLE001 — observability must never alter or fail a decision
        return receipt


def _event_submission_receipt_from_typed_receipt_payload(
    raw_receipt: dict[str, Any],
    event: OpportunityEvent,
    *,
    decision_proof_bundle: NoSubmitProofBundle | None = None,
) -> EventSubmissionReceipt:
    schema = str(raw_receipt.get("schema") or "")
    if schema != "edli_event_bound_no_submit_v1":
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason="EDLI_EVENT_BOUND_RECEIPT_SCHEMA_INVALID",
        )
    if str(raw_receipt.get("side_effect_status") or "") != "NO_SUBMIT":
        return EventSubmissionReceipt(
            False,
            event.event_id,
            event.causal_snapshot_id,
            reason="EDLI_EVENT_BOUND_RECEIPT_NOT_NO_SUBMIT",
        )
    return EventSubmissionReceipt(
        submitted=bool(raw_receipt.get("submitted")),
        event_id=str(raw_receipt.get("event_id") or ""),
        causal_snapshot_id=raw_receipt.get("causal_snapshot_id"),
        city=raw_receipt.get("city"),
        target_date=raw_receipt.get("target_date"),
        metric=raw_receipt.get("metric"),
        condition_id=raw_receipt.get("condition_id"),
        token_id=raw_receipt.get("token_id"),
        outcome_label=raw_receipt.get("outcome_label"),
        candidate_id=raw_receipt.get("candidate_id"),
        executable_snapshot_id=raw_receipt.get("executable_snapshot_id"),
        family_id=raw_receipt.get("family_id"),
        bin_label=raw_receipt.get("bin_label"),
        direction=raw_receipt.get("direction"),
        q_live=_optional_float(raw_receipt.get("q_live")),
        q_lcb_5pct=_optional_float(raw_receipt.get("q_lcb_5pct")),
        c_fee_adjusted=_optional_float(raw_receipt.get("c_fee_adjusted")),
        c_cost_95pct=_optional_float(raw_receipt.get("c_cost_95pct")),
        p_fill_lcb=_optional_float(raw_receipt.get("p_fill_lcb")),
        trade_score=_optional_float(raw_receipt.get("trade_score")),
        native_quote_available=_optional_bool(raw_receipt.get("native_quote_available")),
        source_status=raw_receipt.get("source_status"),
        family_complete=_optional_bool(raw_receipt.get("family_complete")),
        trade_score_positive=bool(raw_receipt.get("trade_score_positive")),
        fdr_pass=bool(raw_receipt.get("fdr_pass")),
        fdr_family_id=raw_receipt.get("fdr_family_id"),
        fdr_hypothesis_count=int(raw_receipt.get("fdr_hypothesis_count") or 0),
        kelly_pass=bool(raw_receipt.get("kelly_pass")),
        kelly_execution_price_type=raw_receipt.get("kelly_execution_price_type"),
        kelly_price_fee_deducted=bool(raw_receipt.get("kelly_price_fee_deducted")),
        kelly_size_usd=float(raw_receipt.get("kelly_size_usd") or 0.0),
        kelly_cost_basis_id=raw_receipt.get("kelly_cost_basis_id"),
        kelly_decision_id=raw_receipt.get("kelly_decision_id"),
        risk_decision_id=raw_receipt.get("risk_decision_id"),
        final_intent_id=raw_receipt.get("final_intent_id"),
        neg_risk=bool(raw_receipt.get("neg_risk") or False),
        side_effect_status="NO_SUBMIT",
        reason=str(raw_receipt.get("reason") or "event_bound_final_intent_no_submit"),
        proof_accepted=bool(raw_receipt.get("proof_accepted")),
        decision_proof_bundle=decision_proof_bundle,
        mainstream_agreement_pass=_optional_bool(raw_receipt.get("mainstream_agreement_pass")),
        mainstream_agreement_fail_reason=raw_receipt.get("mainstream_agreement_fail_reason"),
        mainstream_point=_optional_float(raw_receipt.get("mainstream_point")),
        mainstream_delta=_optional_float(raw_receipt.get("mainstream_delta")),
        mainstream_bin_label=raw_receipt.get("mainstream_bin_label"),
        mainstream_source=raw_receipt.get("mainstream_source"),
        mainstream_fetched_at_utc=raw_receipt.get("mainstream_fetched_at_utc"),
        q_source=raw_receipt.get("q_source"),  # #120 calibrator provenance
        day0_probability_authority=(
            raw_receipt.get("day0_probability_authority")
            if isinstance(raw_receipt.get("day0_probability_authority"), dict)
            else None
        ),
        # B3 authority stamp (mirrors q_source above): the spine-selected execution
        # authority must survive the dict->typed reconstruction or the taker-quality
        # gate is starved (stamp=None) and rejects every live spine taker.
        selection_authority_applied=raw_receipt.get("selection_authority_applied"),
        candidate_bin_id=raw_receipt.get("candidate_bin_id"),
        qkernel_execution_economics=raw_receipt.get("qkernel_execution_economics"),
        q_lcb_calibration_source=raw_receipt.get("q_lcb_calibration_source"),
        min_entry_price=_optional_float(raw_receipt.get("min_entry_price")),
        min_expected_profit_usd=_optional_float(raw_receipt.get("min_expected_profit_usd")),
        min_submit_edge_density=_optional_float(raw_receipt.get("min_submit_edge_density")),
        same_bin_yes_posterior=_optional_float(raw_receipt.get("same_bin_yes_posterior")),
        settlement_coverage_status=(
            str(raw_receipt["settlement_coverage_status"])
            if raw_receipt.get("settlement_coverage_status") is not None
            else None
        ),
        posterior_id=_optional_int(raw_receipt.get("posterior_id")),  # H2_E2E
        probability_authority=raw_receipt.get("probability_authority"),  # H2_E2E
        strategy_key=raw_receipt.get("strategy_key"),
        opportunity_book=raw_receipt.get("opportunity_book"),
        replacement_forecast=raw_receipt.get("replacement_forecast"),
        unit=raw_receipt.get("unit"),
        # P0 mode-authority (operator review 2026-06-10): the proven proof mode + maker
        # limit price travel as first-class receipt fields end-to-end so the final
        # command builder validates (never re-decides) against the proven mode.
        execution_mode_intent=raw_receipt.get("execution_mode_intent"),
        maker_limit_price=_optional_float(raw_receipt.get("maker_limit_price")),
        # K4.0: policy verdict + escalation deadline ride the receipt end-to-end.
        rest_then_cross_policy=raw_receipt.get("rest_then_cross_policy"),
        rest_escalation_deadline_minutes=_optional_float(
            raw_receipt.get("rest_escalation_deadline_minutes")
        ),
    )


def _build_submit_disabled_live_certificates(
    *,
    event: OpportunityEvent,
    receipt: EventSubmissionReceipt,
    decision_time: datetime,
    live_cap_conn: sqlite3.Connection | None = None,
    trade_conn: sqlite3.Connection | None = None,
    pre_submit_authority_provider: Callable[[DecisionCertificate, DecisionCertificate, datetime], PreSubmitAuthorityWitness] | None = None,
) -> tuple[DecisionCertificate, ...]:
    command_certificates = _build_live_execution_command_certificates(
        event=event,
        receipt=receipt,
        decision_time=decision_time,
        live_cap_conn=live_cap_conn,
        trade_conn=trade_conn,
        pre_submit_authority_provider=pre_submit_authority_provider,
    )
    command = _required_cert(command_certificates, claims.EXECUTION_COMMAND)
    certificate_decision_time = command.header.decision_time
    receipt_cert = build_execution_receipt_certificate(
        execution_command_cert=command,
        decision_time=certificate_decision_time,
        status="SUBMIT_DISABLED",
        reason_code="REAL_ORDER_SUBMIT_DISABLED",
    )
    transition_cert = _release_live_cap_for_submit_disabled(
        command_certificates,
        receipt_cert,
        live_cap_conn,
        decision_time=certificate_decision_time,
    )
    return command_certificates + (receipt_cert, transition_cert)


def _fallback_submit_result_after_live_command_failure(
    exc: BaseException,
    *,
    phase: str,
    decision_time: datetime,
) -> EventBoundExecutorSubmitResult:
    """Terminal submit-result fallback after ExecutionCommandCreated is durable.

    If the adapter fails after the command proof is committed but before the
    sanctioned executor returns a normalized result, the aggregate must still
    receive a terminal side-effect event. Before the executor call starts there
    is provably no venue side effect; during the executor call the side effect is
    unknown unless the executor boundary returns its own typed result.
    """

    reason = (
        "EDLI_LIVE_POST_COMMAND_SUBMIT_FAILURE:"
        f"{str(phase or 'unknown')}:{type(exc).__name__}:{str(exc)[:180]}"
    )
    now_iso = datetime.now(UTC).isoformat()
    if phase == "calling_executor_submit":
        return EventBoundExecutorSubmitResult(
            status="POST_SUBMIT_UNKNOWN",
            reason_code=reason,
            submit_started_at=decision_time.astimezone(UTC).isoformat(),
            submit_finished_at=now_iso,
            raw_response={
                "phase": phase,
                "exception_type": type(exc).__name__,
                "message": str(exc),
            },
            reconciliation_followup_required=True,
            venue_call_started=True,
            venue_ack_received=False,
            side_effect_known=False,
        )
    return EventBoundExecutorSubmitResult(
        status="PRE_SUBMIT_ERROR",
        reason_code=reason,
        submit_started_at=None,
        submit_finished_at=now_iso,
        raw_response={
            "phase": phase,
            "exception_type": type(exc).__name__,
            "message": str(exc),
        },
        reconciliation_followup_required=False,
        venue_call_started=False,
        venue_ack_received=False,
        side_effect_known=True,
    )


def _normalize_event_bound_executor_submit_result(
    result: EventBoundExecutorSubmitResult,
) -> EventBoundExecutorSubmitResult:
    status = str(result.status or "").strip().upper()
    venue_call_started = bool(result.venue_call_started)
    venue_ack_received = bool(result.venue_ack_received)
    reconciliation_followup_required = bool(result.reconciliation_followup_required)
    side_effect_known = bool(result.side_effect_known)

    if status in {"SUBMITTED", "REJECTED", "TIMEOUT_UNKNOWN", "POST_SUBMIT_UNKNOWN"}:
        venue_call_started = True
    if status in {"SUBMITTED", "REJECTED"}:
        venue_ack_received = True
        side_effect_known = True
    if status in {"TIMEOUT_UNKNOWN", "POST_SUBMIT_UNKNOWN"}:
        reconciliation_followup_required = True
    if status == "POST_SUBMIT_UNKNOWN":
        side_effect_known = False
    if status == "PRE_SUBMIT_ERROR":
        venue_call_started = False
        venue_ack_received = False
        side_effect_known = True

    if (
        venue_call_started == result.venue_call_started
        and venue_ack_received == result.venue_ack_received
        and reconciliation_followup_required == result.reconciliation_followup_required
        and side_effect_known == result.side_effect_known
    ):
        return result
    return dataclass_replace(
        result,
        venue_call_started=venue_call_started,
        venue_ack_received=venue_ack_received,
        reconciliation_followup_required=reconciliation_followup_required,
        side_effect_known=side_effect_known,
    )


# Sentinel prefix the caller (process_pending submit body) recognizes to map a
# final-stage mode-flip to the first-class SUBMIT_ABORTED_MODE_FLIPPED lifecycle
# state instead of the generic EDLI_LIVE_CERTIFICATE_BUILD_FAILED. The single
# source of truth for the reason string is _SUBMIT_ABORT_RECEIPT_REASON keyed on
# CandidateLifecycleState.SUBMIT_ABORTED_MODE_FLIPPED.
_MODE_FLIPPED_ABORT_PREFIX = "SUBMIT_ABORTED_MODE_FLIPPED"
_PRICE_MOVED_ABORT_PREFIX = "SUBMIT_ABORTED_PRICE_MOVED"


class _SubmitAbortedModeFlipped(ValueError):
    """Typed final-stage abort: the proven proof mode is no longer executable.

    The selected proof's maker/taker ``execution_mode_intent`` was proven through
    submit recapture under that mode's economics. A MAKER proof may upgrade to a
    TAKER submit only when the fresh rest-then-cross policy and downstream taker
    certificates clear on the same live book. TAKER->MAKER, missing/unknown proof
    mode, and legacy second-doctrine mode changes remain stale/unproven economics
    and abort for a full re-rank.

    Subclasses ValueError so it propagates through the existing ``except Exception``
    submit boundary; the caller maps it to the first-class SUBMIT_ABORTED_MODE_FLIPPED
    receipt by matching :data:`_MODE_FLIPPED_ABORT_PREFIX`.
    """


_TAKER_TOUCH_RESERVATION_RACE_PREFIXES = (
    "TAKER_BUY_TOUCH_EXCEEDS_RESERVATION",
    "TAKER_SELL_TOUCH_BELOW_RESERVATION",
)


def _submit_price_moved_abort_reason(exc: BaseException) -> str | None:
    """Map final taker touch/reservation races to the first-class price-moved abort.

    The fresh JIT book can make the selected taker leg no longer executable at its
    admitted reservation before any venue POST occurs. That is the same transient
    stale-decision-vs-fresh-book family as submit recapture PRICE_MOVED, not a
    structural certificate-build failure.
    """

    message = str(exc)
    if any(
        message.startswith(prefix) or f":{prefix}" in message
        for prefix in _TAKER_TOUCH_RESERVATION_RACE_PREFIXES
    ):
        return f"{_PRICE_MOVED_ABORT_PREFIX}:{message}"
    return None


_PRESUBMIT_STRATEGY_FLOOR_ABORT_REASONS: tuple[tuple[str, str], ...] = (
    (
        "PreSubmitRevalidated entry price below strategy floor",
        "SUBMIT_ABORTED_ENTRY_PRICE_BELOW_STRATEGY_FLOOR",
    ),
    (
        "PreSubmitRevalidated expected profit below strategy floor",
        "SUBMIT_ABORTED_EXPECTED_PROFIT_BELOW_STRATEGY_FLOOR",
    ),
    (
        "PreSubmitRevalidated submit edge density below strategy floor",
        "SUBMIT_ABORTED_EDGE_DENSITY_BELOW_STRATEGY_FLOOR",
    ),
)


def _presubmit_strategy_floor_abort_reason(exc: BaseException) -> str | None:
    if not isinstance(exc, LiveOrderAggregateError):
        return None
    message = str(exc)
    for needle, reason_base in _PRESUBMIT_STRATEGY_FLOOR_ABORT_REASONS:
        if needle in message:
            return f"{reason_base}:{message}"
    return None


def _fresh_rest_then_cross_mode(
    *,
    actionable_payload: Mapping[str, Any],
    executable_snapshot: "DecisionCertificate",
    fresh_best_bid: float | None,
    fresh_best_ask: float | None,
    tick_size: float,
    decision_time: datetime,
) -> str:
    """Fresh-book mode via the SAME K4.0 rest-then-cross policy as the proof.

    Single mode authority (twin-authority #9): the validator compares proof mode
    against a policy-consistent fresh evaluation — same doctrine, fresh inputs.
    Inputs mirror the proof side: the candidate's q_lcb and fee-adjusted
    reservation from the actionable payload; the taker all-in cost recomputed on
    the FRESH ask with the same taker fee law (0.05*p*(1-p)); minutes to event
    end from the snapshot's market_end_at.

    Rest-state flags: the proof's adjudicated POLICY LANE is the single
    authority for them (it travels on the payload as ``rest_then_cross_policy``).
    A proof in the escalated lane (TAKER_ESCALATED_AFTER_REST) re-evaluates
    fresh WITH ``escalated_after_rest=True`` — hardcoding False here
    re-adjudicated the lane and made every deadline cross recompute as
    REST_DEFAULT/MAKER, i.e. a guaranteed MODE_FLIPPED abort loop on exactly
    the orders the escalation job exists to place (external review finding,
    2026-06-11). The fresh evaluation still subordinates to the fresh book: if
    the fresh taker lane is inadmissible (spread guard), the policy rests and
    the validator aborts the cross — the correct outcome.
    ``unexpired_family_rest`` stays False: the HOLD lane yields chosen_ev=-inf
    at proof time and never reaches submit. Missing fresh inputs degrade to
    MAKER (the conservative resting default), matching the policy's own
    unknown-horizon behavior.
    """
    from src.strategy.live_inference.mode_consistent_ev import (
        POLICY_TAKER_ESCALATED_AFTER_REST,
        select_rest_then_cross_mode,
    )

    if _day0_maker_only_required(actionable_payload):
        return "MAKER"

    proof_policy = str(actionable_payload.get("rest_then_cross_policy") or "").strip()
    escalated_after_rest = proof_policy == POLICY_TAKER_ESCALATED_AFTER_REST
    q_lcb = _optional_float(actionable_payload.get("q_lcb_5pct"))
    reservation = _optional_float(actionable_payload.get("c_fee_adjusted"))
    taker_all_in = None
    if fresh_best_ask is not None and 0.0 < float(fresh_best_ask) < 1.0:
        ask = float(fresh_best_ask)
        taker_all_in = ask + 0.05 * ask * (1.0 - ask)
    minutes_to_event_end: float | None = None
    market_end_raw = executable_snapshot.payload.get("market_end_at")
    end_dt = _parse_utc(str(market_end_raw)) if market_end_raw else None
    if end_dt is not None:
        minutes_to_event_end = max(
            0.0, (end_dt - decision_time.astimezone(UTC)).total_seconds() / 60.0
        )
    if q_lcb is None or reservation is None:
        return "MAKER"
    # P0-1 (2026-06-23): mode selection must use the SAME execution-conditioned bound the taker
    # quality proof gate uses (_build_event_bound_taker_quality_proof), else mode could pick TAKER
    # off the plain q_lcb while the proof refuses it -> a MODE_FLIPPED abort loop. Absent/thin
    # cell -> q_exec_lcb == q_lcb (identity).
    q_exec_lcb_value, _ = _event_bound_q_exec_lcb(
        direction=str(actionable_payload.get("direction") or ""),
        price=fresh_best_ask,
        q_decision_lcb=float(q_lcb),
    )
    mode_ev = select_rest_then_cross_mode(
        q_lcb=float(q_lcb),
        q_exec_lcb=q_exec_lcb_value,
        taker_all_in_cost=taker_all_in,
        p_fill_taker=1.0,
        best_bid=fresh_best_bid,
        best_ask=fresh_best_ask,
        tick_size=float(tick_size),
        reservation=float(reservation),
        minutes_to_event_end=minutes_to_event_end,
        unexpired_family_rest=False,
        escalated_after_rest=escalated_after_rest,
    )
    chosen = str(getattr(mode_ev, "chosen_mode", "") or "").strip().upper()
    return chosen if chosen in {"MAKER", "TAKER"} else "MAKER"


def _validate_final_order_mode_or_abort(
    *,
    proof_mode: str | None,
    fresh_mode: str,
    fresh_best_bid: float | None,
    fresh_best_ask: float | None,
) -> str:
    """Validate or upgrade the proven proof mode against the fresh submit book.

    The fresh-book ``fresh_mode`` comes from the same rest-then-cross policy that selected
    the proof mode. It is therefore allowed to upgrade a resting maker proof into a taker
    submit when the live book now clears the crossing economics. Other disagreements remain
    fail-closed because they indicate stale or unproven submit economics.

    * proof_mode present and EQUAL to fresh_mode  -> return proof_mode.
    * proof_mode MAKER and fresh_mode TAKER       -> return TAKER; downstream taker
      quality, pre-submit, and executor expressibility certificates must still pass.
    * proof_mode TAKER and fresh_mode MAKER       -> raise _SubmitAbortedModeFlipped.
    * proof_mode MISSING / unknown at this stage  -> FAIL CLOSED: raise (treat as unproven;
      never default to a taker submit).
    """
    _proof = str(proof_mode or "").strip().upper() or None
    _fresh = str(fresh_mode or "").strip().upper() or None
    if _proof not in {"MAKER", "TAKER"}:
        # Fail-closed: a missing/unknown proven mode at the final stage is unproven.
        raise _SubmitAbortedModeFlipped(
            f"{_MODE_FLIPPED_ABORT_PREFIX}:proof_mode={_proof}:fresh_mode={_fresh}:"
            f"reason=MISSING_OR_UNKNOWN_PROOF_MODE:"
            f"fresh_bid={fresh_best_bid}:fresh_ask={fresh_best_ask}"
        )
    if _proof != _fresh:
        if _proof == "MAKER" and _fresh == "TAKER":
            return "TAKER"
        raise _SubmitAbortedModeFlipped(
            f"{_MODE_FLIPPED_ABORT_PREFIX}:proof_mode={_proof}:fresh_mode={_fresh}:"
            f"fresh_bid={fresh_best_bid}:fresh_ask={fresh_best_ask}"
        )
    return _proof


def _event_bound_q_exec_lcb(
    *, direction: str, price: float | None, q_decision_lcb: float
) -> tuple[float, str]:
    """Execution-(price)-conditioned tightening of the buy_no authorization bound.

    Returns ``(min(q_decision_lcb, realized_no_rate_lcb(price)), basis)``. The selection-curse bound
    (src/decision/selection_curse_bound.py) is loaded read-only and FAIL-SOFT: absent / unarmed
    side / price out of training support (or a missing direction/price) yields the plain
    ``q_decision_lcb`` (identity no-op, today's exact behavior), so this can ONLY ever TIGHTEN, never
    loosen. The bound is the settlement-evidenced realized NO win-rate as a monotone function of the
    NO price, fit walk-forward on the counterfactual admission ledger — it deflates mid-price buy_no
    (the +14pp winner's curse) toward its realized rate while leaving deep favorites and buy_yes
    untouched (docs/evidence/live_order_pathology/2026-06-23_selection_curse_*.md).

    Called by ALL THREE taker mode/admission seams off the SAME (side, price) so the bound is one
    consistent value: the proof-side mode decision (_mode_consistent_ev_for_proof), the submit-time
    fresh re-eval (_fresh_rest_then_cross_mode), and the taker quality proof gate
    (_build_event_bound_taker_quality_proof). The basis travels on the receipt for settlement audit.
    """
    # FAIL-SOFT: any error in the correction (load, parse, interp) must degrade to the raw bound and
    # never break the live gate. corrected_side_q_lcb already returns identity for non-finite price /
    # buy_yes / absent / unarmed / out-of-support; this wrapper additionally catches import/IO faults.
    try:
        from src.decision.selection_curse_bound import corrected_side_q_lcb
        from src.decision.selection_curse_bound_loader import load_bound

        side = str(direction or "").strip().lower()
        if not side or price is None:
            return float(q_decision_lcb), "BOUND_INPUTS_MISSING"
        return corrected_side_q_lcb(
            load_bound(), side=side, price=price, raw_q_lcb=q_decision_lcb
        )
    except Exception as exc:  # noqa: BLE001 — never break admission for the correction.
        logger.warning("selection-curse correction failed, using raw q_lcb: %s", exc)
        try:
            return float(q_decision_lcb), "BOUND_ERROR"
        except (TypeError, ValueError):
            return 0.0, "BOUND_ERROR"


def _build_event_bound_taker_quality_proof(
    *,
    actionable_payload: Mapping[str, Any],
    order_mode: str,
    fresh_best_bid: float | None,
    fresh_best_ask: float | None,
) -> dict[str, object] | None:
    """Build the executor-required taker proof for event-bound final intents."""

    if str(order_mode or "").strip().upper() != "TAKER":
        return None
    direction = str(actionable_payload.get("direction") or "")
    touch = fresh_best_ask if direction.startswith("buy_") else fresh_best_bid
    q_lcb_source = "q_lcb_5pct"
    if actionable_payload.get("qkernel_execution_economics") is not None:
        # B3 (PR415, 2026-06-20) — MANDATORY authority stamp + STRICT selected-candidate
        # identity match BEFORE the qkernel payoff_q_lcb may drive the money-path taker
        # proof. A syntactically-valid qkernel economics cert is NOT sufficient: it must
        # ALSO be (a) under qkernel execution authority for THIS payload
        # (q_source == "qkernel_spine"), and (b) bound to the SELECTED candidate the
        # payload is for (cert.candidate_id == payload.candidate_id). The cert's own
        # source/route/side/bin consistency is enforced by
        # _valid_qkernel_execution_economics_payload. Any absence OR mismatch FAILS
        # CLOSED here (passed=False with a typed reason) — it does NOT silently fall
        # through to the q_lcb_5pct path, because a present-but-unbound/unstamped cert is
        # a provenance fault, not a license to size off a different authority's q. This
        # mirrors the consume-time guard _qkernel_execution_economics() (bin/route/side
        # identity) and the receipt-time _assert_receipt_qkernel_execution_economics()
        # (hash-equality vs the book) — closing the money-path gap where the taker proof
        # consumed the cert WITHOUT the authority+identity pair.
        # B3 authority stamp — read the SAME fields as the canonical
        # _proof_uses_qkernel_spine: the qkernel_spine_bridge PRESERVES q_source as the
        # probability track label ("replacement_0_1") and records the EXECUTION authority
        # in selection_authority_applied="qkernel_spine". Checking only the outer q_source
        # rejected EVERY live spine-selected taker (2026-06-23). Accept EITHER stamp;
        # cert validity (source=="qkernel_spine") and candidate identity are still
        # enforced below.
        _under_qkernel_authority = (
            str(actionable_payload.get("selection_authority_applied") or "").strip()
            == "qkernel_spine"
            or str(actionable_payload.get("q_source") or "").strip() == "qkernel_spine"
        )
        if not _under_qkernel_authority:
            return {
                "schema_version": 1,
                "passed": False,
                "reason": "qkernel_cert_present_without_qkernel_authority_stamp",
                "model_confidence": "0",
                "taker_fee_adjusted_edge": "0",
                "taker_expected_profit_usd": "0",
                "maker_expected_profit_usd": "0",
                "incremental_expected_profit_usd": "0",
            }
        qkernel_cert = _valid_qkernel_execution_economics_payload(
            actionable_payload.get("qkernel_execution_economics"),
            direction=direction,
        )
        if qkernel_cert is None:
            return {
                "schema_version": 1,
                "passed": False,
                "reason": "qkernel_execution_economics_missing_or_invalid",
                "model_confidence": "0",
                "taker_fee_adjusted_edge": "0",
                "taker_expected_profit_usd": "0",
                "maker_expected_profit_usd": "0",
                "incremental_expected_profit_usd": "0",
            }
        cert_candidate_id = str(qkernel_cert.get("candidate_id") or "").strip()
        payload_candidate_id = str(actionable_payload.get("candidate_id") or "").strip()
        # IDENTITY (B3, corrected 2026-06-23): the cert (qkernel namespace,
        # candidate_id == SIDE:bin_id:route_id) and the reactor payload (Polymarket
        # namespace, candidate_id == family_id:condition_id, event_reactor_adapter.py
        # ~4228) reference the SAME selected leg in DIFFERENT id-spaces, so raw
        # candidate_id equality can NEVER hold for a live spine taker (PR415's check
        # rejected every one: qkernel_cert_candidate_identity_mismatch on every cycle,
        # 2026-06-23). The SHARED identity key is the bin_id hash — the cert's bin_id
        # is byte-identical to the reactor's _candidate_bin_id(proof) (qkernel_spine_
        # bridge._candidate_bin_id_for), threaded onto the payload as candidate_bin_id.
        # Identity holds if EITHER a full candidate_id match (test/legacy, same space)
        # OR a bin_id match (live spine) — both are sufficient proofs of the same leg,
        # and the side is already validated by _valid_qkernel_execution_economics_payload
        # (bin_id + side == full leg identity), so the OR never loosens the foreign-cert
        # guard: a cert for a different bin/side fails both disjuncts.
        cert_bin_id = str(qkernel_cert.get("bin_id") or "").strip()
        if not cert_bin_id and cert_candidate_id:
            # bin_id is the middle segment of the qkernel candidate_id (SIDE:bin_id:route_id)
            _cid_parts = cert_candidate_id.split(":", 2)
            if len(_cid_parts) >= 2:
                cert_bin_id = _cid_parts[1].strip()
        payload_bin_id = str(actionable_payload.get("candidate_bin_id") or "").strip()
        _candidate_id_match = bool(
            cert_candidate_id
            and payload_candidate_id
            and cert_candidate_id == payload_candidate_id
        )
        _bin_id_match = bool(cert_bin_id and payload_bin_id and cert_bin_id == payload_bin_id)
        if not (_candidate_id_match or _bin_id_match):
            # OBSERVABILITY (2026-06-23): surface both id-spaces AND the bin_id key so a
            # genuine mismatch is distinguishable from a still-unthreaded candidate_bin_id.
            logging.getLogger(__name__).info(
                "b3_identity_mismatch_debug: cert_candidate_id=%s payload_candidate_id=%s "
                "cert_bin_id=%s payload_candidate_bin_id=%s cert_route_id=%s cert_side=%s "
                "payload_condition_id=%s direction=%s",
                cert_candidate_id,
                payload_candidate_id,
                cert_bin_id,
                payload_bin_id,
                qkernel_cert.get("route_id"),
                qkernel_cert.get("side"),
                actionable_payload.get("condition_id"),
                direction,
            )
            return {
                "schema_version": 1,
                "passed": False,
                "reason": "qkernel_cert_candidate_identity_mismatch",
                "model_confidence": "0",
                "taker_fee_adjusted_edge": "0",
                "taker_expected_profit_usd": "0",
                "maker_expected_profit_usd": "0",
                "incremental_expected_profit_usd": "0",
            }
        near_day0_reason = _qkernel_near_day0_cert_rejection_reason(qkernel_cert)
        if near_day0_reason is not None:
            return {
                "schema_version": 1,
                "passed": False,
                "reason": near_day0_reason,
                "model_confidence": "0",
                "taker_fee_adjusted_edge": "0",
                "taker_expected_profit_usd": "0",
                "maker_expected_profit_usd": "0",
                "incremental_expected_profit_usd": "0",
                "q_lcb_source": q_lcb_source,
            }
        q_live = _optional_float(qkernel_cert.get("payoff_q_point"))
        q_lcb = _optional_float(qkernel_cert.get("payoff_q_lcb"))
        payload_q_live = _optional_float(actionable_payload.get("q_live"))
        payload_q_lcb = _optional_float(actionable_payload.get("q_lcb_5pct"))
        if (
            q_live is None
            or q_lcb is None
            or payload_q_live is None
            or payload_q_lcb is None
        ):
            return {
                "schema_version": 1,
                "passed": False,
                "reason": "qkernel_live_posterior_bound_missing",
                "model_confidence": "0",
                "taker_fee_adjusted_edge": "0",
                "taker_expected_profit_usd": "0",
                "maker_expected_profit_usd": "0",
                "incremental_expected_profit_usd": "0",
            }
        if not (
            math.isclose(q_live, payload_q_live, rel_tol=1e-9, abs_tol=1e-6)
            and math.isclose(q_lcb, payload_q_lcb, rel_tol=1e-9, abs_tol=1e-6)
        ):
            return {
                "schema_version": 1,
                "passed": False,
                "reason": "qkernel_payoff_probability_mismatch",
                "model_confidence": "0",
                "taker_fee_adjusted_edge": "0",
                "taker_expected_profit_usd": "0",
                "maker_expected_profit_usd": "0",
                "incremental_expected_profit_usd": "0",
            }
        q_lcb_source = "qkernel_execution_economics.payoff_q_lcb"
    else:
        q_live = _optional_float(actionable_payload.get("q_live"))
        q_lcb = _optional_float(actionable_payload.get("q_lcb_5pct"))
    notional = _optional_float(
        actionable_payload.get("live_cap_reserved_notional_usd")
        or actionable_payload.get("kelly_size_usd")
    )
    if touch is None or q_lcb is None or notional is None:
        return {
            "schema_version": 1,
            "passed": False,
            "reason": "missing_taker_quality_inputs",
            "model_confidence": "0",
            "taker_fee_adjusted_edge": "0",
            "taker_expected_profit_usd": "0",
            "maker_expected_profit_usd": "0",
            "incremental_expected_profit_usd": "0",
        }
    touch_dec = Decimal(str(touch))
    q_lcb_dec = Decimal(str(q_lcb))
    notional_dec = Decimal(str(max(float(notional), 0.0)))
    from src.strategy.live_inference.live_admission import (
        live_entry_probability_quality_rejection_reason,
    )

    live_win_rate_floor_reason = live_entry_probability_quality_rejection_reason(
        q_lcb=q_lcb,
        direction=direction,
        strategy_key=actionable_payload.get("strategy_key"),
        selection_authority_applied=actionable_payload.get("selection_authority_applied"),
        qkernel_execution_economics=actionable_payload.get("qkernel_execution_economics"),
    )
    if live_win_rate_floor_reason is not None:
        return {
            "schema_version": 1,
            "passed": False,
            "reason": live_win_rate_floor_reason,
            "model_confidence": "0",
            "taker_fee_adjusted_edge": "0",
            "taker_expected_profit_usd": "0",
            "maker_expected_profit_usd": "0",
            "incremental_expected_profit_usd": "0",
            "q_lcb_source": q_lcb_source,
        }
    fee_dec = Decimal("0.05") * touch_dec * (Decimal("1") - touch_dec)
    # P0-1 (2026-06-23): the after-cost admissibility edge is gated on the EXECUTION-CONDITIONED
    # bound q_exec_lcb = min(q_lcb, settlement-evidenced cell LCB), never the plain q_lcb. Absent/
    # thin cell -> q_exec_lcb == q_lcb (identity). q_lcb_dec is still used for model_confidence (a
    # belief-gap telemetry, not a gate). This only TIGHTENS the cross, consistent with FIX B.
    q_exec_lcb_value, q_exec_lcb_basis = _event_bound_q_exec_lcb(
        direction=direction, price=float(touch), q_decision_lcb=float(q_lcb)
    )
    q_gate_dec = Decimal(str(q_exec_lcb_value))
    taker_edge_dec = q_gate_dec - touch_dec - fee_dec
    taker_expected_profit_usd = (
        max(Decimal("0"), taker_edge_dec)
        * notional_dec
        / max(touch_dec, Decimal("0.000001"))
    )

    maker_limit = _optional_float(actionable_payload.get("proof_maker_limit_price"))
    proof_ev_maker = _optional_float(actionable_payload.get("proof_ev_maker"))
    maker_expected_profit_usd = Decimal("0")
    if maker_limit is not None and proof_ev_maker is not None and maker_limit > 0:
        maker_expected_profit_usd = (
            max(Decimal("0"), Decimal(str(proof_ev_maker)))
            * notional_dec
            / Decimal(str(maker_limit))
        )
    incremental_expected_profit_usd = taker_expected_profit_usd - maker_expected_profit_usd
    confidence_gap = Decimal("1")
    if q_live is not None:
        confidence_gap = Decimal("1") - abs(Decimal(str(q_live)) - q_lcb_dec)
    model_confidence = max(Decimal("0"), min(Decimal("1"), confidence_gap))

    min_taker_edge = Decimal(str(actionable_payload.get("min_taker_fee_adjusted_edge") or "0.03"))
    min_incremental_profit = Decimal(str(actionable_payload.get("min_taker_incremental_profit_usd") or "0.05"))
    min_model_confidence = Decimal(str(actionable_payload.get("min_taker_model_confidence") or "0.60"))
    min_profit_ratio = Decimal(str(actionable_payload.get("min_taker_profit_ratio") or "1.20"))
    live_quality_floors = _event_bound_effective_live_quality_floors(actionable_payload)
    declared_min_entry_price = Decimal(str(live_quality_floors["min_entry_price"]))
    floor_decision = entry_price_floor_decision(
        strategy_key=actionable_payload.get("strategy_key"),
        direction=actionable_payload.get("direction"),
        declared_min_entry_price=declared_min_entry_price,
        selection_authority_applied=actionable_payload.get("selection_authority_applied"),
        economics=(
            actionable_payload.get("qkernel_execution_economics")
            if isinstance(actionable_payload.get("qkernel_execution_economics"), Mapping)
            else None
        ),
        q_live=q_live,
        q_lcb=q_lcb,
        limit_price=touch,
    )
    effective_min_entry_price = Decimal(str(floor_decision.effective_min_entry_price))
    min_expected_profit = Decimal(str(live_quality_floors["min_expected_profit_usd"]))
    min_submit_edge_density = Decimal(str(live_quality_floors["min_submit_edge_density"]))
    required_profit = max(
        maker_expected_profit_usd * min_profit_ratio,
        maker_expected_profit_usd + min_incremental_profit,
    )
    taker_edge_density = taker_edge_dec / max(touch_dec, Decimal("0.000001"))
    conservative_surplus_ok = taker_edge_dec >= Decimal("0")
    taker_quality_threshold_pass = bool(
        taker_edge_dec >= min_taker_edge
        and incremental_expected_profit_usd >= min_incremental_profit
        and taker_expected_profit_usd >= required_profit
        and model_confidence >= min_model_confidence
    )
    entry_price_floor_pass = bool(touch_dec + Decimal("1e-12") >= effective_min_entry_price)
    strategy_quality_floor_pass = bool(
        entry_price_floor_pass
        and taker_expected_profit_usd >= min_expected_profit
        and taker_edge_density >= min_submit_edge_density
    )
    passed = bool(
        conservative_surplus_ok
        and taker_quality_threshold_pass
        and strategy_quality_floor_pass
    )
    reason = "allowed"
    if not conservative_surplus_ok:
        reason = "negative_conservative_after_cost_surplus"
    elif not taker_quality_threshold_pass:
        reason = "taker_quality_threshold_not_met"
    elif not strategy_quality_floor_pass:
        reason = "strategy_live_quality_floor_not_met"
    return {
        "schema_version": 1,
        "passed": bool(passed),
        "reason": reason,
        "passed_basis": "conservative_after_cost_plus_taker_and_strategy_quality_floors",
        "taker_quality_threshold_pass": taker_quality_threshold_pass,
        "strategy_quality_floor_pass": strategy_quality_floor_pass,
        "legacy_threshold_pass": taker_quality_threshold_pass,
        "taker_fee_adjusted_edge": str(taker_edge_dec),
        "taker_fee_adjusted_edge_density": str(taker_edge_density),
        "taker_expected_profit_usd": str(taker_expected_profit_usd),
        "maker_expected_profit_usd": str(maker_expected_profit_usd),
        "incremental_expected_profit_usd": str(incremental_expected_profit_usd),
        "model_confidence": str(model_confidence),
        "model_confidence_source": "q_live_minus_q_lcb_gap",
        "min_taker_fee_adjusted_edge": str(min_taker_edge),
        "min_taker_incremental_profit_usd": str(min_incremental_profit),
        "min_taker_model_confidence": str(min_model_confidence),
        "min_taker_profit_ratio": str(min_profit_ratio),
        "min_entry_price": str(declared_min_entry_price),
        "effective_min_entry_price": str(effective_min_entry_price),
        "qkernel_low_price_floor_authorized": str(
            floor_decision.qkernel_low_price_floor_authorized
        ),
        "entry_price_floor_applies": str(
            not floor_decision.qkernel_low_price_floor_authorized
        ),
        "entry_price_floor_pass": str(entry_price_floor_pass),
        "min_expected_profit_usd": str(min_expected_profit),
        "min_submit_edge_density": str(min_submit_edge_density),
        "fresh_touch_price": str(touch_dec),
        "fresh_touch_fee": str(fee_dec),
        "notional_usd": str(notional_dec),
        "maker_context_source": "proof_mode_ev",
        "q_lcb_source": q_lcb_source,
        "q_exec_lcb": str(q_exec_lcb_value),
        "q_exec_lcb_basis": q_exec_lcb_basis,
    }


def _day0_live_source_health_state(actionable_payload: Mapping[str, object]) -> str:
    """Compact health label for the Day0 live-admission predicate."""

    live_authority = str(actionable_payload.get("live_authority_status") or "").strip().lower()
    source_authorized = str(
        actionable_payload.get("source_authorized_status") or ""
    ).strip().upper()
    source_match = str(actionable_payload.get("source_match_status") or "").strip().upper()
    local_date = str(actionable_payload.get("local_date_status") or "").strip().upper()
    station = str(actionable_payload.get("station_match_status") or "").strip().upper()
    metric = str(actionable_payload.get("metric_match_status") or "").strip().upper()
    rounding = str(actionable_payload.get("rounding_status") or "").strip().upper()
    if (
        live_authority == "live"
        and source_authorized == "AUTHORIZED"
        and source_match == "MATCH"
        and local_date == "MATCH"
        and station == "MATCH"
        and metric == "MATCH"
        and rounding == "MATCH"
    ):
        return "OK_FAST_AND_WU"
    return "BLOCKED"


def _day0_bin_stress_verdict(
    *,
    actionable_payload: Mapping[str, object],
    event_payload: Mapping[str, object],
) -> tuple[float, bool]:
    """Return distance-to-death in integer quanta and one-bin-stress survival."""

    direction = str(actionable_payload.get("direction") or "").strip().lower()
    if direction != "buy_yes":
        return float("inf"), True
    observed_raw = event_payload.get("rounded_value")
    if observed_raw is None:
        observed_raw = actionable_payload.get("rounded_value")
    observed = _optional_float(observed_raw)
    if observed is None:
        return 0.0, False
    bin_label = str(actionable_payload.get("bin_label") or "").strip()
    if not bin_label:
        return 0.0, False
    try:
        from src.data.market_scanner import _parse_temp_range

        low, high = _parse_temp_range(bin_label)
    except Exception:  # noqa: BLE001
        return 0.0, False
    metric = str(
        actionable_payload.get("metric")
        or actionable_payload.get("temperature_metric")
        or event_payload.get("metric")
        or ""
    ).strip().lower()
    if metric == "high":
        if high is None:
            return float("inf"), True
        distance = max(0.0, float(high) - float(observed))
        return distance, bool(float(observed) + 1.0 <= float(high) + 1e-9)
    if metric == "low":
        if low is None:
            return float("inf"), True
        distance = max(0.0, float(observed) - float(low))
        return distance, bool(float(observed) - 1.0 >= float(low) - 1e-9)
    return 0.0, False


def _day0_live_submit_admission_rejection_reason(
    *,
    event: OpportunityEvent,
    actionable_payload: Mapping[str, object],
    authority_witness: PreSubmitAuthorityWitness,
    order_mode: str,
    decision_time: datetime,
) -> str | None:
    """Apply the Day0 live-admission predicate at the final submit seam."""

    event_type = str(actionable_payload.get("event_type") or "").strip()
    if event_type != "DAY0_EXTREME_UPDATED":
        return None
    from src.engine.day0_admission import (
        Day0AdmissionContext,
        day0_live_admission_rejection_reason,
    )

    event_payload = _payload(event)
    quote_time = (
        _parse_utc(authority_witness.book_captured_at)
        or _parse_utc(authority_witness.checked_at)
        or decision_time.astimezone(UTC)
    )
    observation_available = _parse_utc(
        event_payload.get("observation_available_at")
        or actionable_payload.get("observation_available_at")
    )
    distance_quanta, stress_survives = _day0_bin_stress_verdict(
        actionable_payload=actionable_payload,
        event_payload=event_payload,
    )
    station_id = str(event_payload.get("station_id") or "").strip()
    settlement_source_type = str(
        event_payload.get("settlement_source_type")
        or event_payload.get("source_type")
        or event_payload.get("settlement_source")
        or ""
    ).strip().lower()
    ctx = Day0AdmissionContext(
        event_type=event_type,
        city=str(actionable_payload.get("city") or event_payload.get("city") or ""),
        metric=str(
            actionable_payload.get("metric")
            or actionable_payload.get("temperature_metric")
            or event_payload.get("metric")
            or ""
        ),
        settlement_source_type=settlement_source_type,
        fast_obs_supported=bool(station_id and observation_available is not None),
        source_health_state=_day0_live_source_health_state(actionable_payload),
        execution_mode=str(order_mode or "").strip().lower(),
        quote_time_utc=quote_time,
        latest_observation_available_at_utc=observation_available,
        in_post_extreme_quiet_window=False,
        in_final_localday_noentry_window=False,
        selected_bin_edge_distance_quanta=distance_quanta,
        edge_survives_one_bin_stress=stress_survives,
        city_allowlist=frozenset(
            {str(actionable_payload.get("city") or event_payload.get("city") or "")}
        ),
    )
    return day0_live_admission_rejection_reason(ctx)


def _build_live_execution_command_certificates(
    *,
    event: OpportunityEvent,
    receipt: EventSubmissionReceipt,
    decision_time: datetime,
    live_cap_conn: sqlite3.Connection | None = None,
    trade_conn: sqlite3.Connection | None = None,
    pre_submit_authority_provider: Callable[[DecisionCertificate, DecisionCertificate, datetime], PreSubmitAuthorityWitness] | None = None,
) -> tuple[DecisionCertificate, ...]:
    _assert_event_bound_strategy_live_admitted(
        strategy_key=receipt.strategy_key,
        direction=receipt.direction,
        metric=receipt.metric,
    )
    _assert_event_bound_receipt_live_authority(receipt)
    proof_bundle = receipt.decision_proof_bundle
    decision_time = _live_certificate_decision_time_from_proof_bundle(decision_time, proof_bundle)
    compile_result = DecisionCompiler().compile_authority_graph(
        event,
        decision_time=decision_time,
        mode="LIVE",
        proof_bundle=proof_bundle,
    )
    if compile_result.status != "VERIFIED":
        # KILLER 2 (2026-05-31): surface the UNDERLYING failing assertion, not just the
        # generic stage reason_code. compiler._rejected() captures the specific failure
        # message in CompileFailure.reason_detail (e.g. the exact field/parent that failed
        # _validate_no_submit_parent_consistency), but only reason_code was propagated —
        # so 147/308 positive-edge candidates died as opaque NO_SUBMIT_CERTIFICATE_REJECTED
        # with no diagnosable sub-reason in no_trade_regret_events. Append reason_detail so
        # the regret row records WHY the no-submit certificate was rejected.
        if compile_result.failures:
            failure = compile_result.failures[0]
            reason = failure.reason_code
            detail = getattr(failure, "reason_detail", None)
            if detail:
                reason = f"{reason}:{detail}"
        else:
            reason = "LIVE_AUTHORITY_GRAPH_REJECTED"
        raise ValueError(reason)
    base_certs = tuple(compile_result.certificates)
    _assert_event_bound_calibration_live_admitted(_required_cert(base_certs, claims.CALIBRATION))
    executable_snapshot = _required_cert(base_certs, claims.EXECUTABLE_SNAPSHOT)
    day0_source_certs = _day0_live_source_parent_certificates(
        event=event,
        payload=_payload(event),
        base_certs=base_certs,
        decision_time=decision_time,
    )
    live_cap = _build_live_cap_certificate_from_ledger(
        event=event,
        receipt=receipt,
        decision_time=decision_time,
        live_cap_conn=live_cap_conn,
        persist=False,
    )
    try:
        actionable_payload = _actionable_payload_from_receipt(
            receipt,
            live_cap,
            event=event,
        )
        _assert_live_entry_submit_authority(actionable_payload)
        actionable = build_actionable_trade_certificate(
            payload=actionable_payload,
            parent_certificates=base_certs + day0_source_certs + (live_cap,),
            decision_time=decision_time,
        )
        forecast_authority = _required_cert(base_certs, claims.FORECAST_AUTHORITY)
        quote_feasibility = _required_cert(base_certs, claims.QUOTE_FEASIBILITY)
        cost_model = _required_cert(base_certs, claims.COST_MODEL)
        quote_payload = quote_feasibility.payload
        from types import SimpleNamespace

        side = "BUY" if str(actionable.payload.get("direction")) in {"buy_yes", "buy_no"} else "SELL"
        provisional_final_intent = SimpleNamespace(
            payload={
                "token_id": actionable.payload["token_id"],
                "side": side,
                "tick_size": float(_float_or_default(executable_snapshot.payload.get("min_tick_size"), 0.01)),
                "min_order_size": float(_float_or_default(executable_snapshot.payload.get("min_order_size"), 1.0)),
                "neg_risk": bool(actionable.payload.get("neg_risk", False)),
            }
        )
        authority_witness = _require_pre_submit_authority_witness(
            pre_submit_authority_provider,
            provisional_final_intent,
            executable_snapshot,
            decision_time,
        )
        fresh_best_bid = _optional_float(authority_witness.current_best_bid)
        fresh_best_ask = _optional_float(authority_witness.current_best_ask)
        # K=1 STAGE 1 (k1_final_snapshot_authority_plan_2026-06-11.md §4): persist the
        # fresh submit-time JIT book (R8 — already fetched [NET] above, inside the
        # witness provider) as ONE first-class executable_market_snapshots row tagged
        # source=JIT_PRESUBMIT, BEFORE it is consumed below. Pure additive persistence
        # + provenance; the witness STILL flows through the existing R9-R15 path
        # untouched. Wave-1 2026-06-12: the k1_persist_presubmit_snapshot_enabled flag is
        # DELETED — this is the receipt's provenance substrate, not a throttle, so it now
        # ALWAYS runs (fail-soft: a failed persist never blocks submit). §5.2 SQLite
        # discipline: the [NET] fetch is done; this opens a short-lived zeus_trades
        # write+commit only — the trade WAL lock is never held across the fetch, and
        # zeus-world (#95 mutex) is untouched.
        if trade_conn is not None:
            _k1_elected_id = str(
                executable_snapshot.payload.get("identity")
                or executable_snapshot.payload.get("selected_snapshot_id")
                or ""
            )
            _k1_elected_snapshot = None
            if _k1_elected_id:
                try:
                    _k1_elected_snapshot = get_snapshot(trade_conn, _k1_elected_id)
                except Exception:  # noqa: BLE001 - fail-soft: never block submit on a read
                    _k1_elected_snapshot = None
            persist_presubmit_jit_snapshot(
                trade_conn,
                _k1_elected_snapshot,
                witness=authority_witness,
                decision_time=decision_time,
            )
        best_bid = _optional_float(quote_payload.get("best_bid"))
        best_ask = _optional_float(quote_payload.get("best_ask"))
        # Mode redecision at the live submit boundary: proof mode is not decorative, but
        # a MAKER proof is only a resting plan. If the same rest-then-cross policy now
        # says the fresh book should be crossed, the builder may upgrade to TAKER and
        # must then pass taker quality, pre-submit revalidation, live-cap, and executor
        # certificates on that same fresh book. TAKER->MAKER and missing/unknown proof
        # modes still fail closed because those are stale/unproven submit economics.
        # SINGLE MODE AUTHORITY (twin-authority #9, 2026-06-11 live): the proof
        # mode comes from the K4.0 rest-then-cross policy; the validator's fresh
        # mode MUST come from the SAME policy evaluated on the FRESH book —
        # otherwise the two doctrines disagree systematically and every plan
        # aborts MODE_FLIPPED. The old bug was two independent doctrines: proof
        # mode from rest-then-cross, then a separate late EV override. The repair is
        # one doctrine, not forced maker: both proof and fresh validation use the
        # same conservative q/q_exec bound, spread/fee law, maker haircut, and
        # mode-consistent EV margin.
        _fresh_mode = _fresh_rest_then_cross_mode(
            actionable_payload=actionable.payload,
            executable_snapshot=executable_snapshot,
            fresh_best_bid=fresh_best_bid,
            fresh_best_ask=fresh_best_ask,
            tick_size=float(provisional_final_intent.payload["tick_size"]),
            decision_time=decision_time,
        )
        order_mode = _validate_final_order_mode_or_abort(
            proof_mode=str(actionable.payload.get("proof_execution_mode_intent") or "") or None,
            fresh_mode=_fresh_mode,
            fresh_best_bid=fresh_best_bid,
            fresh_best_ask=fresh_best_ask,
        )
        day0_admission_rejection = _day0_live_submit_admission_rejection_reason(
            event=event,
            actionable_payload=actionable.payload,
            authority_witness=authority_witness,
            order_mode=order_mode,
            decision_time=decision_time,
        )
        if day0_admission_rejection is not None:
            raise ValueError(f"DAY0_LIVE_ADMISSION_REJECTED:{day0_admission_rejection}")
        # WALL #1 (GATE #85 follow-on, 2026-06-01): the passive-maker context is a
        # MAKER-ONLY structural input. ``FinalExecutionIntent`` only requires it when
        # ``order_policy == "post_only_passive_limit"`` (execution_intent.py:1735); a
        # taker FOK/FAK crosses the JIT book at submit and never rests, so its
        # economics do not depend on the snapshot's top-of-book maker context.
        #
        # The pre-#85 path built ``_passive_maker_context_from_authorities``
        # UNCONDITIONALLY, which raises QUOTE_FEASIBILITY_BID_ASK_REQUIRED whenever the
        # elected snapshot has no captured book — killing every taker candidate whose
        # snapshot happened to be book-less (the DOMINANT live wall: 713/2h). Conditioning
        # the construction on order_mode makes that rejection CATEGORY impossible for
        # taker orders (Fitz #1: make the category impossible, not the instance). MAKER
        # still requires the maker context (and still raises if bid/ask are absent — the
        # correct fail-closed behavior, since a resting maker order genuinely needs a book).
        passive_maker_context = (
            _passive_maker_context_from_authorities(
                actionable=actionable,
                quote_feasibility_cert=quote_feasibility,
                executable_snapshot_cert=executable_snapshot,
                decision_time=decision_time,
            )
            if str(order_mode).strip().upper() == "MAKER"
            else None
        )
        # WALL #5 PRICE-SEAM DEFENSE (K=1, 2026-06-12). The maker limit is derived from the
        # quote-cert book (best_bid/best_ask). The pre-submit JIT witness (fresh_best_bid/ask)
        # is the SAME selected candidate's book re-fetched at submit time. If the two books'
        # mids disagree by more than a small tolerance the quote-cert book is not the
        # candidate's live book (wrong-bin book, or a stale ghost) — fail closed rather than
        # rest a maker order at a price the fresh book proves cannot fill. The root fix already
        # binds the cert to proof.row; this is the independent second wall at the price seam so
        # the 0.02-on-a-0.64-book intent is structurally unreachable even if the cert regresses.
        if str(order_mode).strip().upper() == "MAKER":
            _assert_maker_book_agrees_with_fresh_witness(
                quote_best_bid=best_bid,
                quote_best_ask=best_ask,
                fresh_best_bid=fresh_best_bid,
                fresh_best_ask=fresh_best_ask,
                tick_size=float(provisional_final_intent.payload["tick_size"]),
            )
        # SIZE-TO-DEPTH + SWEEP-VWAP (Wall B / Wall C, 2026-06-01):
        # For TAKER FOK orders, compute the crossable depth and sweep VWAP from
        # the elected snapshot's live book BEFORE building the cert.  This ensures:
        #   (a) size is capped at available depth (FOK semantics preserved on the
        #       sized amount → no DEPTH_INSUFFICIENT at executor validation).
        #   (b) expected_fill_price_before_fee = sweep VWAP, not limit_price, so
        #       the executor sweep-average check (executor.py:1778) passes on
        #       multi-level books.
        # If no trade_conn is available, or order is MAKER, skip (legacy behaviour).
        available_crossable_shares: float | None = None
        sweep_expected_fill_price: float | None = None
        # MUST be initialized before the TAKER block: the final_intent build below
        # (Bug A tick_size source) references `_snap_for_depth` for ALL order modes,
        # but it is only assigned inside the TAKER+trade_conn block. Without this
        # initialization a MAKER order (or taker without trade_conn) raises
        # UnboundLocalError at cert build. None → tick_size falls back to the
        # executable_snapshot payload default, which is correct for the MAKER path.
        _snap_for_depth = None
        # MARKET-IDENTITY HYDRATION FOR ALL MODES (live 2026-06-12 00:52-01:13Z,
        # five maker intents PRE_SUBMIT_ERROR): the snapshot OBJECT also feeds
        # _executable_market_context_from_snapshot below, whose event_id becomes
        # the final intent's market_event_id — the venue-event identity the
        # executor's pre-venue guard compares against the snapshot row
        # (executor.py "FinalExecutionIntent event_id does not match executable
        # snapshot"). Loading the object ONLY inside the TAKER depth block left
        # every MAKER intent with market_event_id=None → the intent fell back to
        # the EDLI opportunity event id → guaranteed namespace mismatch → every
        # maker submit died pre-venue. (Denver's taker fill passed because the
        # taker path loaded the object for the depth sweep.) The hydration is a
        # PK lookup, fail-soft; depth-sweep usage stays taker-only.
        _snap_for_context = None
        if trade_conn is not None:
            _snap_id_for_context = str(
                executable_snapshot.payload.get("identity")
                or executable_snapshot.payload.get("selected_snapshot_id")
                or ""
            )
            try:
                _snap_for_context = get_snapshot(trade_conn, _snap_id_for_context) if _snap_id_for_context else None
            except Exception:
                _snap_for_context = None
        if str(order_mode).strip().upper() == "TAKER" and trade_conn is not None:
            from src.contracts.execution_intent import (
                quantize_submit_shares_for_venue_at_most,
                simulate_clob_sweep,
            )
            _snap_for_depth = _snap_for_context
            if _snap_for_depth is not None:
                _action_payload = actionable.payload
                _min_order_size_d = Decimal(str(
                    executable_snapshot.payload.get("min_order_size") or "1.0"
                ))
                _tick_size_d = Decimal(str(
                    executable_snapshot.payload.get("min_tick_size") or "0.01"
                ))
                _reservation = Decimal(str(_action_payload.get("c_fee_adjusted") or "0"))
                _direction_for_depth = str(_action_payload.get("direction") or "buy_no")
                if _direction_for_depth.startswith("buy_"):
                    _fresh_touch = Decimal(str(fresh_best_ask))
                    # A BUY taker must cross the fresh ask.  If the ask is now above
                    # the reservation, this candidate is no longer executable and
                    # must be rejected so the reactor can continue to the next market.
                    if _fresh_touch > _reservation:
                        raise ValueError(
                            "TAKER_BUY_TOUCH_EXCEEDS_RESERVATION:"
                            f"best_ask={_fresh_touch}:reservation={_reservation}"
                        )
                    _limit_price_d = _fresh_touch
                    _rounding_mode = "up"
                else:
                    _fresh_touch = Decimal(str(fresh_best_bid))
                    if _fresh_touch < _reservation:
                        raise ValueError(
                            "TAKER_SELL_TOUCH_BELOW_RESERVATION:"
                            f"best_bid={_fresh_touch}:reservation={_reservation}"
                        )
                    _limit_price_d = _fresh_touch
                    _rounding_mode = "down"
                # FINDING-A FIX (twin-authority kill, external review 2026-06-12):
                # the FINAL taker size is swept from this snapshot's DEPTH, but the
                # limit price (_fresh_touch) is the FRESH submit-time WITNESS price.
                # The witness (PreSubmitAuthorityWitness) proves PRICE only — it
                # carries NO depth/size-at-best field — so sizing from the elected DB
                # snapshot's depth pairs FRESH price authority with STALE size
                # authority. If the elected snapshot saw a DIFFERENT top-of-book than
                # the witness (a fresher/thinner book — e.g. 300-share DB depth behind
                # a 5-share live book), the swept size is sized against liquidity that
                # is no longer witnessed: an oversized FOK/FAK reject or a wrong VWAP.
                # The depth is trustworthy ONLY when the snapshot's own top-of-book on
                # THIS side agrees with the witnessed touch (same book → same depth).
                # On any divergence (or a missing snapshot touch on this side) the
                # fresh book's depth is UNWITNESSED: fail CLOSED with a typed TRANSIENT
                # reason so the candidate requeues with a snapshot refresh, rather than
                # sweeping the stale depth. The check is a named relationship invariant
                # (_assert_taker_depth_authority_fresh) so it is unit-testable apart from
                # the full cert-build path.
                _assert_taker_depth_authority_fresh(
                    snapshot=_snap_for_depth,
                    direction=_direction_for_depth,
                    witness_touch=_fresh_touch,
                    tick_size=_tick_size_d,
                )
                # Tick-align the marketable touch using the canonical tick_size:
                # BUY rounds up to keep crossing; SELL rounds down to keep crossing.
                import math as _math
                if _tick_size_d > 0:
                    _ratio = float(_limit_price_d) / float(_tick_size_d)
                    _round_fn = _math.ceil if _rounding_mode == "up" else _math.floor
                    _epsilon = -1e-9 if _rounding_mode == "up" else 1e-9
                    _limit_price_d = Decimal(str(
                        round(_round_fn(_ratio + _epsilon) * float(_tick_size_d), 10)
                    ))
                    if _direction_for_depth.startswith("buy_") and _limit_price_d > _reservation:
                        raise ValueError(
                            "TAKER_BUY_TOUCH_EXCEEDS_RESERVATION:"
                            f"marketable_limit={_limit_price_d}:reservation={_reservation}"
                        )
                    if (
                        not _direction_for_depth.startswith("buy_")
                        and _limit_price_d < _reservation
                    ):
                        raise ValueError(
                            "TAKER_SELL_TOUCH_BELOW_RESERVATION:"
                            f"marketable_limit={_limit_price_d}:reservation={_reservation}"
                        )
                if _limit_price_d <= 0:
                    raise ValueError(
                        "EXECUTION_PRICE_BELOW_MIN_TICK:"
                        f"limit_price={_limit_price_d}:min_tick_size={_tick_size_d}"
                    )
                _reserved_notional = Decimal(str(
                    _action_payload.get("live_cap_reserved_notional_usd")
                    or _action_payload.get("kelly_size_usd")
                    or "0"
                ))
                # Bug B fix (2026-06-01) + K1.1 unification (consolidated overhaul
                # 2026-06-11): the share-sizing formula lives ONCE in
                # desired_shares_for_reserved_notional (decision_kernel cert builder) —
                # float arithmetic is the contract; this re-sweep must request EXACTLY
                # the share count the cert builder computes or sweep VWAP diverges and
                # parity rejects. Previously a byte-parity COPY kept in sync by comment.
                from src.decision_kernel.certificates.execution import (
                    desired_shares_for_reserved_notional as _desired_shares_shared,
                )

                _desired_shares_f = _desired_shares_shared(
                    float(_min_order_size_d), float(_reserved_notional), float(_limit_price_d)
                )
                _desired_shares = Decimal(str(_desired_shares_f))
                _depth_sweep = simulate_clob_sweep(
                    snapshot=_snap_for_depth,
                    direction=_direction_for_depth,
                    requested_size_kind="shares",
                    requested_size_value=_desired_shares,
                    limit_price=_limit_price_d,
                )
                if _depth_sweep.filled_shares > 0:
                    # SEV-1.2 fix (2026-06-06): the submitted share amount itself
                    # must already obey the venue's immediate-BUY amount grids before
                    # the final intent certificate is built.  The earlier Wall-B fix
                    # mirrored the cert builder's size cap, but left many-decimal BUY
                    # sizes such as 36.304447843137254 in SubmitPlanBuilt; the
                    # executor correctly rejected them before contacting the SDK.
                    #
                    # Mirror the final builder's exact size law here, then sweep on
                    # the largest venue-legal size that does not exceed the target or
                    # available depth. If no venue-legal size can fully fill, fail
                    # closed rather than submitting a deterministic reject.
                    _raw_capped_shares = min(_desired_shares, _depth_sweep.filled_shares)
                    _venue_quantized_shares = quantize_submit_shares_for_venue_at_most(
                        _direction_for_depth,
                        _raw_capped_shares,
                        final_limit_price=_limit_price_d,
                        order_type="FOK",
                        tick_size=_tick_size_d,
                    )
                    _venue_quantized_sweep = simulate_clob_sweep(
                        snapshot=_snap_for_depth,
                        direction=_direction_for_depth,
                        requested_size_kind="shares",
                        requested_size_value=_venue_quantized_shares,
                        limit_price=_limit_price_d,
                    )
                    if not _venue_quantized_sweep.fully_filled:
                        raise ValueError(
                            "DEPTH_BELOW_VENUE_QUANTIZED_SIZE:"
                            f"filled_shares={_venue_quantized_sweep.filled_shares}:"
                            f"venue_quantized_shares={_venue_quantized_shares}:"
                            f"depth_status={_venue_quantized_sweep.depth_status}"
                        )
                    available_crossable_shares = float(_venue_quantized_shares)
                    # Single-source principle: the final intent size, the stored
                    # expected fill price, and the executor guard re-sweep are all
                    # driven by the same snapshot, limit, and venue-legal size.
                    sweep_expected_fill_price = (
                        str(_venue_quantized_sweep.average_price)
                        if _venue_quantized_sweep.average_price is not None else None
                    )
        executable_market_context = _executable_market_context_from_snapshot(_snap_for_context)
        taker_quality_proof = _build_event_bound_taker_quality_proof(
            actionable_payload=actionable.payload,
            order_mode=order_mode,
            fresh_best_bid=fresh_best_bid,
            fresh_best_ask=fresh_best_ask,
        )
        if (
            str(order_mode).strip().upper() == "TAKER"
            and (
                not isinstance(taker_quality_proof, dict)
                or taker_quality_proof.get("passed") is not True
            )
        ):
            raise ValueError(
                "TAKER_QUALITY_PROOF_NOT_PASSED:"
                f"reason={None if not isinstance(taker_quality_proof, dict) else taker_quality_proof.get('reason')}:"
                f"edge={None if not isinstance(taker_quality_proof, dict) else taker_quality_proof.get('taker_fee_adjusted_edge')}:"
                f"incremental_profit={None if not isinstance(taker_quality_proof, dict) else taker_quality_proof.get('incremental_expected_profit_usd')}:"
                f"confidence={None if not isinstance(taker_quality_proof, dict) else taker_quality_proof.get('model_confidence')}"
            )
        final_intent = build_final_intent_certificate_from_actionable(
            actionable_cert=actionable,
            executable_snapshot_cert=executable_snapshot,
            quote_feasibility_cert=quote_feasibility,
            cost_model_cert=cost_model,
            forecast_authority_cert=forecast_authority,
            decision_source_context=_final_intent_decision_source_context_payload(
                event=event,
                forecast_authority=forecast_authority,
                day0_source_certs=day0_source_certs,
            ),
            passive_maker_context=passive_maker_context,
            decision_time=decision_time,
            order_mode=order_mode,
            # BUG #92 structural fix (2026-06-02): the intent's tick_size MUST be the
            # min_tick_size of the SAME snapshot the executor re-hydrates at submit
            # time (intent.snapshot_id == proof.executable_snapshot_id ==
            # executable_snapshot.payload['identity']).  Both branches below are bound
            # to that one snapshot:
            #   - TAKER: `_snap_for_depth` = get_snapshot(proof.executable_snapshot_id).
            #   - else : executable_snapshot.payload['min_tick_size'], populated at
            #            reactor:2448 from `_hydrated_snapshot =
            #            get_snapshot(proof.executable_snapshot_id)`.
            # The pre-fix `_float_or_default(..., 0.01)` silent default was an UNBOUND
            # tick source: when the canonical tick disagreed with a hardcoded 0.01 the
            # intent diverged from the executor's snapshot (live 2026-06-01: intent
            # tick=0.001 vs bound snapshot tick=0.01 → 28 EXECUTOR_PRE_VENUE_REJECTED).
            # Fail closed instead of defaulting — a missing canonical tick is a
            # provenance fault, not a 0.01 market.
            tick_size=str(_snap_for_depth.min_tick_size) if _snap_for_depth is not None else _required_bound_tick_size(_snap_for_depth, executable_snapshot.payload),
            min_order_size=_float_or_default(executable_snapshot.payload.get("min_order_size"), 1.0),
            best_bid=fresh_best_bid if str(order_mode).strip().upper() == "TAKER" else best_bid,
            best_ask=fresh_best_ask if str(order_mode).strip().upper() == "TAKER" else best_ask,
            available_crossable_shares=available_crossable_shares,
            sweep_expected_fill_price=sweep_expected_fill_price,
            executable_market_context=executable_market_context,
            taker_quality_proof=taker_quality_proof,
        )
        # Legacy guard for old proofs without rest_then_cross policy. Modern proofs already
        # use the same policy in _validate_final_order_mode_or_abort; if a MAKER proof
        # upgrades to TAKER, that happened before the final intent was built and all taker
        # certificates are evaluated below. This block only prevents legacy second-doctrine
        # late EV overrides.
        from src.strategy.live_inference.mode_consistent_ev import (
            taker_spread_guard_reason as _taker_spread_guard_reason,
        )

        # K4.0: this tripwire applies ONLY to LEGACY proofs (no rest_then_cross
        # policy on the payload). Under REST-THEN-CROSS, a policy proof is already
        # the selected mode for THIS submit attempt. If the fresh book now prefers a
        # different mode, the validator aborts for a full re-rank; this block must
        # not perform a second inline maker->taker rebuild.
        _rtc_policy_present = bool(
            str(actionable.payload.get("rest_then_cross_policy") or "").strip()
        )
        if (
            not _rtc_policy_present
            and final_intent.payload.get("post_only") is True
            and _taker_spread_guard_reason(
                fresh_best_bid,
                fresh_best_ask,
                max_relative_spread=_taker_max_relative_spread(),
            )
            is None
            and _ev_boundary_favors_cross(
                actionable_payload=actionable.payload,
                quote_payload=quote_payload,
                best_bid=fresh_best_bid,
                best_ask=fresh_best_ask,
                reservation=_optional_float(actionable.payload.get("c_fee_adjusted")),
                side=str(actionable.payload.get("side") or "BUY"),
            )
        ):
            raise _SubmitAbortedModeFlipped(
                f"{_MODE_FLIPPED_ABORT_PREFIX}:proof_mode={order_mode}:"
                f"fresh_mode=TAKER:reason=FRESH_BOOK_EV_FAVORS_CROSS_FOR_PROVEN_MAKER:"
                f"fresh_bid={fresh_best_bid}:fresh_ask={fresh_best_ask}"
            )
        if live_cap_conn is None:
            raise ValueError("LIVE_CAP_CONNECTION_REQUIRED")
        _release_live_order_build_stale_transaction(
            live_cap_conn,
            phase="active_duplicate_read",
        )
        # FIX A (#125): live-order-state duplicate lock. Suppress THIS submit only
        # while an order for the same (token, direction) is genuinely ACTIVE on the
        # venue (open/pending/in-flight/unknown). After a TERMINAL unfilled cancel
        # the lock releases and the family re-decides at the fresh price — no
        # arbitrary 2c price-improvement requirement, full re-certification still
        # applies downstream. Fail-closed: an unreadable/indeterminate live state
        # suppresses (never a double-submit).
        already_locked_reason = _locked_live_opportunity_active_order_reason(
            live_cap_conn,
            condition_id=str(final_intent.payload["condition_id"]),
            token_id=str(final_intent.payload["token_id"]),
            direction=str(final_intent.payload["direction"]),
            family_id=str(actionable.payload.get("family_id") or ""),
            city=str(actionable.payload.get("city") or ""),
            target_date=str(actionable.payload.get("target_date") or ""),
            metric=str(
                actionable.payload.get("metric")
                or actionable.payload.get("temperature_metric")
                or ""
            ),
            side=str(final_intent.payload.get("side") or "BUY"),
            limit_price=_optional_float(final_intent.payload.get("limit_price")),
        )
        if already_locked_reason is not None:
            raise _LiveOpportunityAlreadyLocked(already_locked_reason)
        executor_native_intent_hash = validate_final_intent_cert_for_existing_executor(final_intent)

        def _append_live_order_state() -> tuple[DecisionCertificate, DecisionCertificate, DecisionCertificate]:
            aggregate_ledger = LiveOrderAggregateLedger(live_cap_conn)
            aggregate_id = _live_order_aggregate_id(event.event_id, str(final_intent.payload["final_intent_id"]))
            decision_event = aggregate_ledger.append_event(
                aggregate_id=aggregate_id,
                event_type="DecisionProofAccepted",
                payload={
                    "event_id": event.event_id,
                    "final_intent_id": final_intent.payload["final_intent_id"],
                    "no_submit_certificate_count": len(base_certs),
                    "no_submit_receipt_event_id": receipt.event_id,
                    "decision_audit": _live_decision_audit_payload(
                        receipt=receipt,
                        base_certs=base_certs,
                        actionable=actionable,
                        final_intent=final_intent,
                    ),
                },
                occurred_at=decision_time,
                source_authority="decision_kernel",
            )
            submit_plan_event = aggregate_ledger.append_event(
                aggregate_id=aggregate_id,
                event_type="SubmitPlanBuilt",
                payload={
                    "event_id": event.event_id,
                    "final_intent_id": final_intent.payload["final_intent_id"],
                    "condition_id": final_intent.payload["condition_id"],
                    "token_id": final_intent.payload["token_id"],
                    "direction": final_intent.payload["direction"],
                    "family_id": actionable.payload.get("family_id"),
                    "city": actionable.payload.get("city"),
                    "target_date": actionable.payload.get("target_date"),
                    "metric": actionable.payload.get("metric") or actionable.payload.get("temperature_metric"),
                    "order_type": final_intent.payload["order_type"],
                    "time_in_force": final_intent.payload["time_in_force"],
                    "post_only": final_intent.payload["post_only"],
                    "limit_price": final_intent.payload["limit_price"],
                    "size": final_intent.payload["size"],
                },
                occurred_at=decision_time,
                source_authority="engine_adapter",
                expected_parent_event_hash=decision_event.event_hash,
            )
            pre_submit_event = aggregate_ledger.append_event(
                aggregate_id=aggregate_id,
                event_type="PreSubmitRevalidated",
                payload=_pre_submit_revalidation_payload_from_final_intent(
                    final_intent=final_intent,
                    executable_snapshot=executable_snapshot,
                    decision_time=decision_time,
                    authority_witness=authority_witness,
                ),
                occurred_at=decision_time,
                source_authority="engine_adapter",
                expected_parent_event_hash=submit_plan_event.event_hash,
            )
            live_cap_event = aggregate_ledger.append_event(
                aggregate_id=aggregate_id,
                event_type="LiveCapReserved",
                payload={
                    "event_id": event.event_id,
                    "final_intent_id": final_intent.payload["final_intent_id"],
                    "usage_id": live_cap.payload["usage_id"],
                    "reserved_notional_usd": live_cap.payload["reserved_notional_usd"],
                    "reservation_status": live_cap.payload["reservation_status"],
                },
                occurred_at=decision_time,
                source_authority="live_cap_ledger",
                expected_parent_event_hash=pre_submit_event.event_hash,
            )
            execution_command_id = _execution_command_id_from_final_intent(actionable, final_intent)
            expressibility = build_executor_expressibility_certificate(
                final_intent_cert=final_intent,
                executable_snapshot_cert=executable_snapshot,
                live_cap_cert=live_cap,
                decision_time=decision_time,
                executor_native_intent_hash=executor_native_intent_hash,
            )
            command_event = aggregate_ledger.append_event(
                aggregate_id=aggregate_id,
                event_type="ExecutionCommandCreated",
                payload={
                    "event_id": event.event_id,
                    "final_intent_id": final_intent.payload["final_intent_id"],
                    "execution_command_id": execution_command_id,
                    "pre_submit_event_hash": pre_submit_event.event_hash,
                    "live_cap_reserved_event_hash": live_cap_event.event_hash,
                    "usage_id": live_cap.payload["usage_id"],
                },
                occurred_at=decision_time,
                source_authority="engine_adapter",
                expected_parent_event_hash=live_cap_event.event_hash,
            )
            pre_submit = build_pre_submit_revalidation_certificate(
                pre_submit_event=pre_submit_event,
                final_intent_cert=final_intent,
                live_cap_cert=live_cap,
                decision_time=decision_time,
                execution_command_event_hash=command_event.event_hash,
            )
            command = build_execution_command_certificate_from_final_intent(
                actionable_cert=actionable,
                final_intent_cert=final_intent,
                executor_expressibility_cert=expressibility,
                live_cap_cert=live_cap,
                pre_submit_revalidation_cert=pre_submit,
                decision_time=decision_time,
            )
            from src.events.live_cap import LIVE_EXECUTION_RESERVATION_SCOPE, LiveCapLedger

            # Durable re-reservation of the Kelly notional already computed by
            # _build_live_cap_certificate_from_ledger above (which built the cert with
            # persist=False). This is the EXACTLY-ONCE + DRIFT-DETECT write: it dedupes
            # by (event_id, cap_scope) and raises if the reserved notional drifted.
            reserve_result = LiveCapLedger(live_cap_conn).reserve(
                event_id=event.event_id,
                decision_time=decision_time,
                cap_scope=LIVE_EXECUTION_RESERVATION_SCOPE,
                requested_notional_usd=float(live_cap.payload["reserved_notional_usd"]),
                final_intent_id=str(final_intent.payload["final_intent_id"]),
                execution_command_id=execution_command_id,
            )
            if reserve_result.usage_id != str(live_cap.payload["usage_id"]):
                raise ValueError("live cap reservation drift for provisional certificate")
            if float(reserve_result.reserved_notional_usd) != float(live_cap.payload["reserved_notional_usd"]):
                raise ValueError("LIVE_CAP_RESERVED_NOTIONAL_DRIFT")
            return expressibility, pre_submit, command

        # The HTTP/JIT book work above must not hold the trade DB write lock. This
        # savepoint covers only the aggregate/live-cap write unit and rolls it back
        # as a whole on aggregate validation or reservation failure.
        expressibility, pre_submit, command = _run_live_order_build_savepoint(
            live_cap_conn,
            _append_live_order_state,
            savepoint_name="edli_execution_command_build",
        )
    except Exception:
        raise
    return base_certs + day0_source_certs + (
        live_cap,
        actionable,
        final_intent,
        expressibility,
        pre_submit,
        command,
    )


def _selected_candidate_mode_fields_from_receipt(
    receipt: EventSubmissionReceipt,
) -> dict[str, object]:
    """Extract the proof-time mode-consistent EV fields for the selected candidate.

    P0-A (2026-06-10): execution_mode_intent and its siblings are computed at
    candidate-generation time (_generate_candidate_proofs) and stored in the
    CandidateEvaluation → opportunity_book["candidates"][N]. Thread them into
    the actionable payload so _build_live_execution_command_certificates can
    compare the proof's mode against the fresh-snapshot mode and abort on flip.

    Returns an empty dict when the receipt carries no opportunity book or the
    selected candidate cannot be located (legacy receipts — no-op for callers).
    """
    book = receipt.opportunity_book
    if not isinstance(book, dict):
        return {}
    candidate_id = receipt.candidate_id or book.get("selected_candidate_id")
    if not candidate_id:
        return {}
    candidates = book.get("candidates")
    if not isinstance(candidates, list):
        return {}
    for cand in candidates:
        if not isinstance(cand, dict):
            continue
        if str(cand.get("candidate_id") or "") == str(candidate_id):
            result: dict[str, object] = {}
            for key in (
                "execution_mode_intent",
                "ev_taker",
                "ev_maker",
                "maker_limit_price",
                "taker_forbidden_reason",
                "relative_spread_at_eval",
            ):
                val = cand.get(key)
                if val is not None:
                    result[f"proof_{key}"] = val
            return result
    return {}


def _assert_live_entry_submit_authority(actionable_payload: Mapping[str, object]) -> None:
    """Fail closed unless the event's live entry lane has its own executable authority."""

    event_type = str(actionable_payload.get("event_type") or "").strip()
    if event_type in _FORECAST_DECISION_EVENT_TYPES:
        _assert_forecast_entry_uses_qkernel_authority(actionable_payload)
        return
    if event_type in _DAY0_LANE_EVENT_TYPES:
        _assert_day0_entry_uses_live_observation_authority(actionable_payload)
        return
    raise ValueError(f"LIVE_ENTRY_AUTHORITY_UNSUPPORTED_EVENT_TYPE:{event_type or 'missing'}")


def _assert_forecast_entry_uses_qkernel_authority(actionable_payload: Mapping[str, object]) -> None:
    """Forecast live ENTRY submit is licensed only by qkernel spine economics."""

    if str(actionable_payload.get("selection_authority_applied") or "").strip() != "qkernel_spine":
        raise ValueError("LIVE_ENTRY_QKERNEL_AUTHORITY_REQUIRED")
    direction = str(actionable_payload.get("direction") or "")
    cert = _valid_qkernel_execution_economics_payload(
        actionable_payload.get("qkernel_execution_economics"),
        direction=direction,
    )
    if cert is None:
        raw_cert = actionable_payload.get("qkernel_execution_economics")
        if raw_cert in (None, ""):
            raise ValueError("LIVE_ENTRY_QKERNEL_EXECUTION_ECONOMICS_REQUIRED")
        if isinstance(raw_cert, Mapping):
            from src.strategy.live_inference.live_admission import (
                live_entry_probability_quality_rejection_reason,
            )

            win_rate_reason = live_entry_probability_quality_rejection_reason(
                q_lcb=raw_cert.get("payoff_q_lcb"),
                direction=direction,
                strategy_key=actionable_payload.get("strategy_key"),
                selection_authority_applied=actionable_payload.get(
                    "selection_authority_applied"
                ),
                qkernel_execution_economics=raw_cert,
            )
            if win_rate_reason is not None:
                raise ValueError(win_rate_reason)
        raise ValueError("LIVE_ENTRY_QKERNEL_EXECUTION_ECONOMICS_INVALID")
    near_day0_reason = _qkernel_near_day0_cert_rejection_reason(cert)
    if near_day0_reason is not None:
        raise ValueError(near_day0_reason)
    cert_bin_id = str(cert.get("bin_id") or "").strip()
    if not cert_bin_id:
        cert_candidate_id = str(cert.get("candidate_id") or "").strip()
        parts = cert_candidate_id.split(":", 2)
        if len(parts) >= 2:
            cert_bin_id = parts[1].strip()
    payload_bin_id = str(actionable_payload.get("candidate_bin_id") or "").strip()
    if not cert_bin_id or not payload_bin_id or cert_bin_id != payload_bin_id:
        raise ValueError(
            "LIVE_ENTRY_QKERNEL_CERT_BIN_MISMATCH:"
            f"cert_bin_id={cert_bin_id}:payload_bin_id={payload_bin_id}"
        )
    cert_q_live = _optional_float(cert.get("payoff_q_point"))
    cert_q_lcb = _optional_float(cert.get("payoff_q_lcb"))
    payload_q_live = _optional_float(actionable_payload.get("q_live"))
    payload_q_lcb = _optional_float(actionable_payload.get("q_lcb_5pct"))
    if (
        cert_q_live is None
        or cert_q_lcb is None
        or payload_q_live is None
        or payload_q_lcb is None
    ):
        raise ValueError("LIVE_ENTRY_QKERNEL_POSTERIOR_BOUND_MISSING")
    if not (
        math.isclose(cert_q_live, payload_q_live, rel_tol=1e-9, abs_tol=1e-6)
        and math.isclose(cert_q_lcb, payload_q_lcb, rel_tol=1e-9, abs_tol=1e-6)
    ):
        raise ValueError(
            "LIVE_ENTRY_QKERNEL_PAYOFF_PROBABILITY_MISMATCH:"
            f"cert_q={cert_q_live:.9f}:payload_q={payload_q_live:.9f}:"
            f"cert_q_lcb={cert_q_lcb:.9f}:payload_q_lcb={payload_q_lcb:.9f}"
        )
    from src.strategy.live_inference.live_admission import (
        live_entry_probability_quality_rejection_reason,
    )

    win_rate_reason = live_entry_probability_quality_rejection_reason(
        q_lcb=cert_q_lcb,
        direction=direction,
        strategy_key=actionable_payload.get("strategy_key"),
        selection_authority_applied=actionable_payload.get("selection_authority_applied"),
        qkernel_execution_economics=cert,
    )
    if win_rate_reason is not None:
        raise ValueError(win_rate_reason)


def _assert_day0_entry_uses_live_observation_authority(actionable_payload: Mapping[str, object]) -> None:
    """Day0 live ENTRY submit requires observation truth plus qkernel economics."""

    from src.events.day0_authority import (
        Day0AuthorityError,
        assert_live_day0_probability_authority,
        assert_live_day0_payload_authority,
        assert_live_day0_qkernel_guard_authority,
    )

    try:
        assert_live_day0_payload_authority(actionable_payload)
    except Day0AuthorityError as exc:
        raise ValueError(f"LIVE_ENTRY_DAY0_OBSERVATION_AUTHORITY_REQUIRED:{exc}") from None
    try:
        assert_live_day0_probability_authority(
            actionable_payload,
            direction=actionable_payload.get("direction"),
            condition_id=actionable_payload.get("condition_id"),
            q_live=actionable_payload.get("q_live"),
            q_lcb=actionable_payload.get("q_lcb_5pct"),
        )
    except Day0AuthorityError as exc:
        raise ValueError(f"LIVE_ENTRY_DAY0_PROBABILITY_AUTHORITY_REQUIRED:{exc}") from None
    economics = actionable_payload.get("qkernel_execution_economics")
    if not isinstance(economics, Mapping):
        raise ValueError("LIVE_ENTRY_QKERNEL_EXECUTION_ECONOMICS_REQUIRED")
    try:
        assert_live_day0_qkernel_guard_authority(economics)
    except Day0AuthorityError as exc:
        raise ValueError(f"LIVE_ENTRY_DAY0_QKERNEL_GUARD_AUTHORITY_REQUIRED:{exc}") from None
    _assert_forecast_entry_uses_qkernel_authority(actionable_payload)


def _actionable_payload_from_receipt(
    receipt: EventSubmissionReceipt,
    live_cap_cert: DecisionCertificate,
    *,
    event: OpportunityEvent | None = None,
) -> dict[str, object]:
    reserved_notional = float(live_cap_cert.payload["reserved_notional_usd"])
    live_quality_floors = _event_bound_strategy_live_quality_floors(receipt.strategy_key)
    def _receipt_floor(field: str, value: object) -> float:
        receipt_value = _optional_float(value)
        registry_value = float(live_quality_floors[field])
        if receipt_value is None:
            return registry_value
        return max(receipt_value, registry_value)

    city = receipt.city or _event_identity_value(event, "city")
    target_date = receipt.target_date or _event_identity_value(event, "target_date")
    metric = receipt.metric or _event_identity_value(event, "metric") or _event_identity_value(event, "temperature_metric")
    # P0-A (2026-06-10): thread the proof-time mode fields into the actionable
    # payload so the final-command builder can VALIDATE the proven mode vs the fresh
    # mode and abort SUBMIT_ABORTED_MODE_FLIPPED on disagreement.
    #
    # AUTHORITY ORDER (operator review 2026-06-10 P0 mode-authority, Fitz #4 provenance):
    # the receipt's first-class execution_mode_intent / maker_limit_price are the SOLE
    # authority — they were PROVEN through submit recapture under that mode's economics.
    # The opportunity-book sibling fields (ev_taker/ev_maker/taker_forbidden_reason/...) are
    # carried for observability but the MODE itself is taken from the receipt field, not the
    # book back-channel. The receipt field overrides any book value for proof_execution_mode_intent
    # / proof_maker_limit_price so the final-stage validator can never disagree with the proven mode.
    proof_mode_fields = dict(_selected_candidate_mode_fields_from_receipt(receipt))
    if receipt.execution_mode_intent is not None:
        proof_mode_fields["proof_execution_mode_intent"] = (
            str(receipt.execution_mode_intent).strip().upper()
        )
    if receipt.maker_limit_price is not None:
        proof_mode_fields["proof_maker_limit_price"] = receipt.maker_limit_price
    # K4.0: the rest-then-cross policy verdict travels to the final command builder
    # so submit-time validation can compare the proven mode with fresh policy math.
    if getattr(receipt, "rest_then_cross_policy", None) is not None:
        proof_mode_fields["rest_then_cross_policy"] = str(receipt.rest_then_cross_policy)
    qkernel_execution_economics = None
    if receipt.qkernel_execution_economics is not None:
        qkernel_cert = _valid_qkernel_execution_economics_payload(
            receipt.qkernel_execution_economics,
            direction=str(receipt.direction or ""),
        )
        if qkernel_cert is not None:
            qkernel_execution_economics = _json_finite(dict(qkernel_cert))
    day0_probability_authority = (
        _json_finite(receipt.day0_probability_authority)
        if isinstance(receipt.day0_probability_authority, dict)
        else None
    )

    def _day0_probability_value(key: str) -> object | None:
        if isinstance(day0_probability_authority, dict):
            value = day0_probability_authority.get(key)
            if value not in (None, ""):
                return value
        return None

    def _present(value: object | None) -> object | None:
        return None if value in (None, "") else value

    def _first_present(*values: object | None) -> object | None:
        for value in values:
            present = _present(value)
            if present is not None:
                return present
        return None

    return {
        "event_id": receipt.event_id,
        "event_type": event.event_type if event is not None else None,
        "causal_snapshot_id": receipt.causal_snapshot_id,
        "strategy_key": receipt.strategy_key,
        "family_id": receipt.family_id,
        "candidate_id": receipt.candidate_id,
        "condition_id": receipt.condition_id,
        "token_id": receipt.token_id,
        "direction": receipt.direction,
        "executable_snapshot_id": receipt.executable_snapshot_id,
        "q_source": receipt.q_source,
        # B3 authority stamp: the spine bridge preserves q_source as the probability
        # track label and records the EXECUTION authority here. The taker-quality proof
        # reads this (mirroring _proof_uses_qkernel_spine) so a spine-selected taker
        # under the live "replacement_0_1" q_source is correctly recognized.
        "selection_authority_applied": receipt.selection_authority_applied,
        # B3 identity key: the reactor bin_id hash so the taker-quality proof matches the
        # qkernel cert to THIS selected leg across the two candidate_id namespaces.
        "candidate_bin_id": receipt.candidate_bin_id,
        "qkernel_execution_economics": qkernel_execution_economics,
        "day0_probability_authority": day0_probability_authority,
        "_edli_q_source": _day0_probability_value("q_source"),
        "_edli_day0_q_mode": _day0_probability_value("q_mode"),
        "_edli_day0_remaining_models": _day0_probability_value("remaining_models"),
        "_edli_day0_remaining_model_names": _day0_probability_value("remaining_model_names"),
        "_edli_day0_remaining_source_cycle_time_utc": _day0_probability_value(
            "remaining_source_cycle_time_utc"
        ),
        "_edli_day0_remaining_capture_times_utc": _day0_probability_value(
            "remaining_capture_times_utc"
        ),
        "_edli_day0_remaining_expected_models": _day0_probability_value(
            "remaining_expected_models"
        ),
        "_edli_day0_exit_authority_status": _day0_probability_value("exit_authority_status"),
        "_edli_day0_exit_authority_reason": _day0_probability_value("exit_authority_reason"),
        "_edli_day0_bound_classification": _day0_probability_value("bound_classification"),
        "_edli_day0_lcb_transform": _day0_probability_value("lcb_transform"),
        "opportunity_book": _json_finite(receipt.opportunity_book),
        "q_live": receipt.q_live,
        "q_lcb_5pct": receipt.q_lcb_5pct,
        "c_fee_adjusted": receipt.c_fee_adjusted,
        "c_cost_95pct": receipt.c_cost_95pct,
        "p_fill_lcb": receipt.p_fill_lcb,
        "trade_score": receipt.trade_score,
        "action_score": receipt.trade_score,
        "min_entry_price": _receipt_floor("min_entry_price", receipt.min_entry_price),
        "min_expected_profit_usd": _receipt_floor(
            "min_expected_profit_usd",
            receipt.min_expected_profit_usd,
        ),
        "min_submit_edge_density": _receipt_floor(
            "min_submit_edge_density",
            receipt.min_submit_edge_density,
        ),
        "fdr_family_id": receipt.fdr_family_id,
        "kelly_decision_id": receipt.kelly_decision_id,
        "kelly_size_usd": receipt.kelly_size_usd,
        "risk_decision_id": receipt.risk_decision_id,
        "live_cap_usage_id": live_cap_cert.payload["usage_id"],
        "live_cap_reserved_notional_usd": reserved_notional,
        "final_intent_id": receipt.final_intent_id,
        "neg_risk": receipt.neg_risk,
        "side_effect_status": "ACTIONABLE_NOT_SUBMITTED",
        "native_quote_available": receipt.native_quote_available,
        "city": city,
        "target_date": target_date,
        "metric": metric,
        "temperature_metric": metric,
        "source_match_status": _event_identity_value(event, "source_match_status"),
        "local_date_status": _event_identity_value(event, "local_date_status"),
        "station_match_status": _event_identity_value(event, "station_match_status"),
        "dst_status": _event_identity_value(event, "dst_status"),
        "metric_match_status": _event_identity_value(event, "metric_match_status"),
        "rounding_status": _event_identity_value(event, "rounding_status"),
        "source_authorized_status": _event_identity_value(event, "source_authorized_status"),
        "live_authority_status": _event_identity_value(event, "live_authority_status"),
        "raw_value": _first_present(
            _event_identity_value(event, "raw_value"),
            _day0_probability_value("observed_extreme_native"),
        ),
        "rounded_value": _first_present(
            _event_identity_value(event, "rounded_value"),
            _day0_probability_value("rounded_value"),
        ),
        "high_so_far": _event_identity_value(event, "high_so_far"),
        "low_so_far": _event_identity_value(event, "low_so_far"),
        "observation_time": _first_present(
            _event_identity_value(event, "observation_time"),
            _day0_probability_value("observation_time"),
        ),
        "observation_available_at": _first_present(
            _event_identity_value(event, "observation_available_at"),
            _day0_probability_value("observation_available_at"),
        ),
        "bin_label": receipt.bin_label,
        "outcome_label": receipt.outcome_label,
        "unit": receipt.unit,
        "submitted": False,
        **proof_mode_fields,
    }


def _live_decision_audit_payload(
    *,
    receipt: EventSubmissionReceipt,
    base_certs: tuple[DecisionCertificate, ...],
    actionable: DecisionCertificate,
    final_intent: DecisionCertificate,
) -> dict[str, object]:
    """Compact durable audit payload for real-submit aggregate root events.

    ``edli_no_submit_receipts`` intentionally rejects real-submit receipts. The
    live-order aggregate is therefore the durable source for reconstructing why a
    submitted order existed. Keep this payload small and derived from the same
    receipt/certificates already authorized by the money path.
    """

    book = receipt.opportunity_book if isinstance(receipt.opportunity_book, dict) else {}
    selected_candidate_id = str(book.get("selected_candidate_id") or "").strip() or None
    actual_candidate_id = str(book.get("actual_receipt_selected_candidate_id") or "").strip() or None
    selected_candidate: Mapping[str, object] | None = None
    candidates = book.get("candidates")
    if isinstance(candidates, list) and selected_candidate_id is not None:
        for candidate in candidates:
            if not isinstance(candidate, Mapping):
                continue
            if str(candidate.get("candidate_id") or "").strip() == selected_candidate_id:
                selected_candidate = candidate
                break

    return {
        "schema": "edli_live_decision_audit_v1",
        "event_id": receipt.event_id,
        "final_intent_id": receipt.final_intent_id,
        "family_id": receipt.family_id,
        "candidate_id": receipt.candidate_id,
        "condition_id": receipt.condition_id,
        "token_id": receipt.token_id,
        "direction": receipt.direction,
        "city": receipt.city,
        "target_date": receipt.target_date,
        "metric": receipt.metric,
        "bin_label": receipt.bin_label,
        "outcome_label": receipt.outcome_label,
        "unit": receipt.unit,
        "strategy_key": receipt.strategy_key,
        "q_source": receipt.q_source,
        "qkernel_execution_economics": _json_finite(receipt.qkernel_execution_economics),
        # H2_E2E: make the live-order aggregate self-contained — the fill->posterior
        # link is reconstructable from the aggregate payload without JSON_EXTRACT on
        # the receipt blob. None on canonical orders.
        "posterior_id": receipt.posterior_id,
        "probability_authority": receipt.probability_authority,
        "q_lcb_calibration_source": receipt.q_lcb_calibration_source,
        "q_live": receipt.q_live,
        "q_lcb_5pct": receipt.q_lcb_5pct,
        "c_fee_adjusted": receipt.c_fee_adjusted,
        "c_cost_95pct": receipt.c_cost_95pct,
        "p_fill_lcb": receipt.p_fill_lcb,
        "trade_score": receipt.trade_score,
        "min_entry_price": receipt.min_entry_price,
        "min_expected_profit_usd": receipt.min_expected_profit_usd,
        "min_submit_edge_density": receipt.min_submit_edge_density,
        "kelly_size_usd": receipt.kelly_size_usd,
        "kelly_decision_id": receipt.kelly_decision_id,
        "risk_decision_id": receipt.risk_decision_id,
        "opportunity_book": _json_finite(receipt.opportunity_book),
        "selected_candidate_id": selected_candidate_id,
        "actual_receipt_selected_candidate_id": actual_candidate_id,
        "selected_condition_id": (
            str(selected_candidate.get("condition_id") or "").strip()
            if selected_candidate is not None
            else None
        ),
        "selected_token_id": (
            str(selected_candidate.get("token_id") or "").strip()
            if selected_candidate is not None
            else None
        ),
        "selected_direction": (
            str(selected_candidate.get("direction") or "").strip()
            if selected_candidate is not None
            else None
        ),
        "selected_bin_label": (
            selected_candidate.get("bin_label")
            if selected_candidate is not None
            else None
        ),
        "actual_condition_id": receipt.condition_id,
        "actual_token_id": receipt.token_id,
        "actual_direction": receipt.direction,
        "actual_bin_label": receipt.bin_label,
        "actionable_certificate_hash": actionable.certificate_hash,
        "final_intent_certificate_hash": final_intent.certificate_hash,
        "parent_certificates": [
            {
                "certificate_type": cert.certificate_type,
                "certificate_id": cert.certificate_id,
                "certificate_hash": cert.certificate_hash,
            }
            for cert in base_certs
        ],
    }


def _event_identity_value(event: OpportunityEvent | None, key: str) -> object | None:
    if event is None:
        return None
    parsed_payload = _payload(event)
    if key in parsed_payload:
        return parsed_payload.get(key)
    payload = getattr(event, "payload", None)
    if isinstance(payload, dict):
        return payload.get(key)
    return getattr(payload, key, None)


def _live_order_aggregate_id(event_id: str, final_intent_id: str) -> str:
    return f"{event_id}:{final_intent_id}"


def _execution_command_id_from_final_intent(
    actionable: DecisionCertificate,
    final_intent: DecisionCertificate,
) -> str:
    action = actionable.payload
    intent = final_intent.payload
    return (
        f"edli_exec_cmd:{action['event_id']}:{intent['final_intent_id']}:"
        f"{intent['token_id']}:{intent['direction']}"
    )


# =============================================================================
# FIX A (#125, 2026-06-15): LIVE-ORDER-STATE active-order lock.
#
# The retired predicate (_locked_live_opportunity_no_price_improvement_reason)
# was a HISTORICAL-COMMAND lock: it suppressed re-bidding the same
# (condition/token/direction) whenever ANY past aggregate had reached
# ExecutionCommandCreated and lacked a SubmitRejected, UNLESS the limit price
# improved by >= 0.02. That arbitrary 0.02-improvement gate meant a resting
# maker order that timed out UNFILLED at 900s (terminal CANCEL, no
# SubmitRejected, usually no 2c price move) left the family permanently
# suppressed — it NEVER re-bid (live evidence: lone Chengdu 06-17 buy_no @0.72
# rested 1c under the 0.73 ask, would time out, never re-decide).
#
# The replacement is a LIVE-ORDER-STATE lock keyed on the aggregate lifecycle:
# suppress a NEW submit ONLY while an order for that (token, direction) is
# genuinely ACTIVE (OPEN / PENDING / in-flight / UNKNOWN — a real live order, so
# we never double-submit). The moment the latest order for the family reaches a
# TERMINAL lifecycle event (a confirmed cancel/expiry/reject/reconcile/cap
# release, or a fill) the lock RELEASES: the family re-enters the normal
# decision pipeline at the fresh price (re-rest or cross per the rest-then-cross
# policy), still requiring FULL re-certification downstream (no gate bypassed).
# The 0.02-improvement requirement is GONE — duplicate prevention is now bounded
# to genuinely ACTIVE orders, not to historical price levels.
#
# FAIL-CLOSED: a family whose live-order state is UNKNOWN / indeterminate is
# treated as ACTIVE (suppress) — never risk a double-submit on an order that
# might still be live on the venue.
# =============================================================================

# Terminal-event SQL fragment: returns a row IFF the aggregate has reached a
# TERMINAL lifecycle state, correctly handling payload variants:
#
#   - SubmitRejected                            : venue rejected; never rested.
#   - UserTradeObserved                         : fill confirmed; order done.
#   - CapTransitioned  to_status=CONSUMED       : cap COMMITTED to a SUBMITTED
#       order that is RESTING LIVE on the venue — emitted on submit SUCCESS
#       (status=SUBMITTED), BEFORE any fill (the fill is a later
#       UserTradeObserved).  The order is ACTIVE, not done.  NOT terminal —
#       must SUPPRESS, or every resting order instantly releases its own
#       duplicate lock and the family re-bids a SECOND concurrent ENTRY
#       (live-money defect 2026-06-16: token …2060729 double-rested @0.570).
#   - CapTransitioned  to_status=RELEASED       : closed without position; done.
#   - CapTransitioned  to_status=PENDING_RECONCILE : cap RESERVED, order MAY
#       still be resting live (emitted on TIMEOUT_UNKNOWN / POST_SUBMIT_UNKNOWN
#       alongside SubmitUnknown).  NOT terminal — must SUPPRESS (fail-closed).
#   - Reconciled       pending_reconcile=False  : fully settled; terminal.
#   - Reconciled       pending_reconcile=True   : matched-pending-finality; NOT
#       terminal for re-bid — must SUPPRESS (fail-closed).
#   - OrderLifecycleProjected order_lifecycle_state=TERMINAL_NO_FILL and
#       exposure_created=false: venue facts prove the acknowledged order is gone
#       with zero matched size; terminal.
#
# A row returned by this query means TERMINAL → RELEASE.
# No row means ACTIVE (or indeterminate) → SUPPRESS (fail-closed).
_TERMINAL_EVENT_SQL = """
    SELECT 1 FROM edli_live_order_events
    WHERE aggregate_id = ?
      AND (
        event_type = 'SubmitRejected'
        OR event_type = 'UserTradeObserved'
        OR (event_type = 'CapTransitioned'
            AND json_extract(payload_json, '$.to_status') = 'RELEASED')
        OR (event_type = 'Reconciled'
            AND COALESCE(json_extract(payload_json, '$.pending_reconcile'), 0) = 0)
        OR (event_type = 'OrderLifecycleProjected'
            AND json_extract(payload_json, '$.order_lifecycle_state') = 'TERMINAL_NO_FILL'
            AND COALESCE(json_extract(payload_json, '$.exposure_created'), 1) = 0)
      )
    LIMIT 1
"""

_TERMINAL_VENUE_COMMAND_STATES = {
    "CANCELED",
    "CANCELLED",
    "EXPIRED",
    "FAILED",
    "FILLED",
    "REJECTED",
    "SUBMIT_REJECTED",
    "VOIDED",
}


def _aggregate_terminal_venue_command_releases_lock(
    live_cap_conn: sqlite3.Connection,
    *,
    aggregate_id: str,
) -> bool:
    """Return True when canonical venue command state proves the aggregate is closed.

    The live-order aggregate can lag terminal venue reconciliation: an order may
    have reached ``venue_commands.state=EXPIRED`` while the aggregate still ends
    at ``CapTransitioned(to_status=CONSUMED)``. In that case the duplicate lock
    must release; otherwise a closed maker rest permanently suppresses future
    redecision entries for the same token. Absence or unreadable tables remain
    non-evidence and therefore do not release the fail-closed lock.
    """

    def _command_state_on_conn(
        conn: sqlite3.Connection,
        *,
        execution_command_id: str,
        venue_order_ids: tuple[str, ...],
    ) -> str | None:
        if not _adapter_table_exists(conn, "venue_commands"):
            return None
        cols = {
            str(row[1] if not isinstance(row, sqlite3.Row) else row["name"])
            for row in conn.execute("PRAGMA table_info(venue_commands)").fetchall()
        }
        match_terms = []
        params: list[str] = []
        if "command_id" in cols:
            match_terms.append("command_id = ?")
            params.append(execution_command_id)
        if "decision_id" in cols:
            match_terms.append("decision_id = ?")
            params.append(execution_command_id)
        if "venue_order_id" in cols:
            for venue_order_id in venue_order_ids:
                match_terms.append("venue_order_id = ?")
                params.append(venue_order_id)
        if not match_terms:
            return None
        command = conn.execute(
            f"""
            SELECT state
            FROM venue_commands
            WHERE {' OR '.join(match_terms)}
            ORDER BY COALESCE(updated_at, created_at) DESC, rowid DESC
            LIMIT 1
            """,
            tuple(params),
        ).fetchone()
        if command is None:
            return None
        return str(command[0] or "").strip().upper()

    def _append_nonempty(values: list[str], value: object) -> None:
        text = str(value or "").strip()
        if text and text not in values:
            values.append(text)

    try:
        row = live_cap_conn.execute(
            """
            SELECT json_extract(payload_json, '$.execution_command_id') AS execution_command_id
            FROM edli_live_order_events
            WHERE aggregate_id = ?
              AND event_type = 'ExecutionCommandCreated'
            ORDER BY event_sequence DESC
            LIMIT 1
            """,
            (aggregate_id,),
        ).fetchone()
        execution_command_id = str(row[0] or "").strip() if row is not None else ""
        if not execution_command_id:
            return False
    except Exception:
        return False

    venue_order_ids: list[str] = []
    try:
        if _adapter_table_exists(live_cap_conn, "edli_live_order_projection"):
            projection_row = live_cap_conn.execute(
                """
                SELECT venue_order_id
                FROM edli_live_order_projection
                WHERE aggregate_id = ?
                LIMIT 1
                """,
                (aggregate_id,),
            ).fetchone()
            if projection_row is not None:
                _append_nonempty(venue_order_ids, projection_row[0])
    except Exception:
        pass
    try:
        event_rows = live_cap_conn.execute(
            """
            SELECT
              COALESCE(
                json_extract(payload_json, '$.venue_order_id'),
                json_extract(payload_json, '$.orderID'),
                json_extract(payload_json, '$.orderId'),
                json_extract(payload_json, '$.order_id'),
                json_extract(payload_json, '$.id')
              ) AS venue_order_id
            FROM edli_live_order_events
            WHERE aggregate_id = ?
              AND event_type IN (
                'VenueSubmitAcknowledged',
                'VenueSubmitAttempted',
                'UserOrderObserved',
                'UserTradeObserved',
                'Reconciled'
              )
            ORDER BY event_sequence DESC
            LIMIT 8
            """,
            (aggregate_id,),
        ).fetchall()
        for event_row in event_rows:
            _append_nonempty(venue_order_ids, event_row[0])
    except Exception:
        pass
    venue_order_id_tuple = tuple(venue_order_ids)

    current_conn_state = _command_state_on_conn(
        live_cap_conn,
        execution_command_id=execution_command_id,
        venue_order_ids=venue_order_id_tuple,
    )
    trade_conn_state = None
    try:
        from src.state.db import get_trade_connection_read_only

        trade_conn = get_trade_connection_read_only()
        try:
            trade_conn_state = _command_state_on_conn(
                trade_conn,
                execution_command_id=execution_command_id,
                venue_order_ids=venue_order_id_tuple,
            )
        finally:
            try:
                trade_conn.close()
            except Exception:
                pass
    except Exception:
        trade_conn_state = None
    canonical_state = trade_conn_state or current_conn_state
    if canonical_state is None:
        return False
    return canonical_state in _TERMINAL_VENUE_COMMAND_STATES


def _locked_live_opportunity_active_order_reason(
    live_cap_conn: sqlite3.Connection | None,
    *,
    condition_id: str,
    token_id: str,
    direction: str,
    family_id: str | None = None,
    city: str | None = None,
    target_date: str | None = None,
    metric: str | None = None,
    side: str | None = None,
    limit_price: float | None = None,
) -> str | None:
    """Suppress a NEW submit ONLY while a LIVE order for the family is active.

    FIX A (#125). Duplicate-prevention lock derived from the
    ``edli_live_order_events`` aggregate lifecycle (the live-order-state
    projection), NOT from "any historical command that is not a SubmitRejected".

    For the given weather family we find every order aggregate keyed off its
    ``SubmitPlanBuilt`` event. New SubmitPlanBuilt payloads carry
    ``family_id`` and ``(city,target_date,metric)`` so sibling bins share one
    mutex. Older payloads fall back to the exact ``condition_id/token_id/direction``
    key.

      * TERMINAL (cancel/expiry/reject/reconcile/cap-release, or a fill) -> the
        order is closed, NOT an active duplicate -> keep scanning older
        aggregates. A newer terminal row must not hide an older active row.
      * ACTIVE (any state up to and including an acknowledged resting order, an
        in-flight submit, or a pending-reconcile) -> a real live order exists ->
        SUPPRESS (return a reason) so we never double-submit.

    FAIL-CLOSED: on any query error, or an aggregate present but indeterminate,
    treat as ACTIVE and suppress — never risk a second live order on a family
    whose true venue state we cannot read. ``side`` / ``limit_price`` are
    accepted for call-site compatibility and observability only; they no longer
    gate (the retired 0.02 price-improvement requirement is gone).
    """

    if live_cap_conn is None or not condition_id or not token_id or not direction:
        return None
    family_id = str(family_id or "").strip()
    city = str(city or "").strip()
    target_date = str(target_date or "").strip()
    metric = str(metric or "").strip()
    family_key_available = bool(family_id or (city and target_date and metric))
    try:
        LiveOrderAggregateLedger(live_cap_conn)
        if family_key_available:
            plan_rows = live_cap_conn.execute(
                """
                SELECT plan.aggregate_id, plan.occurred_at, plan.payload_json
                FROM edli_live_order_events AS plan
                WHERE plan.event_type = 'SubmitPlanBuilt'
                  AND (
                    (? != '' AND json_extract(plan.payload_json, '$.family_id') = ?)
                    OR (
                      ? != '' AND ? != '' AND ? != ''
                      AND json_extract(plan.payload_json, '$.city') = ?
                      AND json_extract(plan.payload_json, '$.target_date') = ?
                      AND COALESCE(
                        json_extract(plan.payload_json, '$.metric'),
                        json_extract(plan.payload_json, '$.temperature_metric')
                      ) = ?
                    )
                    OR (
                      json_extract(plan.payload_json, '$.family_id') IS NULL
                      AND json_extract(plan.payload_json, '$.city') IS NULL
                      AND json_extract(plan.payload_json, '$.target_date') IS NULL
                      AND json_extract(plan.payload_json, '$.condition_id') = ?
                      AND json_extract(plan.payload_json, '$.token_id') = ?
                      AND json_extract(plan.payload_json, '$.direction') = ?
                    )
                  )
                ORDER BY plan.occurred_at DESC, plan.event_sequence DESC
                LIMIT 128
                """,
                (
                    family_id,
                    family_id,
                    city,
                    target_date,
                    metric,
                    city,
                    target_date,
                    metric,
                    condition_id,
                    token_id,
                    direction,
                ),
            ).fetchall()
        else:
            plan_rows = live_cap_conn.execute(
                """
                SELECT plan.aggregate_id, plan.occurred_at, plan.payload_json
                FROM edli_live_order_events AS plan
                WHERE plan.event_type = 'SubmitPlanBuilt'
                  AND json_extract(plan.payload_json, '$.condition_id') = ?
                  AND json_extract(plan.payload_json, '$.token_id') = ?
                  AND json_extract(plan.payload_json, '$.direction') = ?
                ORDER BY plan.occurred_at DESC, plan.event_sequence DESC
                LIMIT 64
                """,
                (condition_id, token_id, direction),
            ).fetchall()
    except Exception as exc:  # noqa: BLE001 - dedup must fail CLOSED (suppress).
        return (
            "EDLI_LIVE_ORDER_STATE_UNREADABLE_FAIL_CLOSED:"
            f"condition_id={condition_id}:token_id={token_id}:direction={direction}:"
            f"error={type(exc).__name__}"
        )
    if not plan_rows:
        # No order has ever been planned for this family -> nothing can be a
        # duplicate -> the family is free to submit.
        return None

    for row in plan_rows:
        aggregate_id = str(row[0])
        try:
            terminal_row = live_cap_conn.execute(
                _TERMINAL_EVENT_SQL,
                (aggregate_id,),
            ).fetchone()
        except Exception as exc:  # noqa: BLE001 - fail CLOSED on a read error.
            return (
                "EDLI_LIVE_ORDER_STATE_UNREADABLE_FAIL_CLOSED:"
                f"condition_id={condition_id}:token_id={token_id}:direction={direction}:"
                f"aggregate_id={aggregate_id}:error={type(exc).__name__}"
            )

        if terminal_row is not None:
            # A qualifying terminal event (RELEASED cap, SubmitRejected,
            # UserTradeObserved, or a fully-settled Reconcile) was found. Keep
            # scanning older aggregates; a newer terminal order must not hide an
            # older active/ambiguous order for the same weather family.
            continue

        if _aggregate_terminal_venue_command_releases_lock(
            live_cap_conn,
            aggregate_id=aggregate_id,
        ):
            continue

        # No qualifying terminal event found. This covers ACTIVE states
        # (command-created, submit-attempted, acknowledged-resting,
        # cap-CONSUMED-resting-live, submit-unknown, user-order-observed with no
        # fill, PENDING_RECONCILE) and indeterminate states. All are treated as
        # ACTIVE: suppress the potential duplicate.
        return (
            "EDLI_LIVE_ORDER_ACTIVE_DUPLICATE_SUPPRESSED:"
            f"condition_id={condition_id}:token_id={token_id}:direction={direction}:"
            f"family_id={family_id}:city={city}:target_date={target_date}:metric={metric}:"
            f"aggregate_id={aggregate_id}"
        )

    return None


# Back-compat alias: the historical-command predicate name is retained as a thin
# pointer to the live-order-state lock so any out-of-tree caller resolves to the
# corrected semantics. The signature is a superset of the old one (the retired
# ``improve_delta`` keyword is accepted and ignored).
def _locked_live_opportunity_no_price_improvement_reason(
    live_cap_conn: sqlite3.Connection | None,
    *,
    condition_id: str,
    token_id: str,
    direction: str,
    side: str | None = None,
    limit_price: float | None = None,
    improve_delta: float = 0.02,  # retired; accepted for signature compatibility.
) -> str | None:
    return _locked_live_opportunity_active_order_reason(
        live_cap_conn,
        condition_id=condition_id,
        token_id=token_id,
        direction=direction,
        family_id=None,
        city=None,
        target_date=None,
        metric=None,
        side=side,
        limit_price=limit_price,
    )


def _pre_submit_revalidation_payload_from_final_intent(
    *,
    final_intent: DecisionCertificate,
    executable_snapshot: DecisionCertificate,
    decision_time: datetime,
    authority_witness: PreSubmitAuthorityWitness,
) -> dict[str, object]:
    payload = final_intent.payload
    limit_price = _float_or_default(payload.get("limit_price"), 0.01)
    quote_seen_at = _parse_utc(authority_witness.quote_seen_at)
    if quote_seen_at is None:
        raise ValueError("PRE_SUBMIT_QUOTE_SEEN_AT_REQUIRED")
    checked_at = _parse_utc(authority_witness.checked_at) or decision_time.astimezone(UTC)
    quote_age_ms = int(max(0.0, (checked_at.astimezone(UTC) - quote_seen_at).total_seconds() * 1000.0))
    current_best_bid = _optional_float(authority_witness.current_best_bid)
    current_best_ask = _optional_float(authority_witness.current_best_ask)
    tick_size = float(authority_witness.tick_size)
    min_order_size = float(authority_witness.min_order_size)
    side = str(payload["side"])
    would_cross = _would_cross_post_only_book(
        side=side,
        limit_price=limit_price,
        current_best_bid=current_best_bid,
        current_best_ask=current_best_ask,
    )
    return {
        "event_id": payload["event_id"],
        "event_type": payload.get("event_type"),
        "final_intent_id": payload["final_intent_id"],
        "strategy_key": payload.get("strategy_key"),
        "condition_id": payload["condition_id"],
        "token_id": payload["token_id"],
        "side": payload["side"],
        "direction": payload["direction"],
        "city": payload.get("city"),
        "target_date": payload.get("target_date"),
        "metric": payload.get("metric") or payload.get("temperature_metric"),
        "temperature_metric": payload.get("temperature_metric") or payload.get("metric"),
        "bin_label": payload.get("bin_label"),
        "outcome_label": payload.get("outcome_label"),
        "unit": payload.get("unit"),
        "order_type": payload["order_type"],
        "time_in_force": payload["time_in_force"],
        "post_only": payload["post_only"],
        "checked_at": authority_witness.checked_at or decision_time.isoformat(),
        "quote_seen_at": authority_witness.quote_seen_at,
        "quote_age_ms": quote_age_ms,
        "max_quote_age_ms": int(authority_witness.max_quote_age_ms),
        "book_hash": authority_witness.book_hash,
        "current_best_bid": current_best_bid,
        "current_best_ask": current_best_ask,
        "limit_price": limit_price,
        "q_live": payload.get("q_live"),
        "q_lcb_5pct": payload.get("q_lcb_5pct"),
        "expected_edge": payload.get("trade_score"),
        "action_score": payload.get("action_score"),
        "size": payload.get("size"),
        "min_entry_price": payload.get("min_entry_price"),
        "min_expected_profit_usd": payload.get("min_expected_profit_usd"),
        "min_submit_edge_density": payload.get("min_submit_edge_density"),
        "c_fee_adjusted": payload.get("c_fee_adjusted"),
        "c_cost_95pct": payload.get("c_cost_95pct"),
        "selection_authority_applied": payload.get("selection_authority_applied"),
        "qkernel_execution_economics": payload.get("qkernel_execution_economics"),
        "day0_probability_authority": payload.get("day0_probability_authority"),
        "_edli_q_source": payload.get("_edli_q_source"),
        "_edli_day0_q_mode": payload.get("_edli_day0_q_mode"),
        "_edli_day0_remaining_models": payload.get("_edli_day0_remaining_models"),
        "_edli_day0_remaining_model_names": payload.get("_edli_day0_remaining_model_names"),
        "_edli_day0_remaining_source_cycle_time_utc": payload.get(
            "_edli_day0_remaining_source_cycle_time_utc"
        ),
        "_edli_day0_remaining_capture_times_utc": payload.get(
            "_edli_day0_remaining_capture_times_utc"
        ),
        "_edli_day0_remaining_expected_models": payload.get(
            "_edli_day0_remaining_expected_models"
        ),
        "_edli_day0_exit_authority_status": payload.get("_edli_day0_exit_authority_status"),
        "_edli_day0_exit_authority_reason": payload.get("_edli_day0_exit_authority_reason"),
        "_edli_day0_bound_classification": payload.get("_edli_day0_bound_classification"),
        "_edli_day0_lcb_transform": payload.get("_edli_day0_lcb_transform"),
        "source_match_status": payload.get("source_match_status"),
        "local_date_status": payload.get("local_date_status"),
        "station_match_status": payload.get("station_match_status"),
        "dst_status": payload.get("dst_status"),
        "metric_match_status": payload.get("metric_match_status"),
        "rounding_status": payload.get("rounding_status"),
        "source_authorized_status": payload.get("source_authorized_status"),
        "live_authority_status": payload.get("live_authority_status"),
        "raw_value": payload.get("raw_value"),
        "rounded_value": payload.get("rounded_value"),
        "high_so_far": payload.get("high_so_far"),
        "low_so_far": payload.get("low_so_far"),
        "observation_time": payload.get("observation_time"),
        "observation_available_at": payload.get("observation_available_at"),
        "would_cross_book": would_cross,
        "tick_size": tick_size,
        "tick_aligned": _is_price_tick_aligned(limit_price, tick_size),
        "min_order_size": min_order_size,
        "size_ok": _float_or_default(payload.get("size"), 0.0) >= min_order_size,
        "neg_risk": authority_witness.neg_risk,
        "heartbeat_status": authority_witness.heartbeat_status,
        "user_ws_status": authority_witness.user_ws_status,
        "venue_connectivity_status": authority_witness.venue_connectivity_status,
        "balance_allowance_status": authority_witness.balance_allowance_status,
        "book_authority_id": authority_witness.book_authority_id,
        "book_captured_at": authority_witness.book_captured_at,
        "heartbeat_authority_id": authority_witness.heartbeat_authority_id,
        "heartbeat_checked_at": authority_witness.heartbeat_checked_at,
        "user_ws_authority_id": authority_witness.user_ws_authority_id,
        "user_ws_checked_at": authority_witness.user_ws_checked_at,
        "venue_connectivity_authority_id": authority_witness.venue_connectivity_authority_id,
        "venue_connectivity_checked_at": authority_witness.venue_connectivity_checked_at,
        "balance_allowance_authority_id": authority_witness.balance_allowance_authority_id,
        "balance_allowance_checked_at": authority_witness.balance_allowance_checked_at,
        "expected_edge_source_certificate_hash": payload.get("actionable_certificate_hash"),
        "cost_basis_source_certificate_hash": payload.get("cost_basis_hash"),
        "final_intent_certificate_hash": final_intent.certificate_hash,
    }


def _require_pre_submit_authority_witness(
    provider: Callable[[DecisionCertificate, DecisionCertificate, datetime], PreSubmitAuthorityWitness] | None,
    final_intent: DecisionCertificate,
    executable_snapshot: DecisionCertificate,
    decision_time: datetime,
) -> PreSubmitAuthorityWitness:
    if provider is None:
        raise ValueError("PRE_SUBMIT_AUTHORITY_WITNESS_REQUIRED")
    witness = provider(final_intent, executable_snapshot, decision_time)
    if not isinstance(witness, PreSubmitAuthorityWitness):
        raise ValueError("PRE_SUBMIT_AUTHORITY_WITNESS_REQUIRED")
    required_text_fields = {
        "book_hash": witness.book_hash,
        "book_authority_id": witness.book_authority_id,
        "book_captured_at": witness.book_captured_at,
        "heartbeat_authority_id": witness.heartbeat_authority_id,
        "heartbeat_checked_at": witness.heartbeat_checked_at,
        "user_ws_authority_id": witness.user_ws_authority_id,
        "user_ws_checked_at": witness.user_ws_checked_at,
        "venue_connectivity_authority_id": witness.venue_connectivity_authority_id,
        "venue_connectivity_checked_at": witness.venue_connectivity_checked_at,
        "balance_allowance_authority_id": witness.balance_allowance_authority_id,
        "balance_allowance_checked_at": witness.balance_allowance_checked_at,
    }
    missing = [field for field, value in required_text_fields.items() if not str(value or "").strip()]
    if missing:
        raise ValueError("PRE_SUBMIT_AUTHORITY_PROVENANCE_REQUIRED:" + ",".join(missing))
    return witness


_MAKER_BOOK_FRESH_MID_TOLERANCE_TICKS = 10.0


def _assert_maker_book_agrees_with_fresh_witness(
    *,
    quote_best_bid: float | None,
    quote_best_ask: float | None,
    fresh_best_bid: float | None,
    fresh_best_ask: float | None,
    tick_size: float,
    tolerance_ticks: float = _MAKER_BOOK_FRESH_MID_TOLERANCE_TICKS,
) -> None:
    """Fail closed when the maker-priced book disagrees with the fresh submit-time book.

    WALL #5 price-seam defense (2026-06-12). The maker limit is computed off the quote-cert
    book; the pre-submit JIT witness is the SAME candidate's book re-observed at submit. A mid
    divergence beyond ``tolerance_ticks`` means the quote book is not this candidate's live
    book (wrong-bin or ghost). Fail closed with a typed
    MAKER_BOOK_FRESH_WITNESS_DISAGREEMENT — the Busan incident's quote-mid (~0.0265) vs fresh
    mid (~0.64) is ~37 ticks at a 0.01 tick, far past tolerance, so it would have been
    rejected (or, post root-fix, priced off the right 0.64 book) and never rest at 0.02.
    """
    tick = max(float(tick_size), 0.0)
    if tick <= 0.0:
        # Without a positive tick the tolerance is undefined; the tick provenance guard
        # upstream already fails closed on a missing tick, so do not invent a bound here.
        return
    quote_mid = _two_sided_mid(quote_best_bid, quote_best_ask)
    fresh_mid = _two_sided_mid(fresh_best_bid, fresh_best_ask)
    if quote_mid is None or fresh_mid is None:
        # One side is single-sided/empty: the maker_limit_price / post-only crossing guards
        # own that case. This seam only adjudicates two measurable two-sided books.
        return
    divergence_ticks = abs(quote_mid - fresh_mid) / tick
    if divergence_ticks > float(tolerance_ticks):
        raise ValueError(
            "MAKER_BOOK_FRESH_WITNESS_DISAGREEMENT:"
            f"quote_mid={quote_mid:.6f}:fresh_mid={fresh_mid:.6f}:"
            f"divergence_ticks={divergence_ticks:.2f}:tolerance_ticks={float(tolerance_ticks):.2f}"
        )


def _two_sided_mid(best_bid: float | None, best_ask: float | None) -> float | None:
    """Mid of a two-sided book, or None when either side is missing/non-positive."""
    bid = _optional_float(best_bid)
    ask = _optional_float(best_ask)
    if bid is None or ask is None or bid <= 0.0 or ask <= 0.0:
        return None
    return (bid + ask) / 2.0


def _would_cross_post_only_book(
    *,
    side: str,
    limit_price: float,
    current_best_bid: float | None,
    current_best_ask: float | None,
) -> bool:
    if side == "BUY":
        if current_best_ask is None:
            raise ValueError("PRE_SUBMIT_BUY_BEST_ASK_REQUIRED")
        return limit_price >= current_best_ask
    if side == "SELL":
        if current_best_bid is None:
            raise ValueError("PRE_SUBMIT_SELL_BEST_BID_REQUIRED")
        return limit_price <= current_best_bid
    raise ValueError(f"unsupported pre-submit side: {side!r}")


def _is_price_tick_aligned(price: float, tick_size: float) -> bool:
    if tick_size <= 0:
        return False
    units = round(price / tick_size)
    return abs(price - units * tick_size) < 1e-9


def _build_live_cap_certificate_from_ledger(
    *,
    event: OpportunityEvent,
    receipt: EventSubmissionReceipt,
    decision_time: datetime,
    live_cap_conn: sqlite3.Connection | None,
    persist: bool = True,
) -> DecisionCertificate:
    if live_cap_conn is None:
        raise ValueError("LIVE_CAP_LEDGER_CONNECTION_REQUIRED")
    from src.events.live_cap import LIVE_EXECUTION_RESERVATION_SCOPE, LiveCapLedger

    # 2026-06-08 operator directive: the tiny_live $5 notional + per-day/window
    # order-count caps are DELETED. Order size is governed SOLELY by the
    # structural fractional-Kelly sizing upstream (money_path_adapters.evaluate_kelly).
    # The reservation records the (uncapped) Kelly notional; it clamps NOTHING.
    # A one-tick floor still guards against a sub-tick request.
    price = _float_or_default(receipt.c_fee_adjusted, 0.01)
    kelly_usd = float(receipt.kelly_size_usd or 0.0)
    min_order_notional = max(price, 0.01)
    requested_notional = max(kelly_usd, min_order_notional)
    usage_id = LiveCapLedger._usage_id(event.event_id, LIVE_EXECUTION_RESERVATION_SCOPE)
    if persist:
        reservation = LiveCapLedger(live_cap_conn).reserve(
            event_id=event.event_id,
            decision_time=decision_time,
            cap_scope=LIVE_EXECUTION_RESERVATION_SCOPE,
            requested_notional_usd=float(requested_notional),
            final_intent_id=receipt.final_intent_id,
        )
    else:
        from src.events.live_cap import LiveCapReservation

        reservation = LiveCapReservation(
            usage_id=usage_id,
            event_id=event.event_id,
            decision_time=decision_time,
            cap_scope=LIVE_EXECUTION_RESERVATION_SCOPE,
            reserved_notional_usd=float(requested_notional),
            reservation_status="RESERVED",
            final_intent_id=receipt.final_intent_id,
        )
    payload = reservation.certificate_payload()
    return build_certificate(
        certificate_type=claims.LIVE_CAP,
        semantic_key=f"live_cap:{reservation.usage_id}",
        claim_type=claims.LIVE_CAP,
        mode="LIVE",
        decision_time=decision_time,
        source_available_at=decision_time,  # AVAIL-POSSESSION-EXEMPTED: structural decision-time cert (submit-disabled LIVE_CAP reservation record generated AT decision_time, wraps no external source); field consumed only by verifier no-future-leakage check (<=decision_time), cert hash, max_parent_* monotonicity — never a freshness gate or q. decision_time is the only honest anchor.
        agent_received_at=decision_time,
        persisted_at=decision_time,
        payload=payload,
        parent_edges=(),
        parent_certificates=(),
        authority_id="edli.live_execution_reservation",
        authority_version="v1",
        algorithm_id="edli.live_execution_reservation",
        algorithm_version="v1",
    )


def _release_live_cap_for_submit_disabled(
    certificates: tuple[DecisionCertificate, ...],
    receipt_cert: DecisionCertificate,
    live_cap_conn: sqlite3.Connection | None,
    *,
    decision_time: datetime,
) -> DecisionCertificate:
    live_cap = _required_cert(certificates, claims.LIVE_CAP)
    command = _required_cert(certificates, claims.EXECUTION_COMMAND)
    _release_live_cap_certificate(live_cap, live_cap_conn, reason="SUBMIT_DISABLED")
    cap_event_hash = _append_cap_transition_aggregate_event(
        live_cap_conn,
        command,
        receipt_cert,
        to_status="RELEASED",
        projection_status="RELEASED",
        reason_code="SUBMIT_DISABLED",
        decision_time=decision_time,
    )
    return build_live_cap_transition_certificate(
        live_cap_cert=live_cap,
        execution_receipt_cert=receipt_cert,
        decision_time=decision_time,
        to_status="RELEASED",
        reason_code="SUBMIT_DISABLED",
        aggregate_event_hash=cap_event_hash,
    )


def _transition_live_cap_after_submit(
    certificates: tuple[DecisionCertificate, ...],
    live_cap_conn: sqlite3.Connection,
    command: DecisionCertificate,
    receipt_cert: DecisionCertificate,
    submit_result: EventBoundExecutorSubmitResult,
    *,
    decision_time: datetime,
) -> DecisionCertificate:
    live_cap = _required_cert(certificates, claims.LIVE_CAP)
    usage_id = str(live_cap.payload["usage_id"])
    from src.events.live_cap import LiveCapLedger

    ledger = LiveCapLedger(live_cap_conn)
    if submit_result.status == "SUBMITTED":
        ledger.consume(
            usage_id,
            final_intent_id=str(command.payload["final_intent_id"]),
            execution_command_id=str(command.payload["execution_command_id"]),
        )
        return build_live_cap_transition_certificate(
            live_cap_cert=live_cap,
            execution_receipt_cert=receipt_cert,
            decision_time=decision_time,
            to_status="CONSUMED",
            reason_code=submit_result.reason_code,
            aggregate_event_hash=_append_cap_transition_aggregate_event(
                live_cap_conn,
                command,
                receipt_cert,
                to_status="CONSUMED",
                projection_status="CONSUMED",
                reason_code=submit_result.reason_code,
                decision_time=decision_time,
            ),
        )
    elif submit_result.status in {"REJECTED", "PRE_SUBMIT_ERROR"}:
        ledger.release(usage_id, submit_result.reason_code)
        return build_live_cap_transition_certificate(
            live_cap_cert=live_cap,
            execution_receipt_cert=receipt_cert,
            decision_time=decision_time,
            to_status="RELEASED",
            reason_code=submit_result.reason_code,
            aggregate_event_hash=_append_cap_transition_aggregate_event(
                live_cap_conn,
                command,
                receipt_cert,
                to_status="RELEASED",
                projection_status="RELEASED",
                reason_code=submit_result.reason_code,
                decision_time=decision_time,
            ),
        )
    elif submit_result.status in {"TIMEOUT_UNKNOWN", "POST_SUBMIT_UNKNOWN"}:
        _append_submit_unknown_aggregate_event(
            live_cap_conn,
            command,
            receipt_cert,
            submit_result=submit_result,
            decision_time=decision_time,
        )
        return build_live_cap_transition_certificate(
            live_cap_cert=live_cap,
            execution_receipt_cert=receipt_cert,
            decision_time=decision_time,
            to_status="PENDING_RECONCILE",
            projection_status="RESERVED",
            reason_code=submit_result.reason_code,
            aggregate_event_hash=_append_cap_transition_aggregate_event(
                live_cap_conn,
                command,
                receipt_cert,
                to_status="PENDING_RECONCILE",
                projection_status="RESERVED",
                reason_code=submit_result.reason_code,
                decision_time=decision_time,
            ),
        )
    raise ValueError(f"unsupported submit result status for live cap transition: {submit_result.status!r}")


def _append_venue_submit_attempted_aggregate_event(
    conn: sqlite3.Connection | None,
    command: DecisionCertificate,
    *,
    decision_time: datetime,
) -> str | None:
    if conn is None:
        return None
    aggregate_id = str(command.payload.get("aggregate_id") or "")
    if not aggregate_id:
        return None
    event = LiveOrderAggregateLedger(conn).append_event(
        aggregate_id=aggregate_id,
        event_type="VenueSubmitAttempted",
        payload={
            "event_id": command.payload["event_id"],
            "final_intent_id": command.payload["final_intent_id"],
            "execution_command_id": command.payload["execution_command_id"],
            "idempotency_key": command.payload.get("idempotency_key"),
        },
        occurred_at=decision_time,
        source_authority="existing_executor",
    )
    return event.event_hash


def _append_submit_terminal_aggregate_event(
    conn: sqlite3.Connection | None,
    command: DecisionCertificate,
    receipt_cert: DecisionCertificate,
    *,
    submit_result: EventBoundExecutorSubmitResult,
    decision_time: datetime,
) -> str | None:
    if conn is None:
        return None
    aggregate_id = str(command.payload.get("aggregate_id") or "")
    if not aggregate_id:
        return None
    if submit_result.status == "SUBMITTED":
        event = LiveOrderAggregateLedger(conn).append_event(
            aggregate_id=aggregate_id,
            event_type="VenueSubmitAcknowledged",
            payload={
                "event_id": command.payload["event_id"],
                "final_intent_id": command.payload["final_intent_id"],
                "execution_command_id": command.payload["execution_command_id"],
                "execution_receipt_hash": receipt_cert.certificate_hash,
                "venue_order_id": submit_result.venue_order_id,
                "venue_ack_received": submit_result.venue_ack_received,
                "raw_response_hash": submit_result.raw_response_hash,
            },
            occurred_at=decision_time,
            source_authority="existing_executor",
        )
        return event.event_hash
    if submit_result.status in {"REJECTED", "PRE_SUBMIT_ERROR"}:
        is_pre_submit_rejection = submit_result.status == "PRE_SUBMIT_ERROR"
        event = LiveOrderAggregateLedger(conn).append_event(
            aggregate_id=aggregate_id,
            event_type="SubmitRejected",
            payload={
                "event_id": command.payload["event_id"],
                "final_intent_id": command.payload["final_intent_id"],
                "execution_command_id": command.payload["execution_command_id"],
                "execution_receipt_hash": receipt_cert.certificate_hash,
                "reason_code": submit_result.reason_code,
                "submit_status": submit_result.status,
                "venue_call_started": submit_result.venue_call_started,
                "venue_ack_received": submit_result.venue_ack_received,
                "pre_submit_rejection": is_pre_submit_rejection,
                "venue_order_id": submit_result.venue_order_id,
                "raw_response_hash": submit_result.raw_response_hash,
            },
            occurred_at=decision_time,
            source_authority="existing_executor",
        )
        return event.event_hash
    return None


