# mx2t3 carrier-decouple (GATE-1 C): the members_json_source a posterior-provenance forecast
# authority carries — MUST equal src/decision_kernel/verifier.POSTERIOR_MEMBERS_JSON_SOURCE (kept as
# a local literal to avoid an adapter→verifier import cycle; the two MUST agree).
_POSTERIOR_MEMBERS_JSON_SOURCE = "raw_model_forecasts.multimodel"
_REPLACEMENT_0_1_PRODUCT_ID = "openmeteo_ecmwf_ifs9_bayes_fusion_v1"
# The posterior applied-validations set the cert verifier/compiler require for posterior provenance
# (verifier.REQUIRED_POSTERIOR_FORECAST_VALIDATIONS). Stamped only when the posterior row exists and
# the decorrelated model floor is met — never fabricated.
_POSTERIOR_APPLIED_VALIDATIONS: tuple[str, ...] = (
    "posterior_complete_by_construction",
    "decorrelated_model_count_floor",
    "causality_status_ok",
    "authority_verified",
    "available_at_not_future",
)


def _parse_source_cycle_utc(value: object) -> datetime | None:
    if value is None or value == "":
        return None
    try:
        parsed = datetime.fromisoformat(str(value).replace("Z", "+00:00"))
    except ValueError:
        return None
    if parsed.tzinfo is None or parsed.utcoffset() is None:
        parsed = parsed.replace(tzinfo=UTC)
    return parsed.astimezone(UTC)


def _latest_raw_model_input_cycle_for_family(
    conn: sqlite3.Connection,
    *,
    family,
    decision_time: datetime,
) -> datetime | None:
    table_ref = _authority_table_ref(conn, "raw_model_forecasts")
    if table_ref is None:
        return None
    columns = _table_ref_columns(conn, table_ref)
    required = {"model", "city", "target_date", "metric", "source_cycle_time"}
    if not required.issubset(columns):
        return None
    predicates = ["city = ?", "target_date = ?", "metric = ?"]
    params: list[object] = [family.city, family.target_date, family.metric]
    decision_iso = decision_time.astimezone(UTC).isoformat()
    if "endpoint" in columns:
        predicates.append("endpoint = 'single_runs'")
    if "coverage_status" in columns:
        predicates.append("(coverage_status IS NULL OR coverage_status = 'COVERED')")
    if "captured_at" in columns:
        predicates.append("(captured_at IS NULL OR datetime(captured_at) <= datetime(?))")
        params.append(decision_iso)
    if "source_available_at" in columns:
        predicates.append(
            "(source_available_at IS NULL OR datetime(source_available_at) <= datetime(?))"
        )
        params.append(decision_iso)
    anchor_terms = ["model = 'ecmwf_ifs'"]
    if "source_id" in columns:
        anchor_terms.append("source_id = 'ecmwf_ifs_single_runs'")
    if "product_id" in columns:
        anchor_terms.append("product_id = 'ecmwf_ifs::single_runs'")
    anchor_expr = " OR ".join(anchor_terms)
    try:
        row = conn.execute(
            f"""
            SELECT source_cycle_time
              FROM {table_ref}
             WHERE {' AND '.join(predicates)}
               AND datetime(source_cycle_time) <= datetime(?)
             GROUP BY source_cycle_time
             HAVING COUNT(DISTINCT model) >= 2
                AND SUM(CASE WHEN ({anchor_expr}) THEN 1 ELSE 0 END) > 0
             ORDER BY datetime(source_cycle_time) DESC
             LIMIT 1
            """,
            tuple([*params, decision_iso]),
        ).fetchone()
    except Exception:  # noqa: BLE001 - live gate must fail closed at the caller
        return None
    if row is None:
        return None
    try:
        raw_value = row["source_cycle_time"]
    except Exception:  # noqa: BLE001
        raw_value = row[0]
    return _parse_source_cycle_utc(raw_value)


def _latest_raw_artifact_input_cycle_for_family(
    conn: sqlite3.Connection,
    *,
    family,
    decision_time: datetime,
) -> datetime | None:
    table_ref = _authority_table_ref(conn, "raw_forecast_artifacts")
    if table_ref is None:
        return None
    columns = _table_ref_columns(conn, table_ref)
    required = {
        "source_cycle_time",
        "captured_at",
        "source_available_at",
        "artifact_metadata_json",
    }
    if not required.issubset(columns):
        return None
    predicates = [
        "json_extract(artifact_metadata_json, '$.city') = ?",
        "json_extract(artifact_metadata_json, '$.target_date') = ?",
        "json_extract(artifact_metadata_json, '$.metric') = ?",
        "datetime(captured_at) <= datetime(?)",
        "datetime(source_available_at) <= datetime(?)",
    ]
    decision_iso = decision_time.astimezone(UTC).isoformat()
    params: list[object] = [
        family.city,
        family.target_date,
        family.metric,
        decision_iso,
        decision_iso,
    ]
    if "source_id" in columns:
        predicates.append("source_id = 'openmeteo_ecmwf_ifs_9km'")
    try:
        row = conn.execute(
            f"""
            SELECT source_cycle_time
              FROM {table_ref}
             WHERE {' AND '.join(predicates)}
               AND datetime(source_cycle_time) <= datetime(?)
             GROUP BY source_cycle_time
             ORDER BY datetime(source_cycle_time) DESC
             LIMIT 1
            """,
            tuple([*params, decision_iso]),
        ).fetchone()
    except Exception:  # noqa: BLE001 - live gate must fail closed at the caller
        return None
    if row is None:
        return None
    try:
        raw_value = row["source_cycle_time"]
    except Exception:  # noqa: BLE001
        raw_value = row[0]
    return _parse_source_cycle_utc(raw_value)


def _latest_live_input_cycle_for_family(
    conn: sqlite3.Connection,
    *,
    family,
    decision_time: datetime,
) -> tuple[datetime | None, str | None]:
    candidates = [
        (
            _latest_raw_model_input_cycle_for_family(
                conn, family=family, decision_time=decision_time
            ),
            "source_cycle_time_raw_model_forecasts_lag",
        ),
        (
            _latest_raw_artifact_input_cycle_for_family(
                conn, family=family, decision_time=decision_time
            ),
            "source_cycle_time_raw_forecast_artifacts_lag",
        ),
    ]
    candidates = [(cycle, basis) for cycle, basis in candidates if cycle is not None]
    if not candidates:
        return None, None
    return max(candidates, key=lambda item: item[0])


def _replacement_live_input_lag_reason(
    conn: sqlite3.Connection,
    *,
    family,
    decision_time: datetime,
    posterior_source_cycle_time: object,
) -> str | None:
    posterior_cycle = _parse_source_cycle_utc(posterior_source_cycle_time)
    if posterior_cycle is None:
        return f"posterior_source_cycle_unparseable={posterior_source_cycle_time!s}"
    latest_raw_cycle, basis = _latest_live_input_cycle_for_family(
        conn, family=family, decision_time=decision_time
    )
    if latest_raw_cycle is None or latest_raw_cycle <= posterior_cycle:
        return None
    lag_hours = (latest_raw_cycle - posterior_cycle).total_seconds() / 3600.0
    return (
        f"basis={basis or 'source_cycle_time_live_input_lag'}:"
        f"latest_raw_cycle={latest_raw_cycle.isoformat()}:"
        f"posterior_cycle={posterior_cycle.isoformat()}:"
        f"lag_h={lag_hours:.2f}"
    )


def _forecast_authority_payload_from_posterior(
    conn: sqlite3.Connection,
    *,
    event: OpportunityEvent,
    family,
    payload: dict[str, object],
    decision_time: datetime,
) -> tuple[dict[str, Any], EvidenceClock] | None:
    """GATE-1 C: build the no-submit cert's FORECAST_AUTHORITY payload + clock from
    ``forecast_posteriors`` + ``raw_model_forecasts`` (mx2t3-independent), NOT ensemble_snapshots.

    Returns the SAME-shaped ``(payload_out, EvidenceClock)`` the ensemble path returns, but with
    posterior provenance: ``members_json_source='raw_model_forecasts.multimodel'``,
    ``members_json_hash=sha256(sorted native member set)``, ``source_run_id=posterior_identity_hash``,
    the decorrelated model count as expected==observed members, and the posterior applied-validations
    set. The cert verifier/compiler validate this via the EQUALLY-STRICT posterior branch.

    Internal-consistency keys are set so the bundle cross-checks hold:
      * ``forecast_source_id`` / ``source_id`` == the FSR ``payload['source_id']`` (source_truth eq);
      * ``source_run_id`` == ``payload['source_run_id']`` (== posterior_identity_hash; chain eq);
      * ``snapshot_id`` == the neutral ``rmf-...`` ``event.causal_snapshot_id`` (causal eq);
      * ``members_json_hash`` is read by BOTH the forecast and belief cells from this one dict.

    FAIL-CLOSED: returns ``None`` only for ordinary missing posterior evidence. If a newer live
    raw input exists than the selected posterior's source cycle, this raises a typed blocker so the
    replacement lane cannot fall back to legacy ensemble evidence and trade on an old belief.
    """
    city_config = runtime_cities_by_name().get(family.city)
    if city_config is None:
        return None
    posterior_table = _authority_table_ref(conn, "forecast_posteriors")
    if posterior_table is None:
        return None
    _decision_iso = decision_time.astimezone(UTC).isoformat()
    try:
        prow = conn.execute(
            f"""
            SELECT source_id, source_cycle_time, source_available_at, computed_at,
                   posterior_identity_hash, data_version
              FROM {posterior_table}
             WHERE product_id = ?
               AND city = ? AND target_date = ? AND temperature_metric = ?
               AND (source_available_at IS NULL OR source_available_at <= ?)
               AND (computed_at IS NULL OR computed_at <= ?)
               AND datetime(source_available_at) <= datetime(computed_at)
             ORDER BY source_cycle_time DESC, computed_at DESC, posterior_id DESC
             LIMIT 1
            """,
            (
                _REPLACEMENT_0_1_PRODUCT_ID,
                family.city,
                family.target_date,
                family.metric,
                _decision_iso,
                _decision_iso,
            ),
        ).fetchone()
    except Exception:  # noqa: BLE001 — fall back to the ensemble path on any read fault
        return None
    if prow is None:
        return None
    (
        p_source_id,
        p_source_cycle_time,
        p_source_available_at,
        p_computed_at,
        p_identity_hash,
        p_data_version,
    ) = prow
    if not p_identity_hash or not p_source_cycle_time:
        return None
    raw_lag_reason = _replacement_live_input_lag_reason(
        conn,
        family=family,
        decision_time=decision_time,
        posterior_source_cycle_time=p_source_cycle_time,
    )
    if raw_lag_reason is not None:
        raise ValueError(f"REPLACEMENT_LIVE_INPUT_LAG:{raw_lag_reason}")
    # The decorrelated multi-model member set for this family/cycle (the SAME set the spine used).
    members = _spine_multimodel_members_for_event(
        conn, event=event, family=family, decision_time=decision_time
    )
    if members is None:
        return None
    members_native, _causal_sct, _spine_precision = members
    if len(members_native) < 3:
        return None
    member_count = len(members_native)
    members_json_hash = stable_hash(tuple(sorted(float(v) for v in members_native)))
    metric = family.metric
    # source_id / source_run_id MUST match what source_truth reads off the FSR payload so the
    # cert's source_truth.source_id==forecast.forecast_source_id and source_run_id chain eq hold.
    source_id = _nonnull(payload.get("source_id")) or _nonnull(p_source_id) or "openmeteo"
    source_run_id = _nonnull(payload.get("source_run_id")) or str(p_identity_hash)
    snapshot_id = _nonnull(getattr(event, "causal_snapshot_id", None)) or str(p_identity_hash)
    try:
        source_run_row = conn.execute(
            """
            SELECT fetch_started_at, fetch_finished_at, valid_time_start
              FROM source_run
             WHERE source_run_id = ?
             LIMIT 1
            """,
            (source_run_id,),
        ).fetchone()
    except Exception:  # noqa: BLE001 - source_run evidence is optional for posterior payloads
        source_run_row = None

    def _source_run_value(index: int, key: str) -> object:
        if source_run_row is None:
            return None
        try:
            return source_run_row[key]
        except Exception:  # noqa: BLE001
            try:
                return source_run_row[index]
            except Exception:  # noqa: BLE001
                return None

    source_fetch_started_at = _nonnull(_source_run_value(0, "fetch_started_at"))
    source_fetch_finished_at = _nonnull(_source_run_value(1, "fetch_finished_at"))
    forecast_valid_time = _nonnull(_source_run_value(2, "valid_time_start")) or f"{family.target_date}T00:00:00"
    payload_out = {
        "identity": snapshot_id,
        "snapshot_id": snapshot_id,
        "reader_authority": "forecast_posteriors.replacement_0_1",
        "reader_status": FORECAST_LIVE_ELIGIBLE_STATUS,
        "reader_reason_code": None,
        "city": family.city,
        "target_date": family.target_date,
        "metric": metric,
        "temperature_metric": metric,
        "members_extrema_metric_identity": metric,
        "members_extrema_transform": _members_extrema_transform(metric),
        "members_json_source": _POSTERIOR_MEMBERS_JSON_SOURCE,
        "members_json_hash": members_json_hash,
        "target_local_date": family.target_date,
        "city_timezone": city_config.timezone,
        "settlement_unit": str(getattr(city_config, "settlement_unit", "C") or "C"),
        "members_unit": str(getattr(city_config, "settlement_unit", "C") or "C"),
        "unit": str(getattr(city_config, "settlement_unit", "C") or "C"),
        "unit_authority_source": "city_config.settlement_unit",
        "local_date_window_hash": stable_hash(
            {
                "city": family.city,
                "target_date": family.target_date,
                "temperature_metric": metric,
                "members_json_hash": members_json_hash,
                "source_cycle_time": str(p_source_cycle_time),
            }
        ),
        "forecast_source_id": source_id,
        "source_id": source_id,
        "model": _POSTERIOR_MEMBERS_JSON_SOURCE,
        "model_family": _POSTERIOR_MEMBERS_JSON_SOURCE,
        "forecast_issue_time": str(p_source_cycle_time),
        "forecast_valid_time": forecast_valid_time,
        "forecast_fetch_time": _nonnull(p_computed_at),
        "forecast_available_at": _nonnull(p_source_available_at),
        "raw_payload_hash": str(p_identity_hash),
        "forecast_source_role": "entry_primary",
        "degradation_level": "OK",
        "authority_tier": "FORECAST",
        "decision_time": _decision_iso,
        "decision_time_status": "OK",
        "first_member_observed_time": source_fetch_started_at or _nonnull(p_source_available_at),
        "run_complete_time": source_fetch_finished_at or _nonnull(p_computed_at),
        "forecast_data_version": _nonnull(p_data_version) or _POSTERIOR_MEMBERS_JSON_SOURCE,
        "source_cycle_time": str(p_source_cycle_time),
        "source_issue_time": _nonnull(p_source_available_at) or str(p_source_cycle_time),
        "horizon_profile": _posterior_horizon_profile(str(p_source_cycle_time)),
        "source_run_id": source_run_id,
        "coverage_id": str(p_identity_hash),
        "posterior_identity_hash": str(p_identity_hash),
        "manifest_hash": str(p_identity_hash),
        # Posterior completeness-by-construction: model COUNT is the completeness metric (the
        # ensemble member/step floors do not apply). expected==observed==count, count>=3.
        "expected_members": member_count,
        "observed_members": member_count,
        "required_steps": (str(p_source_cycle_time)[:10],),
        "observed_steps": (str(p_source_cycle_time)[:10],),
        "source_run_status": "COMPLETE",
        "source_run_completeness_status": "COMPLETE",
        "coverage_completeness_status": "COMPLETE",
        "coverage_readiness_status": "LIVE_ELIGIBLE",
        "applied_validations": _POSTERIOR_APPLIED_VALIDATIONS,
        "source_available_at": _nonnull(p_source_available_at),
        "fetch_started_at": source_fetch_started_at or None,
        "fetch_finished_at": source_fetch_finished_at or _nonnull(p_computed_at),
        "captured_at": _nonnull(p_computed_at),
    }
    source_time = _parse_utc(p_source_available_at)
    agent_time = _parse_utc(p_computed_at) or source_time
    persisted_time = _parse_utc(p_computed_at) or source_time
    if source_time is None or agent_time is None or persisted_time is None:
        return None
    return payload_out, EvidenceClock(source_time, agent_time, persisted_time)


def _posterior_horizon_profile(source_cycle_time: str) -> str:
    """Derive the live posterior horizon stratum.

    Replacement posteriors sourced from 00Z/06Z/12Z/18Z are all authorized live
    cycles. Do not downgrade 06Z/18Z into a short/experimental calibration layer.
    """
    try:
        hour = int(str(source_cycle_time)[11:13])
    except (ValueError, IndexError):
        return "full"
    return "full" if hour in (0, 6, 12, 18) else "short"


def _forecast_authority_payload_and_clock(
    conn: sqlite3.Connection,
    *,
    event: OpportunityEvent,
    family,
    payload: dict[str, object],
    decision_time: datetime,
) -> tuple[dict[str, Any], EvidenceClock]:
    # mx2t3 carrier-decouple (GATE-1 C): under the replacement lane the no-submit cert's forecast
    # authority is built from forecast_posteriors + raw_model_forecasts (mx2t3-independent) instead
    # of the cold ensemble_snapshots row + read_executable_forecast(members_json). This runs for the
    # FORECAST decision lanes ONLY (NOT day0 — day0 keeps its ensemble base, carrier_decouple_plan
    # §4). Forked on the SAME _replacement_authority_enabled() flag the live q is gated by; the
    # legacy ensemble path below is untouched for flag-OFF and for day0.
    if (
        _replacement_authority_enabled()
        and event.event_type in _FORECAST_DECISION_EVENT_TYPES
        and event.event_type not in _DAY0_LANE_EVENT_TYPES
    ):
        posterior = _forecast_authority_payload_from_posterior(
            conn, event=event, family=family, payload=payload, decision_time=decision_time
        )
        if posterior is not None:
            return posterior
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:replacement_posterior")
    allow_latest = event.event_type == "DAY0_EXTREME_UPDATED"
    snapshot = _forecast_snapshot_row_for_event(
        conn,
        event=event,
        family=family,
        allow_latest=allow_latest,
        decision_time=decision_time,
    )
    if snapshot is None:
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:snapshot")
    source_run_id = _nonnull(snapshot.get("source_run_id") or payload.get("source_run_id"))
    source_run_table = _authority_table_ref(conn, "source_run")
    coverage_table = _authority_table_ref(conn, "source_run_coverage")
    if not source_run_id or source_run_table is None or coverage_table is None:
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:scope")
    source_run = _row_by_id(conn, source_run_table, "source_run_id", source_run_id)
    if source_run is None:
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:source_run")
    coverage = _coverage_row_for_snapshot(
        conn,
        coverage_table,
        source_run_id=source_run_id,
        family=family,
        snapshot=snapshot,
    )
    if coverage is None:
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:coverage")
    if getattr(event, "event_type", None) == "DAY0_EXTREME_UPDATED":
        return _day0_forecast_authority_payload_and_clock(
            snapshot=snapshot,
            source_run=source_run,
            coverage=coverage,
            event=event,
            family=family,
            payload=payload,
            decision_time=decision_time,
        )
    result = _read_executable_forecast_bundle_result(
        conn,
        snapshot=snapshot,
        source_run=source_run,
        coverage=coverage,
        event=event,
        family=family,
        decision_time=decision_time,
    )
    if not result.ok or result.bundle is None:
        raise ValueError(f"FORECAST_AUTHORITY_EVIDENCE_MISSING:{result.reason_code}")
    evidence = result.bundle.evidence
    if not tuple(evidence.applied_validations):
        raise ValueError("FORECAST_AUTHORITY_VALIDATIONS_MISSING")
    unit = _snapshot_unit(snapshot, payload)
    city_config = runtime_cities_by_name().get(family.city)
    if city_config is None:
        raise ValueError(f"FORECAST_AUTHORITY_EVIDENCE_MISSING:city:{family.city}")
    members_json_hash = _snapshot_members_json_hash(snapshot)
    # horizon_profile is NOT a column on ensemble_snapshots and is not populated upstream
    # (forecast_calibration_domain.derive_phase2_keys_from_ens_result docstring). The calibrator
    # lookup DERIVES the horizon stratum from the forecast cycle (00/12 -> 'full', else 'short').
    # The forecast authority must carry that SAME derived value so the no-submit cert can enforce a
    # real calibration.horizon_profile == forecast.horizon_profile equality instead of silently
    # comparing a derived 'full' against a structural None (the live FORECAST horizon mismatch leak).
    from src.calibration.forecast_calibration_domain import derive_phase2_keys_from_ens_result

    _, _, derived_horizon_profile = derive_phase2_keys_from_ens_result(
        {
            "issue_time": _nonnull(
                evidence.source_issue_time
                or evidence.source_cycle_time
                or snapshot.get("source_issue_time")
                or snapshot.get("source_cycle_time")
                or payload.get("issue_time")
                or payload.get("source_cycle_time")
            ),
            "source_id": _nonnull(evidence.forecast_source_id or snapshot.get("source_id") or payload.get("source_id")),
            "horizon_profile": snapshot.get("horizon_profile"),
        }
    )
    ens_result = result.bundle.to_ens_result()
    payload_out = {
        "identity": str(result.bundle.snapshot.snapshot_id),
        "snapshot_id": str(result.bundle.snapshot.snapshot_id),
        "reader_authority": "read_executable_forecast",
        "reader_status": normalize_forecast_reader_status(result.status, result.reason_code) or result.status,
        "reader_reason_code": None if result.reason_code in {None, "", "OK", "LIVE_ELIGIBLE", "EXECUTABLE_FORECAST_READY"} else result.reason_code,
        "city": family.city,
        "target_date": family.target_date,
        "metric": family.metric,
        "temperature_metric": family.metric,
        "members_extrema_metric_identity": snapshot.get("temperature_metric"),
        "members_extrema_transform": _members_extrema_transform(family.metric),
        "members_json_source": "ensemble_snapshots.daily_extrema",
        "members_json_hash": members_json_hash,
        "target_local_date": family.target_date,
        "city_timezone": city_config.timezone,
        "settlement_unit": snapshot.get("settlement_unit"),
        "members_unit": snapshot.get("members_unit"),
        "unit": unit,
        "unit_authority_source": _snapshot_unit_authority_source(snapshot),
        "local_date_window_hash": stable_hash(
            {
                "city": snapshot.get("city"),
                "target_date": snapshot.get("target_date"),
                "temperature_metric": snapshot.get("temperature_metric"),
                "members_json_hash": members_json_hash,
                "local_day_start_utc": snapshot.get("local_day_start_utc"),
                "forecast_window_start_utc": snapshot.get("forecast_window_start_utc"),
                "forecast_window_end_utc": snapshot.get("forecast_window_end_utc"),
            }
        ),
        "forecast_source_id": evidence.forecast_source_id,
        "model": ens_result.get("model"),
        "model_family": ens_result.get("model"),
        "forecast_issue_time": ens_result.get("issue_time"),
        "forecast_valid_time": ens_result.get("valid_time"),
        "forecast_fetch_time": ens_result.get("fetch_time"),
        "forecast_available_at": ens_result.get("available_at"),
        "degradation_level": ens_result.get("degradation_level"),
        "forecast_source_role": ens_result.get("forecast_source_role"),
        "authority_tier": ens_result.get("authority_tier"),
        "decision_time": decision_time.astimezone(UTC).isoformat(),
        "decision_time_status": "OK",
        "first_member_observed_time": ens_result.get("first_member_observed_time"),
        "run_complete_time": ens_result.get("run_complete_time"),
        "forecast_data_version": evidence.forecast_data_version,
        "source_transport": evidence.source_transport,
        "source_cycle_time": evidence.source_cycle_time,
        "source_issue_time": evidence.source_issue_time,
        "horizon_profile": _nonnull(snapshot.get("horizon_profile")) or derived_horizon_profile,
        "source_run_id": evidence.source_run_id,
        "coverage_id": evidence.coverage_id,
        "producer_readiness_id": evidence.producer_readiness_id,
        "entry_readiness_id": evidence.entry_readiness_id,
        "input_snapshot_ids": tuple(str(item) for item in evidence.input_snapshot_ids),
        "raw_payload_hash": ens_result.get("raw_payload_hash"),
        "manifest_hash": evidence.manifest_hash,
        "required_steps": tuple(evidence.required_steps),
        "observed_steps": tuple(evidence.observed_steps),
        "expected_members": evidence.expected_members,
        "observed_members": evidence.observed_members,
        "source_run_status": evidence.source_run_status,
        "source_run_completeness_status": evidence.source_run_completeness_status,
        "coverage_completeness_status": evidence.coverage_completeness_status,
        "coverage_readiness_status": evidence.coverage_readiness_status,
        "applied_validations": tuple(evidence.applied_validations),
        "source_available_at": evidence.source_available_at,
        "fetch_started_at": evidence.fetch_started_at,
        "fetch_finished_at": evidence.fetch_finished_at,
        "captured_at": evidence.captured_at,
    }
    source_time = _parse_utc(evidence.source_available_at)
    agent_time = _parse_utc(evidence.fetch_finished_at) or _parse_utc(evidence.captured_at)
    persisted_time = (
        _parse_utc(source_run.get("imported_at"))
        or _parse_utc(coverage.get("computed_at"))
        or _parse_utc(evidence.captured_at)
    )
    if source_time is None or agent_time is None or persisted_time is None:
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:clock")
    return payload_out, EvidenceClock(source_time, agent_time, persisted_time)


def _day0_forecast_authority_payload_and_clock(
    *,
    snapshot: dict[str, Any],
    source_run: dict[str, Any],
    coverage: dict[str, Any],
    event: OpportunityEvent,
    family,
    payload: dict[str, object],
    decision_time: datetime,
) -> tuple[dict[str, Any], EvidenceClock]:
    """Build the forecast-base authority for DAY0 hard-fact decisions.

    Day0 consumes realized observation facts, then uses the latest causality-safe
    forecast snapshot only as a base distribution to mask. The entry forecast reader's
    runtime readiness TTL licenses new forecast-entry decisions; it must not veto a
    live-authorized Day0 observation after the target day is already realizing.
    """

    from src.calibration.forecast_calibration_domain import derive_phase2_keys_from_ens_result

    unit = _snapshot_unit(snapshot, payload)
    city_config = runtime_cities_by_name().get(family.city)
    if city_config is None:
        raise ValueError(f"FORECAST_AUTHORITY_EVIDENCE_MISSING:city:{family.city}")
    coverage_readiness = _nonnull(coverage.get("readiness_status"))
    coverage_completeness = _nonnull(coverage.get("completeness_status"))
    source_run_completeness = _nonnull(source_run.get("completeness_status"))
    if coverage_readiness != "LIVE_ELIGIBLE":
        raise ValueError(f"FORECAST_AUTHORITY_EVIDENCE_MISSING:coverage_readiness:{coverage_readiness or 'missing'}")
    if coverage_completeness != "COMPLETE":
        raise ValueError(f"FORECAST_AUTHORITY_EVIDENCE_MISSING:coverage_completeness:{coverage_completeness or 'missing'}")
    if source_run_completeness not in {"COMPLETE", "PARTIAL"}:
        raise ValueError(f"FORECAST_AUTHORITY_EVIDENCE_MISSING:source_run_completeness:{source_run_completeness or 'missing'}")
    required_steps = tuple(str(item) for item in _json_list(coverage.get("expected_steps_json") or source_run.get("expected_steps_json")))
    observed_steps = tuple(str(item) for item in _json_list(coverage.get("observed_steps_json") or source_run.get("observed_steps_json")))
    expected_members = int(coverage.get("expected_members") or source_run.get("expected_members") or 0)
    observed_members = int(coverage.get("observed_members") or source_run.get("observed_members") or 0)
    if not required_steps or not set(required_steps).issubset(set(observed_steps)):
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:steps")
    if expected_members <= 0 or observed_members < expected_members:
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:members")
    if _nonnull(snapshot.get("authority") or "VERIFIED") != "VERIFIED":
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:authority")
    if _nonnull(snapshot.get("causality_status") or "OK") != "OK":
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:causality")
    if int(snapshot.get("boundary_ambiguous") or 0) != 0:
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:boundary_ambiguous")
    available_at = _parse_utc(snapshot.get("available_at"))
    if available_at is None or available_at > decision_time.astimezone(UTC):
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:available_at")
    _, _, derived_horizon_profile = derive_phase2_keys_from_ens_result(
        {
            "issue_time": _nonnull(
                source_run.get("source_issue_time")
                or snapshot.get("source_issue_time")
                or snapshot.get("issue_time")
                or payload.get("issue_time")
                or payload.get("source_cycle_time")
            ),
            "source_id": _nonnull(coverage.get("source_id") or source_run.get("source_id") or snapshot.get("source_id")),
            "horizon_profile": snapshot.get("horizon_profile"),
        }
    )
    payload_out = {
        "identity": str(snapshot.get("snapshot_id")),
        "snapshot_id": str(snapshot.get("snapshot_id")),
        "reader_authority": "day0_latest_forecast_snapshot_seed",
        "reader_status": "VERIFIED",
        "reader_reason_code": None,
        "city": family.city,
        "target_date": family.target_date,
        "metric": family.metric,
        "temperature_metric": family.metric,
        "members_extrema_metric_identity": snapshot.get("temperature_metric"),
        "members_extrema_transform": _members_extrema_transform(family.metric),
        "members_json_source": "ensemble_snapshots.daily_extrema",
        "members_json_hash": _snapshot_members_json_hash(snapshot),
        "target_local_date": family.target_date,
        "city_timezone": _nonnull(coverage.get("city_timezone") or source_run.get("city_timezone") or snapshot.get("city_timezone") or city_config.timezone),
        "settlement_unit": snapshot.get("settlement_unit"),
        "members_unit": snapshot.get("members_unit"),
        "unit": unit,
        "unit_authority_source": _snapshot_unit_authority_source(snapshot),
        "local_date_window_hash": stable_hash(
            {
                "city": snapshot.get("city"),
                "target_date": snapshot.get("target_date"),
                "temperature_metric": snapshot.get("temperature_metric"),
                "members_json_hash": _snapshot_members_json_hash(snapshot),
                "local_day_start_utc": snapshot.get("local_day_start_utc"),
                "forecast_window_start_utc": snapshot.get("forecast_window_start_utc"),
                "forecast_window_end_utc": snapshot.get("forecast_window_end_utc"),
            }
        ),
        "forecast_source_id": coverage.get("source_id") or source_run.get("source_id") or snapshot.get("source_id"),
        "model": snapshot.get("model_version"),
        "model_family": snapshot.get("model_version"),
        "forecast_issue_time": snapshot.get("issue_time") or source_run.get("source_issue_time"),
        "forecast_valid_time": snapshot.get("valid_time"),
        "forecast_fetch_time": snapshot.get("fetch_time") or source_run.get("fetch_finished_at"),
        "forecast_available_at": snapshot.get("available_at") or source_run.get("source_available_at"),
        "degradation_level": "OK",
        "forecast_source_role": "day0_base_distribution",
        "authority_tier": "FORECAST",
        "decision_time": decision_time.astimezone(UTC).isoformat(),
        "decision_time_status": "OK",
        "first_member_observed_time": snapshot.get("first_member_observed_time"),
        "run_complete_time": snapshot.get("run_complete_time"),
        "forecast_data_version": coverage.get("data_version") or snapshot.get("dataset_id"),
        "source_transport": coverage.get("source_transport") or snapshot.get("source_transport"),
        "source_cycle_time": source_run.get("source_cycle_time") or snapshot.get("source_cycle_time"),
        "source_issue_time": source_run.get("source_issue_time") or snapshot.get("source_issue_time") or snapshot.get("issue_time"),
        "horizon_profile": _nonnull(snapshot.get("horizon_profile")) or derived_horizon_profile,
        "source_run_id": source_run.get("source_run_id") or snapshot.get("source_run_id"),
        "coverage_id": coverage.get("coverage_id"),
        "producer_readiness_id": None,
        "entry_readiness_id": None,
        "input_snapshot_ids": tuple(str(item) for item in _json_list(coverage.get("snapshot_ids_json"))),
        "raw_payload_hash": source_run.get("raw_payload_hash")
        or stable_hash(
            {
                "source": "day0_latest_forecast_snapshot_seed",
                "snapshot_id": snapshot.get("snapshot_id"),
                "source_run_id": source_run.get("source_run_id") or snapshot.get("source_run_id"),
                "members_json_hash": _snapshot_members_json_hash(snapshot),
                "available_at": snapshot.get("available_at") or source_run.get("source_available_at"),
            }
        ),
        "manifest_hash": source_run.get("manifest_hash") or snapshot.get("manifest_hash"),
        "required_steps": required_steps,
        "observed_steps": observed_steps,
        "expected_members": expected_members,
        "observed_members": observed_members,
        "source_run_status": source_run.get("status"),
        "source_run_completeness_status": source_run_completeness,
        "coverage_completeness_status": coverage_completeness,
        "coverage_readiness_status": coverage_readiness,
        "applied_validations": (
            "source_run_completeness_status",
            "coverage_completeness_status",
            "coverage_readiness_status",
            "required_steps_observed",
            "expected_members_observed",
            "causality_status_ok",
            "authority_verified",
            "available_at_not_future",
        ),
        "source_available_at": snapshot.get("source_available_at") or source_run.get("source_available_at") or snapshot.get("available_at"),
        "fetch_started_at": source_run.get("fetch_started_at"),
        "fetch_finished_at": source_run.get("fetch_finished_at") or snapshot.get("fetch_time"),
        "captured_at": source_run.get("captured_at") or snapshot.get("fetch_time") or snapshot.get("available_at"),
        "day0_entry_readiness_expiry_not_applied": True,
        "day0_base_forecast_scope": "base_distribution_only",
    }
    source_time = _parse_utc(payload_out.get("source_available_at"))
    agent_time = _parse_utc(payload_out.get("fetch_finished_at")) or _parse_utc(payload_out.get("captured_at"))
    persisted_time = (
        _parse_utc(source_run.get("imported_at"))
        or _parse_utc(coverage.get("computed_at"))
        or _parse_utc(snapshot.get("recorded_at"))
        or _parse_utc(payload_out.get("captured_at"))
    )
    if source_time is None or agent_time is None or persisted_time is None:
        raise ValueError("FORECAST_AUTHORITY_EVIDENCE_MISSING:clock")
    return payload_out, EvidenceClock(source_time, agent_time, persisted_time)


def _calibration_authority_payload_and_clock(
    calibration_conn: sqlite3.Connection,
    *,
    event: OpportunityEvent,
    family,
    payload: dict[str, object],
    forecast_payload: dict[str, Any],
    decision_time: datetime,
) -> tuple[dict[str, Any], EvidenceClock]:
    city = runtime_cities_by_name().get(family.city)
    if city is None:
        raise ValueError("CALIBRATION_AUTHORITY_EVIDENCE_MISSING:city")
    if getattr(event, "event_type", None) == "DAY0_EXTREME_UPDATED":
        return _day0_calibration_authority_payload_and_clock(
            city=city,
            family=family,
            payload=payload,
            forecast_payload=forecast_payload,
            decision_time=decision_time,
        )
    # CERT BRIDGE (2026-06-10, funnel #1 unlock) — replacement-chain candidates carry their
    # OWN calibration credential (fused-center bootstrap bounds + settlement-backward
    # coverage), stamped onto `payload` by the live replacement builder. When present, mint
    # the first-class FUSED_BOOTSTRAP_SETTLEMENT_COVERAGE authority and SHORT-CIRCUIT the
    # legacy Platt-bucket lookup entirely — their q never passed through Platt, so demanding
    # its credential is a category mismatch. Absent the credential (legacy path, OR a
    # replacement candidate without certified bounds) we fall through to the Platt path
    # below unchanged → IDENTITY_FALLBACK reject exactly as today (strictness (a) and (b)).
    _replacement_credential = payload.get(_REPLACEMENT_CALIBRATION_CREDENTIAL_KEY)
    if isinstance(_replacement_credential, Mapping):
        # horizon_profile MUST equal forecast.horizon_profile (verifier round-trip
        # _validate_calibration_payload); read it from the same forecast/payload sources the
        # legacy path uses. The bootstrap bounds are model-available at decision time (the
        # posterior is materialized before the decision), so the clock is the decision time
        # — identical treatment to the IDENTITY_FALLBACK alternative-credential clock.
        _horizon_profile = _nonnull(
            payload.get("horizon_profile") or forecast_payload.get("horizon_profile")
        )
        payload_out = _replacement_calibration_payload_from_credential(
            _replacement_credential,
            horizon_profile=_horizon_profile,
            decision_time=decision_time,
        )
        return payload_out, EvidenceClock(decision_time, decision_time, decision_time)
    source_id = _nonnull(payload.get("source_id") or forecast_payload.get("forecast_source_id"))
    issue_time = _nonnull(
        payload.get("issue_time")
        or payload.get("source_cycle_time")
        or payload.get("cycle")
        or forecast_payload.get("source_issue_time")
        or forecast_payload.get("source_cycle_time")
    )
    if not source_id or not issue_time:
        raise ValueError("CALIBRATION_AUTHORITY_EVIDENCE_MISSING:forecast_provenance")
    from src.calibration.forecast_calibration_domain import derive_phase2_keys_from_ens_result
    from src.data.forecast_source_registry import calibration_source_id_for_lookup

    cycle, raw_source_id, horizon_profile = derive_phase2_keys_from_ens_result(
        {
            "issue_time": issue_time,
            "source_id": source_id,
            "horizon_profile": payload.get("horizon_profile") or forecast_payload.get("horizon_profile"),
        }
    )
    calibration_source_id = calibration_source_id_for_lookup(raw_source_id)
    if calibration_source_id is None:
        raise ValueError("CALIBRATION_AUTHORITY_EVIDENCE_MISSING:source_id")
    if not _table_exists(calibration_conn, "platt_models"):
        raise ValueError("CALIBRATION_AUTHORITY_EVIDENCE_MISSING:store")
    row, level, _model_data = _persisted_calibration_model_row_for_receipt(
        calibration_conn,
        city=city,
        target_date=str(family.target_date),
        temperature_metric=family.metric,
        cycle=cycle,
        source_id=calibration_source_id,
        horizon_profile=horizon_profile,
    )
    if row is None:
        model_key = (
            "identity_fallback_no_platt_bucket_v1:"
            f"{family.metric}:{city.cluster}:{str(family.target_date)}:"
            f"{cycle}:{calibration_source_id}:{horizon_profile}"
        )
        training_cutoff_raw = decision_time.astimezone(UTC).isoformat()
        payload_out = {
            "identity": model_key,
            "calibrator_model_key": model_key,
            "calibrator_version": model_key,
            "calibration_source_id": calibration_source_id,
            "raw_source_id": raw_source_id,
            "source_cycle": cycle,
            "horizon_profile": horizon_profile,
            "training_cutoff": training_cutoff_raw,
            "model_available_at": training_cutoff_raw,
            "model_materialized_at": training_cutoff_raw,
            "model_hash": _hash_jsonish(
                {
                    "model_key": model_key,
                    "calibration_method": "identity_missing_platt_bucket_v1",
                    "cluster": city.cluster,
                    "temperature_metric": family.metric,
                    "source_id": calibration_source_id,
                    "cycle": cycle,
                    "horizon_profile": horizon_profile,
                }
            ),
            "maturity_level": 4,
            "n_samples": 0,
            "input_space": "width_normalized_density",
            "authority": "IDENTITY_FALLBACK_NO_PLATT_BUCKET",
        }
        return payload_out, EvidenceClock(
            decision_time,
            decision_time,
            decision_time,
        )
    model_key = row.get("model_key")
    training_cutoff_raw = row.get("training_cutoff") or _date_cutoff_from_calibration_row(row)
    training_cutoff_time = _parse_utc(training_cutoff_raw)
    if training_cutoff_time is None:
        raise ValueError("CALIBRATION_AUTHORITY_EVIDENCE_MISSING:clock")
    materialized_at = row.get("recorded_at") or row.get("fitted_at")
    payload_out = {
        "identity": str(model_key or ""),
        "calibrator_model_key": model_key,
        "calibrator_version": row.get("model_key"),
        "calibration_source_id": calibration_source_id,
        "raw_source_id": raw_source_id,
        "source_cycle": cycle,
        "horizon_profile": horizon_profile,
        "training_cutoff": training_cutoff_raw,
        "model_available_at": training_cutoff_raw,
        "model_materialized_at": materialized_at,
        "model_hash": _hash_jsonish({
            "model_key": row.get("model_key"),
            "param_A": row.get("param_A"),
            "param_B": row.get("param_B"),
            "param_C": row.get("param_C"),
            "bootstrap_params_json": row.get("bootstrap_params_json"),
        }),
        "maturity_level": level,
        "n_samples": row.get("n_samples"),
        "input_space": row.get("input_space"),
        "authority": row.get("authority"),
    }
    return payload_out, EvidenceClock(
        training_cutoff_time,
        training_cutoff_time,
        training_cutoff_time,
    )


def _day0_calibration_authority_payload_and_clock(
    *,
    city,
    family,
    payload: Mapping[str, Any],
    forecast_payload: Mapping[str, Any],
    decision_time: datetime,
) -> tuple[dict[str, Any], EvidenceClock]:
    """Certificate calibration authority for live Day0 remaining-window probability."""

    from src.events.day0_authority import (
        Day0AuthorityEvidence,
        assert_live_day0_probability_authority,
        assert_live_day0_authority,
        normalize_day0_live_authority_status,
    )

    try:
        raw_value = float(payload.get("raw_value"))
        rounded_value = int(payload.get("rounded_value"))
    except (TypeError, ValueError):
        raise ValueError("DAY0_CALIBRATION_AUTHORITY_MISSING:observation_value") from None
    semantics = SettlementSemantics.for_city(city)
    evidence = Day0AuthorityEvidence(
        city=str(payload.get("city") or family.city),
        target_date=str(payload.get("target_date") or family.target_date),
        metric=str(payload.get("metric") or family.metric),
        source_match_status=str(payload.get("source_match_status") or "UNKNOWN"),
        station_match_status=str(payload.get("station_match_status") or "UNKNOWN"),
        local_date_status=str(payload.get("local_date_status") or "UNKNOWN"),
        dst_status=str(payload.get("dst_status") or "UNKNOWN"),
        metric_match_status=str(payload.get("metric_match_status") or "UNKNOWN"),
        rounding_status=str(payload.get("rounding_status") or "UNKNOWN"),
        source_authorized_status=str(payload.get("source_authorized_status") or "UNKNOWN"),
        live_authority_status=normalize_day0_live_authority_status(
            payload.get("live_authority_status")
        ),
        observation_available_at=str(payload.get("observation_available_at") or ""),
        observation_time=str(payload.get("observation_time") or ""),
        raw_value=raw_value,
        rounded_value=rounded_value,
        settlement_semantics=semantics,
    )
    try:
        assert_live_day0_authority(evidence)
    except Exception as exc:
        raise ValueError(f"DAY0_CALIBRATION_AUTHORITY_BLOCKED:{exc}") from exc
    source_time = _parse_utc(evidence.observation_time)
    available_time = _parse_utc(evidence.observation_available_at)
    if source_time is None or available_time is None:
        raise ValueError("DAY0_CALIBRATION_AUTHORITY_MISSING:clock")
    try:
        assert_live_day0_probability_authority(payload)
    except Exception as exc:
        raise ValueError(f"DAY0_CALIBRATION_AUTHORITY_BLOCKED:{exc}") from exc
    horizon_profile = _nonnull(
        payload.get("horizon_profile") or forecast_payload.get("horizon_profile")
    )
    lcb_transform = payload.get("_edli_day0_lcb_transform")
    lcb_transform_hash = _hash_jsonish(lcb_transform) if isinstance(lcb_transform, Mapping) else ""
    model_key = (
        "day0_remaining_window_probability_v1:"
        f"{evidence.city}:{evidence.target_date}:{evidence.metric}:"
        f"{evidence.rounded_value}:{evidence.observation_time}:"
        f"{payload.get('_edli_day0_remaining_source_cycle_time_utc') or 'cycle_unknown'}"
    )
    payload_out = {
        "identity": model_key,
        "calibrator_model_key": model_key,
        "calibrator_version": model_key,
        "calibration_method": "day0_remaining_window_probability",
        "model_hash": _hash_jsonish(
            {
                "model_key": model_key,
                "city": evidence.city,
                "target_date": evidence.target_date,
                "metric": evidence.metric,
                "station_id": payload.get("station_id"),
                "source": payload.get("source") or payload.get("settlement_source"),
                "rounding_rule": semantics.rounding_rule,
                "rounded_value": evidence.rounded_value,
                "q_source": payload.get("_edli_q_source"),
                "q_mode": payload.get("_edli_day0_q_mode"),
                "remaining_models": payload.get("_edli_day0_remaining_models"),
                "lcb_transform_hash": lcb_transform_hash,
            }
        ),
        "horizon_profile": horizon_profile,
        "training_cutoff": (
            payload.get("_edli_day0_remaining_source_cycle_time_utc")
            or evidence.observation_time
        ),
        "model_available_at": evidence.observation_available_at,
        "model_materialized_at": decision_time.astimezone(UTC).isoformat(),
        "observation_time": evidence.observation_time,
        "observation_available_at": evidence.observation_available_at,
        "source_authorized_status": evidence.source_authorized_status,
        "live_authority_status": evidence.live_authority_status,
        "input_space": "day0_remaining_window_probability",
        "q_source": payload.get("_edli_q_source"),
        "q_mode": payload.get("_edli_day0_q_mode"),
        "remaining_models": payload.get("_edli_day0_remaining_models"),
        "remaining_model_names": payload.get("_edli_day0_remaining_model_names"),
        "remaining_source_cycle_time_utc": payload.get("_edli_day0_remaining_source_cycle_time_utc"),
        "remaining_capture_times_utc": payload.get("_edli_day0_remaining_capture_times_utc"),
        "day0_exit_authority_status": payload.get("_edli_day0_exit_authority_status"),
        "day0_exit_authority_reason": payload.get("_edli_day0_exit_authority_reason"),
        "lcb_transform_hash": lcb_transform_hash,
        "day0_probability_authority": {
            "q_source": payload.get("_edli_q_source"),
            "q_mode": payload.get("_edli_day0_q_mode"),
            "remaining_models": payload.get("_edli_day0_remaining_models"),
            "rounded_value": evidence.rounded_value,
            "observation_time": evidence.observation_time,
            "observation_available_at": evidence.observation_available_at,
            "lcb_transform": lcb_transform if isinstance(lcb_transform, Mapping) else None,
        },
        "maturity_level": 4,
        "n_samples": payload.get("_edli_day0_remaining_models") or 0,
        "authority": DAY0_REMAINING_WINDOW_CALIBRATION_AUTHORITY,
    }
    return payload_out, EvidenceClock(source_time, available_time, decision_time)


def _persisted_calibration_model_row_for_receipt(
    conn: sqlite3.Connection,
    *,
    city,
    target_date: str,
    temperature_metric: str,
    cycle: str | None,
    source_id: str | None,
    horizon_profile: str | None,
) -> tuple[dict[str, Any] | None, int, dict[str, Any] | None]:
    """Load calibration authority without fitting inside the live reactor.

    ``get_calibrator()`` may train a Platt model from historical pair rows on a
    cache miss. Receipt compilation is an authority read seam: it may use an
    already-persisted model or fail closed, but it must not perform runtime
    training while the scheduler is trying to emit liveness receipts.
    """

    if not _table_exists(conn, "platt_models"):
        return None, 4, None
    from src.calibration.manager import (
        _candidate_data_versions_for_metric_source,
        _low_live_min_decision_groups,
        _resolve_pin_for_bucket,
        maturity_level,
        season_from_date,
    )
    from src.calibration.store import load_platt_model

    season = season_from_date(target_date, lat=city.lat)
    cluster = city.cluster
    candidate_data_versions = _candidate_data_versions_for_metric_source(
        temperature_metric, source_id
    )
    primary_frozen, primary_model_key = _resolve_pin_for_bucket(
        temperature_metric, cluster, season, cycle
    )
    opendata_to_tigge_bridge = (
        len(candidate_data_versions) > 1
        and candidate_data_versions[0].startswith("ecmwf_opendata_")
    )
    selected_model_data: dict[str, Any] | None = None
    for data_version in candidate_data_versions:
        if opendata_to_tigge_bridge and data_version.startswith("tigge_"):
            lookup_cycle, lookup_source_id, lookup_horizon = "00", "tigge_mars", "full"
        else:
            lookup_cycle, lookup_source_id, lookup_horizon = cycle, source_id, horizon_profile
        model_data = load_platt_model(
            conn,
            temperature_metric=temperature_metric,
            cluster=cluster,
            season=season,
            data_version=data_version,
            frozen_as_of=primary_frozen,
            model_key=primary_model_key,
            cycle=lookup_cycle,
            source_id=lookup_source_id,
            horizon_profile=lookup_horizon,
        )
        if model_data is not None:
            selected_model_data = model_data
            break
    if selected_model_data is None:
        return None, 4, None
    model_key = selected_model_data.get("model_key")
    row = _calibration_model_row(conn, model_key=model_key)
    if row is None:
        return None, 4, None
    if row.get("calibration_method") == "identity_full_transport_v1":
        return row, 1, selected_model_data
    n_samples = int(row.get("n_samples") or 0)
    if temperature_metric == "low" and n_samples < _low_live_min_decision_groups():
        return None, 4, None
    return row, maturity_level(n_samples), selected_model_data


def _date_cutoff_from_calibration_row(row: dict[str, Any]) -> str | None:
    """Return the date-level training cutoff for legacy platt_models rows.

    Older live/cache schemas do not persist ``training_cutoff`` even though the
    certificate payload requires that semantic. ``fitted_at``/``recorded_at`` are
    model materialization times and can be created by read-time cache writes during
    the reactor cycle; using the full timestamp as ``training_cutoff`` makes the
    proof non-causal by construction. The established calibration producer
    convention writes date-only cutoffs, so legacy rows degrade to the UTC date of
    the materialization timestamp.
    """

    for key in ("fitted_at", "recorded_at"):
        parsed = _parse_utc(row.get(key))
        if parsed is not None:
            return datetime.combine(parsed.date(), time.min, tzinfo=UTC).isoformat()
    return None


_MIN_ROBUST_CAPITAL_EFFICIENCY_ROI = 0.0


# REMOVED 2026-06-08 (S7; operator directive; "bin selection.md" §14 item 8): the
# `_env_flag_enabled` helper was used ONLY to read the opportunity-book probe
# toggle env var into the cache_summary. With the probe / off-able selector
# artifacts deleted (single-primary-live, no flag, no alternate path), it has no caller
# and is removed — there is no env-driven branch on the selection path.


# REMOVED 2026-06-08 (operator directive; "bin selection.md" §14 item 8 single-
# primary-live): the family-selector on/off gate (its env var + its
# edli settings key) is GONE. The bin-selection robust marginal-log-utility
# ranker is the UNCONDITIONAL single live decision surface — there is no disable
# path to silently flip. A scattered off-able gate is the regression disease the
# directive abolishes; correctness is enforced by types + relationship tests +
# the ff-branch review, never a runtime flag. (S7 also deleted the last literal
# toggle-name strings so the symbol cannot be re-grepped into a gate; antibody
# tests/engine/test_s7_selector_gate_removed.py.)
#
# REMOVED 2026-06-08 (S4; "bin selection.md" §6/§9 Hidden #3/#10/§13): the scalar
# market-disagreement buy_no demotion (_market_disagreement_demotes_buy_no + its
# _MARKET_DISAGREE_* thresholds) is GONE. The marginal-utility ranker subsumes it:
# a cheap NO scored with its OWN honest robust NO q_lcb (1 - q_ucb_yes) against the
# cheap NO all-in cost yields a negative robust edge -> ΔU <= 0 -> §13 no-trade,
# whenever the market is confident YES. One ranking surface, no scalar side-gate.
# Antibody: tests/engine/test_s4_subsumed_gates.py.


def _capital_efficiency_untradeable_reason(
    *,
    execution_price: ExecutionPrice | None,
    q_lcb_5pct: float,
    trade_score: float,
) -> str | None:
    if execution_price is None:
        return "ADMISSION_CAPITAL_EFFICIENCY:price=missing"
    return live_capital_efficiency_rejection_reason(
        q_lcb=q_lcb_5pct,
        execution_price=execution_price.value,
        trade_score=trade_score,
    )


def _candidate_robust_roi(proof: _CandidateProof) -> float:
    execution_price = getattr(proof, "execution_price", None)
    if execution_price is None:
        return 0.0
    price = _optional_float(execution_price.value)
    if price is None or price <= 0.0:
        return 0.0
    return float(getattr(proof, "trade_score", 0.0) or 0.0) / price


def _candidate_evaluation_id(proof: _CandidateProof) -> str:
    condition_id = str(getattr(proof.candidate, "condition_id", "") or "")
    return stable_hash(
        {
            "condition_id": condition_id,
            "token_id": proof.token_id,
            "direction": proof.direction,
        }
    )


def _candidate_low_volume_usd(row: Mapping[str, object]) -> float | None:
    for key in ("volume_usd", "volume", "total_volume"):
        if key in row and row.get(key) not in (None, ""):
            return _optional_float(row.get(key))
    return None


def _candidate_max_executable_shares(proof: _CandidateProof) -> float | None:
    row = proof.row
    if row is None or proof.execution_price is None:
        return None
    try:
        book = _native_quote_book_from_snapshot_row(row)
    except Exception:
        return None
    levels = {
        "buy_yes": book.yes_asks,
        "buy_no": book.no_asks,
        "sell_yes": book.yes_bids,
        "sell_no": book.no_bids,
    }.get(str(proof.direction or ""))
    if not levels:
        return 0.0
    try:
        return float(sum((level.size for level in levels), Decimal("0")))
    except Exception:
        return None


def _candidate_bin_id(proof: _CandidateProof) -> str:
    """Stable per-bin id for a proof's NativeSideCandidate (spec §14.2 bin_id).

    The bin id keys a bin WITHIN a family; the YES and NO sides of one bin share
    it (so the two native side candidates are recognisably the same bin), while
    distinct bins differ. Derived from the bin's settlement-defining geometry
    (low/high/unit/label) plus the condition id, never the side or token — those
    are what distinguish the two SIDES of the same bin.
    """
    candidate = proof.candidate
    bin_obj = getattr(candidate, "bin", None)
    return stable_hash(
        {
            "condition_id": str(getattr(candidate, "condition_id", "") or ""),
            "bin_low": getattr(bin_obj, "low", None),
            "bin_high": getattr(bin_obj, "high", None),
            "bin_unit": getattr(bin_obj, "unit", None),
            "bin_label": getattr(bin_obj, "label", None),
        }
    )


def _proof_probability_uncertainty(
    *, q_point: float, q_lcb: float
) -> "ProbabilityUncertainty":
    """Wrap the proof's scalar S2 q authority as a ProbabilityUncertainty (§14.4).

    The proof carries the per-side robust authority as SCALARS already computed by
    S2 (``q_posterior`` -> q_point, ``q_lcb_5pct`` -> q_lcb). For the YES side
    ``q_lcb_5pct`` is ``q_lcb_yes`` (lower tail of the YES probability samples);
    for the NO side it is ``q_lcb_no = 1 - q_ucb_yes`` (lower tail of the per-sample
    complement, Hidden #3) — NOT ``1 - q_lcb_yes``. This function only TRANSPORTS
    that authority; it never recomputes or complements it, so the §4 belief-space
    separation the S2 seam established is preserved verbatim.

    The probability bootstrap sample VECTOR is not threaded to this materialization
    layer (the proof carries only the scalars), so q_ucb is set to q_point here:
    the candidate object uses q_lcb as its sizing authority, and the
    ProbabilityUncertainty invariant only requires ``q_lcb <= q_point <= q_ucb``.
    A future phase that threads the sample vector can populate the real q_ucb /
    q_samples_hash without changing this contract.
    """
    from src.strategy.probability_uncertainty import ProbabilityUncertainty as _PU

    qp = float(min(max(q_point, 0.0), 1.0))
    ql = float(min(max(q_lcb, 0.0), 1.0))
    # Structural guard: q_lcb must not exceed q_point (edge_ci_lower-as-q_lcb is
    # Hidden #2). S2 already enforces this at the proof boundary; clamp defensively
    # so a degenerate scalar can never raise inside the constructor.
    ql = min(ql, qp)
    return _PU(
        q_point=qp,
        q_samples_hash="",
        q_lcb=ql,
        q_ucb=qp,
    )


_QKERNEL_EXECUTION_ECONOMICS_REQUIRED_KEYS = frozenset(
    {
        "source",
        "candidate_id",
        "route_id",
        "payoff_q_point",
        "payoff_q_lcb",
        "edge_lcb",
        "delta_u_at_min",
        "optimal_stake_usd",
        "optimal_delta_u",
        "cost",
        "false_edge_rate",
        "direction_law_ok",
        "coherence_allows",
        "selection_guard_basis",
        "selection_guard_abstained",
        "selection_guard_q_safe",
    }
)


def _qkernel_max_false_edge_rate() -> float:
    try:
        from src.strategy.fdr_filter import DEFAULT_FDR_ALPHA

        alpha = float(DEFAULT_FDR_ALPHA)
    except Exception:  # noqa: BLE001
        alpha = 0.05
    if not math.isfinite(alpha) or alpha <= 0.0:
        return 0.05
    return alpha


def _qkernel_day0_guard_rejection_reason(cert: Mapping[str, Any]) -> str | None:
    bases = (
        str(cert.get("q_lcb_guard_basis") or "").strip(),
        str(cert.get("selection_guard_basis") or "").strip(),
    )
    for basis in bases:
        if basis == "DAY0_OBSERVED_BOUNDARY":
            return "QKERNEL_DAY0_OBSERVED_BOUNDARY_NOT_ENTRY_AUTHORITY"
    if "DAY0_REMAINING_DAY_Q_LCB" not in bases:
        return None
    try:
        selection_guard_n = int(float(cert.get("selection_guard_n")))
    except (TypeError, ValueError):
        return "QKERNEL_DAY0_REMAINING_DAY_GUARD_N_MISSING"
    if selection_guard_n <= 0:
        return "QKERNEL_DAY0_REMAINING_DAY_GUARD_N_MISSING"
    return None


def _qkernel_roi_frontier_useful_cert(
    *,
    side: str | None,
    cost: float,
    payoff_q_lcb: float,
    edge_lcb: float,
    stake: float,
    delta_u_at_min: float,
) -> bool:
    return roi_frontier_useful_values(
        side=side,
        cost=cost,
        payoff_q_lcb=payoff_q_lcb,
        edge_lcb=edge_lcb,
        stake=stake,
        delta_u_at_min=delta_u_at_min,
    )


def _proof_uses_qkernel_spine(proof: "_CandidateProof") -> bool:
    # B3 residual (2026-06-20 re-review): the qkernel execution authority is the
    # SELECTION STAMP, not the mere presence of a syntactically-valid cert. The old
    # cert-alone branch let an UNSTAMPED (legacy-selected) proof that happened to
    # carry a valid qkernel_execution_economics cert source its payoff_q_lcb from
    # that cert in sizing/materialization (_qkernel_execution_economics ->
    # _robust_marginal_utility_stake_and_price) without the spine actually being the
    # selector — a money-path provenance gap. Every spine-selected proof carries the
    # stamp (qkernel_spine_bridge sets selection_authority_applied="qkernel_spine"),
    # so requiring the stamp keeps all legitimate qkernel sizing and only fails closed
    # the unstamped-with-stray-cert case (correct: legacy proofs size on legacy q,
    # never on an unbound qkernel cert). Cert validity/identity (route/side/bin) is
    # still enforced downstream in _qkernel_execution_economics.
    if str(getattr(proof, "q_source", "") or "") == "qkernel_spine":
        return True
    if str(getattr(proof, "selection_authority_applied", "") or "") == "qkernel_spine":
        return True
    return False


def _qkernel_execution_economics(proof: "_CandidateProof") -> Mapping[str, Any] | None:
    """Return the qkernel guarded execution-economics certificate, if valid.

    ``selection_authority_applied == "qkernel_spine"`` is an execution authority
    switch: the submit path may size only from the guarded qkernel certificate.
    Missing or malformed certificates therefore return ``None`` and the caller
    must fail closed rather than fall back to legacy proof-qLCB sizing.
    """
    if not _proof_uses_qkernel_spine(proof):
        return None
    cert = _valid_qkernel_execution_economics_payload(
        getattr(proof, "qkernel_execution_economics", None),
        direction=str(getattr(proof, "direction", "") or ""),
    )
    if cert is None:
        return None
    bin_id = str(cert.get("bin_id") or "").strip()
    if bin_id and bin_id != _candidate_bin_id(proof):
        return None
    route_id = str(cert.get("route_id") or "").strip()
    native_side = _native_curve_side_for_direction(str(getattr(proof, "direction", "") or ""))
    if route_id.startswith("DIRECT_YES:") and native_side != "YES":
        return None
    if route_id.startswith("DIRECT_NO:") and native_side != "NO":
        return None
    if _qkernel_cert_served_belief_rejection_reason(
        cert,
        proof_q_point=_optional_float(getattr(proof, "q_posterior", None)),
        proof_q_lcb=_optional_float(getattr(proof, "q_lcb_5pct", None)),
    ):
        return None
    return cert


def _qkernel_candidate_execution_economics(proof: "_CandidateProof") -> Mapping[str, Any] | None:
    """Return a candidate-local qkernel certificate without granting submit authority.

    Submit sizing still requires ``_qkernel_execution_economics`` on the selected proof,
    which checks the qkernel selection stamp.  Family-rank recapture, however, must compare
    the sibling certificates emitted by the same qkernel decision.  Non-selected siblings
    deliberately do not carry the submit-authority stamp, so this read boundary validates
    the certificate's economics, route identity, and served-belief consistency without
    treating that sibling as directly submittable.
    """

    cert = _valid_qkernel_execution_economics_payload(
        getattr(proof, "qkernel_execution_economics", None),
        direction=str(getattr(proof, "direction", "") or ""),
    )
    if cert is None:
        return None
    bin_id = str(cert.get("bin_id") or "").strip()
    if bin_id and bin_id != _candidate_bin_id(proof):
        return None
    route_id = str(cert.get("route_id") or "").strip()
    native_side = _native_curve_side_for_direction(str(getattr(proof, "direction", "") or ""))
    if route_id.startswith("DIRECT_YES:") and native_side != "YES":
        return None
    if route_id.startswith("DIRECT_NO:") and native_side != "NO":
        return None
    if _qkernel_cert_served_belief_rejection_reason(
        cert,
        proof_q_point=_optional_float(getattr(proof, "q_posterior", None)),
        proof_q_lcb=_optional_float(getattr(proof, "q_lcb_5pct", None)),
    ):
        return None
    return cert


def _qkernel_recapture_rank_key(
    proof: "_CandidateProof",
) -> tuple[float, float, float, float, float, float] | None:
    cert = _qkernel_candidate_execution_economics(proof)
    if cert is None:
        return None
    try:
        side = str(cert.get("side") or "").strip().upper()
        cost = float(cert.get("cost"))
        edge_lcb = float(cert.get("edge_lcb"))
        payoff_q_lcb = float(cert.get("payoff_q_lcb"))
        stake = float(cert.get("optimal_stake_usd"))
        delta_u_at_min = float(cert.get("delta_u_at_min"))
        optimal_delta_u = float(cert.get("optimal_delta_u"))
    except (TypeError, ValueError):
        return None
    if not all(
        math.isfinite(value)
        for value in (cost, edge_lcb, payoff_q_lcb, stake, delta_u_at_min, optimal_delta_u)
    ):
        return None
    profit_lcb = roi_frontier_profit_lcb_usd(stake=stake, cost=cost, edge_lcb=edge_lcb)
    growth_density = roi_frontier_growth_density(
        cost=cost,
        edge_lcb=edge_lcb,
        payoff_q_lcb=payoff_q_lcb,
    )
    roi_lcb = edge_lcb / cost if cost > 0.0 else float("-inf")
    utility_density = optimal_delta_u / stake if stake > 0.0 else float("-inf")
    if not roi_frontier_useful_values(
        side=side,
        cost=cost,
        payoff_q_lcb=payoff_q_lcb,
        edge_lcb=edge_lcb,
        stake=stake,
        delta_u_at_min=delta_u_at_min,
    ):
        return None
    return (
        float(growth_density),
        float(roi_lcb),
        float(profit_lcb),
        float(utility_density),
        float(optimal_delta_u),
        -float(cost),
    )


def _qkernel_cert_served_belief_rejection_reason(
    cert: Mapping[str, Any],
    *,
    proof_q_point: float | None,
    proof_q_lcb: float | None,
) -> str | None:
    """Reject qkernel certs whose direct-route q is not the served proof belief."""

    try:
        payoff_q_point = float(cert.get("payoff_q_point"))
        payoff_q_lcb = float(cert.get("payoff_q_lcb"))
    except (TypeError, ValueError):
        return "QKERNEL_SERVED_BELIEF_INVALID"
    values = (payoff_q_point, payoff_q_lcb, proof_q_point, proof_q_lcb)
    if not all(value is not None and math.isfinite(float(value)) for value in values):
        return "QKERNEL_SERVED_BELIEF_INVALID"
    assert proof_q_point is not None
    assert proof_q_lcb is not None
    if not (0.0 <= proof_q_lcb <= proof_q_point <= 1.0):
        return "QKERNEL_SERVED_BELIEF_INVALID"
    tolerance = 1e-6
    if not math.isclose(payoff_q_point, proof_q_point, rel_tol=1e-9, abs_tol=tolerance):
        return (
            "QKERNEL_SERVED_BELIEF_POINT_MISMATCH:"
            f"payoff_q_point={payoff_q_point:.9f}:served_q_point={proof_q_point:.9f}"
        )
    if payoff_q_lcb > proof_q_lcb + tolerance:
        return (
            "QKERNEL_SERVED_BELIEF_LCB_LOOSENED:"
            f"payoff_q_lcb={payoff_q_lcb:.9f}:served_q_lcb={proof_q_lcb:.9f}"
        )
    return None


def _qkernel_execution_float(
    proof: "_CandidateProof",
    key: str,
) -> float | None:
    cert = _qkernel_execution_economics(proof)
    if cert is None:
        return None
    value = cert.get(key)
    try:
        out = float(value)
    except (TypeError, ValueError):
        return None
    if not math.isfinite(out):
        return None
    return out


def _qkernel_execution_q_lcb(proof: "_CandidateProof") -> float | None:
    """The guarded payoff-space lower bound the qkernel selected and sized on.

    Qkernel-spine proofs deliberately preserve ``q_posterior`` / ``q_lcb_5pct``
    as receipt-facing selected-side probability provenance. They are not the
    execution-sizing authority once ``selection_authority_applied`` stamps the
    proof as qkernel-selected. The money path may use the payoff qLCB only after
    ``_qkernel_execution_economics`` validates the authority stamp and route/side/bin
    identity; after that validation, applying the old proof qLCB again creates a
    second decision authority and starves valid center-YES / payoff-vector trades.
    """
    q_lcb = _qkernel_execution_float(proof, "payoff_q_lcb")
    if q_lcb is None:
        return None
    if not (0.0 <= q_lcb <= 1.0):
        return None
    return q_lcb


def _qkernel_execution_q_point(proof: "_CandidateProof") -> float | None:
    """The guarded payoff-space point probability paired with qkernel qLCB."""
    q_point = _qkernel_execution_float(proof, "payoff_q_point")
    if q_point is None:
        return None
    if not (0.0 <= q_point <= 1.0):
        return None
    return q_point


def _event_bound_execution_probability_pair(proof: "_CandidateProof") -> tuple[float, float]:
    """Return the single probability pair that may drive live execution."""

    qkernel_q_point = _qkernel_execution_q_point(proof)
    qkernel_q_lcb = _qkernel_execution_q_lcb(proof)
    if qkernel_q_point is not None and qkernel_q_lcb is not None:
        return qkernel_q_point, qkernel_q_lcb
    return float(proof.q_posterior), float(proof.q_lcb_5pct)


def _native_side_cost_curve_from_execution_price(
    *,
    proof: _CandidateProof,
    side: str,
    token_id: str,
    market_snapshot_id: str,
) -> "ExecutableCostCurve | None":
    """Single-level fallback cost curve from the proof's OWN-side all-in price.

    Used ONLY when the snapshot row's native ask ladder cannot be rebuilt into a
    full ExecutableCostCurve (no depth json) but the proof IS genuinely priced.
    The proof's ``execution_price`` is its OWN native side's depth-walked all-in
    cost (S1, fee-deducted, probability_units). A single-level curve at that price
    reproduces the same scalar cost-of-entry the proof was priced at, so the ΔU
    ranker (the single live decision surface) can rank it instead of spuriously
    no-trading a priced candidate.

    §4 separation is preserved: the level price is the proof's OWN-side all-in
    cost and the curve is tagged with the proof's OWN ``side`` — it is NEVER a
    ``1 - p_exec(other side)`` complement. ``fee_rate=0`` so the curve's
    ``all_in_price`` reproduces the already-fee-deducted scalar verbatim (no
    double fee). ``min_tick`` is chosen to land the price on grid; depth is the
    proof's executable share count when known, else a unit of depth at min order.

    Returns ``None`` when the proof carries no usable own-side executable price
    (the candidate then stays a NATIVE_QUOTE_MISSING no-trade — fail closed).
    """
    if side not in ("YES", "NO"):
        return None
    execution_price = getattr(proof, "execution_price", None)
    price_value = _optional_float(getattr(execution_price, "value", None))
    if price_value is None or not (0.0 < price_value < 1.0):
        return None
    if not bool(getattr(proof, "native_quote_available", False)):
        return None

    # Land the all-in price on a tick grid fine enough to represent it exactly.
    price = Decimal(str(price_value)).quantize(Decimal("0.0001"))
    if not (Decimal("0") < price < Decimal("1")):
        return None
    min_tick = Decimal("0.0001")

    row = proof.row or {}
    min_order = _optional_float(row.get("min_order_size"))
    min_order_size = Decimal(str(min_order)) if (min_order and min_order > 0) else Decimal("1")

    shares = _candidate_max_executable_shares(proof)
    depth_shares = (
        Decimal(str(shares)) if (shares is not None and shares > 0) else None
    )
    # Depth must cover at least one min order; default to a deep single level so
    # the ΔU stake sweep is not artificially depth-capped when share count is
    # unknown (the scalar all-in price is the only executable fact available).
    if depth_shares is None or depth_shares < min_order_size:
        depth_shares = max(min_order_size, Decimal("1000000"))

    try:
        return ExecutableCostCurve(
            token_id=str(token_id),
            side=side,  # type: ignore[arg-type]
            snapshot_id=str(market_snapshot_id or ""),
            book_hash=str(row.get("book_hash") or row.get("snapshot_hash") or ""),
            levels=(BookLevel(price=price, size=depth_shares),),
            fee_model=FeeModel(fee_rate=Decimal("0")),
            min_tick=min_tick,
            min_order_size=min_order_size,
            quote_ttl=timedelta(seconds=1),
        )
    except (ValueError, KeyError, TypeError):
        return None


def _native_side_candidate_from_proof(
    *,
    family_key: str,
    proof: _CandidateProof,
) -> NativeSideCandidate:
    """Materialize a priced ``_CandidateProof`` as a unified NativeSideCandidate.

    S3 (spec §14.2 / §6 pseudocode / §11 Phase 1). This is the ONE materialization
    path: every priced YES/NO proof on the live selection path becomes a single
    ``NativeSideCandidate`` object — the unified candidate shape the ranker/selector
    consumes. There is no flag, no alternate branch, and no alternate candidate shape.

    DIRECTION LAW (money-path iron law, spec §4/§6): ``buy_yes`` -> ``side="YES"``
    (the proof's own bin is the WIN outcome); ``buy_no`` -> ``side="NO"`` (the own
    bin is the LOSE outcome). The mapping is ``_native_curve_side_for_direction``
    and is NEVER inverted here. A direction that is neither buy_yes nor buy_no has
    no native BUY side to price -> NATIVE_QUOTE_MISSING no-trade.

    ROBUST LOWER BOUND (spec §5.6 / Hidden #2): legacy proofs use
    ``q_posterior`` / ``q_lcb_5pct`` as the point/lower-bound pair. A proof stamped
    with qkernel execution authority uses the guarded certificate's
    ``payoff_q_point`` / ``payoff_q_lcb`` pair instead. The constructor enforces
    ``q_lcb <= q_point``; mixing a qkernel LCB with a legacy point q is a
    money-path probability-authority bug.

    NATIVE EXECUTABLE SEPARATION (spec §4 / Hidden #1): the executable cost curve
    is rebuilt from the proof's OWN snapshot-row native ask ladder, side-tagged
    with the proof's side (the S1 ``_native_side_cost_curve_from_snapshot_row``
    builder). A NO candidate therefore walks the NO ask book; the contract raises
    if a side-mismatched curve is ever fed in (``p_exec(NO) != 1 - p_exec(YES)``).

    MISSING TOKEN/QUOTE -> NO-TRADE (spec §13 / Hidden #4): a missing native token
    id, an unpriced side (``execution_price is None`` /
    ``native_quote_available`` False), or a side with no executable ask ladder
    downgrades to a recorded ``NATIVE_TOKEN_MISSING`` / ``NATIVE_QUOTE_MISSING``
    no-trade candidate. The no-trade candidate carries NO executable curve and NO
    probability authority — there is nothing to complement-substitute from. It is
    RECORDED (not omitted) so the family hypothesis set / FDR denominator and the
    learning layer see the tested-and-untradeable side (Hidden #1).
    """
    candidate = proof.candidate
    condition_id = str(getattr(candidate, "condition_id", "") or "")
    token_id = str(proof.token_id or "")
    bin_id = _candidate_bin_id(proof)
    forecast_snapshot_id = str(getattr(proof, "executable_snapshot_id", "") or "")
    row = proof.row or {}
    market_snapshot_id = str(row.get("snapshot_id") or forecast_snapshot_id or "")
    hypothesis_id = _candidate_evaluation_id(proof)

    side = _native_curve_side_for_direction(str(proof.direction or ""))

    # Missing native token id -> NATIVE_TOKEN_MISSING (no native identity to trade).
    if not token_id:
        return NativeSideCandidate.no_trade(
            family_key=family_key,
            bin_id=bin_id,
            side=side or "YES",
            token_id=token_id,
            condition_id=condition_id,
            forecast_snapshot_id=forecast_snapshot_id,
            market_snapshot_id=market_snapshot_id,
            reason=CandidateNoTradeReason.NATIVE_TOKEN_MISSING,
            hypothesis_id=hypothesis_id,
        )

    # No native BUY side for this direction, or the proof was not priced
    # (execution_price missing / native quote unavailable) -> NATIVE_QUOTE_MISSING.
    # No complement substitution: a side with no executable ask is recorded as a
    # no-trade telemetry, never a YES-derived price.
    if (
        side is None
        or proof.execution_price is None
        or not bool(proof.native_quote_available)
    ):
        return NativeSideCandidate.no_trade(
            family_key=family_key,
            bin_id=bin_id,
            side=side or ("NO" if str(proof.direction or "") == "buy_no" else "YES"),
            token_id=token_id,
            condition_id=condition_id,
            forecast_snapshot_id=forecast_snapshot_id,
            market_snapshot_id=market_snapshot_id,
            reason=CandidateNoTradeReason.NATIVE_QUOTE_MISSING,
            hypothesis_id=hypothesis_id,
        )

    # Rebuild this side's OWN executable cost curve from its native ask ladder
    # (S1 builder, side-tagged). A book that cannot build a curve (empty/off-grid)
    # falls back to the proof's OWN-side scalar all-in cost (execution_price): a
    # single-level curve at the price the proof was ALREADY priced at (S1). This
    # keeps a genuinely-priced proof rankable by the ΔU ranker (the single decision
    # surface) instead of spuriously no-trading it, WITHOUT fabricating a complement
    # — the fallback curve uses the proof's own native side and its own all-in
    # price (§4: never 1 - p_exec(other side)). Only a proof with no own-side
    # executable price at all stays a NATIVE_QUOTE_MISSING no-trade.
    try:
        curve = _native_side_cost_curve_from_snapshot_row(
            row, side=side, token_id=token_id
        )
    except (ValueError, KeyError, TypeError):
        curve = _native_side_cost_curve_from_execution_price(
            proof=proof,
            side=side,
            token_id=token_id,
            market_snapshot_id=market_snapshot_id,
        )
        if curve is None:
            return NativeSideCandidate.no_trade(
                family_key=family_key,
                bin_id=bin_id,
                side=side,
                token_id=token_id,
                condition_id=condition_id,
                forecast_snapshot_id=forecast_snapshot_id,
                market_snapshot_id=market_snapshot_id,
                reason=CandidateNoTradeReason.NATIVE_QUOTE_MISSING,
                hypothesis_id=hypothesis_id,
            )

    q_point = float(proof.q_posterior)
    q_lcb = float(proof.q_lcb_5pct)
    qkernel_q_point = _qkernel_execution_q_point(proof)
    qkernel_q_lcb = _qkernel_execution_q_lcb(proof)
    if qkernel_q_lcb is not None:
        if qkernel_q_point is None:
            return NativeSideCandidate.no_trade(
                family_key=family_key,
                bin_id=bin_id,
                side=side,
                token_id=token_id,
                condition_id=condition_id,
                forecast_snapshot_id=forecast_snapshot_id,
                market_snapshot_id=market_snapshot_id,
                reason=CandidateNoTradeReason.Q_LCB_INVALID,
                hypothesis_id=hypothesis_id,
            )
        q_point = qkernel_q_point
        q_lcb = qkernel_q_lcb

    # §13 / Hidden #2 live no-trade gate: q_lcb is INVALID when it is out of
    # [0, 1] or EXCEEDS q_point (a lower-confidence bound above the point estimate
    # is the "edge_ci_lower masquerading as q_lcb" corruption). A corrupt q_lcb
    # must NOT size a trade — record a Q_LCB_INVALID no-trade candidate rather than
    # clamping it into a tradeable one (clamping would hide the corruption and let
    # a low-win-rate candidate trade on a fabricated lower bound). On the real path
    # S2 guarantees q_lcb <= q_point per side, so this only fires on corrupt input.
    if not (0.0 <= q_lcb <= 1.0) or not (0.0 <= q_point <= 1.0) or q_lcb > q_point:
        return NativeSideCandidate.no_trade(
            family_key=family_key,
            bin_id=bin_id,
            side=side,
            token_id=token_id,
            condition_id=condition_id,
            forecast_snapshot_id=forecast_snapshot_id,
            market_snapshot_id=market_snapshot_id,
            reason=CandidateNoTradeReason.Q_LCB_INVALID,
            hypothesis_id=hypothesis_id,
        )

    probability_uncertainty = _proof_probability_uncertainty(
        q_point=q_point, q_lcb=q_lcb
    )

    return NativeSideCandidate.tradeable(
        family_key=family_key,
        bin_id=bin_id,
        side=side,
        token_id=token_id,
        condition_id=condition_id,
        q_point=q_point,
        q_lcb=q_lcb,
        probability_uncertainty=probability_uncertainty,
        executable_cost_curve=curve,
        forecast_snapshot_id=forecast_snapshot_id,
        market_snapshot_id=market_snapshot_id,
        hypothesis_id=hypothesis_id,
    )


def _candidate_evaluation_from_proof(
    *,
    family_id: str,
    proof: _CandidateProof,
    kelly_size_usd: float = 0.0,
    support_index: int | None = None,
    bin_id: str | None = None,
) -> CandidateEvaluation:
    """Derive the legacy CandidateEvaluation RECEIPT from the materialized candidate.

    S3 (operator directive 2026-06-08): the priced proof is materialized as the
    canonical ``NativeSideCandidate`` FIRST (``_native_side_candidate_from_proof``
    — the one candidate object), then this function derives the legacy
    ``CandidateEvaluation`` receipt shape FROM that candidate so the existing
    opportunity_book ranking/serialization surface keeps working unchanged. There
    is ONE materialization path producing ONE candidate object; the receipt is a
    projection of it, not a parallel re-derivation off the proof.

    The receipt-only / ranking fields that the NativeSideCandidate does not model
    (trade_score, p_value, p_fill_lcb, c_cost_95pct, kelly_size_usd,
    max_executable_shares, low_volume_usd, calibration source, same-bin posterior,
    and the legacy ranker's native_quote_available / missing_reason admission
    inputs) are read from the proof — they are scalar-Kelly ranking inputs that S4
    retires when the marginal-utility ranker replaces this surface. The IDENTITY
    fields (candidate_id, condition_id, token_id) are sourced from the materialized
    NativeSideCandidate so the receipt and the candidate cannot drift on identity.
    """
    native_candidate = _native_side_candidate_from_proof(
        family_key=family_id, proof=proof
    )
    execution_price = _optional_float(getattr(getattr(proof, "execution_price", None), "value", None))
    row = proof.row or {}
    candidate = proof.candidate
    bin_obj = getattr(candidate, "bin", None)
    if bin_id is None:
        bin_id = _candidate_bin_id(proof)
    return CandidateEvaluation(
        # Identity sourced from the materialized NativeSideCandidate (single
        # candidate object) so the receipt and the candidate cannot drift.
        candidate_id=native_candidate.hypothesis_id,
        family_id=family_id,
        condition_id=native_candidate.condition_id,
        token_id=native_candidate.token_id,
        direction=str(proof.direction or ""),
        bin_label=getattr(bin_obj, "label", None),
        support_index=support_index,
        bin_id=bin_id,
        execution_price=execution_price,
        # Diagnostic q fields record what the proof TESTED on this side (the S2
        # robust authority). A no-trade NativeSideCandidate carries no q authority
        # (q_point/q_lcb None) precisely because there is nothing to size — the
        # receipt still reports the tested scalars so the family/FDR/learning layer
        # sees the side was tested-and-untradeable (Hidden #1).
        q_posterior=float(proof.q_posterior),
        q_lcb_5pct=float(proof.q_lcb_5pct),
        q_lcb_calibration_source=proof.q_lcb_calibration_source,
        same_bin_yes_posterior=proof.same_bin_yes_posterior,
        settlement_coverage_status=proof.settlement_coverage_status,
        c_cost_95pct=_optional_float(proof.c_cost_95pct),
        p_fill_lcb=float(proof.p_fill_lcb),
        trade_score=float(proof.trade_score),
        p_value=float(proof.p_value),
        passed_prefilter=bool(proof.passed_prefilter),
        # The receipt's native_quote_available / missing_reason are the LEGACY
        # selector's ranking-admission inputs; they remain sourced from the proof
        # so S3 does not change which proofs the legacy ranker admits (that is S4's
        # job when the marginal-utility ranker replaces this surface). On the real
        # path a priced proof's row always carries the native ask ladder it was
        # priced from, so the materialized NativeSideCandidate is tradeable
        # whenever the proof is — they agree; this preserves byte-identical legacy
        # ranking while the candidate object becomes the canonical materialization.
        native_quote_available=bool(proof.native_quote_available),
        missing_reason=proof.missing_reason,
        kelly_size_usd=max(0.0, float(kelly_size_usd)),
        max_executable_shares=_candidate_max_executable_shares(proof),
        book_hash=_nonnull(row.get("book_hash") or row.get("executable_book_hash") or row.get("snapshot_hash")),
        low_volume_usd=_candidate_low_volume_usd(row),
        # FIX C: mode-consistent EV provenance (chosen mode + both EVs).
        execution_mode_intent=proof.execution_mode_intent,
        ev_taker=proof.ev_taker,
        ev_maker=proof.ev_maker,
        maker_limit_price=proof.maker_limit_price,
        relative_spread_at_eval=proof.relative_spread_at_eval,
        taker_forbidden_reason=proof.taker_forbidden_reason,
        maker_fill_probability=proof.maker_fill_probability,
        maker_fill_probability_source=proof.maker_fill_probability_source,
        qkernel_execution_economics=_json_finite(proof.qkernel_execution_economics),
    )


# REMOVED 2026-06-08 (S4; operator directive; "bin selection.md" §3/§5.2/§5.3):
# _candidate_selection_kelly_size_usd_by_id — the pre-selection scalar binary-Kelly
# sizing pass over every sibling candidate (sized on q_point via evaluate_kelly).
# Exposure-aware sizing is now the marginal-utility ranker's
# RobustCandidateScore.optimal_stake_usd, computed POST-selection on the WINNING leg
# (_robust_marginal_utility_optimal_stake_usd) against the family payoff matrix +
# existing per-outcome exposure (Hidden #10). One sizing surface, sized on the robust
# q_lcb (not q_point), no parallel pre-selection scalar Kelly.


def _qkernel_same_token_fill_up_selection_rejection_reason(
    *,
    proof: _CandidateProof,
    held_position_conn: sqlite3.Connection | None,
    locked_opportunity_conn: sqlite3.Connection | None,
) -> str | None:
    """Return why a qkernel-selected same-token fill-up is not an executable action.

    Redecision ranks over actions, not just instruments. If the top qkernel leg is
    the already-held token but the committed fill-up predicate would immediately
    abort, keeping that leg selected starves sibling shift candidates. This pure
    pre-lease probe uses the same ``decide_fill_up`` predicate as the submit path
    and only removes the same-token action when it is provably unactionable.
    """

    selected_token_id = str(getattr(proof, "token_id", "") or "").strip()
    if not selected_token_id:
        return None
    held = _fill_up_wiring.read_held_same_token_exposure(
        held_position_conn,
        token_id=selected_token_id,
    )
    if held is None:
        return None
    cert = _valid_qkernel_execution_economics_payload(
        getattr(proof, "qkernel_execution_economics", None),
        direction=str(getattr(proof, "direction", "") or ""),
    )
    if cert is None:
        return "QKERNEL_EXECUTION_ECONOMICS_UNAVAILABLE"
    q_current_lcb = _optional_float(cert.get("payoff_q_lcb"))
    target_total_exposure = _optional_float(cert.get("optimal_stake_usd"))
    if q_current_lcb is None or target_total_exposure is None:
        return "QKERNEL_FILL_UP_TARGET_UNAVAILABLE"
    row = getattr(proof, "row", {}) or {}
    min_order_shares = (
        _float_or_default(row.get("min_order_size"), 1.0)
        if isinstance(row, Mapping) else 1.0
    )
    cost = _optional_float(cert.get("cost"))
    if cost is None:
        cost = _optional_float(getattr(getattr(proof, "execution_price", None), "value", None))
    venue_min_increment_usd = (
        float(min_order_shares) * float(cost)
        if cost is not None and cost > 0.0
        else float(min_order_shares)
    )
    pending_same_token_usd = _same_token_pending_entry_usd(
        locked_opportunity_conn,
        token_id=selected_token_id,
        trade_conn=held_position_conn,
    )
    decision = _fill_up_wiring.decide_fill_up(
        is_redecision_event=True,
        selected_token_id=selected_token_id,
        selected_bin_id=_candidate_bin_id(proof),
        selected_direction=str(getattr(proof, "direction", "") or ""),
        held_token_id=selected_token_id,
        held_bin_id=_candidate_bin_id(proof),
        held_direction=str(getattr(proof, "direction", "") or ""),
        q_current_lcb=float(q_current_lcb),
        q_entry_lcb=held.entry_q_lcb,
        target_total_exposure_usd=float(target_total_exposure),
        current_live_exposure_usd=float(held.current_live_usd),
        same_token_pending_entry_usd=float(pending_same_token_usd),
        venue_min_increment_usd=float(venue_min_increment_usd),
        has_unowned_pending_or_unknown_entry=False,
    )
    if decision.allow:
        return None
    return str(decision.reason or "FILL_UP_NOT_ACTIONABLE")


def _selection_scoped_proofs(
    *,
    proofs: tuple[_CandidateProof, ...],
    locked_opportunity_conn: sqlite3.Connection | None = None,
    held_position_conn: sqlite3.Connection | None = None,
    strategy_policy_conn: sqlite3.Connection | None = None,
    strategy_policy_event_type: str | None = None,
    decision_time: datetime | None = None,
    allow_same_family_monitor_owned: bool = False,
    honor_admission_rejections: bool = True,
    enforce_win_rate_floor: bool = True,
) -> tuple[_CandidateProof, ...]:
    executable = [proof for proof in proofs if proof.execution_price is not None]
    executable = [
        proof
        for proof in executable
        if _live_selection_rejection_reason(
            proof,
            strategy_policy_conn=strategy_policy_conn,
            strategy_policy_event_type=strategy_policy_event_type,
            decision_time=decision_time,
            enforce_win_rate_floor=enforce_win_rate_floor,
        )
        is None
    ]
    # FIX A/B hardening (2026-06-10 Milan-24C incident): a priced proof that an
    # admission gate REJECTED (missing_reason set: DIRECTION_LAW / COVERAGE_
    # UNLICENSED_TAIL / capital efficiency / buy_no evidence) must not enter the
    # ΔU ranking at all. Before this filter a rejected proof with a juicy
    # (corrupt) q_lcb could win the ΔU rank and then dead-end at the
    # TRADE_SCORE_NON_POSITIVE submit gate — never a bad order, but it STARVED
    # the legitimate admitted sibling of its selection. Gate-rejected proofs are
    # unrankable, not merely unsubmittable.
    def _qkernel_may_rescore_rejected_proof(missing_reason: str | None) -> bool:
        """Whether the qkernel may re-evaluate a legacy admission rejection.

        The qkernel replaces scalar economics and owns live side/bin selection for
        forecast families. It may restore a proof removed by the old
        capital-efficiency prefilter or the retired rounded-mu direction heuristic so
        the vector payoff engine can compare the leg honestly under the qkernel's
        settlement-bin law. It must not resurrect missing native structure,
        near-settled-price blocks, or buy-NO conservative-evidence failures; those are
        executable/semantic defects, not legacy scalar objective drift.
        """
        text = str(missing_reason or "").strip()
        if not text:
            return True
        return text.startswith(
            (
                "ADMISSION_CAPITAL_EFFICIENCY_LCB_EV",
                "ADMISSION_CAPITAL_EFFICIENCY",
                "ADMISSION_WIN_RATE_FLOOR",
                "DIRECTION_LAW_BIN_FORECAST_MISMATCH",
            )
        )

    if honor_admission_rejections:
        executable = [
            proof
            for proof in executable
            if proof.missing_reason is None
            or (
                allow_same_family_monitor_owned
                and _is_entry_held_redecision_reason(proof.missing_reason)
            )
        ]
    else:
        executable = [
            proof
            for proof in executable
            if _qkernel_may_rescore_rejected_proof(proof.missing_reason)
            or (
                allow_same_family_monitor_owned
                and _is_entry_held_redecision_reason(proof.missing_reason)
            )
        ]
    tradeable_limit = [
        proof
        for proof in executable
        if _candidate_limit_price_untradeable_reason(proof) is None
    ]
    scoped = executable
    if tradeable_limit:
        scoped = tradeable_limit
    if locked_opportunity_conn is not None:
        unlocked = [
            proof
            for proof in scoped
            if _locked_candidate_no_price_improvement_reason(
                locked_opportunity_conn,
                proof,
            )
            is None
        ]
        if unlocked:
            scoped = unlocked
        elif scoped:
            return ()
    if held_position_conn is not None:
        unheld: list[_CandidateProof] = []
        for proof in scoped:
            reason = _entry_held_position_reason_for_proof(held_position_conn, proof)
            if reason is None:
                unheld.append(proof)
                continue
            if allow_same_family_monitor_owned and _is_entry_held_redecision_reason(reason):
                unheld.append(proof)
        if unheld:
            scoped = unheld
        elif scoped:
            return ()
    return tuple(scoped)


def _strategy_policy_selection_rejection_reason(
    proof: _CandidateProof,
    *,
    strategy_policy_conn: sqlite3.Connection | None = None,
    strategy_policy_event_type: str | None = None,
    decision_time: datetime | None = None,
) -> str | None:
    """Return the strategy-governance reason that removes an entry proof.

    Legacy evaluator entry already resolves ``risk_actions`` via
    ``resolve_strategy_policy``.  EDLI/qkernel is the newer live selection authority,
    so it must consume the same policy surface before ranking a family; otherwise a
    strategy degraded by settled/live performance can keep submitting through the
    qkernel path.
    """

    if strategy_policy_conn is None or strategy_policy_event_type is None:
        return None
    try:
        strategy_key = _event_bound_strategy_key(
            event_type=str(strategy_policy_event_type),
            direction=str(getattr(proof, "direction", "") or ""),
            metric=str(
                getattr(getattr(proof, "candidate", None), "metric", "")
                or getattr(getattr(proof, "candidate", None), "temperature_metric", "")
                or ""
            ),
            require_metric_live=False,
        )
        policy_now = decision_time
        if policy_now is None:
            policy_now = datetime.now(timezone.utc)
            logger.warning(
                "DECISION_TIME_FABRICATED_AT_EDLI_STRATEGY_POLICY: strategy_key=%s policy_now=%s",
                strategy_key,
                policy_now,
            )
        from src.riskguard.policy import resolve_strategy_policy

        policy = resolve_strategy_policy(strategy_policy_conn, strategy_key, policy_now)
    except Exception as exc:  # noqa: BLE001
        return f"STRATEGY_POLICY_UNAVAILABLE:{type(exc).__name__}"

    source_values = tuple(str(source) for source in policy.sources)
    sources = ",".join(source_values) or "none"
    if policy.gated and _strategy_policy_has_selection_gate(source_values):
        return f"STRATEGY_POLICY_GATED:{strategy_key}:sources={sources}"
    if policy.exit_only:
        return f"STRATEGY_POLICY_EXIT_ONLY:{strategy_key}:sources={sources}"
    return None


def _strategy_policy_has_selection_gate(sources: tuple[str, ...]) -> bool:
    """Return whether strategy governance, not global submit safety, gates selection.

    ``pause_entries`` and deployment freshness are global submit/admission controls.
    They must stop venue submission at the executor boundary, but they are not
    evidence that a candidate is economically inferior inside the family optimizer.
    Per-strategy controls still remove candidates before ranking.
    """

    for source in sources:
        if source in {"manual_override:gate", "risk_action:gate"}:
            return True
    return False


def _proof_strategy_key_for_quality(
    proof: _CandidateProof,
    *,
    strategy_policy_event_type: str | None,
) -> str | None:
    if not str(strategy_policy_event_type or "").strip():
        return None
    try:
        return _event_bound_strategy_key(
            event_type=strategy_policy_event_type or "",
            direction=str(getattr(proof, "direction", "") or ""),
            metric=str(
                getattr(getattr(proof, "candidate", None), "metric", "")
                or getattr(
                    getattr(proof, "candidate", None),
                    "temperature_metric",
                    "",
                )
                or ""
            ),
            require_metric_live=False,
        )
    except Exception:  # noqa: BLE001 - quality gate falls back to ordinary binary floor.
        return None


def _live_selection_rejection_reason(
    proof: _CandidateProof,
    *,
    strategy_policy_conn: sqlite3.Connection | None = None,
    strategy_policy_event_type: str | None = None,
    decision_time: datetime | None = None,
    enforce_win_rate_floor: bool = True,
) -> str | None:
    """Return the live admission reason that prevents a proof from being ranked.

    The ΔU selector is the entry decision surface; proofs that cannot satisfy live
    selected-side evidence must be removed before ranking, not merely rejected by
    the final venue submit gate.  This keeps cheap positive-EV lottery legs and
    qkernel SIDE_NOT_ARMED telemetry from becoming selected live intents.
    """
    if enforce_win_rate_floor:
        from src.strategy.live_inference.live_admission import (
            live_entry_probability_quality_rejection_reason,
        )

        win_rate_reason = live_entry_probability_quality_rejection_reason(
            q_lcb=getattr(proof, "q_lcb_5pct", None),
            direction=getattr(proof, "direction", None),
            strategy_key=_proof_strategy_key_for_quality(
                proof,
                strategy_policy_event_type=strategy_policy_event_type,
            ),
            selection_authority_applied="qkernel_spine",
            qkernel_execution_economics=getattr(proof, "qkernel_execution_economics", None),
        )
        if win_rate_reason is not None:
            return win_rate_reason

    strategy_policy_reason = _strategy_policy_selection_rejection_reason(
        proof,
        strategy_policy_conn=strategy_policy_conn,
        strategy_policy_event_type=strategy_policy_event_type,
        decision_time=decision_time,
    )
    if strategy_policy_reason is not None:
        return strategy_policy_reason

    cert = getattr(proof, "qkernel_execution_economics", None)
    if cert is None:
        return None
    if not isinstance(cert, Mapping):
        return "QKERNEL_EXECUTION_ECONOMICS_INVALID"
    if str(cert.get("source") or "").strip() != "qkernel_spine":
        return None
    if _valid_qkernel_execution_economics_payload(
        cert,
        direction=str(getattr(proof, "direction", "") or ""),
    ) is None:
        return _qkernel_selection_economics_rejection_reason(
            cert,
            direction=str(getattr(proof, "direction", "") or ""),
        )
    final_floor_reason = _qkernel_final_submit_floor_rejection_reason(
        proof=proof,
        cert=cert,
        strategy_policy_event_type=strategy_policy_event_type,
    )
    if final_floor_reason is not None:
        return final_floor_reason
    return None


def _qkernel_final_submit_floor_rejection_reason(
    *,
    proof: _CandidateProof,
    cert: Mapping[str, Any],
    strategy_policy_event_type: str | None = None,
) -> str | None:
    """Reject qkernel candidates that cannot clear the final live submit floors."""

    try:
        cost = float(cert.get("cost"))
        edge_lcb = float(cert.get("edge_lcb"))
        payoff_q_point = float(cert.get("payoff_q_point"))
        payoff_q_lcb = float(cert.get("payoff_q_lcb"))
        optimal_stake_usd = float(cert.get("optimal_stake_usd"))
    except (TypeError, ValueError):
        return "QKERNEL_FINAL_SUBMIT_FLOOR:invalid_economics"
    if not all(
        math.isfinite(value)
        for value in (cost, edge_lcb, payoff_q_point, payoff_q_lcb, optimal_stake_usd)
    ):
        return "QKERNEL_FINAL_SUBMIT_FLOOR:non_finite_economics"

    from src.strategy.live_inference.live_admission import (
        live_entry_probability_quality_rejection_reason,
    )

    strategy_key_for_quality = _proof_strategy_key_for_quality(
        proof,
        strategy_policy_event_type=strategy_policy_event_type,
    )
    if (
        strategy_key_for_quality is None
        and str(getattr(proof, "direction", "") or "").strip() == "buy_yes"
        and str(cert.get("source") or "").strip() == "qkernel_spine"
    ):
        strategy_key_for_quality = "forecast_qkernel_entry"

    win_rate_reason = live_entry_probability_quality_rejection_reason(
        q_lcb=payoff_q_lcb,
        direction=str(getattr(proof, "direction", "") or ""),
        strategy_key=strategy_key_for_quality,
        selection_authority_applied="qkernel_spine",
        qkernel_execution_economics=cert,
    )
    if win_rate_reason is not None:
        return win_rate_reason
    near_day0_reason = _qkernel_near_day0_cert_rejection_reason(cert)
    if near_day0_reason is not None:
        return near_day0_reason

    if not str(strategy_policy_event_type or "").strip():
        return None
    try:
        strategy_key = _event_bound_strategy_key(
            event_type=str(strategy_policy_event_type or ""),
            direction=str(getattr(proof, "direction", "") or ""),
            metric=str(
                getattr(getattr(proof, "candidate", None), "metric", "")
                or getattr(getattr(proof, "candidate", None), "temperature_metric", "")
                or ""
            ),
            require_metric_live=False,
        )
    except Exception as exc:  # noqa: BLE001
        return f"QKERNEL_FINAL_SUBMIT_FLOOR_UNAVAILABLE:{type(exc).__name__}"

    floors = _event_bound_strategy_live_quality_floors(strategy_key)
    floor_decision = entry_price_floor_decision(
        strategy_key=strategy_key,
        direction=str(getattr(proof, "direction", "") or ""),
        declared_min_entry_price=floors["min_entry_price"],
        selection_authority_applied="qkernel_spine",
        economics=cert,
        q_live=payoff_q_point,
        q_lcb=payoff_q_lcb,
        limit_price=cost,
    )
    effective_min_entry_price = float(floor_decision.effective_min_entry_price)
    min_expected_profit_usd = float(floors["min_expected_profit_usd"])
    if cost + 1e-12 < effective_min_entry_price:
        return (
            "QKERNEL_FINAL_SUBMIT_FLOOR:limit_price_below_strategy_entry_floor:"
            f"strategy={strategy_key}:cost={cost:.6f}:floor={effective_min_entry_price:.6f}"
        )
    profit_lcb_usd = roi_frontier_profit_lcb_usd(
        stake=optimal_stake_usd,
        cost=cost,
        edge_lcb=edge_lcb,
    )
    if profit_lcb_usd + 1e-9 < min_expected_profit_usd:
        return (
            "QKERNEL_FINAL_SUBMIT_FLOOR:expected_profit_below_strategy_floor:"
            f"strategy={strategy_key}:profit_lcb_usd={profit_lcb_usd:.6f}:"
            f"floor={min_expected_profit_usd:.6f}"
        )
    return None


def _qkernel_actual_submit_quality_rejection_reason(
    *,
    proof: _CandidateProof,
    strategy_policy_event_type: str | None = None,
    actual_stake_usd: float,
    actual_cost: float,
) -> str | None:
    """Reject qkernel orders that only looked profitable at theoretical size.

    Selection certificates carry the qkernel's unconstrained optimal stake.  Live
    submission is sized later by recapture, Kelly haircuts, free-cash, and venue
    constraints.  The final money-path quality proof must therefore use the
    notional and limit price that will actually be submitted.
    """

    raw_cert = getattr(proof, "qkernel_execution_economics", None)
    cert = _valid_qkernel_execution_economics_payload(
        raw_cert,
        direction=str(getattr(proof, "direction", "") or ""),
    )
    if cert is None:
        if (
            isinstance(raw_cert, Mapping)
            and str(raw_cert.get("source") or "").strip() == "qkernel_spine"
        ):
            detail = _qkernel_selection_economics_rejection_reason(
                raw_cert,
                direction=str(getattr(proof, "direction", "") or ""),
            )
            return f"QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:{detail}"
        return None
    try:
        stake = float(actual_stake_usd)
        cost = float(actual_cost)
        payoff_q_point = float(cert.get("payoff_q_point"))
        payoff_q_lcb = float(cert.get("payoff_q_lcb"))
    except (TypeError, ValueError):
        return "QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:invalid_actual_submit_economics"
    if not all(math.isfinite(value) for value in (stake, cost, payoff_q_point, payoff_q_lcb)):
        return "QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:non_finite_actual_submit_economics"
    if stake <= 0.0 or not (0.0 < cost < 1.0):
        return (
            "QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:non_positive_actual_submit:"
            f"stake_usd={stake:.6f}:cost={cost:.6f}"
        )
    edge_lcb = payoff_q_lcb - cost
    if edge_lcb <= 0.0:
        return (
            "QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:actual_edge_non_positive:"
            f"payoff_q_lcb={payoff_q_lcb:.6f}:cost={cost:.6f}"
        )

    from src.strategy.live_inference.live_admission import (
        live_entry_probability_quality_rejection_reason,
    )

    strategy_key_for_quality: str | None = None
    if str(strategy_policy_event_type or "").strip():
        try:
            strategy_key_for_quality = _event_bound_strategy_key(
                event_type=str(strategy_policy_event_type or ""),
                direction=str(getattr(proof, "direction", "") or ""),
                metric=str(
                    getattr(getattr(proof, "candidate", None), "metric", "")
                    or getattr(getattr(proof, "candidate", None), "temperature_metric", "")
                    or ""
                ),
                require_metric_live=False,
            )
        except Exception as exc:  # noqa: BLE001
            return f"QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR_UNAVAILABLE:{type(exc).__name__}"
    elif (
        str(getattr(proof, "direction", "") or "").strip() == "buy_yes"
        and str(cert.get("source") or "").strip() == "qkernel_spine"
    ):
        strategy_key_for_quality = "forecast_qkernel_entry"

    win_rate_reason = live_entry_probability_quality_rejection_reason(
        q_lcb=payoff_q_lcb,
        direction=str(getattr(proof, "direction", "") or ""),
        strategy_key=strategy_key_for_quality,
        selection_authority_applied="qkernel_spine",
        qkernel_execution_economics=cert,
    )
    if win_rate_reason is not None:
        return f"QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:{win_rate_reason}"

    if not str(strategy_policy_event_type or "").strip():
        return None
    try:
        strategy_key = _event_bound_strategy_key(
            event_type=str(strategy_policy_event_type or ""),
            direction=str(getattr(proof, "direction", "") or ""),
            metric=str(
                getattr(getattr(proof, "candidate", None), "metric", "")
                or getattr(getattr(proof, "candidate", None), "temperature_metric", "")
                or ""
            ),
            require_metric_live=False,
        )
    except Exception as exc:  # noqa: BLE001
        return f"QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR_UNAVAILABLE:{type(exc).__name__}"

    floors = _event_bound_strategy_live_quality_floors(strategy_key)
    floor_decision = entry_price_floor_decision(
        strategy_key=strategy_key,
        direction=str(getattr(proof, "direction", "") or ""),
        declared_min_entry_price=floors["min_entry_price"],
        selection_authority_applied="qkernel_spine",
        economics=cert,
        q_live=payoff_q_point,
        q_lcb=payoff_q_lcb,
        limit_price=cost,
    )
    effective_min_entry_price = float(floor_decision.effective_min_entry_price)
    if cost + 1e-12 < effective_min_entry_price:
        return (
            "QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:limit_price_below_strategy_entry_floor:"
            f"strategy={strategy_key}:cost={cost:.6f}:floor={effective_min_entry_price:.6f}"
        )

    min_expected_profit_usd = float(floors["min_expected_profit_usd"])
    profit_lcb_usd = roi_frontier_profit_lcb_usd(
        stake=stake,
        cost=cost,
        edge_lcb=edge_lcb,
    )
    if profit_lcb_usd + 1e-9 < min_expected_profit_usd:
        return (
            "QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:actual_profit_below_strategy_floor:"
            f"strategy={strategy_key}:profit_lcb_usd={profit_lcb_usd:.6f}:"
            f"floor={min_expected_profit_usd:.6f}:stake_usd={stake:.6f}:cost={cost:.6f}"
        )

    min_submit_edge_density = float(floors["min_submit_edge_density"])
    edge_density = edge_lcb / cost
    if edge_density + 1e-9 < min_submit_edge_density:
        return (
            "QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:actual_edge_density_below_strategy_floor:"
            f"strategy={strategy_key}:edge_density={edge_density:.6f}:"
            f"floor={min_submit_edge_density:.6f}:stake_usd={stake:.6f}:cost={cost:.6f}"
        )
    try:
        side = str(cert.get("side") or "").strip().upper()
        delta_u_at_min = float(cert.get("delta_u_at_min"))
    except (TypeError, ValueError):
        return "QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:invalid_roi_frontier_economics"
    if not roi_frontier_useful_values(
        side=side,
        cost=cost,
        payoff_q_lcb=payoff_q_lcb,
        edge_lcb=edge_lcb,
        stake=stake,
        delta_u_at_min=delta_u_at_min,
    ):
        return (
            "QKERNEL_ACTUAL_SUBMIT_QUALITY_FLOOR:actual_roi_frontier_not_useful:"
            f"strategy={strategy_key}:stake_usd={stake:.6f}:cost={cost:.6f}:"
            f"edge_lcb={edge_lcb:.6f}:payoff_q_lcb={payoff_q_lcb:.6f}"
        )
    return None


def _opportunity_book_proofs_with_selection_rejections(
    *,
    proofs: tuple[_CandidateProof, ...],
    locked_opportunity_conn: sqlite3.Connection | None = None,
    held_position_conn: sqlite3.Connection | None = None,
    strategy_policy_conn: sqlite3.Connection | None = None,
    strategy_policy_event_type: str | None = None,
    decision_time: datetime | None = None,
    allow_same_family_monitor_owned: bool = False,
    enforce_win_rate_floor: bool = True,
) -> tuple[_CandidateProof, ...]:
    excluded_by_id: dict[str, str] = {}
    selected_ids = {
        _candidate_evaluation_id(proof)
        for proof in _selection_scoped_proofs(
            proofs=proofs,
            locked_opportunity_conn=locked_opportunity_conn,
            held_position_conn=held_position_conn,
            strategy_policy_conn=strategy_policy_conn,
            strategy_policy_event_type=strategy_policy_event_type,
            decision_time=decision_time,
            allow_same_family_monitor_owned=allow_same_family_monitor_owned,
            enforce_win_rate_floor=enforce_win_rate_floor,
        )
    }
    for proof in proofs:
        proof_id = _candidate_evaluation_id(proof)
        if selected_ids and proof_id in selected_ids:
            continue
        if proof.execution_price is None:
            continue
        reason = _live_selection_rejection_reason(
            proof,
            strategy_policy_conn=strategy_policy_conn,
            strategy_policy_event_type=strategy_policy_event_type,
            decision_time=decision_time,
            enforce_win_rate_floor=enforce_win_rate_floor,
        )
        if reason is None:
            reason = _candidate_limit_price_untradeable_reason(proof)
        if reason is None and locked_opportunity_conn is not None:
            reason = _locked_candidate_no_price_improvement_reason(
                locked_opportunity_conn,
                proof,
            )
        if reason is None and held_position_conn is not None:
            reason = _entry_held_position_reason_for_proof(
                held_position_conn,
                proof,
            )
            if allow_same_family_monitor_owned and _is_entry_held_redecision_reason(reason):
                reason = None
        if reason is not None:
            excluded_by_id[proof_id] = reason
    if not excluded_by_id:
        return proofs
    annotated: list[_CandidateProof] = []
    for proof in proofs:
        reason = excluded_by_id.get(_candidate_evaluation_id(proof))
        if reason is None:
            annotated.append(proof)
            continue
        annotated.append(
            dataclass_replace(
                proof,
                missing_reason=reason,
                passed_prefilter=False,
                trade_score=0.0,
            )
        )
    return tuple(annotated)


def _qkernel_side_for_direction(direction: str | None) -> str | None:
    if str(direction or "") == "buy_yes":
        return "YES"
    if str(direction or "") == "buy_no":
        return "NO"
    return None


def _proofs_with_qkernel_candidate_economics(
    *,
    proofs: tuple[_CandidateProof, ...],
    qkernel_economics_by_bin_side: Mapping[tuple[str, str], Mapping[str, Any]] | None,
    strategy_policy_event_type: str | None = None,
) -> tuple[_CandidateProof, ...]:
    """Attach qkernel candidate economics to receipt proofs without granting authority.

    Non-selected qkernel candidates need their vector edge / delta-U / stake evidence
    in the live opportunity book and regret rows, but they must not get the
    ``selection_authority_applied`` stamp that authorizes qkernel submit sizing.
    """
    if not qkernel_economics_by_bin_side:
        return proofs
    min_profit_lcb_usd = roi_frontier_min_profit_lcb_usd()

    def _qkernel_receipt_rejection_reason(
        proof: _CandidateProof,
        cert: Mapping[str, Any],
    ) -> str | None:
        try:
            side = str(cert.get("side") or "").strip().upper()
            cost = float(cert.get("cost"))
            payoff_q_lcb = float(cert.get("payoff_q_lcb"))
            edge_lcb = float(cert.get("edge_lcb"))
            delta_u_at_min = float(cert.get("delta_u_at_min"))
            optimal_delta_u = float(cert.get("optimal_delta_u"))
            optimal_stake_usd = float(cert.get("optimal_stake_usd") or 0.0)
        except (TypeError, ValueError):
            return "QKERNEL_EXECUTION_ECONOMICS_INVALID"
        if cert.get("direction_law_ok") is not True:
            return f"QKERNEL_DIRECTION_LAW_REJECTED:side={side or 'UNKNOWN'}"
        if cert.get("coherence_allows") is not True:
            return f"QKERNEL_MARKET_COHERENCE_BLOCKED:side={side or 'UNKNOWN'}"
        if edge_lcb <= 0.0:
            return (
                "QKERNEL_EDGE_LCB_NON_POSITIVE:"
                f"edge_lcb={edge_lcb:.6f}:payoff_q_lcb={payoff_q_lcb:.6f}:cost={cost:.6f}"
            )
        if optimal_delta_u <= 0.0:
            return (
                "QKERNEL_DELTA_U_NON_POSITIVE:"
                f"optimal_delta_u={optimal_delta_u:.9f}:edge_lcb={edge_lcb:.6f}:"
                f"stake={optimal_stake_usd:.6f}"
            )
        if delta_u_at_min <= 0.0:
            return (
                "QKERNEL_DELTA_U_AT_MIN_NON_POSITIVE:"
                f"delta_u_at_min={delta_u_at_min:.9f}:edge_lcb={edge_lcb:.6f}:"
                f"stake={optimal_stake_usd:.6f}"
            )
        if optimal_stake_usd <= 0.0:
            return (
                "QKERNEL_STAKE_NON_POSITIVE:"
                f"stake={optimal_stake_usd:.6f}:edge_lcb={edge_lcb:.6f}"
            )
        final_floor_reason = _qkernel_final_submit_floor_rejection_reason(
            proof=proof,
            cert=cert,
            strategy_policy_event_type=strategy_policy_event_type,
        )
        if final_floor_reason is not None:
            return final_floor_reason
        growth_density = roi_frontier_growth_density(
            cost=cost,
            edge_lcb=edge_lcb,
            payoff_q_lcb=payoff_q_lcb,
        )
        min_payoff_q_lcb = float(roi_frontier_min_payoff_q_lcb(side=side, cost=cost))
        profit_lcb_usd = roi_frontier_profit_lcb_usd(
            stake=optimal_stake_usd,
            cost=cost,
            edge_lcb=edge_lcb,
        )
        roi_lcb = edge_lcb / cost if cost > 0.0 else float("-inf")
        roi_frontier_useful = (
            math.isfinite(profit_lcb_usd)
            and profit_lcb_usd >= min_profit_lcb_usd
            and math.isfinite(growth_density)
            and delta_u_at_min > 0.0
            and payoff_q_lcb >= min_payoff_q_lcb
        )
        if not roi_frontier_useful:
            return (
                "QKERNEL_ROI_FRONTIER_NOT_USEFUL:"
                f"profit_lcb_usd={profit_lcb_usd:.6f}:growth_density={growth_density:.9f}:"
                f"edge_roi_lcb={roi_lcb:.6f}:payoff_q_lcb={payoff_q_lcb:.6f}"
            )
        return None

    annotated: list[_CandidateProof] = []
    changed = False
    for proof in proofs:
        side = _qkernel_side_for_direction(proof.direction)
        cert = (
            qkernel_economics_by_bin_side.get((_candidate_bin_id(proof), side))
            if side is not None
            else None
        )
        if cert is None:
            annotated.append(proof)
            continue
        qkernel_reason = _qkernel_receipt_rejection_reason(proof, cert)
        q_point = _optional_float(cert.get("payoff_q_point"))
        q_lcb = _optional_float(cert.get("payoff_q_lcb"))
        trade_score = _optional_float(cert.get("edge_lcb"))
        try:
            proof_q_point = float(proof.q_posterior)
            proof_q_lcb = float(proof.q_lcb_5pct)
        except (TypeError, ValueError):
            proof_q_point = float("nan")
            proof_q_lcb = float("nan")
        cert_payload = dict(cert)
        if math.isfinite(proof_q_point):
            cert_payload["pre_qkernel_q_posterior"] = proof_q_point
        if math.isfinite(proof_q_lcb):
            cert_payload["pre_qkernel_q_lcb_5pct"] = proof_q_lcb
        cert_payload["q_lcb_authority"] = "qkernel_payoff_bound"
        cert_payload["probability_authority"] = "qkernel_payoff_direct_route"
        served_belief_reason = _qkernel_cert_served_belief_rejection_reason(
            cert_payload,
            proof_q_point=proof_q_point if math.isfinite(proof_q_point) else None,
            proof_q_lcb=proof_q_lcb if math.isfinite(proof_q_lcb) else None,
        )
        if qkernel_reason is None and served_belief_reason is not None:
            qkernel_reason = served_belief_reason
        overlay: dict[str, object] = {
            "trade_score": (
                trade_score
                if trade_score is not None and qkernel_reason is None
                else 0.0
            ),
            "passed_prefilter": qkernel_reason is None,
            "missing_reason": qkernel_reason,
            "qkernel_execution_economics": cert_payload,
        }
        if qkernel_reason is None and q_point is not None and q_lcb is not None:
            overlay["q_posterior"] = q_point
            overlay["q_lcb_5pct"] = q_lcb
        annotated.append(
            dataclass_replace(
                proof,
                **overlay,
            )
        )
        changed = True
    return tuple(annotated) if changed else proofs


# REJECTION-LABEL TRUTH (operator law 2026-06-11: 每一个被拒绝的具体原因都要写出来).
# When the family selector returns no live primary, the receipt must say WHY in the
# aggregate — not a single bin's label and not a lie about missing books. These two
# helpers turn the per-candidate missing_reasons (already on the proofs) into one
# deterministic family-level rejection class taxonomy + reason string. Observability
# only: they read proofs, change no gate, and never decide a trade. The class names are
    # stable identifiers (snake_case) so the receipt string is greppable in regret SQL.
_REJECTION_CLASS_PREFIXES: tuple[tuple[str, str], ...] = (
    # (missing_reason prefix, stable class name). Ordered most-specific first; the
    # first prefix that matches a missing_reason wins. CAPITAL_EFFICIENCY_LCB_EV
    # (the EV<=0 efficient-market normal state) is the dominant class in the wild.
    ("ADMISSION_CAPITAL_EFFICIENCY_LCB_EV", "capital_efficiency_lcb_ev"),
    ("ADMISSION_CAPITAL_EFFICIENCY", "capital_efficiency"),
    ("ADMISSION_NEAR_SETTLED_PRICE", "near_settled_price"),
    ("COVERAGE_UNLICENSED_TAIL", "coverage_unlicensed_tail"),
    ("ADMISSION_BUY_NO_CONSERVATIVE_EVIDENCE", "buy_no_evidence"),
    ("ADMISSION_BUY_NO_INDEPENDENT_YES_POSTERIOR_MISSING", "buy_no_evidence"),
    ("DIRECTION_LAW_BIN_FORECAST_MISMATCH", "legacy_rounded_mu_direction"),
    (
        "ADMISSION_QKERNEL_CENTER_YES_QUALITY_FLOOR",
        "qkernel_center_yes_quality_floor",
    ),
    (
        "ADMISSION_DAY0_FORECAST_ENTRY_REQUIRES_OBSERVATION_LANE",
        "near_day0_observation_lane",
    ),
    (
        "ADMISSION_NEAR_DAY0_RAW_EXTREMA",
        "near_day0_raw_extrema",
    ),
    ("ADMISSION_WIN_RATE_FLOOR", "win_rate_floor"),
    ("ADMISSION_LCB_CONSISTENCY", "lcb_consistency"),
    ("STRATEGY_POLICY_GATED", "strategy_policy"),
    ("STRATEGY_POLICY_EXIT_ONLY", "strategy_policy"),
    ("STRATEGY_POLICY_UNAVAILABLE", "strategy_policy"),
    ("QKERNEL_FINAL_SUBMIT_FLOOR", "final_submit_floor"),
    (_ENTRY_HELD_FAMILY_REASON_BASE, "held_family_monitor_owned"),
    (_ENTRY_HELD_POSITION_REASON_BASE, "held_position_monitor_owned"),
    # Genuinely-no-book classes (proof had execution_price None): the maker-quote
    # lane's own-ask-empty marker, plus the structural pre-pricing misses.
    ("clob_no_ask_illiquid", "native_ask_missing"),
    ("missing executable snapshot row", "native_ask_missing"),
    ("missing token id", "native_ask_missing"),
)


def _classify_rejection_missing_reason(missing_reason: str | None) -> str:
    """Map ONE per-candidate missing_reason to its stable rejection class.

    A candidate that was priced but gate-rejected carries the gate's reason; a
    candidate with no executable book carries a native-ask marker. Anything that
    matches no known prefix is bucketed as ``other`` (still counted, never lost) so
    a new gate's reason is visible in the aggregate the day it ships rather than
    silently collapsing into a misleading class.
    """
    text = str(missing_reason or "").strip()
    if not text:
        return "other"
    for prefix, class_name in _REJECTION_CLASS_PREFIXES:
        if text.startswith(prefix):
            return class_name
    return "other"


def _family_all_candidates_rejected_reason(book: OpportunityBook) -> str | None:
    """Deterministic family-level rejection label aggregated from the book.

    Returns a reason of the form::

        EVENT_BOUND_ALL_CANDIDATES_REJECTED:n=16 capital_efficiency_lcb_ev=12 \
            native_ask_missing=3 direction_law=1; best_rejected=<bin> <dir> \
            reason_class=.. missing_reason=.. q_lcb=.. price=.. rejected_ev_per_dollar=..

    when at least one candidate was PRICED-and-rejected (a real "no edge" family).
    Returns None when EVERY evaluated candidate genuinely lacks a book (no priced
    proof at all) — that case keeps the honest EXECUTABLE_NATIVE_ASK_MISSING label.

    The ``best_rejected`` candidate is the highest-conservative-EV-per-dollar
    PRICED proof (deterministic argmax on ``(q_lcb-price)/price`` then
    bin/direction tiebreak). It is still explicitly rejected: the summary carries
    the gate class and raw missing_reason so a vetoed positive-EV leg is not
    misread as confirmed trading value. Pure: reads the book's evaluations,
    decides nothing.
    """
    evaluations = tuple(book.evaluations)
    if not evaluations:
        return None
    class_counts: dict[str, int] = {}
    priced_rejected: list[CandidateEvaluation] = []
    for ev in evaluations:
        # Reaching this function means the selector chose no live primary, so every
        # evaluation is a loser. Each priced loser carries the gate's verdict in
        # ``missing_reason`` (set at proof generation when capital-efficiency /
        # direction-law / buy-NO-evidence rejected it); a bookless loser carries a
        # native-ask marker. The class taxonomy reads that verdict verbatim.
        class_name = _classify_rejection_missing_reason(ev.missing_reason)
        class_counts[class_name] = class_counts.get(class_name, 0) + 1
        if ev.execution_price is not None:
            priced_rejected.append(ev)
    if not priced_rejected:
        # No priced candidate at all -> genuinely missing books; not an
        # all-candidates-rejected family. Caller keeps NATIVE_ASK_MISSING.
        return None

    def _ev_per_dollar(ev: CandidateEvaluation) -> float:
        price = ev.execution_price
        if price is None or price <= 0.0:
            return float("-inf")
        return (float(ev.q_lcb_5pct) - float(price)) / float(price)

    best = max(
        priced_rejected,
        key=lambda ev: (
            _ev_per_dollar(ev),
            str(ev.bin_label or ""),
            str(ev.direction or ""),
        ),
    )
    counts_str = " ".join(
        f"{name}={class_counts[name]}" for name in sorted(class_counts)
    )
    best_price = best.execution_price
    best_reason = str(best.missing_reason or "").strip() or "UNKNOWN"
    best_reason_class = _classify_rejection_missing_reason(best_reason)
    return (
        "EVENT_BOUND_ALL_CANDIDATES_REJECTED:"
        f"n={len(evaluations)} {counts_str};"
        f" best_rejected={best.bin_label or '?'} {best.direction or '?'}"
        f" reason_class={best_reason_class}"
        f" missing_reason={best_reason}"
        f" q_lcb={float(best.q_lcb_5pct):.4f}"
        f" price={float(best_price):.4f}"
        f" rejected_ev_per_dollar={_ev_per_dollar(best):.4f}"
    )


def _opportunity_book_from_proofs(
    *,
    event_id: str,
    family_id: str,
    proofs: tuple[_CandidateProof, ...],
    selected_proof: _CandidateProof | None = None,
    locked_opportunity_conn: sqlite3.Connection | None = None,
    held_position_conn: sqlite3.Connection | None = None,
    strategy_policy_conn: sqlite3.Connection | None = None,
    strategy_policy_event_type: str | None = None,
    decision_time: datetime | None = None,
    allow_same_family_monitor_owned: bool = False,
    qkernel_economics_by_bin_side: Mapping[tuple[str, str], Mapping[str, Any]] | None = None,
    selection_exposure_by_outcome: Mapping[str, float] | None = None,
    enforce_win_rate_floor: bool = True,
) -> OpportunityBook:
    # The per-candidate kelly_size_usd is a DISPLAY field only (S4): the pre-
    # selection scalar-Kelly pass that used to populate it is retired; the live
    # stake is the marginal-utility ranker's optimal_stake_usd on the winning leg.
    # The receipt's display kelly_size_usd defaults to 0.0 for non-winning siblings.
    support_index_by_bin_id: dict[str, int] = {}
    for proof in proofs:
        bin_id = _candidate_bin_id(proof)
        if bin_id not in support_index_by_bin_id:
            support_index_by_bin_id[bin_id] = len(support_index_by_bin_id)
    book_proofs = _proofs_with_qkernel_candidate_economics(
        proofs=proofs,
        qkernel_economics_by_bin_side=qkernel_economics_by_bin_side,
        strategy_policy_event_type=strategy_policy_event_type,
    )
    evaluations = tuple(
        _candidate_evaluation_from_proof(
            family_id=family_id,
            proof=proof,
            support_index=support_index_by_bin_id.get(_candidate_bin_id(proof)),
            bin_id=_candidate_bin_id(proof),
        )
        for proof in _opportunity_book_proofs_with_selection_rejections(
            proofs=book_proofs,
            locked_opportunity_conn=locked_opportunity_conn,
            held_position_conn=held_position_conn,
            strategy_policy_conn=strategy_policy_conn,
            strategy_policy_event_type=strategy_policy_event_type,
            decision_time=decision_time,
            allow_same_family_monitor_owned=allow_same_family_monitor_owned,
            enforce_win_rate_floor=enforce_win_rate_floor,
        )
    )
    # The live decision is the ΔU ranker's pick (selected_proof). The book RECORDS
    # it as the single selected_candidate_id (operator directive 2026-06-08;
    # spec §14 item 7/8) rather than re-deciding via legacy scalar-Kelly. The
    # bin-selection ranker is the unconditional single path: there is no off-able
    # gate, so the receipt's selected_candidate_id is always the ΔU decision (S7
    # deleted the last `selector_enabled` / probe toggle artifacts from the
    # cache_summary; the receipt serializer records the decision unconditionally).
    #
    # A NON-executable selected_proof (execution_price None) is the best-belief
    # fallback surfaced for the EXECUTABLE_NATIVE_ASK_MISSING receipt, NOT a real
    # ΔU trade decision — it must NOT be recorded as the book's selected candidate
    # (else the receipt would claim a non-tradeable leg was selected). Record a
    # selection only for a genuinely-priced ΔU winner.
    decided_candidate_id = (
        _candidate_evaluation_id(selected_proof)
        if selected_proof is not None
        and getattr(selected_proof, "execution_price", None) is not None
        else None
    )
    selection_authority = None
    selected_qkernel_execution_economics = None
    if selected_proof is not None and decided_candidate_id is not None:
        if _proof_uses_qkernel_spine(selected_proof):
            selection_authority = "qkernel_spine"
        else:
            selection_authority = (
                str(selected_proof.selection_authority_applied)
                if selected_proof.selection_authority_applied is not None
                else "robust_marginal_utility"
            )
        selected_qkernel_execution_economics = selected_proof.qkernel_execution_economics
    cache_summary: dict[str, Any] = {
        "belief_cache": "source_run_bound",
        "price_cache": "snapshot_rows_refreshed_for_family",
        "actual_receipt_selected_candidate_id": decided_candidate_id,
    }
    if selection_authority is not None:
        cache_summary["selection_authority"] = selection_authority
    if selected_qkernel_execution_economics is not None:
        cache_summary["selected_qkernel_execution_economics"] = _json_finite(
            selected_qkernel_execution_economics
        )
    selection_exposure_summary = _selection_exposure_receipt_summary(
        selection_exposure_by_outcome
    )
    if selection_exposure_summary is not None:
        cache_summary["selection_exposure"] = selection_exposure_summary
    return build_family_opportunity_book(
        family_id=family_id,
        evaluations=evaluations,
        event_id=event_id,
        decided_candidate_id=decided_candidate_id,
        cache_summary=cache_summary,
    )


def _selection_exposure_receipt_summary(
    exposure_by_outcome: Mapping[str, float] | None,
) -> dict[str, Any] | None:
    """Compact provenance for the family exposure vector used at qkernel selection."""

    if exposure_by_outcome is None:
        return None
    cleaned: dict[str, float] = {}
    for outcome_id, raw_usd in exposure_by_outcome.items():
        try:
            usd = float(raw_usd)
        except (TypeError, ValueError):
            continue
        if not math.isfinite(usd) or usd <= 0.0:
            continue
        cleaned[str(outcome_id)] = usd
    if not cleaned:
        return _json_finite(
            {
                "source": "position_current_family_selection_exposure",
                "status": "checked_empty",
                "nonzero_outcome_count": 0,
                "total_exposure_usd": 0.0,
                "max_outcome_exposure_usd": 0.0,
                "by_outcome_usd": {},
            }
        )
    total = sum(cleaned.values())
    return _json_finite(
        {
            "source": "position_current_family_selection_exposure",
            "status": "nonzero",
            "nonzero_outcome_count": len(cleaned),
            "total_exposure_usd": total,
            "max_outcome_exposure_usd": max(cleaned.values()),
            "by_outcome_usd": dict(sorted(cleaned.items())),
        }
    )


def _coverage_unlicensed_tail_telemetry(
    *,
    q_lcb: float | int | None,
    execution_price: float | int | None,
    q_lcb_calibration_source: str | None,
) -> bool:
    """Telemetry-only (pr408 #2): would the cheap-tail unlicensed guard have fired?

    True iff the old fail-CLOSED tail guard WOULD have rejected (price<0.05, q_lcb>2x price,
    unlicensed source). Pure telemetry — the caller stamps it on the proof for settlement-
    graded study. It is NEVER consulted for score / prefilter / no-trade-reason / size. The
    ONE definition of the tail concern stays in live_admission.coverage_unlicensed_tail_
    rejection_reason; this wraps it as a boolean so no second copy of the rule exists.
    """
    return (
        coverage_unlicensed_tail_rejection_reason(
            q_lcb=q_lcb,
            execution_price=execution_price,
            q_lcb_calibration_source=q_lcb_calibration_source,
        )
        is not None
    )


def _generate_candidate_proofs(
    *,
    event: OpportunityEvent,
    payload: dict[str, object],
    family,
    snapshot_rows: list[dict[str, Any]],
    trade_conn: sqlite3.Connection,
    forecast_conn: sqlite3.Connection,
    calibration_conn: sqlite3.Connection,
    decision_time: datetime,
    promotion_evidence: ReplacementForecastPromotionEvidence | None = None,
    capital_objective_evidence: ReplacementForecastCapitalObjectiveEvidence | None = None,
    provenance_capture: dict[str, Any] | None = None,
) -> tuple[_CandidateProof, ...]:
    native_costs = _native_costs_by_candidate_direction(family=family, snapshot_rows=snapshot_rows)
    (
        q_by_condition,
        q_lcb_by_direction,
        generated_p_values,
        generated_prefilter,
        probability_evidence,
    ) = _live_yes_probabilities(
        event=event,
        payload=payload,
        family=family,
        conn=forecast_conn,
        calibration_conn=calibration_conn,
        native_costs=native_costs,
        decision_time=decision_time,
        promotion_evidence=promotion_evidence,
        capital_objective_evidence=capital_objective_evidence,
        provenance_capture=provenance_capture,
    )
    if getattr(event, "event_type", None) == "DAY0_EXTREME_UPDATED":
        _day0_metric = str(payload.get("metric") or payload.get("temperature_metric") or getattr(family, "metric", "") or "")
        _day0_observed_extreme = _observed_day0_extreme_native(payload, _day0_metric)
        if _day0_observed_extreme is not None:
            payload["_edli_spine_day0_observed_extreme_native"] = float(_day0_observed_extreme)
    # P1 BELIEF CAPTURE (continuous re-decision resurrection 2026-06-12). Buffer this family's
    # belief (YES q-posterior + condition_id per bin) into the per-call provenance_capture dict so
    # the reactor can persist it through its OWN world conn inside the open SAVEPOINT — NO second
    # connection, NO commit here (that was the 2026-05-31 self-deadlock). Covers BOTH the
    # replacement (live) and canonical paths because both flow through this ONE seam. Best-effort:
    # any capture error is swallowed — a belief-cache miss must never affect the decision. The
    # snapshot identity is the evidence key the §4.5 anti-twitch screen reads: posterior_id on the
    # replacement path, the bound snapshot_row's snapshot_id on the canonical path — both CHANGE
    # only when new forecast/day0/obs evidence lands and stay stable within the same evidence.
    if provenance_capture is not None:
        try:
            _bin_labels = [str(c.bin.label) for c in family.candidates]
            _cond_ids = [str(c.condition_id or "") for c in family.candidates]
            _posterior_vec = [
                float(q_by_condition.get(str(c.condition_id or ""), 0.0)) for c in family.candidates
            ]
            from src.calibration.qlcb_provenance import _qlcb_raw_float

            def _capture_lcb(condition_id: str, direction: str) -> float | None:
                value = q_lcb_by_direction.get((condition_id, direction))
                if value is None:
                    return None
                try:
                    out = float(_qlcb_raw_float(value))
                except (TypeError, ValueError):
                    return None
                if not math.isfinite(out):
                    return None
                return float(min(max(out, 0.0), 1.0))

            _q_lcb_yes_vec = [
                _capture_lcb(str(c.condition_id or ""), "buy_yes") for c in family.candidates
            ]
            _q_lcb_no_vec = [
                _capture_lcb(str(c.condition_id or ""), "buy_no") for c in family.candidates
            ]
            _snap_row = provenance_capture.get("snapshot_row") or {}
            _snap_id = (
                str(probability_evidence.get("posterior_id"))
                if probability_evidence.get("posterior_id") is not None
                else str(_snap_row.get("snapshot_id") or event.causal_snapshot_id or "")
            )
            _calib_hash = str(
                probability_evidence.get("probability_authority")
                or probability_evidence.get("p_cal_vector_hash")
                or "identity"
            )
            if _snap_id:
                provenance_capture["edli_belief"] = {
                    "family_id": str(family.family_id),
                    "city": str(family.city),
                    "target_date": str(family.target_date),
                    "temperature_metric": str(getattr(family, "metric", "") or ""),
                    "snapshot_id": _snap_id,
                    "calibrator_model_hash": _calib_hash,
                    "bin_labels": _bin_labels,
                    "p_posterior_vec": _posterior_vec,
                    "q_lcb_yes_vec": _q_lcb_yes_vec,
                    "q_lcb_no_vec": _q_lcb_no_vec,
                    "condition_ids": _cond_ids,
                }
        except Exception:  # noqa: BLE001 — belief capture is non-critical; never break the decision
            pass
    # === Q-KERNEL SPINE INPUTS — populate from the canonical member-envelope belief (2026-06-15) ===
    # The LIVE q above is the replacement provider-fused chain (_live_yes_probabilities), which
    # carries an anchor-fused posterior with NO debiased ensemble member envelope. The rebuilt
    # qkernel spine REQUIRES that envelope (build_center). Wave-5B wired the spine producer ONLY
    # into the canonical path (_market_analysis_from_event_snapshot), which is NOT on the live
    # replacement lane — so the spine got SPINE_INPUTS_UNAVAILABLE:MU_SIGMA_NOT_STASHED universally
    # (SPINE_STASH_DIAG=0 confirmed the producer never ran live). Fix: for spine-eligible families,
    # run that SAME validated producer here (read-only) on a payload COPY and lift ONLY the
    # _edli_spine_* keys onto the real payload — the live decision provenance (_edli_q_source etc.)
    # is untouched, and the spine bridge gets the exact debiased belief the ARM replay validated.
    # Bias-safe: the producer applies whatever de-bias is live (currently off => raw envelope, the
    # ARM-validated center) — NOT a new/contaminated correction. Fail-soft: any error stashes
    # nothing and never disturbs the decision.
    # SOURCE-PARITY AUTHORITY (2026-06-16, canonical-stash pre-emption fix): the
    # multi-model producer is AUTHORITATIVE for the spine-decision keys. The guard
    # formerly skipped when ``_edli_spine_mu_native`` was already in the payload —
    # but the canonical Stage-0 stash (``_market_analysis_from_event_snapshot``,
    # observability-only) populates that key from ``ensemble_snapshots`` on a
    # replacement-flag-OFF fall-through, which then PRE-EMPTED this raw_model_forecasts
    # fix and silently seeded the spine from the cold ECMWF-ensemble center again. We
    # now ALWAYS run the multi-model accessor for forecast-decision events; when it
    # SUCCEEDS it OVERWRITES the decision-consumed keys (mu/sigma/raw+debiased members)
    # with the ``raw_model_forecasts`` envelope, so an ensemble-derived value can never
    # reach a spine DECISION. When it returns None (fail-closed: <3 members / no causal
    # cycle) the canonical observability keys are left untouched (honest receipt + a
    # typed SPINE_INPUTS_UNAVAILABLE no-trade downstream). The accessor is ONE indexed
    # SQL query (NOT the ~22-CLOB-fetch q-build), so running it unconditionally is cheap.
    if getattr(event, "event_type", None) in _FORECAST_DECISION_EVENT_TYPES:
        try:
            # Bind the spine belief to the event's CAUSAL forecast snapshot.
            # All forecast lead buckets are now admitted (the 24h-only replay gate is removed),
            # so the causal cycle's lead (e.g. a 06-16 target on the 06-14 cycle = ~48h = the
            # 72h bucket) is tradeable with its conservative per-lead σ-floor. The causal
            # snapshot is the family's own bound forecast and reliably carries its member
            # envelope.
            #
            # ROOT-CAUSE FIX (2026-06-16 COLD-CENTER / 100%-buy_no-losing-book): source the
            # spine member envelope from the MULTI-MODEL DETERMINISTIC fusion table
            # (raw_model_forecasts, ~7-13 decorrelated NWP providers) via
            # _spine_multimodel_members_for_event — NOT from ensemble_snapshots.members_json
            # (51 ecmwf_ens members). The probability authority (AGENTS.md) mandates μ* = T2
            # Bayesian precision fusion over DECORRELATED providers, σ_pred = fusion variance —
            # neither from the ECMWF ensemble. The strategy-of-record, the de-bias provider, AND
            # the ARM-replay validation all use raw_model_forecasts; a 213-family settlement
            # audit found 0/213 ensemble-vs-multimodel member sets equal (mean |Δμ*|=1.14°C),
            # with the ensemble center systematically colder — the cold-center / failed-de-bias-
            # transfer root cause. The new accessor binds to the event's CAUSAL cycle (the bound
            # ensemble snapshot's source_cycle_time DATE, available_at ≤ decision_time), keeps
            # the latest cycle per model, and converts °C→native EXACTLY as build_family_spine —
            # so the live producer stashes the SAME member set the validated replay produces.
            #
            # CHEAP belief stash — ONE indexed SQL query, NO full q-build, NO network. Calling
            # _market_analysis_from_event_snapshot here (with its ~22 sequential CLOB /book
            # fetches) per spine family DOUBLED the q-build and HUNG the reactor (a single cycle
            # ran >12 min). De-bias is OFF live (edli_bias_correction_enabled=False +
            # emos_sole_calibrator), so the RAW multi-model member envelope IS the debiased
            # envelope the ARM replay validated; the spine's build_center (NoOpDebiasAuthority)
            # locks to it. mu/sigma are the empirical mean/std of that envelope (the already-
            # implied center/width). FAIL-CLOSED: <3 members or no causal cycle => None => stash
            # NOTHING => honest SPINE_INPUTS_UNAVAILABLE; NEVER falls back to the ensemble.
            _spine_multimodel = _spine_multimodel_members_for_event(
                forecast_conn,
                event=event,
                family=family,
                decision_time=decision_time,
            )
            if _spine_multimodel is not None:
                _spine_raw, _spine_source_cycle, _spine_precision = _spine_multimodel
                (
                    _spine_conditioned,
                    _pre_day0_low_carryover,
                    _pre_day0_low_block_reason,
                ) = _apply_pre_day0_low_carryover_to_spine_members(
                    family=family,
                    decision_time=decision_time,
                    members_native=_spine_raw,
                )
                if _pre_day0_low_block_reason is not None:
                    payload["_edli_spine_pre_day0_low_block_reason"] = _pre_day0_low_block_reason
                    _spine_raw = []
                    _spine_precision = []
                elif _pre_day0_low_carryover is not None:
                    _spine_raw = _spine_conditioned
                    payload["_edli_spine_pre_day0_low_carryover"] = _pre_day0_low_carryover
                    # The empirical residual conditioning expands each model member into a
                    # member x residual-quantile sample space. The original per-model
                    # precision arrays are no longer index-aligned and must not be reused.
                    _spine_precision = []
                _spine_arr = np.asarray(_spine_raw, dtype=float).ravel()
                if _spine_arr.size:
                    _spine_lst = [float(_x) for _x in _spine_arr.tolist()]
                    payload["_edli_spine_raw_members_native"] = _spine_lst
                    payload["_edli_spine_debiased_members_native"] = _spine_lst
                    # RAW PRECISION (FINAL single-live §1-§2): the per-member raw second
                    # moment Ê[(x−Y)²] + n, in the SAME index order as the member list, so
                    # build_fresh_model_set can attach it to each RawModelMember and the
                    # spine's walk_forward_model_weights forms the RAW diagonal 1/E[r²]
                    # weight. None entries (no walk-forward history) stay equal-weighted.
                    if _spine_precision and len(_spine_precision) == len(_spine_lst):
                        payload["_edli_spine_raw_m2_by_index"] = [
                            (None if _m2 is None else float(_m2))
                            for (_mid, _m2, _n, _rr) in _spine_precision
                        ]
                        payload["_edli_spine_n_by_index"] = [
                            int(_n) for (_mid, _m2, _n, _rr) in _spine_precision
                        ]
                        # Option C: index-aligned grid-representativeness variance (native²).
                        payload["_edli_spine_repr_m2_by_index"] = [
                            float(_rr) for (_mid, _m2, _n, _rr) in _spine_precision
                        ]
                    _spine_mean = sum(_spine_lst) / len(_spine_lst)
                    payload["_edli_spine_mu_native"] = float(_spine_mean)
                    if len(_spine_lst) >= 2:
                        _spine_var = sum((_v - _spine_mean) ** 2 for _v in _spine_lst) / (len(_spine_lst) - 1)
                        payload["_edli_spine_sigma_native"] = float(_spine_var ** 0.5)
                    if _spine_source_cycle:
                        payload["_edli_spine_source_cycle_time_utc"] = str(_spine_source_cycle)
            else:
                _pre_day0_low_context, _pre_day0_low_block_reason = _pre_day0_low_carryover_context(
                    family,
                    decision_time,
                )
                if _pre_day0_low_context is not None and _pre_day0_low_block_reason is None:
                    payload["_edli_spine_pre_day0_low_block_reason"] = (
                        "PRE_DAY0_LOW_CARRYOVER_UNAVAILABLE:spine_members_unavailable"
                    )
                elif _pre_day0_low_block_reason is not None:
                    payload["_edli_spine_pre_day0_low_block_reason"] = _pre_day0_low_block_reason
        except Exception as exc:  # noqa: BLE001 — ordinary spine gaps stay typed downstream
            _pre_day0_low_context, _pre_day0_low_block_reason = _pre_day0_low_carryover_context(
                family,
                decision_time,
            )
            if _pre_day0_low_block_reason is not None:
                payload["_edli_spine_pre_day0_low_block_reason"] = _pre_day0_low_block_reason
            elif _pre_day0_low_context is not None:
                payload["_edli_spine_pre_day0_low_block_reason"] = (
                    "PRE_DAY0_LOW_CARRYOVER_UNAVAILABLE:"
                    f"spine_input_population_error:{type(exc).__name__}"
                )
    # === Q-KERNEL REBUILD STAGE 0 — lift the receipt-spine inputs (2026-06-14) ===========
    # READ-ONLY: the q-build (_market_analysis_from_event_snapshot) already stashed the
    # forecast/q spine onto the THREADED payload under payload["_edli_spine_*"]. Lift those
    # values onto provenance_capture here (the same site that captures the belief) so the
    # receipt wrapper can assemble the DecisionReceipt — the threaded payload is the only
    # object that carries them (the wrapper's _payload(event) re-parse does NOT). This copies
    # already-computed values and feeds NOTHING back into the decision. (spec:994-1033.)
    if provenance_capture is not None:
        try:
            _spine_inputs = {
                k: payload.get(k)
                for k in (
                    "_edli_spine_mu_native",
                    "_edli_spine_sigma_native",
                    "_edli_spine_raw_members_native",
                    "_edli_spine_debiased_members_native",
                    "_edli_spine_q_vector",
                    "_edli_spine_source_cycle_time_utc",
                    "_edli_spine_day0_observed_extreme_native",
                    "_edli_spine_pre_day0_low_carryover",
                    "_edli_spine_pre_day0_low_block_reason",
                    "_edli_q_source",
                )
                if k in payload
            }
            if _spine_inputs:
                _spine_inputs["city"] = str(family.city)
                provenance_capture["decision_receipt_spine_inputs"] = _spine_inputs
        except Exception:  # noqa: BLE001 — observability only; never break the decision
            pass
    proofs: list[_CandidateProof] = []
    rows_by_direction = _snapshot_rows_by_condition_and_direction(snapshot_rows)

    # FIX A (direction law; incident 0b5c305e26524042, 2026-06-10 Milan-24C;
    # docs/evidence/2026_06_10_milan_24c_first_fill_rootcause.md): resolve the
    # family forecast center ONCE — fusion provenance (anchor_value_c /
    # bayes_precision_fusion.predictive_sigma_c) when the probability authority carries it,
    # else the q-distribution mean over the family bins (legacy/canonical rows).
    direction_law_mu, direction_law_sigma = _direction_law_family_center(
        family=family,
        q_by_condition=q_by_condition,
        probability_evidence=probability_evidence,
    )
    # Doctrine buy_no half (operator standing law, restored 2026-06-11): the only
    # bin banned for buy_no is the FORECAST BIN — where the canonically-rounded
    # center settles. Rounding is the per-city settlement preimage (#24 K-cut;
    # HKO truncation differs from WMO half-up), resolved ONCE per family here and
    # threaded to every candidate check. None on failure -> the pure module falls
    # back to the contract's WMO half-up default.
    direction_law_mu_settled = _direction_law_mu_settled_for_family(
        family=family, mu=direction_law_mu
    )
    # Single rounding authority for the boundary-zone shifted tests (FIX: the old
    # WMO-delta approximation inside direction_law.py used the wrong rounding family
    # for truncation cities such as HK, potentially banning the wrong runner-up bin
    # or missing the right one). The callable is built ONCE per family here and
    # passed through; it WINS over mu_settled for both the primary and zone tests.
    # Fail-soft None -> pure-module WMO half-up default applies (correct for all
    # non-truncation cities).
    direction_law_settle_value = _direction_law_settle_value_for_family(family=family)
    # K4.0 REST-THEN-CROSS family-level inputs, computed ONCE per family:
    # event-end distance (None -> rest, conservative), and the family rest state
    # from venue truth (open rest -> HOLD antibody; expired-unfilled rest ->
    # escalation license for the deadline cross).
    _rtc_minutes_to_event_end = _minutes_to_family_event_end(family, decision_time)
    _rtc_unexpired_rest, _rtc_escalated = _family_rest_state(
        trade_conn, family=family, decision_time=decision_time
    )
    _day0_proof_maker_only = _is_day0_lane_event_type(getattr(event, "event_type", None))
    # Twin-authority reconciliation #7 (2026-06-11, selected-leg repair 2026-06-30):
    # replacement coverage verdicts are keyed by (condition_id, direction). The
    # selected proof's own leg controls both buy-NO admission and the calibration
    # credential; a family representative verdict would license/block the wrong sibling.
    _coverage_status_by_direction_raw = probability_evidence.get(
        "settlement_coverage_status_by_direction"
    )
    coverage_status_by_direction = (
        _coverage_status_by_direction_raw
        if isinstance(_coverage_status_by_direction_raw, Mapping)
        else {}
    )
    _coverage_verdict_by_direction_raw = probability_evidence.get(
        "settlement_coverage_verdict_by_direction"
    )
    coverage_verdict_by_direction = (
        _coverage_verdict_by_direction_raw
        if isinstance(_coverage_verdict_by_direction_raw, Mapping)
        else {}
    )
    replacement_bundle_for_credential = probability_evidence.get("replacement_bundle")
    replacement_q_mode = str(probability_evidence.get("replacement_q_mode") or "")
    for candidate in family.candidates:
        condition_id = str(candidate.condition_id or "")
        yes_q = q_by_condition.get(condition_id)
        yes_lcb_entry = q_lcb_by_direction.get((condition_id, "buy_yes"))
        no_lcb_entry = q_lcb_by_direction.get((condition_id, "buy_no"))
        if yes_q is None or yes_lcb_entry is None or no_lcb_entry is None:
            raise ValueError(f"missing q_live for condition {condition_id}")
        # K3: q_lcb carrier entries are QlcbProvenance (or bare float on the day0
        # generated path); _qlcb_raw_float reads the RAW (pre-clamp) value so the
        # selection-ranking key (trade_score, q_lcb_5pct) stays byte-identical to
        # legacy when deep-OTM bins carry a legitimately negative bootstrap q_lcb.
        # Clamped vs raw only differs when clamped=True; for in-range bins they are
        # identical. Using raw here restores legacy loser-selection ordering on
        # no-submit receipts (the measurement/telemetry substrate). _qlcb_float
        # (the clamped door) is still used everywhere a value must be in [0,1].
        from src.calibration.qlcb_provenance import _qlcb_raw_float
        yes_lcb = _qlcb_raw_float(yes_lcb_entry)
        no_lcb = _qlcb_raw_float(no_lcb_entry)
        # bin-selection S2 (Hidden #3/#4, §4): the buy_no leg now carries a REAL native-NO
        # belief authority, not the disabled placeholder. The NO point is the per-sample
        # YES complement 1 - yes_q (valid in belief space, §4); the NO q_lcb is no_lcb —
        # the native-NO robust lower bound 1 - q_ucb_yes from the q-construction seam
        # (canonical: _side_q_lcb_from_yes_samples; replacement: _replacement_no_lcb_for_bin).
        # The old ADMISSION_BUY_NO_INDEPENDENT_NO_POSTERIOR_MISSING hardcode (which forced
        # q_no=0 so buy_no never scored) is retired: the native NO authority IS the posterior.
        no_q = float(min(max(1.0 - float(yes_q), 0.0), 1.0))
        for token_id, direction, q_value, q_lcb, independent_no_missing_reason in (
            (str(candidate.yes_token_id or ""), "buy_yes", yes_q, yes_lcb, None),
            (str(candidate.no_token_id or ""), "buy_no", no_q, no_lcb, None),
        ):
            coverage_key = (condition_id, direction)
            _settlement_coverage_status_raw = coverage_status_by_direction.get(coverage_key)
            settlement_coverage_status = (
                str(_settlement_coverage_status_raw)
                if _settlement_coverage_status_raw is not None
                else None
            )
            replacement_calibration_credential = None
            if (
                probability_evidence.get("probability_authority") == "replacement_0_1"
                and replacement_bundle_for_credential is not None
                and replacement_q_mode
            ):
                replacement_calibration_credential = _build_replacement_calibration_credential(
                    replacement_bundle=replacement_bundle_for_credential,
                    q_mode=replacement_q_mode,
                    coverage_verdict=coverage_verdict_by_direction.get(coverage_key),
                    family=family,
                )
            row = rows_by_direction.get((condition_id, direction))
            # bin-selection S2: q_lcb <= q_point is now an UPSTREAM structural guarantee
            # (ProbabilityUncertainty for YES, the 1 - q_ucb_yes complement clamped under
            # 1 - q_yes for NO — both in the q-construction seam). The old here-at-boundary
            # "q_lcb > q_value -> clamp" patch existed only because the edge_ci_lower +
            # cost restore (Hidden #2) could manufacture a lower bound above the point;
            # that restore is gone, so the patch is dead and removed (no redundant gate).
            execution_price: ExecutionPrice | None = None
            c_cost_95pct: float | None = None
            p_fill_lcb = 0.0
            missing_reason: str | None = None
            if independent_no_missing_reason is not None:
                missing_reason = independent_no_missing_reason
            elif not token_id:
                missing_reason = "missing token id"
            elif row is None:
                missing_reason = "missing executable snapshot row"
            else:
                # Price TTL must not shrink the family selector. The selected
                # executable is re-authorized against a JIT book at submit time.
                #
                # SIBLING-ROW COMPLEMENT (2026-06-10 live-v12 fix): for buy_no,
                # the maker-quote lane needs the YES best bid to compute the
                # complementary non-crossing cap.  The NO-outcome snapshot row
                # only carries the NO token's CLOB book (single-token /book
                # response), so book.yes_bids = () on that row.  The YES best bid
                # lives in the sibling YES-outcome row's orderbook_top_bid scalar.
                # We read it here (where both rows are in scope) and pass it down
                # so the maker-quote function can fall back to it when the book's
                # yes_bids side is empty.
                _sibling_complement_bid: float | None = None
                if direction == "buy_no":
                    _yes_row = rows_by_direction.get((condition_id, "buy_yes"))
                    if _yes_row is not None:
                        _sibling_complement_bid = _optional_float(
                            _yes_row.get("orderbook_top_bid")
                        )
                try:
                    execution_price, p_fill_lcb, c_cost_95pct = _execution_price_from_snapshot(
                        row,
                        selected_token_id=token_id,
                        direction=direction,
                        complementary_top_bid=_sibling_complement_bid,
                    )
                except ValueError as exc:
                    missing_reason = str(exc)
            # FIX C (mode-consistent EV; operator directive 2026-06-10): the
            # trade_score is the CHOSEN execution mode's EV, never the hybrid
            # taker-cost x visible-depth-p_fill. TAKER-chosen scores are
            # byte-identical to the legacy kernel (same q_lcb leg, same penalty);
            # MAKER-chosen scores price the resting reality: bid-improving limit,
            # conservative fill prior, adverse-selection half-spread haircut.
            mode_ev = _mode_consistent_ev_for_proof(
                row=row,
                direction=direction,
                q_lcb=q_lcb,
                execution_price=execution_price,
                c_cost_95pct=c_cost_95pct,
                p_fill_lcb=p_fill_lcb,
                minutes_to_event_end=_rtc_minutes_to_event_end,
                unexpired_family_rest=_rtc_unexpired_rest,
                escalated_after_rest=_rtc_escalated,
            )
            if mode_ev is not None:
                if _day0_proof_maker_only:
                    try:
                        maker_ev = float(mode_ev.ev_maker)
                    except (TypeError, ValueError):
                        maker_ev = 0.0
                    score = maker_ev if math.isfinite(maker_ev) else 0.0
                else:
                    score = mode_ev.chosen_ev if math.isfinite(mode_ev.chosen_ev) else 0.0
            else:
                score = _robust_trade_score_from_generated_inputs(
                    q_posterior=q_value,
                    q_lcb_5pct=q_lcb,
                    execution_price=execution_price,
                    c_cost_95pct=c_cost_95pct,
                    p_fill_lcb=p_fill_lcb,
                )
            # REMOVED 2026-06-08 (S4; "bin selection.md" §6/§9 Hidden #3/#10/§13 +
            # operator directive): the scalar market-disagreement buy_no demotion
            # (cheap-NO-overconfidence -> score=0) is GONE. It is SUBSUMED by the
            # marginal-utility ranker: a cheap NO means a low NO all-in cost, and
            # the candidate is scored with its OWN honest robust NO q_lcb
            # (1 - q_ucb_yes). When the market is confident YES (cheap NO) that
            # honest q_lcb_no is low, so q_lcb_no < cost -> negative robust edge ->
            # ΔU <= 0 -> the §13 no-trade gate fires inside the ranker. The cheap-NO
            # loser is UNCONSTRUCTABLE without a separate scalar gate, and where the
            # two differed the ranker is the settlement-correct one (it trades a
            # cheap NO whose HONEST robust q_lcb genuinely covers the cost, instead
            # of hard-blocking everything below a 0.95 cutoff). Antibody:
            # tests/engine/test_s4_subsumed_gates.py::
            # test_cheap_no_overconfidence_loser_is_delta_u_no_trade. Scattered
            # on/off gates ARE the regression disease the directive abolishes.
            capital_efficiency_reason = _capital_efficiency_untradeable_reason(
                execution_price=execution_price,
                q_lcb_5pct=q_lcb,
                trade_score=score,
            )
            if capital_efficiency_reason is not None:
                score = 0.0
                if missing_reason is None:
                    missing_reason = capital_efficiency_reason
            near_settled_reason = live_near_settled_entry_price_rejection_reason(
                execution_price=execution_price.value if execution_price is not None else None,
            )
            if near_settled_reason is not None:
                score = 0.0
                if missing_reason is None:
                    missing_reason = near_settled_reason
            def _lcb_source(value: object) -> str | None:
                source = getattr(value, "calibration_source", None)
                return str(source) if source else None

            q_lcb_source = _lcb_source(no_lcb_entry if direction == "buy_no" else yes_lcb_entry)
            buy_no_conservative_evidence_reason = live_buy_no_conservative_evidence_rejection_reason(
                direction=direction,
                q_direction=q_value,
                q_lcb=q_lcb,
                execution_price=execution_price.value if execution_price is not None else None,
                q_lcb_calibration_source=q_lcb_source,
                same_bin_yes_posterior=yes_q,
                settlement_coverage_status=settlement_coverage_status,
            )
            if buy_no_conservative_evidence_reason is not None:
                score = 0.0
                if missing_reason is None:
                    missing_reason = buy_no_conservative_evidence_reason
            # FIX A — DIRECTION LAW (operator doctrine as code): buy_yes only
            # forecast-adjacent, buy_no only forecast-distant. Deterministic
            # rejection BEFORE ranking/FDR/sizing; the far-tail YES the incident
            # bought is unconstructable, not down-weighted.
            direction_law_reason = _direction_law_reason_for_candidate(
                candidate=candidate,
                direction=direction,
                mu=direction_law_mu,
                predictive_sigma=direction_law_sigma,
                mu_settled=direction_law_mu_settled,
                settle_value=direction_law_settle_value,
            )
            if direction_law_reason is not None:
                score = 0.0
                if missing_reason is None:
                    missing_reason = direction_law_reason
            # TELEMETRY-ONLY — COVERAGE_UNLICENSED_TAIL (pr408 review C1+C2 #2 CRITICAL,
            # 2026-06-14): tail-shape evidence can describe a candidate, but it cannot
            # override the live credential boundary. INSUFFICIENT_DATA now remains
            # provenance/NO_SUBMIT evidence until a sufficiently-sampled calibration
            # license exists; this telemetry still never score-zeros or alters size.
            unlicensed_tail_coverage_telemetry = _coverage_unlicensed_tail_telemetry(
                q_lcb=q_lcb,
                execution_price=execution_price.value if execution_price is not None else None,
                q_lcb_calibration_source=q_lcb_source,
            )
            p_value = generated_p_values[(condition_id, direction)]
            passed_prefilter = bool(generated_prefilter.get((condition_id, direction), execution_price is not None and score > 0.0))
            # A structurally non-tradeable candidate must not enter the FDR family
            # as a "passed" hypothesis. Force prefilter False so it can never be
            # selected. (The S4-removed market-disagreement scalar demotion is no
            # longer one of these triggers — the marginal-utility ranker's §13
            # ΔU<=0 gate subsumes the cheap-NO-overconfidence demotion. The unlicensed-tail
            # concern is telemetry-only now and is deliberately NOT a prefilter trigger.)
            if (
                capital_efficiency_reason is not None
                or near_settled_reason is not None
                or buy_no_conservative_evidence_reason is not None
                or direction_law_reason is not None
            ):
                passed_prefilter = False
            proof_execution_mode_intent = (
                mode_ev.chosen_mode if mode_ev is not None else None
            )
            proof_taker_forbidden_reason = (
                mode_ev.taker_forbidden_reason if mode_ev is not None else None
            )
            proof_rest_then_cross_policy = mode_ev.policy if mode_ev is not None else None
            if _day0_proof_maker_only and mode_ev is not None:
                proof_execution_mode_intent = "MAKER"
                proof_rest_then_cross_policy = _DAY0_MAKER_ONLY_REST_POLICY
                if not proof_taker_forbidden_reason:
                    proof_taker_forbidden_reason = _DAY0_MAKER_ONLY_TAKER_FORBIDDEN_REASON
            proofs.append(
                _CandidateProof(
                    candidate=candidate,
                    token_id=token_id,
                    direction=direction,
                    row=row,
                    executable_snapshot_id=str(row.get("snapshot_id") or "") if row is not None else None,
                    execution_price=execution_price,
                    q_posterior=q_value,
                    q_lcb_5pct=q_lcb,
                    q_lcb_calibration_source=q_lcb_source,
                    c_cost_95pct=c_cost_95pct,
                    p_fill_lcb=p_fill_lcb,
                    trade_score=score,
                    p_value=p_value,
                    passed_prefilter=passed_prefilter,
                    native_quote_available=execution_price is not None,
                    p_cal_vector_hash=str(probability_evidence["p_cal_vector_hash"]),
                    p_live_vector_hash=str(probability_evidence["p_live_vector_hash"]),
                    missing_reason=missing_reason,
                    mainstream_agreement=payload.get(
                        "_mainstream_agreement_verdicts", {}
                    ).get((condition_id, direction)),
                    # #120: calibrator provenance — per-family, set by the
                    # ONE-CALIBRATOR SEAM (era.py:3772 emos / 3774 maze). Same
                    # payload instance (#149 fix), so this is the actual q_source.
                    q_source=payload.get("_edli_q_source"),
                    same_bin_yes_posterior=yes_q,
                    settlement_coverage_status=settlement_coverage_status,
                    replacement_calibration_credential=replacement_calibration_credential,
                    # H2_E2E: carry posterior_id + probability_authority from the
                    # probability evidence dict. Present only on the replacement_0_1
                    # path; None (absent key) on canonical. posterior_id is emitted
                    # as a string by the authority builder — coerce to int for the
                    # typed column / FK to forecast_posteriors(posterior_id).
                    posterior_id=_optional_int(probability_evidence.get("posterior_id")),
                    probability_authority=probability_evidence.get("probability_authority"),
                    # FIX C: the mode decision + BOTH EVs ride the proof to the
                    # receipt (settlement-loop recalibration provenance).
                    execution_mode_intent=proof_execution_mode_intent,
                    ev_taker=(mode_ev.ev_taker if mode_ev is not None else None),
                    ev_maker=(mode_ev.ev_maker if mode_ev is not None else None),
                    maker_limit_price=(mode_ev.maker_limit_price if mode_ev is not None else None),
                    relative_spread_at_eval=(mode_ev.relative_spread if mode_ev is not None else None),
                    taker_forbidden_reason=proof_taker_forbidden_reason,
                    maker_fill_probability=(mode_ev.maker_fill_probability if mode_ev is not None else None),
                    maker_fill_probability_source=(
                        mode_ev.maker_fill_probability_source if mode_ev is not None else None
                    ),
                    # K4.0: the policy verdict + escalation deadline travel with the proof.
                    rest_then_cross_policy=proof_rest_then_cross_policy,
                    rest_escalation_deadline_minutes=(
                        mode_ev.escalation_deadline_minutes if mode_ev is not None else None
                    ),
                    # pr408 #2: telemetry-only unlicensed-tail signal (NEVER gates).
                    unlicensed_tail_coverage_telemetry=unlicensed_tail_coverage_telemetry,
                )
            )
    return tuple(proofs)


def _minutes_to_family_event_end(family, decision_time: datetime) -> float | None:
    """K4.0: minutes from decision_time until the family's event end.

    Event end = end of target_date in the city's local timezone (the settlement
    quantity stops moving at local midnight; the market resolves later, but the
    edge-realization window is the local day). Returns None when the timezone or
    target date is unresolvable — the policy then RESTS (conservative default;
    a None can never open the taker-immediate lane).
    """
    try:
        from zoneinfo import ZoneInfo

        city_config = runtime_cities_by_name().get(str(family.city))
        tz_name = getattr(city_config, "timezone", None) if city_config is not None else None
        if not tz_name:
            return None
        target = date.fromisoformat(str(family.target_date))
        local_end = datetime(
            target.year, target.month, target.day, tzinfo=ZoneInfo(str(tz_name))
        ) + timedelta(days=1)
        delta = local_end.astimezone(UTC) - decision_time.astimezone(UTC)
        return delta.total_seconds() / 60.0
    except Exception:
        return None


def _family_rest_state(
    trade_conn: sqlite3.Connection | None,
    *,
    family,
    decision_time: datetime,
) -> tuple[bool, bool]:
    """K4.0: (unexpired_family_rest, escalated_after_rest) from venue truth.

    Derived from venue_commands + latest venue_order_facts (no new state table —
    provenance lives where the orders live):

    - unexpired_family_rest: ANY open ENTRY order on a family token (latest fact
      LIVE/RESTING/PARTIALLY_MATCHED, or no facts yet with a non-terminal command
      state). While one exists, NO new order may be constructed for the family
      (the operator antibody). Age does not matter here: an over-deadline rest
      still blocks until the escalation job cancels it.
    - escalated_after_rest: a family ENTRY order was cancelled/expired UNFILLED
      after resting >= the escalation deadline, within the last 24h. This is the
      license for the deadline cross (the FULL standard pipeline re-certifies the
      edge; this flag only switches the policy lane).

    Fail-closed direction: on any query error return (False, False) — the policy
    then RESTS by default (never crosses on broken provenance).
    """
    if trade_conn is None:
        return (False, False)
    token_ids = {
        str(tid)
        for candidate in getattr(family, "candidates", ())
        for tid in (getattr(candidate, "yes_token_id", None), getattr(candidate, "no_token_id", None))
        if tid
    }
    if not token_ids:
        return (False, False)
    from src.strategy.live_inference.mode_consistent_ev import (
        MAKER_REST_ESCALATION_DEADLINE_MINUTES,
    )

    # CONVERSION FIX (2026-06-20, lifecycle death-line): the escalation age FLOOR is
    # the maker window AFTER WHICH a cancelled-unfilled rest licenses the deadline
    # cross — NOT the 20-min deadline-job cadence. Live death-line evidence
    # (zeus_trades 06-19/06-20): 60 of 64 terminal-unfilled rests were cancelled at
    # 5-20min by the continuous-redecision SCREEN (CONFIRMED_VALUE_REFRESH @5min,
    # BOOK_MOVED @1 tick) BEFORE the 20-min deadline job could fire; each then
    # re-decided as a fresh REST_DEFAULT (escalated_after_rest=False) and was pulled
    # again -> an infinite rest->pull->re-rest loop, 0 crosses, MATCHED 19->0 by
    # 06-20. The screen's own REST_VALUE_REFRESH_MIN_AGE_SECONDS is the canonical
    # "a real maker window happened" floor (the same evidence the screen requires
    # before a value-refresh pull); arming on it makes a screen-pulled unfilled rest
    # escalation-eligible so the next decision CROSSES (if still admissible) or
    # no-trades — instead of re-posting the identical unfillable rest. This adds NO
    # cap and NO new constant (reuses the screen floor) and NEVER crosses above the
    # conservative q_lcb (FIX B in the policy is unchanged). The first rest for a
    # family (no prior cancelled-unfilled rest) still REST_DEFAULTs (Karachi
    # rest-first antibody intact), and a concurrent LIVE rest still HOLDs via the
    # unexpired_family_rest antibody (single-flight double-submit safety intact).
    from src.events.continuous_redecision import (
        REST_VALUE_REFRESH_MIN_AGE_SECONDS,
    )

    deadline_seconds = float(MAKER_REST_ESCALATION_DEADLINE_MINUTES) * 60.0
    escalation_arm_floor_seconds = min(
        deadline_seconds, float(REST_VALUE_REFRESH_MIN_AGE_SECONDS)
    )
    now = decision_time.astimezone(UTC)
    recent_cutoff = (now - timedelta(hours=24)).isoformat()
    placeholders = ",".join("?" for _ in token_ids)
    from src.state.canonical_projections import is_open_order_fact
    terminal_unfilled_states = ("CANCEL_CONFIRMED", "EXPIRED")
    nonterminal_command_states = ("SUBMITTING", "POSTING", "POST_ACKED", "ACKED", "PARTIAL")
    terminal_command_states = (
        "CANCELLED",
        "CANCELED",
        "EXPIRED",
        "REJECTED",
        "SUBMIT_REJECTED",
        "FILLED",
        "MATCHED",
        "TERMINAL_NOOP",
    )
    try:
        rows = trade_conn.execute(
            f"""
            WITH latest_facts AS (
                SELECT venue_order_id, state, observed_at, matched_size,
                       ROW_NUMBER() OVER (
                           PARTITION BY venue_order_id ORDER BY local_sequence DESC
                       ) AS rn
                FROM venue_order_facts
            )
            SELECT vc.state AS command_state, vc.created_at,
                   lf.state AS fact_state, lf.observed_at, lf.matched_size
            FROM venue_commands vc
            LEFT JOIN latest_facts lf
                   ON lf.venue_order_id = vc.venue_order_id AND lf.rn = 1
            WHERE vc.intent_kind = 'ENTRY'
              AND vc.token_id IN ({placeholders})
              AND vc.created_at >= ?
            """,
            (*sorted(token_ids), recent_cutoff),
        ).fetchall()
    except Exception:
        return (False, False)
    # Normalise the rows ONCE (the per-row reads are identical for both passes).
    parsed_rows = []
    for row in rows:
        command_state = str(row["command_state"] if isinstance(row, sqlite3.Row) else row[0] or "").upper()
        created_at = _parse_utc(row["created_at"] if isinstance(row, sqlite3.Row) else row[1])
        fact_state = row["fact_state"] if isinstance(row, sqlite3.Row) else row[2]
        observed_at = _parse_utc(row["observed_at"] if isinstance(row, sqlite3.Row) else row[3])
        parsed_rows.append(
            (command_state, created_at, str(fact_state or "").upper(), fact_state, observed_at)
        )

    # PASS 1 — escalation arming. A family ENTRY rest cancelled/expired UNFILLED
    # after a real maker window (>= escalation_arm_floor_seconds) LICENSES the
    # deadline cross. `escalation_arm_time` is the LATEST such arming observation
    # (the cancel/expire observed_at): an OPEN rest posted AFTER it is a redundant
    # serial re-rest, not a genuine new first rest (the GAP-4 race).
    #
    # 2026-06-16: REMOVED the `matched <= 0` disqualifier. A rest that took a
    # PARTIAL fill and was then cancelled at the deadline (the escalation job
    # cancels the REMAINDER — maker_rest_escalation.py) must STILL license the
    # cross of the unfilled remainder; disqualifying it forfeited the residual
    # edge (settlement counterfactual: 49 settled day-ahead NO picks, 84% won,
    # +$88 vs $0 captured — the admissible cross is +EV). The re-cert sizes
    # against existing exposure (extra_exposure_by_bin), so the partial position
    # is not double-counted. Fully-filled orders terminate as MATCHED (not in
    # terminal_unfilled_states), so this never re-crosses a completed order.
    escalated = False
    escalation_arm_time: datetime | None = None
    for command_state, created_at, fact_state_s, _fact_state, observed_at in parsed_rows:
        if (
            fact_state_s in terminal_unfilled_states
            and created_at is not None
            and observed_at is not None
            and (observed_at - created_at).total_seconds() >= escalation_arm_floor_seconds
        ):
            escalated = True
            if escalation_arm_time is None or observed_at > escalation_arm_time:
                escalation_arm_time = observed_at

    # PASS 2 — the single-flight antibody (unexpired_rest), with the GAP-4
    # re-rest exemption. An OPEN ENTRY rest (latest fact LIVE/RESTING/
    # PARTIALLY_MATCHED, or acknowledged with no fact yet) normally blocks ANY new
    # family order (operator antibody, double-submit safety). EXCEPTION
    # (2026-06-21 GAP-4 fix): when an escalation is ARMED and this open rest was
    # posted (created_at) STRICTLY AFTER the arming cancellation, it is a
    # redundant SERIAL re-rest (real chain: 2-5 sequential cancelled rests per
    # family) — it must NOT preempt the armed cross. Dropping unexpired_rest for it
    # lets `select_rest_then_cross_mode` reach the TAKER_ESCALATED_AFTER_REST lane
    # (line ~571) instead of being pre-empted by the HOLD antibody (line ~561).
    #
    # FAIL-CLOSED on ambiguity: a genuine live rest that PRE-DATES the arming
    # cancel (created_at <= arm time), or whose created_at is null/unparseable,
    # still sets unexpired_rest=True (HOLD) — never dropped. The double-submit
    # guarantee does not rest on this exemption alone: the executor's own
    # `_entry_duplicate_same_token_component` (src/execution/executor.py) is the
    # authoritative backstop and BLOCKS a cross whenever a same-token ENTRY
    # command is still in an OPEN state (POSTING/ACKED/CANCEL_PENDING/PARTIAL/...);
    # it admits a new entry only once the competing command is CANCELLED/EXPIRED
    # with no fill — and a venue-live order is never in that terminal-no-exposure
    # set (CANCELLED is written only after a venue-confirmed cancel ack). So the
    # cross will frequently still be rejected at submit while the re-rest is truly
    # live, and proceed only once it is genuinely cancelled-unfilled — exactly the
    # safe ordering, with no double-submit window.
    unexpired_rest = False
    for command_state, created_at, fact_state_s, fact_state, _observed_at in parsed_rows:
        if command_state in terminal_command_states:
            continue
        is_open = is_open_order_fact(fact_state_s) or (
            fact_state is None and command_state in nonterminal_command_states
        )
        if not is_open:
            continue
        is_redundant_rerest = (
            escalated
            and escalation_arm_time is not None
            and created_at is not None
            and created_at > escalation_arm_time
        )
        if is_redundant_rerest:
            # Post-escalation serial re-rest: do NOT let it preempt the armed cross.
            continue
        unexpired_rest = True
    return (unexpired_rest, escalated)


def _maker_fill_static_prior() -> tuple[float, str]:
    """The spread-BLIND static resting-fill prior (operator-tunable scalar).

    K4.0 (consolidated overhaul 2026-06-11): the default is the MEASURED
    deadline-horizon fill probability (KM @120min, n=108 right-censored
    resting facts) — the 0.10 GUESS is retired (its provenance was conditioned
    on ~25-minute rests of deep-longshot quotes: the wrong population, Fitz #4).
    Settings override carries its own provenance tag so the receipt records
    WHERE the prior came from.

    This is the FALLBACK for the spread-conditioned calibration below: when the
    spread is unmeasurable, the calibration is disabled, or no realized evidence
    exists, the honest probability degrades to this all-band scalar (exactly the
    pre-2026-06-24 behavior).
    """
    from src.strategy.live_inference.mode_consistent_ev import (
        MAKER_FILL_PROBABILITY_AT_ESCALATION_DEADLINE,
        MAKER_FILL_PROBABILITY_DEADLINE_SOURCE,
    )

    try:
        raw = settings["edli"].get("maker_fill_probability_prior")
    except Exception:
        raw = None
    if raw is None:
        return (
            MAKER_FILL_PROBABILITY_AT_ESCALATION_DEADLINE,
            MAKER_FILL_PROBABILITY_DEADLINE_SOURCE,
        )
    try:
        value = float(raw)
    except (TypeError, ValueError):
        return (
            MAKER_FILL_PROBABILITY_AT_ESCALATION_DEADLINE,
            MAKER_FILL_PROBABILITY_DEADLINE_SOURCE,
        )
    if not (0.0 < value <= 1.0):
        return (
            MAKER_FILL_PROBABILITY_AT_ESCALATION_DEADLINE,
            MAKER_FILL_PROBABILITY_DEADLINE_SOURCE,
        )
    return value, "settings.edli.maker_fill_probability_prior"


def _maker_fill_calibration_enabled() -> bool:
    """Operator toggle for the realized-by-spread maker fill calibration.

    Default ON (edli.maker_fill_spread_calibration_enabled, default True). The
    calibration only TIGHTENS the existing honest EV gate (an un-fillable band gets
    p_fill ~ 0); turning it OFF reverts to the spread-blind static scalar.
    """
    try:
        return bool(settings["edli"].get("maker_fill_spread_calibration_enabled", True))
    except Exception:
        return True


def _maker_fill_calibration_params() -> tuple[float, float]:
    """(window_days, pseudo_count) for the EB Beta-Binomial calibration.

    Operator-tunable; defaults are the module defaults (7-day window, ~24
    pseudo-count). The DEFAULT band rate is MEASURED — never a hand-set number.
    """
    from src.execution.maker_fill_calibration import (
        DEFAULT_PSEUDO_COUNT,
        DEFAULT_WINDOW_DAYS,
    )

    try:
        edli = settings["edli"]
    except Exception:
        edli = {}
    try:
        window = float(edli.get("maker_fill_calibration_window_days", DEFAULT_WINDOW_DAYS))
    except (TypeError, ValueError):
        window = DEFAULT_WINDOW_DAYS
    if not (window > 0.0):
        window = DEFAULT_WINDOW_DAYS
    try:
        kappa = float(edli.get("maker_fill_calibration_pseudo_count", DEFAULT_PSEUDO_COUNT))
    except (TypeError, ValueError):
        kappa = DEFAULT_PSEUDO_COUNT
    if not (kappa > 0.0):
        kappa = DEFAULT_PSEUDO_COUNT
    return window, kappa


# Per-process cache for the realized band-rate rollup. The trade DB is large
# (~59 GB live); re-running the SELECT for every candidate would be wasteful, and
# the realized rate moves on the order of hours, not per cycle. Cache by window for
# a short TTL; fail-safe to the static prior on any error (see caller).
_REALIZED_BAND_TABLE_CACHE: dict[float, tuple[float, object]] = {}
_REALIZED_BAND_TABLE_TTL_SECONDS = 600.0


def _realized_band_table_cached(*, window_days: float):
    """Cached realized-by-spread band-rate rollup (read-only, primary trade DB).

    Opens a short-lived ``mode=ro`` connection to the PRIMARY checkout's
    ``zeus_trades.db`` (the shared live DB; the worktree-local state/ has no live
    facts), computes the per-band rollup, and caches it per window for a short TTL.
    SELECT-only — never writes.
    """
    import time as _time

    now = _time.monotonic()
    cached = _REALIZED_BAND_TABLE_CACHE.get(float(window_days))
    if cached is not None and (now - cached[0]) < _REALIZED_BAND_TABLE_TTL_SECONDS:
        return cached[1]

    import sqlite3 as _sqlite3

    from src.execution.maker_fill_calibration import (
        realized_maker_fill_rate_by_spread_band,
    )
    from src.state.db_paths import primary_trade_db_path

    path = primary_trade_db_path()
    conn = _sqlite3.connect(f"file:{path}?mode=ro", uri=True, timeout=5.0)
    try:
        table = realized_maker_fill_rate_by_spread_band(conn, window_days=window_days)
    finally:
        conn.close()
    _REALIZED_BAND_TABLE_CACHE[float(window_days)] = (now, table)
    return table


def _maker_fill_probability_prior(
    *, rel_spread: float | None = None, limit_price: float | None = None
) -> tuple[float, str]:
    """Spread-conditioned resting-fill prior (the maker EV's p_fill leg).

    Returns ``(p_fill, source_tag)``. When ``rel_spread`` is given and the
    calibration is enabled, the probability is the empirical-Bayes Beta-Binomial
    posterior mean of the REALIZED fill rate in that spread band (sourced from
    venue_order_facts -> venue_commands -> executable_market_snapshots): a band
    with many samples and ~0% realized yields p_fill ~ 0 (so the unchanged
    ``trade_score = EV_maker > 0`` gate REJECTS the un-fillable rest), while a
    well-sampled tight band reflects its own ~24% rate (keeps trading). A sparse
    band shrinks SMOOTHLY toward the global pooled rate (no hard cliff, no ad-hoc
    fallback constant).

    Degrades to the spread-BLIND static scalar (pre-2026-06-24 behavior) when:
    ``rel_spread`` is None, the calibration is disabled, the band is unmeasurable,
    there is no realized evidence yet, or ANY DB error occurs (fail-safe: the
    decision path must never break on a calibration read).

    ``limit_price`` is accepted for forward price-band conditioning (the diagnosis
    also measured a price-band effect) but is not yet used; the spread band is the
    dominant, statistically-legible signal today.
    """
    fallback_prior, fallback_source = _maker_fill_static_prior()
    if rel_spread is None or not _maker_fill_calibration_enabled():
        return fallback_prior, fallback_source

    from src.execution.maker_fill_calibration import maker_fill_probability_for_spread

    window_days, pseudo_count = _maker_fill_calibration_params()
    try:
        table = _realized_band_table_cached(window_days=window_days)
        return maker_fill_probability_for_spread(
            rel_spread,
            conn=None,  # table is supplied; no further DB access
            fallback_prior=fallback_prior,
            fallback_source=fallback_source,
            window_days=window_days,
            pseudo_count=pseudo_count,
            _table=table,
        )
    except Exception:
        # Fail-safe: a cold/locked/missing DB or any read error must NOT break the
        # decision path — fall back to the static all-band prior (prior behavior).
        return fallback_prior, fallback_source


def _taker_max_relative_spread() -> float:
    """Operator-tunable crossing guard (edli.taker_max_relative_spread)."""
    from src.strategy.live_inference.mode_consistent_ev import TAKER_MAX_RELATIVE_SPREAD

    try:
        value = float(settings["edli"].get("taker_max_relative_spread"))
    except Exception:
        return TAKER_MAX_RELATIVE_SPREAD
    if not (0.0 < value <= 2.0):
        return TAKER_MAX_RELATIVE_SPREAD
    return value


def _native_side_top_of_book(row: dict[str, Any], *, direction: str) -> tuple[float | None, float | None, float]:
    """(best_bid, best_ask, tick) for the candidate's OWN native side (S1 row)."""
    book = _native_quote_book_from_snapshot_row(row)
    if direction == "buy_yes":
        asks, bids = book.yes_asks, book.yes_bids
    else:
        asks, bids = book.no_asks, book.no_bids
    best_ask = min((float(level.price) for level in asks), default=None)
    best_bid = max((float(level.price) for level in bids), default=None)
    return best_bid, best_ask, float(book.min_tick_size)


def _mode_consistent_ev_for_proof(
    *,
    row: dict[str, Any] | None,
    direction: str,
    q_lcb: float,
    execution_price: ExecutionPrice | None,
    c_cost_95pct: float | None,
    p_fill_lcb: float,
    # penalty removed 2026-06-14 (RULE 1, trade_score_suppression.md): the flat 0.01
    # was a phantom 2-prob-cent edge floor with NO cost basis — the real fee is already
    # in c_cost_95pct (fee_deducted) and the real tick is enforced separately. It was the
    # dominant live suppressor (Karachi 40C +edge → score −0.00076), harshest exactly
    # where the model disagrees with a cheap market. Honest cost (fee + tick) is preserved.
    penalty: float = 0.0,
    minutes_to_event_end: float | None = None,
    unexpired_family_rest: bool = False,
    escalated_after_rest: bool = False,
):
    """FIX C + K4.0: the per-candidate REST-THEN-CROSS mode decision at the
    evaluation seam (select_rest_then_cross_mode — the one-shot EV comparison
    is retired as the decider; both EVs still travel as provenance).

    Returns None for an unpriced proof (no mode decision exists; the legacy
    quote-missing no-trade path owns it). Penalty mirrors the legacy robust
    kernel's lambda_edge so taker-mode scores stay byte-identical to the
    pre-fix trade_score (same q_lcb leg: c_stress == c_95 and q_lcb <= q_post
    made the legacy min() always pick the q_lcb leg).
    """
    if execution_price is None or row is None or c_cost_95pct is None:
        return None
    from dataclasses import replace as _dataclass_replace

    from src.strategy.live_inference.mode_consistent_ev import (
        TAKER_FORBIDDEN_NO_ASK_EMPTY,
        select_rest_then_cross_mode,
    )

    try:
        best_bid, best_ask, tick = _native_side_top_of_book(row, direction=direction)
    except Exception:
        return None
    # MAKER-QUOTE lane discriminator: a bid-type execution_price is a maker quote
    # produced by _maker_quote_execution_price_from_snapshot (own ask empty/thin).
    # Taker is STRUCTURALLY impossible (no native ask to cross): pass no taker cost
    # so ev_taker is None and the mode can only be MAKER, and label the forbidden
    # reason NO_ASK_EMPTY (not the generic unmeasurable-spread reason). The quote
    # price IS the complementary-bounded reservation; the maker EV reprices it
    # against q_lcb (rejecting a quote the belief does not clear — test (c)).
    _is_maker_quote = str(getattr(execution_price, "price_type", "")) == "bid"
    taker_all_in_cost = None if _is_maker_quote else c_cost_95pct
    # Spread-conditioned maker fill prior (live work): relative spread from the in-scope native
    # top-of-book feeds the EB-shrunk realized-by-spread-band fill rate (0%-band -> p_fill~0 ->
    # EV_maker~0 -> rejected at the unchanged trade_score gate).
    from src.strategy.live_inference.mode_consistent_ev import (
        relative_spread as _relative_spread,
    )

    _rel_spread = _relative_spread(best_bid, best_ask)
    p_fill_maker, p_fill_maker_source = _maker_fill_probability_prior(
        rel_spread=_rel_spread, limit_price=float(execution_price.value)
    )
    # P0-1 (2026-06-23): PROOF-SIDE mode decision ALSO uses the execution-conditioned selection-curse
    # bound so proof_mode/rest_then_cross_policy is MAKER/no-cross for a side whose settlement-
    # evidenced realized rate cannot support the cross. Absent/unarmed -> identity (== q_lcb).
    q_exec_lcb_value, _ = _event_bound_q_exec_lcb(
        direction=direction, price=best_ask, q_decision_lcb=float(q_lcb)
    )
    mode_ev = select_rest_then_cross_mode(
        q_lcb=q_lcb,
        q_exec_lcb=q_exec_lcb_value,
        taker_all_in_cost=taker_all_in_cost,
        p_fill_taker=p_fill_lcb,
        best_bid=best_bid,
        best_ask=best_ask,
        tick_size=tick,
        reservation=float(execution_price.value),
        minutes_to_event_end=minutes_to_event_end,
        unexpired_family_rest=unexpired_family_rest,
        escalated_after_rest=escalated_after_rest,
        p_fill_maker=p_fill_maker,
        p_fill_maker_source=p_fill_maker_source,
        max_relative_spread=_taker_max_relative_spread(),
        penalty=penalty,
    )
    if _is_maker_quote:
        mode_ev = _dataclass_replace(
            mode_ev, taker_forbidden_reason=TAKER_FORBIDDEN_NO_ASK_EMPTY
        )
    return mode_ev


def _direction_law_family_center(
    *,
    family,
    q_by_condition: Mapping[str, float],
    probability_evidence: Mapping[str, object],
) -> tuple[float | None, float | None]:
    """Resolve (mu, predictive_sigma) in the family's bin unit for the direction law.

    FIX A (2026-06-10 Milan-24C incident). Provenance order (Fitz #4):
      1. The probability authority's fused posterior center —
         ``probability_evidence["forecast_mu_c"]`` (anchor_value_c, °C) with
         ``forecast_predictive_sigma_c`` (bayes_precision_fusion predictive sigma, °C),
         converted into the bin unit.
      2. Legacy rows without fusion: the q-distribution mean over the family bins
         (computed natively in the bin unit; open-ended bins contribute their
         single bound). Sigma is None — the law then uses the strictly
         conservative 1-settlement-step threshold.

    Returns (None, None) when no center is resolvable (mixed-unit families, no
    bins, zero q mass) — the law module fail-closes buy_yes on a missing center.
    """
    from src.strategy.live_inference.direction_law import (
        celsius_delta_to_unit,
        celsius_to_unit,
    )

    units = {
        str(candidate.bin.unit)
        for candidate in family.candidates
        if getattr(candidate, "bin", None) is not None
    }
    if len(units) != 1:
        return (None, None)
    unit = next(iter(units))
    mu_c = _optional_float(probability_evidence.get("forecast_mu_c"))
    if mu_c is not None:
        sigma_c = _optional_float(probability_evidence.get("forecast_predictive_sigma_c"))
        return (
            celsius_to_unit(mu_c, unit),
            None if sigma_c is None else celsius_delta_to_unit(sigma_c, unit),
        )
    total = 0.0
    acc = 0.0
    for candidate in family.candidates:
        bin_obj = getattr(candidate, "bin", None)
        if bin_obj is None:
            continue
        q = _optional_float(q_by_condition.get(str(candidate.condition_id or "")))
        if q is None or q <= 0.0:
            continue
        low = bin_obj.low
        high = bin_obj.high
        if low is not None and high is not None:
            center = (float(low) + float(high)) / 2.0
        elif low is not None:
            center = float(low)
        elif high is not None:
            center = float(high)
        else:
            continue
        total += q
        acc += q * center
    if total <= 0.0:
        return (None, None)
    return (acc / total, None)


def _direction_law_reason_for_candidate(
    *,
    candidate,
    direction: str,
    mu: float | None,
    predictive_sigma: float | None,
    mu_settled: float | None = None,
    settle_value: "Callable[[float], float] | None" = None,
) -> str | None:
    """Per-candidate direction-law verdict (FIX A). None = admissible.

    A candidate with no bin object cannot be measured against the center; it is
    structurally untradeable on this path anyway (bin-binding gates), so the law
    abstains rather than inventing a distance.

    ``settle_value``, when provided, is the per-city rounding callable (from
    ``_direction_law_settle_value_for_family``).  It is the single rounding
    authority for BOTH the primary forecast-bin test and the boundary-zone shifted
    tests inside ``direction_law_rejection_reason``.  When absent, the law module
    falls back to ``mu_settled`` (scalar) then the WMO half-up default.
    """
    from src.strategy.live_inference.direction_law import direction_law_rejection_reason

    bin_obj = getattr(candidate, "bin", None)
    if bin_obj is None:
        return None
    return direction_law_rejection_reason(
        direction=direction,
        bin_low=bin_obj.low,
        bin_high=bin_obj.high,
        bin_unit=str(bin_obj.unit),
        mu=mu,
        predictive_sigma=predictive_sigma,
        mu_settled=mu_settled,
        settle_value=settle_value,
    )


def _direction_law_mu_settled_for_family(*, family, mu: float | None) -> float | None:
    """Canonical per-city settlement rounding of the family center, in bin unit.

    The per-city preimage contract (#24 K-cut; SettlementSemantics.for_city) owns
    the rounding rule — WMO half-up for standard cities, HKO/UMA truncation for
    Hong Kong, etc. ``mu`` arrives ALREADY converted to the family bin unit by
    ``_direction_law_family_center``, and a city's settlement measurement_unit is
    that same bin unit, so the rounding is applied directly. Fail-soft None: the
    pure direction-law module then falls back to the contract's WMO half-up
    default (correct for every non-truncation city).

    Kept for backward compat; callers that already pass ``settle_value`` from
    ``_direction_law_settle_value_for_family`` need not call this separately —
    the callable produced there subsumes this scalar lookup.
    """
    if mu is None:
        return None
    try:
        from src.contracts.settlement_semantics import SettlementSemantics

        city_obj = runtime_cities_by_name().get(family.city)
        if city_obj is None:
            return None
        semantics = SettlementSemantics.for_city(city_obj)
        return float(semantics.round_values([float(mu)])[0])
    except Exception:  # noqa: BLE001 — fail-soft; pure-module WMO default applies
        return None


def _direction_law_settle_value_for_family(*, family) -> "Callable[[float], float] | None":
    """Build the per-city rounding callable for the direction-law boundary-zone test.

    Returns a callable ``settle_value(v: float) -> float`` backed by
    ``SettlementSemantics.for_city(city).round_values([v])[0]`` — the single
    authority for this city's preimage rounding (WMO half-up, HKO truncation,
    etc.).  When the city object is not available or construction fails, returns
    None; the direction-law module then falls back to its WMO half-up default
    (correct for all non-truncation cities, a known gap for truncation cities).

    This callable is the fix for the boundary-zone approximation bug: the old
    path used a WMO-delta shift even for truncation cities, which could ban the
    wrong runner-up bin or miss the right one.  Passing ``settle_value`` to
    ``direction_law_rejection_reason`` closes the gap by applying the city's
    actual rounding rule directly to each shifted point.
    """
    try:
        from src.contracts.settlement_semantics import SettlementSemantics

        city_obj = runtime_cities_by_name().get(family.city)
        if city_obj is None:
            return None
        semantics = SettlementSemantics.for_city(city_obj)
        return lambda v: float(semantics.round_values([v])[0])
    except Exception:  # noqa: BLE001 — fail-soft; WMO default applies
        return None


def _per_bin_yes_q_lcb(
    proofs: tuple[_CandidateProof, ...],
) -> dict[str, float]:
    """Robust YES q_lcb for each bin in the family (spec §14.7 / §3 π_y^rob).

    The :func:`utility_ranker.robust_probabilities` outcome vector ``π_y^rob`` is
    built from each bin's ROBUST YES lower bound ``q_lcb_yes_i`` (NOT q_point —
    Hidden #2). A ``buy_yes`` proof carries that value directly in its
    ``q_lcb_5pct`` (YES probability space); a ``buy_no`` proof's ``q_lcb_5pct`` is
    NO-space (``1 - q_ucb_yes``) and must NOT be read as a YES q_lcb — so the map
    is sourced ONLY from YES proofs. A bin with no YES proof is absent from the
    map; ``robust_probabilities`` then assigns it ``q_lcb=0`` win-mass (the
    outcome still exists, so NO candidates still win on it — Hidden #5), which is
    the conservative treatment.

    Keyed by the same ``_candidate_bin_id`` the materialized NativeSideCandidate
    uses, so the per-bin q_lcb and the candidates share one bin index.
    """
    by_bin: dict[str, float] = {}
    for proof in proofs:
        if str(getattr(proof, "direction", None) or "") != "buy_yes":
            continue
        bin_id = _candidate_bin_id(proof)
        q_lcb = float(min(max(float(proof.q_lcb_5pct), 0.0), 1.0))
        # If multiple YES proofs map to the same bin (should not happen on the
        # real path), keep the most conservative (lowest) robust lower bound.
        prior = by_bin.get(bin_id)
        by_bin[bin_id] = q_lcb if prior is None else min(prior, q_lcb)
    return by_bin


def _robust_marginal_utility_baseline_usd() -> Decimal:
    """Flat per-outcome wealth baseline ``A_y`` for the ΔU optimizer (spec §3).

    The marginal log utility ``ΔU = Σ_y π_y [log(A_y + R_y) − log(A_y)]`` needs a
    positive wealth-by-outcome baseline. The baseline is the runtime bankroll when
    it is cheaply available; otherwise a positive constant (the optimum stake
    FRACTION is invariant to the baseline scale under a FLAT baseline, so this only
    sets the ΔU units, never the ranking). Existing per-outcome exposure is layered
    ON TOP of this baseline by :func:`_robust_marginal_utility_exposure` (S4 / §11
    Phase 4), which is what makes existing exposure shrink ΔU (Hidden #10).
    """
    try:
        bankroll = _runtime_bankroll_usd(cached_only=True)
    except (TypeError, ValueError):
        bankroll = 0.0
    if bankroll and bankroll > 0.0:
        return Decimal(str(bankroll))
    return Decimal("1000")


def _robust_marginal_utility_exposure(
    matrix: "utility_ranker.FamilyPayoffMatrix",
    *,
    baseline_usd: Decimal,
    extra_exposure_by_bin_id: Mapping[str, float] | None = None,
) -> "utility_ranker.PortfolioExposureVector":
    """Per-outcome wealth ``A_y`` = flat baseline + EXISTING family exposure (S4, §11 Phase 4).

    The ΔU objective measures the marginal log utility of a NEW leg against the
    wealth the book WOULD hold if Y settled each outcome, given everything ALREADY
    on/pending in this family. ``extra_exposure_by_bin_id[bin_id]`` is the extra
    wealth realized if Y settles that bin (e.g. an existing/pending long on that
    bin's YES). Because log is concave, a new candidate that wins where ``A_y`` is
    already large has LOWER marginal value — so existing exposure shrinks the
    optimal stake or forces a no-trade (spec §6 "too correlated with existing
    exposure"; §11 Phase 4 acceptance; Hidden #10). With NO existing exposure this
    is exactly :meth:`PortfolioExposureVector.flat` (the conservative single-primary
    baseline), so an empty mapping reproduces the prior behavior byte-for-byte.

    Exposure is keyed by the SAME ``_candidate_bin_id`` the candidates use, so an
    existing-position bin and a new candidate on that bin share one outcome index.
    An exposure key that is not a family outcome is ignored (the outcome set is the
    family the ranker is scoring; foreign-family exposure does not enter THIS
    family's payoff geometry).
    """
    extra = {
        bin_id: Decimal(str(usd))
        for bin_id, usd in (extra_exposure_by_bin_id or {}).items()
        if bin_id in matrix.outcomes and float(usd) > 0.0
    }
    if not extra:
        return utility_ranker.PortfolioExposureVector.flat(
            matrix, baseline=baseline_usd
        )
    return utility_ranker.PortfolioExposureVector.from_outcome_wealth(
        matrix, baseline=baseline_usd, extra_by_outcome=extra
    )


def _score_family_candidates_by_robust_marginal_utility(
    *,
    executable: list[_CandidateProof],
    family_key: str,
    per_bin_yes_q_lcb: Mapping[str, float],
    extra_exposure_by_bin_id: Mapping[str, float] | None = None,
    max_stake_usd: Decimal | None = None,
    baseline_usd: Decimal | None = None,
) -> tuple[
    list["utility_ranker.RobustCandidateScore"],
    dict[str, _CandidateProof],
]:
    """Materialize + ΔU-score the family's executable proofs (spec §6 / §14.7).

    The ONE scoring kernel both the live selection (:func:`_select_proof_by_robust_
    marginal_utility`) and the exposure-aware sizing (:func:`_robust_marginal_
    utility_optimal_stake_usd`) share, so the rank and the size are computed on the
    SAME FamilyPayoffMatrix (bins + OUTSIDE, Hidden #5), the SAME robust YES-q_lcb
    π, and the SAME exposure vector — they cannot drift. Returns the ΔU-descending
    scores and a hypothesis_id -> proof index for mapping a winning candidate back
    to its proof.
    """
    candidate_by_proof: list[tuple[NativeSideCandidate, _CandidateProof]] = [
        (
            _native_side_candidate_from_proof(family_key=family_key, proof=proof),
            proof,
        )
        for proof in executable
    ]
    proof_by_hypothesis: dict[str, _CandidateProof] = {
        cand.hypothesis_id: proof for cand, proof in candidate_by_proof
    }
    tradeable = [cand for cand, _ in candidate_by_proof if cand.is_tradeable]
    if not tradeable:
        return [], proof_by_hypothesis

    bin_ids = list(dict.fromkeys(cand.bin_id for cand in tradeable))
    matrix = utility_ranker.FamilyPayoffMatrix.over_bins(bin_ids)
    pi = utility_ranker.robust_probabilities(
        matrix,
        per_bin_q_lcb={
            bin_id: float(per_bin_yes_q_lcb.get(bin_id, 0.0)) for bin_id in bin_ids
        },
    )
    exposure = _robust_marginal_utility_exposure(
        matrix,
        baseline_usd=(
            baseline_usd
            if baseline_usd is not None
            else _robust_marginal_utility_baseline_usd()
        ),
        extra_exposure_by_bin_id=extra_exposure_by_bin_id,
    )
    scored = utility_ranker.rank_candidates(
        tradeable, matrix, pi, exposure, max_stake_usd=max_stake_usd
    )
    return scored, proof_by_hypothesis


def _select_proof_by_robust_marginal_utility(
    *,
    executable: list[_CandidateProof],
    family_key: str,
    per_bin_yes_q_lcb: Mapping[str, float],
    extra_exposure_by_bin_id: Mapping[str, float] | None = None,
) -> _CandidateProof | None:
    """THE single live selection decision (spec §6 / §14.7 / §13).

    Materialize each executable proof as its unified ``NativeSideCandidate`` (the
    ONE materialization path, :func:`_native_side_candidate_from_proof`), build
    the family payoff matrix over every bin PLUS the OUTSIDE outcome (Hidden #5),
    and pick the candidate that maximizes robust marginal expected LOG utility
    ``ΔU`` (:func:`utility_ranker.rank_candidates`). The §13 no-trade gate
    ("robust marginal expected log utility <= 0") fires HERE, on the live path:
    if no candidate has positive ΔU the family no-trades (returns ``None``).

    This REPLACES the legacy scalar-Kelly ranking surfaces
    (``build_family_opportunity_book`` -> ``select_best_family_candidate`` and the
    ``max(executable, key=(trade_score, q_lcb_5pct))`` fallback). There is exactly
    ONE ranking surface now — the bin-selection §7 ranker — so the materialized
    candidate is no longer discarded; it IS the decision (operator directive
    2026-06-08; spec §14.8 single-primary-live).

    Native-NO conservatism (Hidden #3) and the OUTSIDE outcome (Hidden #5) are
    enforced inside the ranker: a NO candidate is scored with its OWN robust NO
    ``q_lcb = 1 - q_ucb_yes`` (its ``candidate.q_lcb``), never the looser
    ``1 - q_lcb_yes`` implied by the shared YES π.

    EXISTING EXPOSURE (S4 / §11 Phase 4 / Hidden #10): ``extra_exposure_by_bin_id``
    layers current/pending family exposure onto the per-outcome wealth baseline, so
    a candidate that wins where the book is already heavily committed scores LOWER
    ΔU (concavity of log) — can flip to no-trade. With no existing exposure (empty
    mapping) this is the conservative flat-baseline single-primary objective.
    """
    scored, proof_by_hypothesis = _score_family_candidates_by_robust_marginal_utility(
        executable=executable,
        family_key=family_key,
        per_bin_yes_q_lcb=per_bin_yes_q_lcb,
        extra_exposure_by_bin_id=extra_exposure_by_bin_id,
    )
    for score in scored:
        # §13 live no-trade gate: skip any non-positive-ΔU candidate. rank_candidates
        # sorts ΔU-descending, so the first positive-ΔU score is the family primary.
        if score.is_no_trade:
            continue
        return proof_by_hypothesis.get(score.candidate.hypothesis_id)
    # Every candidate's robust marginal expected log utility was <= 0 -> no-trade.
    return None


def _chosen_stake_execution_price(
    curve: "ExecutableCostCurve", stake_usd: Decimal | float
) -> ExecutionPrice:
    """Typed Kelly cost-of-entry at the CHOSEN stake (spec §5.3 / §14.10 / Hidden #6).

    S5 (operator directive 2026-06-08). THE boundary recomputation: given the
    selected candidate's OWN native :class:`ExecutableCostCurve` and the ΔU
    optimizer's chosen stake, return the DEPTH-WALKED average all-in cost AT THAT
    STAKE as a typed :class:`ExecutionPrice`. This is the price the live order is
    actually sized against — NOT the cheap min-order / top-of-book scalar the proof
    was first priced at (S1's ``avg_cost_for_shares(min_order_size)``).

    WHY (Hidden #6 — "scalar VWMP hides the convex cost curve"). Scalar Kelly on a
    single top-ask price over-bets into thin levels: the order's true fill cost is
    the convex depth walk, which on a thin book is strictly worse than the top ask.
    The §5.3 optimizer already chose the stake against that convex curve; the Kelly
    boundary the intent carries MUST be the same curve evaluated at the same stake,
    or the realized cost-of-entry (and therefore the executor's limit price and the
    receipt's ``c_fee_adjusted``) would understate cost and the size+price would be
    internally inconsistent.

    The returned ``ExecutionPrice`` is ``fee_adjusted`` / ``fee_deducted=True`` in
    ``probability_units`` (``ExecutableCostCurve.avg_cost`` guarantees this), so it
    passes :meth:`ExecutionPrice.assert_kelly_safe` (R1/R2 identity preserved); we
    assert it here so a corrupt boundary fails closed at this seam rather than
    laundering an unsafe price into the intent.

    Raises ``ValueError`` (fail closed, spec §13) when the stake is below min order
    or above executable depth — but the ΔU optimizer's feasible interval is exactly
    ``[min_order_notional, depth]`` and the fractional haircut only shrinks the
    stake, so on the live path a positive chosen stake is always fillable.
    """
    price = curve.avg_cost(Decimal(str(stake_usd)))
    price.assert_kelly_safe()
    return price


class _StakeBelowMinOrder(RuntimeError):
    """The fractional-Kelly chosen stake fell below the venue min order and could NOT
    be bumped to min order within the bankroll cap.

    This is a SIZING/venue-floor abort, NOT an edge reversal. Raised by the sizing
    kernel (:func:`_robust_marginal_utility_stake_and_price`) and caught in the submit
    decision body, where it becomes a distinct ``SUBMIT_ABORTED_BELOW_MIN_ORDER``
    decision. Never conflated with the zero-stake EDGE_REVERSED gate (antibody for the
    2026-06-09 false-EDGE_REVERSED regression: a positive-edge candidate whose
    post-haircut stake was below min order was being mislabeled "no edge").
    """


# Wave-1 2026-06-12: the _Day0CapExhausted / _Day0CapBelowMinOrder exception classes
# are DELETED with the day0 family notional cap (operator no-caps law).


# FINDING-E (external review 2026-06-12, NO-CAPS operator law): the former
# _MIN_ORDER_BUMP_MAX_BANKROLL_PCT = 0.02 percentage cap on the auto-bump-to-min-order
# action is DELETED. It refused any positive-EV candidate whose venue minimum exceeded
# 2% of the wallet — an artificial throttle producing no-order states that are not honest
# gates. The bump-to-venue-minimum admission is now the HONEST economics only: positive
# q_lcb edge at the venue minimum AND the minimum fitting the free-cash bound (see
# _robust_marginal_utility_stake_and_price). No percentage cap.


def _robust_marginal_utility_stake_and_price(
    *,
    family_key: str,
    selected_proof: _CandidateProof,
    all_proofs: tuple[_CandidateProof, ...] | list[_CandidateProof],
    extra_exposure_by_bin_id: Mapping[str, float] | None,
    bankroll_usd: float,
    kelly_multiplier: float,
    stake_floor_out: dict[str, object] | None = None,
    free_cash_usd: float | None = None,
) -> tuple[float, ExecutionPrice | None]:
    """Chosen FRACTIONAL-Kelly stake AND its typed chosen-stake price (spec §5.3 / §14.10).

    S5 (operator directive 2026-06-08, updated 2026-06-10). THE single sizing+pricing
    kernel for the live intent.

    FAMILY TOTAL (operator single-Kelly directive 2026-06-10, spec point 1):
    ``family_total = bankroll_usd × kelly_multiplier × f*_binary`` where
    ``f*_binary = (q_lcb − cost) / (1 − cost)`` is the binary Kelly fraction
    derived from the selected candidate's certified side-consistent q_lcb and
    all-in execution cost. Fractional Kelly is applied EXACTLY ONCE at this
    step. The ΔU optimizer (:meth:`utility_ranker.score_candidate`) provides the
    SHAPE of allocation across simultaneous legs in a multi-bin family; for
    single-leg selection (the live default) the shape weight = 1.0 and
    ``stake = family_total`` exactly.

    The prior law used ``score.optimal_stake_usd × kelly_multiplier`` as the
    stake. ``optimal_stake_usd`` is the ΔU argmax on the full family payoff
    matrix, which depends on matrix geometry and existing exposure — in certain
    live configurations this can be 5–10× below the binary-Kelly total, silently
    applying the ΔU log-concavity risk-aversion on top of the explicit fractional
    haircut (the L3 attenuation in /tmp/kelly_stack_audit.md). The fix pins the
    TOTAL to the certified binary f* and uses ΔU only for the within-family
    distribution shape.

    Then — the S5 boundary — it RE-PRICES the selected leg at that CHOSEN stake on
    the SAME scored candidate's native :class:`ExecutableCostCurve`
    (:func:`_chosen_stake_execution_price`). Size and price come from ONE scored
    candidate and ONE curve, so the Kelly boundary the intent carries is the
    depth-walked cost the order actually pays (Hidden #6), not S1's cheap min-order
    scalar. There is no second scalar Kelly and no alternate branch.

    ROBUST-LOWER-BOUND SIZING (money-path iron law): the stake derives from
    ``q_lcb`` (via the q_lcb-based π inside ``score_candidate``), NEVER from
    ``q_point``. Two proofs with equal q_lcb but different q_posterior size
    identically — the legacy ``evaluate_kelly`` (sized on ``p_posterior =
    q_posterior``) is no longer the size authority.

    Returns ``(stake_usd, chosen_stake_execution_price)``. ``(0.0, None)`` when no
    positive-ΔU stake clears min order / depth (a no-trade) or the boundary cannot
    be priced. The selected proof is scored within the WHOLE family so the π /
    exposure / OUTSIDE geometry matches the ranking decision exactly.

    MIN-ORDER FLOOR (2026-06-09 false-EDGE_REVERSED fix; FINDING-E 2026-06-12 NO-CAPS).
    When the fractional-Kelly haircut shrinks the chosen stake below the venue min-order
    notional but the ROBUST q_lcb ΔU at min order is strictly positive AND the venue
    minimum fits the FREE-CASH bound, the stake is BUMPED to min order and the floor is
    recorded in ``stake_floor_out`` (if provided) as ``stake_floor="VENUE_MIN_ORDER"``.
    The prior 2% bankroll percentage cap on this bump is DELETED (artificial throttle,
    operator no-caps law). When the bump is not admissible (q_lcb EV non-positive at the
    venue minimum, or the minimum exceeds the free-cash bound) it raises
    :class:`_StakeBelowMinOrder` — a DISTINCT sizing abort the decision body maps to
    ``SUBMIT_ABORTED_BELOW_MIN_ORDER``, never EDGE_REVERSED. A genuinely
    reversed candidate (no positive-ΔU stake at ANY admissible size incl. min order)
    still returns ``(0.0, None)`` -> EDGE_REVERSED.

    ``stake_floor_out`` (optional): a caller-owned dict the kernel writes the stake-floor
    provenance into on a bump. Left unset by callers that don't need provenance (the
    behavior is otherwise identical), so existing 2-tuple call sites are unaffected.

    FREE-CASH ONE-TIME BOUND (operator single-Kelly directive 2026-06-10, spec point 2).
    ``bankroll_usd`` is now the TOTAL portfolio equity basis (free cash + open position
    equity) so the fractional-Kelly stake scales off ~1000 USD, not the ~241 USD free-cash
    floor (the prior ``spendable_cash`` basis silently triple-counted the cash constraint
    as a multiplicative shrink). Free available cash is applied SEPARATELY as a FINAL
    ``min(...)`` BOUND on the chosen stake — a one-time clamp, never another multiplicative
    haircut. When the equity-scaled stake exceeds free cash, the stake is clamped to free
    cash and the provenance ``stake_floor="FREE_CASH_BOUND"`` is recorded in
    ``stake_floor_out`` (loud, never silent). ``free_cash_usd=None`` (the default / legacy
    call sites) disables the bound so existing behavior is byte-identical until the live
    decision body threads the free-cash value. The bound is applied to the chosen stake
    BEFORE the min-order admissibility check, so a cash-bounded stake that lands below the
    venue min order still routes through the existing BELOW_MIN_ORDER / bump logic.
    """
    if bankroll_usd <= 0.0 or selected_proof.execution_price is None:
        return 0.0, None
    mult = float(kelly_multiplier)
    if not (mult > 0.0):
        return 0.0, None

    per_bin_yes_q_lcb = _per_bin_yes_q_lcb(tuple(all_proofs))
    selected_hypothesis_id = _candidate_evaluation_id(selected_proof)

    # Score the WHOLE family (so π / exposure / OUTSIDE match the ranking), then
    # read the selected leg's full-Kelly optimum. The feasible stake ceiling is the
    # SMALLER of two pure UPPER BOUNDS on the chosen stake (the ONE clamp, applied at
    # the single ``min(...)`` choke point below — NOT a second, parallel cap):
    #
    #   1. the FRACTIONAL-Kelly budget ``mult × bankroll`` — the ΔU optimizer never
    #      bets above the fractional-Kelly cap, which is how the variance haircut
    #      bounds the size; AND
    #   2. the SINGLE-POSITION CONCENTRATION CEILING ``max_single_position_pct ×
    #      bankroll`` (operator concentration law, restored to the LIVE bin-selection
    #      sizing path). Without this the S5 ``optimal_stake_usd`` path bypassed the
    #      concentration ceiling that ``money_path_adapters.evaluate_kelly`` restored:
    #      the live decision body OVERRIDES ``evaluate_kelly.size_usd`` with this
    #      function's q_lcb-grounded ΔU stake (event_reactor_adapter ~L2095), so the
    #      ceiling living only inside ``evaluate_kelly`` protected nothing live — a
    #      strong-edge candidate sized at ~10% of a $1k wallet at the live
    #      kelly_multiplier=0.125 (and 83% at full Kelly). The ceiling is reconciled
    #      HERE, at the single live sizing choke point.
    #
    # Both are #107-safe UPPER bounds (``min`` on an already-positive ΔU stake can
    # never zero a positive edge — both bounds are pct·bankroll > 0 whenever the
    # wallet has cash): they clamp only the strong-edge TAIL; weak/modest edges sit
    # below both and keep their full ΔU-proportional stake. The base is the SIZING
    # bankroll (``bankroll_usd`` = total portfolio equity; see _runtime_bankroll_usd /
    # _bankroll_sizing_basis_and_free_cash), which scales the ceiling with wealth ($50 at $1k, $500 at $10k)
    # — a structural concentration limit, not a fixed-dollar clamp. It bounds the
    # STAKE MAGNITUDE only: the ΔU RANK (which side/bin is primary) is decided by
    # _select_proof_by_robust_marginal_utility BEFORE this sizing call, so clamping
    # the winner's stake cannot change which candidate is the winner (ranking
    # invariance). ``max_single_position_pct == 0`` disables the ceiling (only the
    # fractional-Kelly cap binds), matching the no-concentration-cap directive surface.
    from src.config import sizing_defaults

    _single_pos_pct = float(sizing_defaults()["max_single_position_pct"])
    _fractional_cap = Decimal(str(mult)) * Decimal(str(bankroll_usd))
    if _single_pos_pct > 0.0:
        _concentration_ceiling = Decimal(str(_single_pos_pct)) * Decimal(
            str(bankroll_usd)
        )
        max_stake = min(_fractional_cap, _concentration_ceiling)
    else:
        max_stake = _fractional_cap
    # Wave-1 2026-06-12: the DAY0 EXPOSURE CAP kernel bound is DELETED (operator no-caps
    # law). max_stake is governed by the fractional-Kelly budget + concentration ceiling +
    # free-cash bound ONLY — no day0-specific notional clamp.
    qkernel_cert = _qkernel_execution_economics(selected_proof)
    if qkernel_cert is None and _proof_uses_qkernel_spine(selected_proof):
        # qkernel-spine proofs deliberately preserve q_posterior/q_lcb_5pct as
        # receipt provenance. They are not execution-sizing authority. If the
        # guarded qkernel execution certificate is missing or malformed, fail closed
        # instead of falling through to the legacy scorer that would size from those
        # preserved proof fields.
        return 0.0, None
    if qkernel_cert is not None:
        qkernel_q_lcb = _qkernel_execution_q_lcb(selected_proof)
        qkernel_cost = _qkernel_execution_float(selected_proof, "cost")
        qkernel_edge = _qkernel_execution_float(selected_proof, "edge_lcb")
        qkernel_optimal_delta_u = _qkernel_execution_float(
            selected_proof, "optimal_delta_u"
        )
        qkernel_delta_u_at_min = _qkernel_execution_float(
            selected_proof, "delta_u_at_min"
        )
        try:
            qkernel_optimal_stake = Decimal(
                str(qkernel_cert.get("optimal_stake_usd"))
            )
        except (ArithmeticError, TypeError, ValueError):
            qkernel_optimal_stake = Decimal("0")
        # Gate the stake on the same validated qkernel execution certificate the
        # qkernel family optimizer selected. The preserved proof q_lcb_5pct is
        # receipt probability provenance, not a second submit-time authority.
        qkernel_submit_edge = (
            None
            if (qkernel_q_lcb is None or qkernel_cost is None)
            else float(qkernel_q_lcb) - float(qkernel_cost)
        )
        if (
            qkernel_q_lcb is None
            or qkernel_cost is None
            or qkernel_edge is None
            or qkernel_optimal_delta_u is None
            or qkernel_delta_u_at_min is None
            or qkernel_edge <= 0.0
            or qkernel_optimal_delta_u <= 0.0
            or qkernel_optimal_stake <= Decimal("0")
            or qkernel_submit_edge is None
            or qkernel_submit_edge <= 0.0
        ):
            return 0.0, None

        selected_candidate = _native_side_candidate_from_proof(
            family_key=family_key, proof=selected_proof
        )
        if (
            not selected_candidate.is_tradeable
            or selected_candidate.executable_cost_curve is None
        ):
            return 0.0, None

        chosen = min(qkernel_optimal_stake, max_stake)
        if chosen <= Decimal("0"):
            return 0.0, None

        if free_cash_usd is not None and float(free_cash_usd) >= 0.0:
            _free_cash = Decimal(str(free_cash_usd))
            if chosen > _free_cash:
                chosen = _free_cash
                if stake_floor_out is not None:
                    stake_floor_out["stake_floor"] = "FREE_CASH_BOUND"
                    stake_floor_out["stake_floor_free_cash_usd"] = float(_free_cash)
                if chosen <= Decimal("0"):
                    return 0.0, None

        try:
            min_order_price = selected_candidate.executable_cost_curve.avg_cost_for_shares(
                selected_candidate.executable_cost_curve.min_order_size
            )
            min_order_usd = (
                Decimal(str(min_order_price.value))
                * selected_candidate.executable_cost_curve.min_order_size
            )
        except (ArithmeticError, TypeError, ValueError, ExecutionPriceContractError):
            return 0.0, None
        if min_order_usd > Decimal("0") and chosen < min_order_usd:
            _ev_positive_at_min = float(qkernel_delta_u_at_min) > 0.0
            _fits_free_cash = (
                free_cash_usd is None
                or min_order_usd <= Decimal(str(free_cash_usd))
            )
            if _ev_positive_at_min and _fits_free_cash:
                chosen = min_order_usd
                if stake_floor_out is not None:
                    stake_floor_out["stake_floor"] = "VENUE_MIN_ORDER"
                    stake_floor_out["stake_floor_min_order_usd"] = float(min_order_usd)
                    stake_floor_out["stake_floor_delta_u_at_min_order"] = float(
                        qkernel_delta_u_at_min
                    )
            else:
                _why = (
                    "ev_non_positive_at_venue_minimum"
                    if not _ev_positive_at_min
                    else "venue_minimum_exceeds_free_cash_bound"
                )
                _free_cash_str = (
                    f"{float(free_cash_usd):.6f}" if free_cash_usd is not None else "None"
                )
                raise _StakeBelowMinOrder(
                    f"chosen stake {float(chosen):.6f} USD below venue min order "
                    f"{float(min_order_usd):.6f} USD; reason={_why}; "
                    f"delta_u_at_min_order={float(qkernel_delta_u_at_min):.6g}, "
                    f"free_cash_usd={_free_cash_str} "
                    "(qkernel guarded execution economics; NOT an edge reversal)"
                )

        try:
            price = _chosen_stake_execution_price(
                selected_candidate.executable_cost_curve,
                chosen,
            )
        except ValueError as exc:
            if "min_order_size" in str(exc) or "below" in str(exc):
                raise _StakeBelowMinOrder(
                    f"qkernel chosen-stake pricing rejected below min order: {exc}"
                ) from exc
            return 0.0, None
        except (ArithmeticError, ExecutionPriceContractError):
            return 0.0, None
        if stake_floor_out is not None:
            stake_floor_out["qkernel_execution_economics"] = {
                "payoff_q_lcb": float(qkernel_q_lcb),
                "payoff_q_point": float(_qkernel_execution_q_point(selected_proof) or 0.0),
                "submit_edge": float(qkernel_submit_edge),
                "edge_lcb": float(qkernel_edge),
                "optimal_stake_usd": float(qkernel_optimal_stake),
                "optimal_delta_u": float(qkernel_optimal_delta_u),
                "route_id": qkernel_cert.get("route_id"),
                "candidate_id": qkernel_cert.get("candidate_id"),
                "guard_basis": qkernel_cert.get("q_lcb_guard_basis"),
                "guard_cell_key": qkernel_cert.get("q_lcb_guard_cell_key"),
            }
        return float(chosen), price

    scored, proof_by_hypothesis = _score_family_candidates_by_robust_marginal_utility(
        executable=list(all_proofs),
        family_key=family_key,
        per_bin_yes_q_lcb=per_bin_yes_q_lcb,
        extra_exposure_by_bin_id=extra_exposure_by_bin_id,
        baseline_usd=Decimal(str(bankroll_usd)),
    )
    for score in scored:
        if _candidate_evaluation_id(
            proof_by_hypothesis.get(score.candidate.hypothesis_id, selected_proof)
        ) != selected_hypothesis_id:
            continue
        if score.is_no_trade:
            return 0.0, None

        # FAMILY TOTAL via binary Kelly (operator single-Kelly directive 2026-06-10,
        # spec point 1): the ΔU family optimizer provides the SHAPE of allocation
        # across simultaneous legs; the FAMILY TOTAL = bankroll × mult × f*_binary.
        # f*_binary = (q_lcb − cost) / (1 − cost) derived from the selected candidate's
        # certified side-consistent q_lcb and all-in execution cost.
        #
        # Before this fix the kernel used ``score.optimal_stake_usd * mult`` where
        # optimal_stake_usd is the ΔU argmax on the full family payoff matrix. That
        # argmax depends on the matrix geometry and existing exposure: in certain live
        # configurations (e.g. families with existing correlated exposure, or specific
        # probability distributions across 22+ bins) the ΔU argmax can be 5–10× lower
        # than the binary-Kelly total, silently re-applying risk-aversion on top of the
        # explicit fractional-Kelly haircut (the L3 attenuation documented in
        # /tmp/kelly_stack_audit.md). The fix pins the TOTAL to the certified f* and
        # uses the ΔU ratio only to distribute shape across simultaneous bins.
        #
        # ΔU SHAPE (multi-leg distribution): when multiple legs from the same family are
        # simultaneously traded, each leg's stake = family_total × (leg_du / sum_du).
        # For single-leg selection (the live default: ONE candidate per family decision),
        # shape_weight = 1.0 exactly, so stake = family_total directly.
        # execution_price is guaranteed non-None (the guard at line 6719 returned early
        # if selected_proof.execution_price is None). score.candidate.q_lcb is non-None
        # for any tradeable candidate (NativeSideCandidate.__post_init__ enforces it).
        _cost = float(selected_proof.execution_price.value)
        _q_lcb_sel = float(score.candidate.q_lcb)  # type: ignore[arg-type]
        f_star = (_q_lcb_sel - _cost) / (1.0 - _cost)
        if f_star <= 0.0:
            # q_lcb ≤ cost: no positive edge.
            return 0.0, None
        # ΔU shape weight = 1.0 for single-leg selection (the live default).
        family_total = bankroll_usd * mult * f_star
        fractional = family_total
        chosen = Decimal(str(min(Decimal(str(fractional)), max_stake)))
        if chosen <= Decimal("0"):
            return 0.0, None

        # FREE-CASH ONE-TIME BOUND (operator single-Kelly directive 2026-06-10, spec
        # point 2). ``bankroll_usd`` (= equity basis) scaled the fractional-Kelly stake
        # above; free available CASH now bounds it ONCE via min(...), never as another
        # multiplicative haircut. A bet cannot spend more than the wallet's free BUY
        # collateral. When the equity-scaled stake exceeds free cash, clamp to free cash
        # and record the provenance loudly (so the receipt shows the stake equals the cash
        # bound, not a silent shrink). ``free_cash_usd=None`` (legacy / proof-only callers)
        # disables the bound. Applied BEFORE the min-order admissibility check so a
        # cash-bounded stake below the venue floor still routes through the bump /
        # BELOW_MIN_ORDER logic unchanged.
        if free_cash_usd is not None and float(free_cash_usd) >= 0.0:
            _free_cash = Decimal(str(free_cash_usd))
            if chosen > _free_cash:
                chosen = _free_cash
                if stake_floor_out is not None:
                    stake_floor_out["stake_floor"] = "FREE_CASH_BOUND"
                    stake_floor_out["stake_floor_free_cash_usd"] = float(_free_cash)
                if chosen <= Decimal("0"):
                    return 0.0, None

        # MIN-ORDER-AWARE STAKE FLOOR (2026-06-09 false-EDGE_REVERSED fix). The ΔU
        # optimizer sizes ``optimal_stake_usd`` on the full bankroll; the fractional-
        # Kelly haircut (×mult, e.g. 0.125) then shrinks the chosen stake. For cheap
        # low-probability bins the haircut stake can fall BELOW the venue min-order
        # notional even though the ROBUST (q_lcb-based) edge at min order is strictly
        # positive. Previously ``_chosen_stake_execution_price`` raised "below min
        # order" and the generic except mapped it to (0.0, None) -> a FALSE EDGE_REVERSED.
        #
        # FINDING-E FIX (external review 2026-06-12, NO-CAPS operator law). The prior
        # admission test ALSO required ``min_order_usd <= 2% × bankroll`` — an ARTIFICIAL
        # percentage cap that produced no-order states for any positive-EV candidate whose
        # venue minimum happened to exceed 2% of the wallet. That is exactly the kind of
        # artificial throttle the operator law forbids (caps are not honest gates). The
        # 2% cap is DELETED. The admission is now the HONEST economics only:
        #   (1) the robust q_lcb-based edge at the venue minimum is strictly positive
        #       (ΔU(min_order) > 0 — the SAME robust π/exposure the ranker used), AND
        #   (2) the venue minimum fits the FREE-CASH bound (it does not spend more than
        #       the wallet's free BUY collateral; no bound when free cash is unknown).
        # If both hold, trade the venue minimum. Otherwise raise ``_StakeBelowMinOrder``
        # with the HONEST economic reason (EV non-positive at the venue minimum, or the
        # cash bound) -> DISTINCT SUBMIT_ABORTED_BELOW_MIN_ORDER, never EDGE_REVERSED and
        # never an artificial-cap reject.
        min_order_usd = Decimal(str(score.min_order_notional_usd))
        if min_order_usd > Decimal("0") and chosen < min_order_usd:
            delta_u_at_min = float(score.delta_u_at_min_order)
            _ev_positive_at_min = delta_u_at_min > 0.0
            _fits_free_cash = (
                free_cash_usd is None
                or min_order_usd <= Decimal(str(free_cash_usd))
            )
            if _ev_positive_at_min and _fits_free_cash:
                # Edge is genuinely positive at the venue minimum and the minimum fits the
                # free-cash bound -> trade at the venue minimum (no percentage cap).
                chosen = min_order_usd
                if stake_floor_out is not None:
                    stake_floor_out["stake_floor"] = "VENUE_MIN_ORDER"
                    stake_floor_out["stake_floor_min_order_usd"] = float(min_order_usd)
                    stake_floor_out["stake_floor_delta_u_at_min_order"] = delta_u_at_min
            else:
                # Honest economic rejection: either the q_lcb edge is non-positive at the
                # venue minimum, or the venue minimum exceeds the free-cash bound. NOT an
                # edge reversal and NOT an artificial cap.
                _why = (
                    "ev_non_positive_at_venue_minimum"
                    if not _ev_positive_at_min
                    else "venue_minimum_exceeds_free_cash_bound"
                )
                _free_cash_str = (
                    f"{float(free_cash_usd):.6f}" if free_cash_usd is not None else "None"
                )
                raise _StakeBelowMinOrder(
                    f"chosen stake {float(chosen):.6f} USD below venue min order "
                    f"{float(min_order_usd):.6f} USD; reason={_why}; "
                    f"delta_u_at_min_order={delta_u_at_min:.6g}, "
                    f"free_cash_usd={_free_cash_str} "
                    f"(honest economic block at venue minimum; NOT an edge reversal)"
                )

        # S5 boundary: reprice the SELECTED leg at the CHOSEN stake on its OWN curve
        # (the depth-walked avg cost — Hidden #6), as the typed Kelly cost-of-entry.
        curve = score.candidate.executable_cost_curve
        if curve is None:
            return float(chosen), None
        try:
            price = _chosen_stake_execution_price(curve, chosen)
        except ValueError as exc:
            # NARROWED except (2026-06-09): a "below min order" ValueError must NOT be
            # conflated with arithmetic/contract faults. After the bump above the chosen
            # stake is >= min order on the live path, so a below-min ValueError here is a
            # genuine venue-floor block -> route to the distinct BELOW_MIN_ORDER abort.
            # Any OTHER ValueError (depth exhaustion / off-grid) keeps the original
            # fail-closed behavior (0.0 -> EDGE_REVERSED), unchanged.
            if "min_order_size" in str(exc) or "below" in str(exc):
                raise _StakeBelowMinOrder(
                    f"chosen-stake pricing rejected below min order: {exc}"
                ) from exc
            return 0.0, None
        except (ArithmeticError, ExecutionPriceContractError):
            # Arithmetic/contract fault on the boundary -> no priced stake (fail closed,
            # §13). Genuinely unexpected; keep the conservative no-trade behavior.
            return 0.0, None
        # Wave-1 2026-06-12: the DAY0 cap invariant assertion is DELETED with the cap.
        return float(chosen), price
    return 0.0, None


# The ONE submit-recapture state machine. Module-level singleton (the engine is a
# pure, stateless, frozen dataclass — no DB, no clock, no mutable state), so the
# recapture boundary always routes through the SAME RedecisionEngine. Default
# HysteresisPolicy: the inline submit gate aborts-and-defers on a family-rank
# reversal (it never switches inline, §5 AbortOrSwitchOnlyAfterFullRerank), so the
# η_switch / T_no_churn anti-churn policy is exercised only by the WATCH re-rank
# path, not by this gate.
_SUBMIT_RECAPTURE_ENGINE = RedecisionEngine()


# Map the engine's submit-abort lifecycle state to the no-submit receipt reason the
# decision body emits. The single source of truth for the abort-reason taxonomy —
# the receipt reason is DERIVED from the state machine's terminal state, never set
# independently (so the receipt and the lifecycle state can never disagree, §7/§14.9).
_SUBMIT_ABORT_RECEIPT_REASON: dict[CandidateLifecycleState, str] = {
    CandidateLifecycleState.SUBMIT_ABORTED_PRICE_MOVED: "SUBMIT_ABORTED_PRICE_MOVED",
    CandidateLifecycleState.SUBMIT_ABORTED_EDGE_REVERSED: "SUBMIT_ABORTED_EDGE_REVERSED",
    CandidateLifecycleState.SUBMIT_ABORTED_FAMILY_REVERSED: "SUBMIT_ABORTED_FAMILY_REVERSED",
    CandidateLifecycleState.SUBMIT_ABORTED_BELOW_MIN_ORDER: "SUBMIT_ABORTED_BELOW_MIN_ORDER",
    # PR#404 P0-1 — first-class day0 exposure-cap aborts (operator-named reasons).
    CandidateLifecycleState.SUBMIT_ABORTED_DAY0_CAP_EXHAUSTED: "DAY0_EXPOSURE_CAP_EXHAUSTED",
    CandidateLifecycleState.SUBMIT_ABORTED_DAY0_CAP_BELOW_MIN_ORDER: "DAY0_EXPOSURE_CAP_BELOW_MIN_ORDER",
    # P0 mode-authority (operator review 2026-06-10) — the FINAL command builder's proven
    # maker/taker mode is no longer executable on the fresh book (or is missing,
    # fail-closed). Distinct from FAMILY_REVERSED / PRICE_MOVED / EDGE_REVERSED: this is
    # the order-TYPE proof going stale. The submit aborts and defers to a full re-rank.
    CandidateLifecycleState.SUBMIT_ABORTED_MODE_FLIPPED: "SUBMIT_ABORTED_MODE_FLIPPED",
}


def _family_rank_reversed_at_recapture(
    *,
    family_key: str,
    selected_proof: _CandidateProof,
    all_proofs: tuple[_CandidateProof, ...] | list[_CandidateProof],
    locked_opportunity_conn: sqlite3.Connection | None = None,
    held_position_conn: sqlite3.Connection | None = None,
    allow_same_family_monitor_owned: bool = False,
    extra_exposure_by_bin_id: Mapping[str, float] | None = None,
) -> bool:
    """True iff the FRESH-curve re-rank no longer makes ``selected_proof`` primary.

    S6 (spec §5 submit pseudocode ``family_rank_reversed`` / §7 family-rank row /
    Hidden #7). The submit recapture must RECOMPUTE — not just validate — the family
    rank on the recaptured books: re-run the SAME single ΔU selection
    (:func:`_select_proof_by_robust_marginal_utility`, the one ranking surface) over
    the fresh-curve candidates and ask whether a DIFFERENT candidate is now the family
    primary. If a sibling now out-ranks the selected proof (price/forecast moved the
    order), the rank reversed and the inline submit must ABORT and defer to a full
    re-rank (the engine never switches inline; a WATCH fallback cannot auto-submit,
    Hidden #7).

    ``True`` ONLY when a DIFFERENT proof is the fresh ΔU primary. ``False`` when the
    selected proof is still the winner OR when the WHOLE family now no-trades (the
    fresh primary is None): a family-wide no-trade is NOT a rank *reversal* — for the
    selected leg it is its own edge reversal (utility <= 0), which the EDGE gate owns.
    Conflating the two would mislabel a plain edge collapse as a family switch.
    """
    if _proof_uses_qkernel_spine(selected_proof):
        scoped = _selection_scoped_proofs(
            proofs=tuple(all_proofs),
            locked_opportunity_conn=locked_opportunity_conn,
            held_position_conn=held_position_conn,
            allow_same_family_monitor_owned=allow_same_family_monitor_owned,
            enforce_win_rate_floor=False,
        )
        ranked: list[tuple[tuple[float, float, float, float, float, float], _CandidateProof]] = []
        for proof in scoped:
            key = _qkernel_recapture_rank_key(proof)
            if key is not None:
                ranked.append((key, proof))
        if not ranked:
            return False
        fresh_primary = max(ranked, key=lambda item: item[0])[1]
        return _candidate_evaluation_id(fresh_primary) != _candidate_evaluation_id(
            selected_proof
        )

    # S6 SCOPE-SET INVARIANT (2026-06-09): the fresh-curve re-rank MUST be computed over
    # the SAME scoped candidate set SELECTION ranked over — `_selection_scoped_proofs`
    # (limit-tradeable AND unlocked-with-price-improvement only), with `per_bin_yes_q_lcb`
    # over the full set, EXACTLY as `_selected_candidate_proof` (era:6219/6233/6254). Ranking
    # the raw full set let a SCOPED-OUT leg (locked-no-improvement / below-min-tick) — which
    # still materializes is_tradeable — become the ΔU argmax and FALSELY reverse the
    # genuinely-best selected leg (SUBMIT_ABORTED_FAMILY_REVERSED). Mirroring selection's
    # scope is STRICTER, never looser: a scoped-out leg can never be the family primary.
    per_bin_yes_q_lcb = _per_bin_yes_q_lcb(tuple(all_proofs))
    scoped = _selection_scoped_proofs(
        proofs=tuple(all_proofs),
        locked_opportunity_conn=locked_opportunity_conn,
        held_position_conn=held_position_conn,
        allow_same_family_monitor_owned=allow_same_family_monitor_owned,
    )
    if not scoped:
        # Nothing survives selection scoping on the fresh set (all locked / untradeable):
        # selection itself would no-trade — handled by the selected leg's own EDGE gate,
        # not a family-rank *reversal*.
        return False
    fresh_primary = _select_proof_by_robust_marginal_utility(
        executable=list(scoped),
        family_key=family_key,
        per_bin_yes_q_lcb=per_bin_yes_q_lcb,
        extra_exposure_by_bin_id=extra_exposure_by_bin_id,
    )
    if fresh_primary is None:
        # Whole family no-trades on the fresh curves -> not a rank reversal; the
        # selected leg's own EDGE gate handles its nonpositive utility.
        return False
    return _candidate_evaluation_id(fresh_primary) != _candidate_evaluation_id(
        selected_proof
    )


def _evaluate_submit_recapture_for_selected(
    *,
    family_key: str,
    selected_proof: _CandidateProof,
    all_proofs: tuple[_CandidateProof, ...] | list[_CandidateProof],
    extra_exposure_by_bin_id: Mapping[str, float] | None,
    bankroll_usd: float,
    kelly_multiplier: float,
    forecast_still_current: bool,
    locked_opportunity_conn: sqlite3.Connection | None = None,
    held_position_conn: sqlite3.Connection | None = None,
    allow_same_family_monitor_owned: bool = False,
    stake_floor_out: dict[str, object] | None = None,
    order_rests_at_admitted_price: bool = False,
    free_cash_usd: float | None = None,
) -> tuple[SubmitRecaptureDecision, float, ExecutionPrice | None]:
    """THE single fail-closed submit-recapture gate (spec §5 / §7 / §14.9 / §14.10).

    S6 (operator directive 2026-06-08). RECOMPUTE-NOT-VALIDATE at the no-submit
    receipt boundary. This REPLACES the scattered inline submit-time re-gates (the
    ``trade_score <= 0`` / Kelly-not-passed checks that implicitly decided whether the
    recaptured leg could submit) with ONE pass through
    :meth:`RedecisionEngine.evaluate_submit_recapture`. There is no parallel branch
    and no flag: the receipt is built ONLY when ``decision.may_submit`` is True.

    What it recomputes (not validates) on the FRESH books:

      * the selected leg's OWN fresh ``ExecutableCostCurve`` — materialized via the
        ONE candidate path (:func:`_native_side_candidate_from_proof`); the engine
        walks it for the depth-walked all-in cost at the chosen stake (Hidden #6);
      * the chosen FRACTIONAL-Kelly stake + chosen-stake price on that curve (the S5
        kernel :func:`_robust_marginal_utility_stake_and_price`);
      * the family rank (:func:`_family_rank_reversed_at_recapture`) — does the
        selected proof remain the ΔU primary on the fresh curves?
      * the robust q_lcb (the candidate's OWN ``q_lcb`` — NO-side already in NO-space
        as ``1 - q_ucb_yes``; never the YES complement).

    Abort taxonomy (each a first-class fail-closed state, §7), in precedence order:

      1. no fresh curve (stale / failed recapture) -> the engine's missing-recapture
         branch, SUBMIT_ABORTED_PRICE_MOVED (no executable price re-established, §13);
      2. family rank reversed (selected leg no longer the ΔU primary on fresh curves)
         -> FAMILY_REVERSED (abort + defer to full re-rank; a non-primary leg never
         price/edge-checks — Hidden #7 / §5 AbortOrSwitchOnlyAfterFullRerank);
      3. stake <= 0 (no positive-utility stake at ANY admissible size INCLUDING min
         order on the fresh curve) -> EDGE_REVERSED (utility nonpositive, §5 ``if
         utility <= 0: Abort``);
      3b. the fractional-Kelly haircut stake is below the venue min order and the venue
         minimum is not honestly tradeable (q_lcb EV non-positive at the minimum, or the
         minimum exceeds the free-cash bound) -> BELOW_MIN_ORDER (a DISTINCT sizing abort,
         NOT an edge reversal — 2026-06-09 antibody; FINDING-E 2026-06-12 deleted the 2%
         bankroll percentage cap that previously gated this bump; the regret ledger
         records the true cause);
      4. recaptured all-in cost > ``max_acceptable_price`` -> PRICE_MOVED;
      5. ``edge_lcb = q_lcb - all_in_cost <= 0`` or forecast not current -> EDGE_REVERSED.

    Gates 4-5 are resolved by the engine (price -> edge -> forecast). Family rank is
    checked here at top precedence so a no-longer-primary leg reports the governing
    reason, not an incidental own-leg edge/price softening.

    ``max_acceptable_price`` is the leg's DECISION-TIME admitted price (the proof's S1
    ``execution_price.value``): a fresh recapture that prices STRICTLY WORSE than the
    price the candidate was admitted at is a price move through the band (§7 price row).

    Returns ``(decision, chosen_stake_usd, chosen_stake_price)``. On a clean recapture
    the stake/price are the S5 chosen-stake size+boundary the intent must carry; on any
    abort the stake is 0.0 / price is None and the decision's ``state`` is in
    :data:`SUBMIT_ABORT_STATES` with the triggering ``reversal_reason``.
    """
    engine = _SUBMIT_RECAPTURE_ENGINE
    candidate = _native_side_candidate_from_proof(
        family_key=family_key, proof=selected_proof
    )

    # GATE 1 (stale / failed recapture, §13). A no-trade materialization (missing
    # native token / quote / invalid q_lcb) means there is NO fresh executable curve
    # to recapture -> route to the engine's missing-recapture branch by passing
    # recaptured_cost_curve=None (SUBMIT_ABORTED_PRICE_MOVED: no executable price could
    # be re-established; "Snapshot stale and recapture fails"). Never submit from the
    # decision-time snapshot. This is checked FIRST: a missing curve cannot price, rank,
    # or edge-check.
    if not candidate.is_tradeable:
        decision = engine.evaluate_submit_recapture(
            candidate,
            RecaptureInputs(
                recaptured_cost_curve=None,
                stake_usd=Decimal("0"),
                max_acceptable_price=Decimal("0"),
                recaptured_q_lcb=0.0,
                forecast_still_current=bool(forecast_still_current),
                family_rank_reversed=False,
            ),
        )
        reason = getattr(candidate, "no_trade_reason", None)
        if reason is not None:
            decision = dataclass_replace(
                decision,
                detail=(
                    "recapture selected candidate not tradeable: "
                    f"{getattr(reason, 'value', str(reason))}; "
                    "no executable cost curve; fail closed"
                ),
            )
        return decision, 0.0, None
    fresh_curve = candidate.executable_cost_curve

    # GATE 2 (family rank reversed, §5 AbortOrSwitchOnlyAfterFullRerank / §7 family-rank
    # row / Hidden #7). HIGHEST-PRECEDENCE present-curve abort: if the selected proof is
    # no longer the family ΔU primary on the FRESH curves, it has lost submit authority
    # — it must NOT even price/edge-check, and a sibling that now out-ranks it is a
    # WATCH-only fallback that can only submit via a FULL re-rank (never inline). Checked
    # BEFORE the zero-stake/edge gates so a no-longer-primary leg reports the governing
    # reason (family reversed), not an incidental own-leg edge softening.
    if _family_rank_reversed_at_recapture(
        family_key=family_key,
        selected_proof=selected_proof,
        all_proofs=all_proofs,
        locked_opportunity_conn=locked_opportunity_conn,
        held_position_conn=held_position_conn,
        allow_same_family_monitor_owned=allow_same_family_monitor_owned,
        extra_exposure_by_bin_id=extra_exposure_by_bin_id,
    ):
        return (
            SubmitRecaptureDecision(
                state=CandidateLifecycleState.SUBMIT_ABORTED_FAMILY_REVERSED,
                may_submit=False,
                reversal_reason=ReversalReason.FAMILY_RANK,
                detail=(
                    "family rank reversed at recapture: selected leg is no longer the "
                    "ΔU primary on the fresh curves; abort and defer to a full re-rank "
                    "(no inline switch; a WATCH fallback cannot auto-submit, Hidden #7)"
                ),
            ),
            0.0,
            None,
        )

    # Recompute the chosen fractional-Kelly stake + chosen-stake price on the FRESH
    # curve (the S5 kernel — same scored candidate, same curve, no drift). The kernel
    # raises _StakeBelowMinOrder (a DISTINCT sizing abort) when the haircut stake is
    # below the venue min order AND cannot be bumped within the bankroll cap — that is
    # NOT an edge reversal and must NOT be folded into the zero-stake EDGE gate below.
    try:
        chosen_stake_usd, chosen_price = _robust_marginal_utility_stake_and_price(
            family_key=family_key,
            selected_proof=selected_proof,
            all_proofs=all_proofs,
            extra_exposure_by_bin_id=extra_exposure_by_bin_id,
            bankroll_usd=bankroll_usd,
            kelly_multiplier=kelly_multiplier,
            stake_floor_out=stake_floor_out,
            free_cash_usd=free_cash_usd,
        )
    # Wave-1 2026-06-12: the DAY0 cap-exhausted / cap-below-min-order except handlers are
    # DELETED with the cap (the sizing kernel no longer raises those).
    except _StakeBelowMinOrder as exc:
        # GATE 3b (BELOW_MIN_ORDER, 2026-06-09 antibody). Edge is positive at min order
        # but the sized stake could not clear the venue floor within the bankroll cap.
        # A DISTINCT first-class abort so the regret ledger records the true cause —
        # EDGE_REVERSED keeps meaning "no edge at ANY admissible stake".
        return (
            SubmitRecaptureDecision(
                state=CandidateLifecycleState.SUBMIT_ABORTED_BELOW_MIN_ORDER,
                may_submit=False,
                reversal_reason=ReversalReason.MIN_ORDER,
                detail=(
                    f"recaptured edge positive at min order but fractional-Kelly stake "
                    f"below venue min order and not bump-admissible within the bankroll "
                    f"cap: {exc}"
                ),
            ),
            0.0,
            None,
        )

    # GATE 3 (edge reversed, §5 'utility <= 0: Abort' / §7 edge row). A zero chosen
    # stake on a PRESENT fresh curve is an edge reversal: the recompute found no
    # positive-utility stake at ANY admissible size including min order (q_lcb fell,
    # cost rose, or exposure concavity killed it). NOTE: a below-min-order-but-positive
    # edge case is handled by GATE 3b above (distinct BELOW_MIN_ORDER), so reaching here
    # with stake 0 genuinely means no positive-ΔU stake exists. Surface as EDGE_REVERSED
    # directly — feeding stake_usd=0 to the engine would make avg_cost(0) raise (below
    # min order) and mis-map to PRICE_MOVED.
    if chosen_stake_usd <= 0.0:
        return (
            SubmitRecaptureDecision(
                state=CandidateLifecycleState.SUBMIT_ABORTED_EDGE_REVERSED,
                may_submit=False,
                reversal_reason=ReversalReason.EDGE,
                detail=(
                    "recaptured robust marginal utility nonpositive: no positive-ΔU "
                    "stake clears min order / depth on the fresh curve (§5 'utility "
                    "<= 0: Abort'; §7 edge row)"
                ),
            ),
            0.0,
            None,
        )

    # GATE 4 + 5 (price moved / edge<=0 / forecast stale). The decision-time admitted
    # price is the band ceiling: a fresh recapture pricing strictly worse than what the
    # candidate was admitted at is a price move (§7 price row). family_rank_reversed is
    # False here (gate 2 already passed), so the engine resolves the remaining price /
    # edge / forecast-currency gates.
    decision_time_price = selected_proof.execution_price
    max_acceptable_price = (
        Decimal(str(decision_time_price.value))
        if decision_time_price is not None
        else Decimal("0")
    )
    decision = engine.evaluate_submit_recapture(
        candidate,
        RecaptureInputs(
            recaptured_cost_curve=fresh_curve,
            stake_usd=Decimal(str(chosen_stake_usd)),
            max_acceptable_price=max_acceptable_price,
            recaptured_q_lcb=float(candidate.q_lcb),
            forecast_still_current=bool(forecast_still_current),
            family_rank_reversed=False,
            # MAKER (resting GTC/GTD limit at the admitted price) skips the PRICE_MOVED
            # ceiling: the order rests, never chases the recaptured ask. TAKER (FOK/FAK)
            # crosses and pays the recaptured cost, so the bounded slippage tolerance
            # governs the ceiling. Fail-closed False (taker ceiling) when the mode is
            # not supplied.
            order_rests_at_admitted_price=bool(order_rests_at_admitted_price),
        ),
    )
    if decision.may_submit:
        return decision, float(chosen_stake_usd), chosen_price
    return decision, 0.0, None


def _robust_marginal_utility_optimal_stake_usd(
    *,
    family_key: str,
    selected_proof: _CandidateProof,
    all_proofs: tuple[_CandidateProof, ...] | list[_CandidateProof],
    extra_exposure_by_bin_id: Mapping[str, float] | None,
    bankroll_usd: float,
    kelly_multiplier: float,
) -> float:
    """Exposure-aware FRACTIONAL-Kelly stake for the selected leg (spec §3 / §5.2 / §5.3).

    Thin wrapper over :func:`_robust_marginal_utility_stake_and_price` that returns
    only the stake (USD). The size authority for the live intent (S4): the ΔU
    optimizer's ``optimal_stake_usd`` on the candidate's OWN robust q_lcb-based π,
    scaled by the fractional-Kelly haircut. ``0.0`` when no positive-ΔU stake clears
    min order / depth (a no-trade). See the kernel for the full derivation; the live
    decision body uses the kernel directly so it also gets the chosen-stake price.
    """
    stake_usd, _price = _robust_marginal_utility_stake_and_price(
        family_key=family_key,
        selected_proof=selected_proof,
        all_proofs=all_proofs,
        extra_exposure_by_bin_id=extra_exposure_by_bin_id,
        bankroll_usd=bankroll_usd,
        kelly_multiplier=kelly_multiplier,
    )
    return stake_usd


def _family_existing_exposure_by_bin_id(
    *,
    proofs: tuple[_CandidateProof, ...] | list[_CandidateProof],
    selected_proof: _CandidateProof,
    portfolio_state_provider: "Callable[[], Any] | None",
    portfolio_reservation: "PortfolioReservationLedger | list[tuple[str, float]] | None",
    family,
) -> dict[str, float]:
    """Existing/pending per-outcome family exposure for the ΔU sizing vector (§11 Phase 4).

    Maps the family's ALREADY-committed and same-cycle-RESERVED capital onto the
    win OUTCOME it backs, so the marginal-utility optimizer measures the new leg's
    stake against a wealth-by-outcome baseline that already reflects that exposure
    (Hidden #10: a new leg correlated with existing exposure sizes smaller / can
    no-trade). Keyed by ``_candidate_bin_id`` so it lines up with the candidates'
    bins.

    Provenance scope (what we can attribute at THIS phase): the portfolio state
    tracks committed capital by CITY, and the same-cycle reservation ledger by
    city, not yet by bin/outcome. The selected leg's own bin is the only outcome
    whose direction we know here, so SAME-CITY committed + same-cycle reserved
    capital is attributed to the selected proof's bin (the conservative, no-double-
    count choice — it shrinks the marginal stake on the bin the book is already
    leaning into). Returns ``{}`` (flat baseline, no exposure) when no provider /
    reservation is wired or no same-city exposure exists, reproducing the prior
    behavior exactly.
    """
    selected_bin_id = _candidate_bin_id(selected_proof)
    city = str(getattr(family, "city", "") or "")
    exposure_usd = 0.0

    # Same-cycle reservations for this family's city (already-emitted-but-unfilled
    # stakes this cycle). PortfolioReservationLedger and a plain list both iterate
    # as (city, usd) pairs.
    if portfolio_reservation is not None:
        try:
            for res_city, usd in portfolio_reservation:
                if str(res_city) == city:
                    exposure_usd += float(usd)
        except (TypeError, ValueError):
            pass

    # Committed capital already on the book for this city (open positions).
    if portfolio_state_provider is not None:
        try:
            from src.state.portfolio import correlated_committed_usd

            state = portfolio_state_provider()
            if state is not None:
                exposure_usd += float(
                    correlated_committed_usd(state, new_city=city, extra_reserved=None)
                )
        except (TypeError, ValueError, ImportError):
            pass

    if exposure_usd <= 0.0:
        return {}
    return {selected_bin_id: exposure_usd}


def _family_existing_exposure_for_selection_by_bin_id(
    *,
    proofs: tuple[_CandidateProof, ...] | list[_CandidateProof],
    portfolio_state_provider: "Callable[[], Any] | None",
    held_position_conn: sqlite3.Connection | None = None,
    family,
) -> dict[str, float]:
    """PRE-SELECTION per-bin family exposure for the spine's ΔU SELECTION (Fix #4).

    The spine selects the new leg by ``argmax ΔU`` over the WHOLE family, so the
    exposure baseline must be per-bin BEFORE a leg is chosen — a flat/empty baseline
    lets the argmax pick a leg the account is already heavy in (re-sizing after
    selection cannot repair a wrong INSTRUMENT choice; consult_review_pr409.md §5/§6
    "current exposure not in route selection"). Unlike
    :func:`_family_existing_exposure_by_bin_id` (which collapses same-city exposure
    onto the ALREADY-selected bin — a post-selection sizing input), this attributes
    each open committed position to its OWN family bin by matching the position's
    ``condition_id`` to the family candidate's ``condition_id``, keyed by
    ``_candidate_bin_id`` so it lines up with the candidates' bins. The
    attribution must be direction-aware: a buy_yes position pays on its own bin,
    while a buy_no position pays on every other family outcome, including OUTSIDE.

    Scope (what is honestly attributable per-bin at selection): COMMITTED open
    positions carry a ``condition_id`` that maps to exactly one family bin, so
    their ``effective_cost_basis_usd`` is projected through the same payoff
    geometry as ``FamilyPayoffMatrix`` before the concave ΔU objective shrinks
    against it. Same-cycle reservations are city-keyed with NO bin identity, so
    they are NOT fabricated onto a bin here — the post-selection recapture
    already nets them by city. When ``held_position_conn`` is supplied it is the
    canonical live execution state and is read even if no portfolio provider is
    wired; the provider is a secondary in-memory/projected source.
    """
    # condition_id -> bin_id for THIS family (a bin's YES and NO proofs share both).
    bin_id_by_condition: dict[str, str] = {}
    for proof in proofs:
        cond = str(getattr(getattr(proof, "candidate", None), "condition_id", "") or "")
        if cond:
            bin_id_by_condition.setdefault(cond, _candidate_bin_id(proof))
    if not bin_id_by_condition:
        return {}
    all_family_outcomes = tuple(dict.fromkeys(bin_id_by_condition.values())) + (
        utility_ranker.OUTSIDE_OUTCOME,
    )
    exposure_by_bin: dict[str, float] = {}
    family_city = str(getattr(family, "city", "") or "").strip()
    family_target_date = str(getattr(family, "target_date", "") or "").strip()
    family_metric = str(
        getattr(family, "metric", "")
        or getattr(family, "temperature_metric", "")
        or ""
    ).strip()

    def _is_same_weather_family(*, city: object, target_date: object, metric: object) -> bool:
        return (
            bool(family_city and family_target_date and family_metric)
            and str(city or "").strip() == family_city
            and str(target_date or "").strip() == family_target_date
            and str(metric or "").strip() == family_metric
        )

    def _raise_unknown_family_position(condition_id: object) -> None:
        raise RuntimeError(
            "SAME_FAMILY_POSITION_NOT_IN_TOPOLOGY:"
            f"condition_id={condition_id or '<missing>'}:"
            f"city={family_city}:target_date={family_target_date}:metric={family_metric}"
        )

    def _add_exposure(*, condition_id: str, direction: str, committed: float) -> None:
        bin_id = bin_id_by_condition.get(condition_id)
        if bin_id is None or committed <= 0.0:
            return
        if direction == "buy_no":
            outcome_ids = tuple(
                outcome for outcome in all_family_outcomes if outcome != bin_id
            )
        else:
            outcome_ids = (bin_id,)
        for outcome_id in outcome_ids:
            exposure_by_bin[outcome_id] = exposure_by_bin.get(outcome_id, 0.0) + committed

    if held_position_conn is not None:
        try:
            columns = _position_current_columns(held_position_conn)
            if "condition_id" not in columns:
                raise RuntimeError("position_current.condition_id missing")
            phase_sql, phase_params = _position_phase_or_positive_chain_clause(
                columns,
                _ENTRY_HELD_POSITION_BLOCKING_PHASES,
            )
            positive_terms = [
                f"COALESCE({name}, 0) > 0"
                for name in ("chain_shares", "shares", "chain_cost_basis_usd", "cost_basis_usd", "size_usd")
                if name in columns
            ]
            if not positive_terms:
                raise RuntimeError("position_current exposure columns missing")
            condition_placeholders = ",".join("?" for _ in bin_id_by_condition)
            direction_select = "direction" if "direction" in columns else "NULL AS direction"
            chain_cost_select = (
                "chain_cost_basis_usd"
                if "chain_cost_basis_usd" in columns
                else "NULL AS chain_cost_basis_usd"
            )
            cost_select = (
                "cost_basis_usd" if "cost_basis_usd" in columns else "NULL AS cost_basis_usd"
            )
            size_select = "size_usd" if "size_usd" in columns else "NULL AS size_usd"
            city_select = "city" if "city" in columns else "NULL AS city"
            target_date_select = (
                "target_date" if "target_date" in columns else "NULL AS target_date"
            )
            metric_column = (
                "temperature_metric"
                if "temperature_metric" in columns
                else "metric"
                if "metric" in columns
                else ""
            )
            metric_select = (
                f"{metric_column} AS temperature_metric"
                if metric_column
                else "NULL AS temperature_metric"
            )
            same_family_scope_available = (
                bool(family_city and family_target_date and family_metric)
                and "city" in columns
                and "target_date" in columns
                and bool(metric_column)
            )
            scope_sql = f"condition_id IN ({condition_placeholders})"
            scope_params: list[object] = list(bin_id_by_condition.keys())
            if same_family_scope_available:
                scope_sql = (
                    f"({scope_sql} OR "
                    f"(city = ? AND target_date = ? AND {metric_column} = ?))"
                )
                scope_params.extend([family_city, family_target_date, family_metric])
            rows = held_position_conn.execute(
                f"""
                SELECT condition_id, {direction_select},
                       {chain_cost_select}, {cost_select}, {size_select},
                       {city_select}, {target_date_select}, {metric_select}
                  FROM position_current
                 WHERE {phase_sql}
                   AND {scope_sql}
                   AND ({" OR ".join(positive_terms)})
                """,
                (*phase_params, *scope_params),
            ).fetchall()
            for row in rows:
                try:
                    condition_id = str(row["condition_id"] or "")
                    direction_raw = row["direction"]
                    row_city = row["city"]
                    row_target_date = row["target_date"]
                    row_metric = row["temperature_metric"]
                    committed = (
                        _optional_float(row["chain_cost_basis_usd"])
                        or _optional_float(row["cost_basis_usd"])
                        or _optional_float(row["size_usd"])
                        or 0.0
                    )
                except Exception:
                    condition_id = str(row[0] or "")
                    direction_raw = row[1]
                    row_city = row[5] if len(row) > 5 else None
                    row_target_date = row[6] if len(row) > 6 else None
                    row_metric = row[7] if len(row) > 7 else None
                    committed = (
                        _optional_float(row[2])
                        or _optional_float(row[3])
                        or _optional_float(row[4])
                        or 0.0
                    )
                if condition_id not in bin_id_by_condition and _is_same_weather_family(
                    city=row_city,
                    target_date=row_target_date,
                    metric=row_metric,
                ):
                    _raise_unknown_family_position(condition_id)
                direction = str(getattr(direction_raw, "value", direction_raw) or "").strip().lower()
                _add_exposure(
                    condition_id=condition_id,
                    direction=direction,
                    committed=float(committed),
                )
            if exposure_by_bin:
                return exposure_by_bin
        except Exception as exc:  # noqa: BLE001 - exposure ambiguity must not flatten live risk.
            raise RuntimeError(
                f"EDLI_SELECTION_EXPOSURE_UNAVAILABLE:{type(exc).__name__}:{exc}"
            ) from exc

    if portfolio_state_provider is None:
        return {}
    try:
        from src.state.portfolio import (
            _runtime_open_exposure_usd,
            get_open_positions,
        )

        state = portfolio_state_provider()
        if state is None:
            return {}
        for pos in get_open_positions(state):
            cond = str(getattr(pos, "condition_id", "") or "")
            committed = float(_runtime_open_exposure_usd(pos))
            if committed <= 0.0:
                continue
            if cond not in bin_id_by_condition and _is_same_weather_family(
                city=getattr(pos, "city", None),
                target_date=getattr(pos, "target_date", None),
                metric=(
                    getattr(pos, "temperature_metric", None)
                    or getattr(pos, "metric", None)
                ),
            ):
                _raise_unknown_family_position(cond)
            direction_raw = getattr(pos, "direction", "")
            direction = str(getattr(direction_raw, "value", direction_raw) or "").strip().lower()
            _add_exposure(condition_id=cond, direction=direction, committed=committed)
        return exposure_by_bin
    except (TypeError, ValueError, ImportError):
        return {}


def _selected_candidate_proof(
    payload: dict[str, object],
    proofs: tuple[_CandidateProof, ...],
    *,
    locked_opportunity_conn: sqlite3.Connection | None = None,
    held_position_conn: sqlite3.Connection | None = None,
    strategy_policy_conn: sqlite3.Connection | None = None,
    strategy_policy_event_type: str | None = None,
    decision_time: datetime | None = None,
    allow_same_family_monitor_owned: bool = False,
    extra_exposure_by_bin_id: Mapping[str, float] | None = None,
) -> _CandidateProof | None:
    """Pick the single live primary leg via the bin-selection ΔU ranker (§14.7).

    ONE decision path (operator directive 2026-06-08; spec §14 item 8): every
    priced proof is materialized as a ``NativeSideCandidate`` and the family
    primary is the robust-marginal-expected-log-utility winner
    (:func:`_select_proof_by_robust_marginal_utility`). The legacy scalar-Kelly
    surfaces (``select_best_family_candidate`` / the ``(trade_score, q_lcb_5pct)``
    tuple) and the off-able family-selector runtime gate (its env var + settings
    key) are GONE — the ranker is unconditional, so the materialized candidate is
    the decision, never discarded.

    Sizing is computed POST-selection on the winning leg by
    :func:`_robust_marginal_utility_optimal_stake_usd` (the ΔU optimizer's
    ``optimal_stake_usd`` on the candidate's robust q_lcb — spec §3/§5.3); there is
    no pre-selection scalar-Kelly size threaded here.
    """
    family_key = str(payload.get("family_id") or payload.get("event_id") or "family")
    per_bin_yes_q_lcb = _per_bin_yes_q_lcb(proofs)

    # A ``token_id`` in the payload is a continuous-redecision REFRESH SCOPE (it
    # tells the upstream proof-generation which leg to re-capture), NOT a forced
    # selection: the family selector still ranks the WHOLE family and picks the
    # best sibling by ΔU. (Contract: test_token_redecision_refresh_scope_does_not_
    # force_requested_token / test_opportunity_book_selector_is_default_on_for_
    # requested_token.) So there is no requested-token branch here — one ranking
    # surface for every decision.

    # REFERENCE-ONLY GATE (operator directive 2026-06-03). The mainstream-agreement
    # verdict (#135 + #135-B) is recorded on the receipt to inform the ARM decision;
    # it takes NO part in production selection — we trade on the FORECAST. The gate
    # can never exclude a candidate from the ΔU ranking below.
    executable = list(
        _selection_scoped_proofs(
            proofs=proofs,
            locked_opportunity_conn=locked_opportunity_conn,
            held_position_conn=held_position_conn,
            strategy_policy_conn=strategy_policy_conn,
            strategy_policy_event_type=strategy_policy_event_type,
            decision_time=decision_time,
            allow_same_family_monitor_owned=allow_same_family_monitor_owned,
        )
    )
    if not executable:
        # Nothing executable survived scoping. Surface the best-belief NON-executable
        # proof (execution_price None) so the EXECUTABLE_NATIVE_ASK_MISSING receipt
        # (era :1562) can explain the no-native-ask no-trade rather than vanishing
        # silently. A proof that IS executable but was scoped OUT (e.g. locked with
        # no price improvement) must NOT be re-surfaced as the decision — that would
        # trade a locked leg. So the fallback is restricted to non-executable proofs;
        # if there is none, the family no-trades (returns None).
        non_executable = [
            proof for proof in proofs if proof.execution_price is None
        ]
        if not non_executable:
            return None
        return max(non_executable, key=lambda proof: proof.q_lcb_5pct)

    return _select_proof_by_robust_marginal_utility(
        executable=executable,
        family_key=family_key,
        per_bin_yes_q_lcb=per_bin_yes_q_lcb,
        extra_exposure_by_bin_id=extra_exposure_by_bin_id,
    )


def _native_direction(value: object) -> str:
    return str(value or "").split(":", 1)[0]


def _replacement_live_authority_proof_for_direction(
    *,
    proofs: tuple[_CandidateProof, ...],
    baseline_proof: _CandidateProof,
    effective_direction: str,
) -> _CandidateProof | None:
    target_direction = _native_direction(effective_direction)
    if target_direction == baseline_proof.direction:
        return baseline_proof
    condition_id = str(baseline_proof.candidate.condition_id or "")
    for proof in proofs:
        if str(proof.candidate.condition_id or "") != condition_id:
            continue
        if proof.direction != target_direction:
            continue
        if proof.execution_price is None:
            continue
        if _candidate_limit_price_untradeable_reason(proof) is not None:
            continue
        return proof
    return None


def _replacement_primary_authority_already_applied(proof: _CandidateProof) -> bool:
    if str(getattr(proof, "q_source", "") or "") == "replacement_0_1":
        return True
    if str(getattr(proof, "probability_authority", "") or "") == "replacement_0_1":
        return True
    if str(getattr(proof, "probability_authority", "") or "").startswith("day0_absorbing"):
        return True
    if str(getattr(proof, "q_source", "") or "") == "day0_remaining_day":
        return True
    return str(getattr(proof, "selection_authority_applied", "") or "") == "qkernel_spine"


def _locked_candidate_no_price_improvement_reason(
    live_cap_conn: sqlite3.Connection | None,
    proof: _CandidateProof,
) -> str | None:
    # FIX A (#125): the selector-stage duplicate lock is the SAME live-order-state
    # predicate as the cert-build seam — suppress only while a real ACTIVE order
    # exists for the (token, direction); release after a terminal cancel/expiry so
    # the candidate re-enters ranking at the fresh price.
    execution_price = getattr(proof, "execution_price", None)
    limit_price = _optional_float(getattr(execution_price, "value", None))
    return _locked_live_opportunity_active_order_reason(
        live_cap_conn,
        condition_id=str(getattr(getattr(proof, "candidate", None), "condition_id", "") or ""),
        token_id=str(getattr(proof, "token_id", "") or ""),
        direction=str(getattr(proof, "direction", "") or ""),
        family_id=str(getattr(getattr(proof, "candidate", None), "family_id", "") or ""),
        city=str(getattr(getattr(proof, "candidate", None), "city", "") or ""),
        target_date=str(getattr(getattr(proof, "candidate", None), "target_date", "") or ""),
        metric=str(
            getattr(getattr(proof, "candidate", None), "metric", "")
            or getattr(getattr(proof, "candidate", None), "temperature_metric", "")
            or ""
        ),
        side="SELL" if str(getattr(proof, "direction", "") or "").startswith("sell_") else "BUY",
        limit_price=limit_price,
    )


def _candidate_limit_price_untradeable_reason(proof: _CandidateProof) -> str | None:
    execution_price = getattr(proof, "execution_price", None)
    limit_price = _optional_float(getattr(execution_price, "value", None))
    if limit_price is None:
        return "EXECUTION_PRICE_MISSING"
    min_tick = _candidate_min_tick_size(proof)
    if min_tick is None:
        min_tick = 0.01
    if min_tick <= 0.0:
        return f"EXECUTION_PRICE_MIN_TICK_INVALID:{min_tick!r}"
    if limit_price < min_tick - 1e-12:
        return (
            "EXECUTION_PRICE_BELOW_MIN_TICK:"
            f"limit_price={limit_price:.12g}:min_tick_size={min_tick:.12g}"
        )
    return None


def _candidate_min_tick_size(proof: _CandidateProof) -> float | None:
    row = getattr(proof, "row", None)
    if row is None:
        return None
    getter = getattr(row, "get", None)
    for key in ("min_tick_size", "tick_size"):
        try:
            raw = getter(key) if callable(getter) else row[key]
        except Exception:
            raw = None
        value = _optional_float(raw)
        if value is not None:
            return value
    return None


def _live_yes_probabilities(
    *,
    event: OpportunityEvent,
    payload: dict[str, object],
    family,
    conn: sqlite3.Connection,
    calibration_conn: sqlite3.Connection,
    native_costs: dict[tuple[str, str], tuple[dict[str, Any] | None, ExecutionPrice | None, float, float | None, str | None]],
    decision_time: datetime,
    promotion_evidence: ReplacementForecastPromotionEvidence | None = None,
    capital_objective_evidence: ReplacementForecastCapitalObjectiveEvidence | None = None,
    provenance_capture: dict[str, Any] | None = None,
) -> tuple[
    dict[str, float],
    dict[tuple[str, str], float],
    dict[tuple[str, str], float],
    dict[tuple[str, str], bool],
    dict[str, str],
]:
    # 2026-05-30: canonical kernel reconstructed (snapshot fetch + MarketAnalysis assembly +
    # hypothesis-family scan + evaluate_live_bins). Gated by the acceptance suite in
    # tests/engine/test_event_reactor_no_bypass.py.
    # EDLI_REDECISION_PENDING routes through the SAME replacement→canonical forecast dispatch
    # (it is a fresh-price re-decision of a forecast family; the snapshot binding is identical).
    if event.event_type in _FORECAST_DECISION_EVENT_TYPES:
        # FIX-1 Insertion A: thread the settlement-evidence objects (loaded once in
        # main.py, carried through the adapter closure) into the live 0.1 authority
        # builder so the shared gate runs on the path that is actually live.
        replacement = _replacement_authority_probability_and_fdr_proof(
            event=event,
            payload=payload,
            family=family,
            conn=conn,
            native_costs=native_costs,
            decision_time=decision_time,
            promotion_evidence=promotion_evidence,
            capital_objective_evidence=capital_objective_evidence,
            provenance_capture=provenance_capture,
        )
        if replacement is not None:
            return replacement
        return _canonical_probability_and_fdr_proof(
            event=event,
            payload=payload,
            family=family,
            conn=conn,
            calibration_conn=calibration_conn,
            native_costs=native_costs,
            decision_time=decision_time,
        )
    if event.event_type == "DAY0_EXTREME_UPDATED":
        # ORACLE ANOMALY PAUSE (day0 review 2026-06-10 item E, Paris-CDG class):
        # when the WU-vs-METAR divergence detector has flagged this family's
        # (city, target_date), no day0 q may be built — the running extreme's
        # truth source is suspect (sensor tampering / feed fault). Raising here
        # converts to a deterministic no-submit receipt at the
        # _generate_candidate_proofs ValueError boundary
        # (LIVE_INFERENCE_INPUTS_MISSING:DAY0_ORACLE_ANOMALY_PAUSED:...).
        from src.data.day0_oracle_anomaly import is_day0_family_paused

        if is_day0_family_paused(str(family.city), str(family.target_date)):
            raise ValueError(
                f"DAY0_ORACLE_ANOMALY_PAUSED:{family.city}:{family.target_date}"
            )
        generated = _canonical_probability_and_fdr_proof(
            event=event,
            payload=payload,
            family=family,
            conn=conn,
            calibration_conn=calibration_conn,
            native_costs=native_costs,
            allow_latest_snapshot=True,
            decision_time=decision_time,
        )
        q_by_condition, lcb_by_condition, _p_values, _prefilter, evidence = generated
        masked_q, masked_lcb = _apply_day0_mask_to_generated_probabilities(
            payload=payload,
            family=family,
            q_by_condition=q_by_condition,
            lcb_by_condition=lcb_by_condition,
            decision_time=decision_time,
        )
        if provenance_capture is not None:
            observed_extreme_native = payload.get(
                "high_so_far"
                if str(payload.get("metric") or payload.get("temperature_metric") or "")
                == "high"
                else "low_so_far"
            )
            if observed_extreme_native in (None, ""):
                observed_extreme_native = payload.get("raw_value")
            if observed_extreme_native in (None, ""):
                observed_extreme_native = payload.get("rounded_value")
            provenance_capture["day0_probability_authority"] = _json_finite(
                {
                    "q_source": payload.get("_edli_q_source"),
                    "q_mode": payload.get("_edli_day0_q_mode"),
                    "remaining_models": payload.get("_edli_day0_remaining_models"),
                    "remaining_model_names": payload.get("_edli_day0_remaining_model_names"),
                    "remaining_source_cycle_time_utc": payload.get(
                        "_edli_day0_remaining_source_cycle_time_utc"
                    ),
                    "remaining_capture_times_utc": payload.get(
                        "_edli_day0_remaining_capture_times_utc"
                    ),
                    "remaining_expected_models": payload.get(
                        "_edli_day0_remaining_expected_models"
                    ),
                    "exit_authority_status": payload.get("_edli_day0_exit_authority_status"),
                    "exit_authority_reason": payload.get("_edli_day0_exit_authority_reason"),
                    "bound_classification": payload.get("_edli_day0_bound_classification"),
                    "observed_extreme_native": observed_extreme_native,
                    "rounded_value": payload.get("rounded_value"),
                    "observation_time": payload.get("observation_time"),
                    "observation_available_at": payload.get("observation_available_at"),
                    "lcb_transform": payload.get("_edli_day0_lcb_transform"),
                }
            )
        p_values, prefilter = _day0_hard_fact_fdr_maps(
            family=family,
            native_costs=native_costs,
            masked_lcb_by_condition=masked_lcb,
        )
        # LCB AUDIT IDENTITY (PR#404 P1): the staleness guard can revoke submit
        # licenses (q_lcb -> 0) WITHOUT moving q, so p_live_vector_hash alone
        # cannot distinguish two receipts with different eligibility. Hash the
        # buy_yes LCB vector AND the full day0 lcb transform (per-direction
        # lcbs, mask, suppressed bins, obs age/budget/margin) so receipts can
        # explain 'q unchanged but submit license revoked'.
        import hashlib

        from src.calibration.qlcb_provenance import _qlcb_float as _lcbf

        _lcb_transform = payload.get("_edli_day0_lcb_transform") or {}
        _transform_canonical = json.dumps(
            _lcb_transform, sort_keys=True, separators=(",", ":"), default=str
        )
        return masked_q, masked_lcb, p_values, prefilter, {
            **evidence,
            "probability_authority": "day0_absorbing_hard_fact",
            "p_live_vector_hash": _probability_vector_hash(
                masked_q[str(candidate.condition_id or "")]
                for candidate in family.candidates
            ),
            "q_lcb_vector_hash": _probability_vector_hash(
                _lcbf(masked_lcb.get((str(candidate.condition_id or ""), "buy_yes"), 0.0))
                for candidate in family.candidates
            ),
            "day0_lcb_transform_hash": "sha256:"
            + hashlib.sha256(_transform_canonical.encode("utf-8")).hexdigest(),
            "day0_lcb_staleness_suppressed_bins": len(
                _lcb_transform.get("staleness_suppressed_conditions") or ()
            ),
            "day0_lcb_obs_age_minutes": _lcb_transform.get("obs_age_minutes"),
            "day0_lcb_staleness_budget_minutes": _lcb_transform.get("staleness_budget_minutes"),
            "day0_lcb_staleness_margin": _lcb_transform.get("staleness_margin"),
        }
    raise ValueError(f"unsupported EDLI event type for inference: {event.event_type}")


# FIX 1 (2026-06-09) — replacement q-mode live eligibility gate. The materializer derives an
# explicit `replacement_q_mode` into provenance_json (FUSED_NORMAL_FULL/PARTIAL,
# ANCHOR_ONLY_CURRENT, FUSED_CENTER_ONLY_NORMAL, BAYES_PRECISION_FUSION_CAPTURE_MISSING,
# FUSED_Q_BUILD_FAILED). Real submit is allowed ONLY for fused Normal carriers with certified
# q_lcb/q_ucb; this excludes legacy member-vote and anchor-only fallback rows. Missing BPF
# current inputs must heal through the capture lane, not continue as a live single-anchor
# surrogate.
# This kills the silent-degradation category: a row that fell back to the legacy member-vote
# soft-anchor q (or had no fusion at all) must NOT size live Kelly under the wrong probability
# regime just because all flags were on.
_REPLACEMENT_Q_MODE_FUSED_NORMAL_FULL = "FUSED_NORMAL_FULL"
_REPLACEMENT_Q_MODE_FUSED_NORMAL_PARTIAL = "FUSED_NORMAL_PARTIAL"
_REPLACEMENT_Q_MODE_ANCHOR_ONLY_CURRENT = "ANCHOR_ONLY_CURRENT"
_REPLACEMENT_Q_MODE_LIVE_ELIGIBLE = frozenset(
    {
        _REPLACEMENT_Q_MODE_FUSED_NORMAL_FULL,
        _REPLACEMENT_Q_MODE_FUSED_NORMAL_PARTIAL,
    }
)


def _replacement_q_mode_live_eligibility(replacement_bundle: object) -> tuple[bool, str]:
    """Return (live_eligible, mode) for a replacement posterior bundle. Fail-closed.

    Reads provenance_json.replacement_q_mode. Eligible only for live fused Normal carrier modes
    (FUSED_NORMAL_FULL / FUSED_NORMAL_PARTIAL). No grandfather clause.

    GRANDFATHER REVOKED (operator directive 2026-06-10 P0): the former q_shape=="fused_normal_direct"
    grandfather branch that returned (True, "FUSED_NORMAL_GRANDFATHERED") has been DELETED. Old DB
    rows with no replacement_q_mode key and q_shape=="fused_normal_direct" are NOT live-eligible —
    they have no certified bootstrap bounds and would size Kelly with mismatched probability and
    q_lcb measures. Those rows must rematerialize to get proper bounds.
    """
    provenance = getattr(replacement_bundle, "provenance_json", None)
    if not isinstance(provenance, Mapping):
        provenance = {}
    mode = provenance.get("replacement_q_mode")
    if isinstance(mode, str) and mode:
        return (mode in _REPLACEMENT_Q_MODE_LIVE_ELIGIBLE, mode)
    # No explicit mode key: reject regardless of q_shape (no grandfather).
    q_shape = str(provenance.get("q_shape") or "")
    if q_shape == "fused_normal_direct":
        return (False, "FUSED_NORMAL_GRANDFATHER_REVOKED")
    return (False, "NO_Q_MODE_KEY")


# CERT BRIDGE (2026-06-10, operator-gated funnel #1 unlock) — first-class calibration
# authority for replacement-chain candidates. The legacy decision certificate demands a
# platt_models bucket per (cluster, metric, source_id, cycle, horizon_profile); when
# absent it stamps authority=IDENTITY_FALLBACK_NO_PLATT_BUCKET and the live gate REJECTS.
# Replacement-chain candidates' q NEVER passes through Platt — their calibration authority
# is the fused-center bootstrap bounds (q_lcb_basis=fused_center_bootstrap_p05, 200 draws)
# + the settlement-backward coverage license. Demanding the legacy chain's credential from
# them is a CATEGORY MISMATCH. This credential admits EXACTLY the coverage states the ARM
# gate (settlement_backward_coverage.arm_gate_coverage_blocks) admits — so you can never
# get a live calibration credential on a coverage state the ARM gate would refuse.
#
# STRICTNESS (iron rule — this must not weaken anything):
#   (a) legacy-path candidates still REQUIRE Platt buckets (this credential is only built
#       when the candidate's q source is the replacement bundle).
#   (b) replacement candidates WITHOUT bounds (q_lcb_json null / basis mismatch) get NO
#       credential here → fall through to the legacy Platt path → IDENTITY_FALLBACK reject
#       exactly as today.
#   (c) bounds present but coverage NEVER evaluated the scope, or produced an unknown
#       status, or produced no verdict, → authority is FUSED_BOOTSTRAP_COVERAGE_UNEVALUATED,
#       which the gate REJECTS with a distinct reason. A typed INSUFFICIENT_DATA verdict is
#       preserved as provenance and admits only through FUSED_BOOTSTRAP_CONSERVATIVE_Q_LCB.
FUSED_BOOTSTRAP_CALIBRATION_AUTHORITY = "FUSED_BOOTSTRAP_SETTLEMENT_COVERAGE"
FUSED_BOOTSTRAP_CONSERVATIVE_QLCB_AUTHORITY = "FUSED_BOOTSTRAP_CONSERVATIVE_Q_LCB"
FUSED_BOOTSTRAP_COVERAGE_UNEVALUATED_AUTHORITY = "FUSED_BOOTSTRAP_COVERAGE_UNEVALUATED"
_FUSED_BOOTSTRAP_CERT_COVERAGE_STATUSES = frozenset(
    {"LICENSED", "UNLICENSED"}
)
_FUSED_BOOTSTRAP_MIN_LIVE_SAMPLES = 30
_FUSED_BOOTSTRAP_MIN_BOOTSTRAP_DRAWS = 100
# The only q_lcb_basis marker the materializer writes for certified fused-center bootstrap
# bounds; the credential's bounds leg requires an EXACT match (basis-pinned, no aliasing).
_FUSED_BOOTSTRAP_QLCB_BASIS = "fused_center_bootstrap_p05"
# Payload key under which the live replacement builder stamps the credential facts onto the
# threaded `payload` dict so `_calibration_authority_payload_and_clock` can read them
# without re-reading the bundle (single source of truth at the point of computation; the
# payload is the per-candidate instance-safe carrier per the #149 one-calibrator-seam fix).
_REPLACEMENT_CALIBRATION_CREDENTIAL_KEY = "_edli_replacement_calibration_credential"


def _replacement_family_coverage_verdict(
    *,
    family,
    forecast_conn: sqlite3.Connection,
    lcb_by_direction,
    coverage_cache: dict | None = None,
):
    """Settlement-backward coverage VERDICT for the family scope.

    The credential needs to know whether the settled record evaluated this scope and what
    it said. The ARM gate reads it unconditionally, and the shrink helper applies the same
    verdict to the live q_lcb when the settled record proves overconfidence.

    Returns the family-representative ``CoverageVerdict`` (the buy_yes leg of the first
    candidate whose q_lcb is present), or ``None`` when the check could not run.  An
    INSUFFICIENT_DATA verdict is returned for thin history and preserved for provenance.
    It licenses the certificate authority only as an evaluated coverage state; downstream
    selection/economic/material-NO gates still decide whether any live order is acceptable.

    STRUCTURAL FAULT (pr408 #1 CRITICAL): a read/parse/schema fault in the observation
    build must NOT collapse into INSUFFICIENT_DATA or a swallowed None — it raises
    ``QLCB_COVERAGE_AUTHORITY_FAULT`` and is allowed to PROPAGATE (fail closed). The
    per-candidate ``except`` below catches only NON-fault errors (e.g. a single malformed
    candidate) so the scan can try the next candidate; a coverage authority fault is
    re-raised.
    """
    try:
        from src.calibration.qlcb_provenance import _qlcb_float
        from src.calibration.settlement_backward_coverage import (
            settlement_backward_coverage_check,
        )
        from src.contracts.season import season_from_date

        metric = str(getattr(family, "metric", "") or "").lower()
        city_obj = runtime_cities_by_name().get(family.city)
        lat = getattr(city_obj, "lat", 90.0) if city_obj else 90.0
        season = season_from_date(str(getattr(family, "target_date", "")), lat=lat)
    except Exception:
        return None

    for candidate in family.candidates:
        condition_id = str(candidate.condition_id or "")
        bin_obj = getattr(candidate, "bin", None)
        if bin_obj is None:
            continue
        key = (condition_id, "buy_yes")
        if key not in lcb_by_direction:
            continue
        try:
            claimed = _qlcb_float(lcb_by_direction[key])
            obs = _settlement_coverage_observations(
                forecast_conn=forecast_conn,
                city=family.city,
                metric=metric,
                bin=bin_obj,
                direction="buy_yes",
                claimed_q_lcb=claimed,
                fail_closed_on_fault=True,
                coverage_cache=coverage_cache,
            )
            verdict = settlement_backward_coverage_check(
                city=family.city, metric=metric, season=season,
                q_lcb=claimed, observations=obs, min_n=30,
            )
            return verdict
        except Exception as exc:
            # A coverage AUTHORITY fault (structural read/schema fault with the safety gate
            # on) must fail CLOSED — propagate, never swallow to None or try the next candidate
            # (a real fault is not a per-candidate hiccup). Other errors skip this candidate.
            if "QLCB_COVERAGE_AUTHORITY_FAULT" in str(exc):
                raise
            continue
    return None


def _build_replacement_calibration_credential(
    *,
    replacement_bundle,
    q_mode: str,
    coverage_verdict,
    family,
) -> dict[str, Any] | None:
    """Assemble the replacement calibration credential facts for ``payload`` stamping.

    Returns a dict the calibration-authority builder turns into the certificate payload,
    or ``None`` when the bounds leg is absent (→ caller stamps nothing → legacy Platt path
    → IDENTITY_FALLBACK reject, strictness (b)). The bounds leg requires: a live-eligible
    fused-Normal q_mode, a non-empty bundle q_lcb map, AND provenance q_lcb_basis EXACTLY
    equal to the fused-center bootstrap marker. Coverage verdict is carried as-is:
    None/unknown stays UNEVALUATED and blocked downstream; typed INSUFFICIENT_DATA is
    preserved as evaluated thin history and admits only as conservative bootstrap q_lcb.
    """
    if q_mode not in _REPLACEMENT_Q_MODE_LIVE_ELIGIBLE:
        return None
    provenance = getattr(replacement_bundle, "provenance_json", None)
    if not isinstance(provenance, Mapping):
        provenance = {}
    q_lcb_map = getattr(replacement_bundle, "q_lcb", None)
    q_lcb_basis = provenance.get("q_lcb_basis")
    bounds_ok = (
        isinstance(q_lcb_map, Mapping)
        and bool(q_lcb_map)
        and q_lcb_basis == _FUSED_BOOTSTRAP_QLCB_BASIS
    )
    if not bounds_ok:
        return None
    season = None
    try:
        from src.contracts.season import season_from_date

        city_obj = runtime_cities_by_name().get(family.city)
        lat = getattr(city_obj, "lat", 90.0) if city_obj else 90.0
        season = season_from_date(str(getattr(family, "target_date", "")), lat=lat)
    except Exception:
        season = None
    coverage: dict[str, Any] = {
        "status": None, "coverage_ratio": None, "n": None,
        "shrink": None, "shrink_applied": False,
    }
    if coverage_verdict is not None:
        try:
            shrink = float(coverage_verdict.q_lcb_in) - float(coverage_verdict.q_lcb_out)
        except (TypeError, ValueError):
            shrink = None
        # pr408 #1 CRITICAL: an UNLICENSED verdict only LICENSES the credential when
        # the verdict produced a real downward shrink (q_lcb_out < q_lcb_in). A
        # no-op UNLICENSED verdict would leave an overconfident bound serving live.
        shrink_applied = bool(
            str(coverage_verdict.status) == "UNLICENSED"
            and shrink is not None
            and shrink > 0.0
        )
        coverage = {
            "status": str(coverage_verdict.status),
            "coverage_ratio": coverage_verdict.coverage_ratio,
            "realized_win_rate": coverage_verdict.realized_win_rate,
            "n": int(coverage_verdict.n_settlement_observations),
            "shrink": shrink,
            "shrink_applied": shrink_applied,
        }
    return {
        "q_mode": q_mode,
        "q_lcb_basis": _FUSED_BOOTSTRAP_QLCB_BASIS,
        "bootstrap_draws": provenance.get("q_lcb_bootstrap_draws"),
        "posterior_id": getattr(replacement_bundle, "posterior_id", None),
        "season": season,
        "cohort": f"{family.city}:{str(family.metric).lower()}:{season}",
        "coverage": coverage,
    }


def _replacement_calibration_payload_from_credential(
    credential: Mapping[str, Any],
    *,
    horizon_profile: str | None,
    decision_time: datetime,
) -> dict[str, Any]:
    """Turn the stamped credential facts into the certificate calibration payload.

    AUTHORITY:
      * LICENSED → admit with authority=FUSED_BOOTSTRAP_SETTLEMENT_COVERAGE.
      * INSUFFICIENT_DATA → admit with authority=FUSED_BOOTSTRAP_CONSERVATIVE_Q_LCB.
        Thin settled claim-history is non-refuting; it is not a settlement-coverage
        license, but it also must not default-deny a fused bootstrap q_lcb that is
        already a conservative live confidence bound.
      * UNLICENSED (``settlement_coverage_refutes_claim``) → admit ONLY when the selected
        leg's q_lcb was ACTUALLY shrunk (coverage gate flag ON and q_lcb_out < q_lcb_in,
        recorded as ``coverage.shrink_applied``). An UNLICENSED verdict whose shrink was
        NOT applied (flag OFF) is a proven-overconfident bound serving UNSHRUNK → block as
        UNEVALUATED. (Mirrors arm_gate_coverage_blocks, which refuses UNLICENSED outright;
        here we additionally LICENSE the case where the shrink made the bound honest.)
      * None / unknown / no verdict → UNEVALUATED → reject with the distinct reason.
    The status string is preserved on the cert (coverage_status)
    for observability regardless of the licensing decision. The payload carries the full
    provenance the receipt/verifier round-trips, plus the fields _validate_calibration_payload
    requires (horizon_profile == forecast's, training_cutoff/model_available_at <= decision_time,
    a non-empty model_hash).
    """
    coverage = credential.get("coverage") or {}
    status = coverage.get("status")
    status_str = status if isinstance(status, str) else ""
    if status_str == "LICENSED":
        licensed = True
    elif settlement_coverage_refutes_claim(status_str):
        # UNLICENSED: admit ONLY if the shrink was actually applied to the live leg
        # (otherwise the unshrunk overconfident bound would serve live → block).
        licensed = bool(coverage.get("shrink_applied"))
    else:
        # None / UNEVALUATED / unknown: no verdict → never license.
        licensed = False
    if licensed:
        authority = FUSED_BOOTSTRAP_CALIBRATION_AUTHORITY
    elif status_str == "INSUFFICIENT_DATA":
        authority = FUSED_BOOTSTRAP_CONSERVATIVE_QLCB_AUTHORITY
    else:
        authority = FUSED_BOOTSTRAP_COVERAGE_UNEVALUATED_AUTHORITY
    q_mode = str(credential.get("q_mode") or "")
    posterior_id = credential.get("posterior_id")
    model_key = (
        "fused_bootstrap_settlement_coverage_v1:"
        f"{credential.get('cohort')}:{q_mode}:posterior={posterior_id}"
    )
    n_samples = coverage.get("n")
    cutoff_iso = decision_time.astimezone(UTC).isoformat()
    model_hash = _hash_jsonish(
        {
            "model_key": model_key,
            "calibration_method": "fused_center_bootstrap_settlement_coverage",
            "q_lcb_basis": credential.get("q_lcb_basis"),
            "bootstrap_draws": credential.get("bootstrap_draws"),
            "replacement_q_mode": q_mode,
            "posterior_id": posterior_id,
            "cohort": credential.get("cohort"),
            "coverage_status": status,
        }
    )
    return {
        "identity": model_key,
        "calibrator_model_key": model_key,
        "calibrator_version": model_key,
        "calibration_method": "fused_center_bootstrap_settlement_coverage",
        "model_hash": model_hash,
        "horizon_profile": horizon_profile,
        "training_cutoff": cutoff_iso,
        "model_available_at": cutoff_iso,
        "model_materialized_at": cutoff_iso,
        "q_lcb_basis": credential.get("q_lcb_basis"),
        "bootstrap_draws": credential.get("bootstrap_draws"),
        "replacement_q_mode": q_mode,
        "posterior_id": posterior_id,
        "season": credential.get("season"),
        "cohort": credential.get("cohort"),
        "coverage_status": status,
        "coverage_ratio": coverage.get("coverage_ratio"),
        "coverage_realized_win_rate": coverage.get("realized_win_rate"),
        "coverage_shrink": coverage.get("shrink"),
        "input_space": "fused_center_bootstrap_lcb",
        "maturity_level": 4,
        "n_samples": n_samples,
        "authority": authority,
    }

def _replacement_authority_enabled() -> bool:
    try:
        flags = settings["feature_flags"]
    except Exception:
        return False
    return bool(flags.get("openmeteo_ecmwf_ifs9_bayes_fusion_live_enabled", False))


def _wilson_lower_bound(successes: float, trials: float, *, z: float = 1.645) -> float:
    if trials <= 0.0:
        return 0.0
    successes = min(max(float(successes), 0.0), float(trials))
    p_hat = successes / float(trials)
    z2 = z * z
    denom = 1.0 + z2 / float(trials)
    center = p_hat + z2 / (2.0 * float(trials))
    margin = z * float(np.sqrt((p_hat - (p_hat * p_hat) + z2 / (4.0 * float(trials))) / float(trials)))
    return max(0.0, min(1.0, (center - margin) / denom))


def _candidate_replacement_bin_id(candidate: object, replacement_bundle: object) -> str | None:
    provenance = getattr(replacement_bundle, "provenance_json", None) or {}
    if not isinstance(provenance, Mapping):
        return None
    topology = provenance.get("bin_topology")
    if not isinstance(topology, list) or not topology:
        return None
    bin_obj = getattr(candidate, "bin", None)
    unit = str(getattr(bin_obj, "unit", "") or "")
    if not unit:
        return None
    lower_c = _replacement_bound_to_c(getattr(bin_obj, "low", None), unit=unit)
    upper_c = _replacement_bound_to_c(getattr(bin_obj, "high", None), unit=unit)
    matches: list[str] = []
    for item in topology:
        if not isinstance(item, Mapping):
            continue
        bin_id = str(item.get("bin_id") or "").strip()
        if not bin_id:
            continue
        item_lower = item.get("lower_c")
        item_upper = item.get("upper_c")
        lower_ok = (item_lower is None and lower_c is None) or (
            item_lower is not None and lower_c is not None and math.isclose(float(item_lower), float(lower_c), rel_tol=0.0, abs_tol=1e-9)
        )
        upper_ok = (item_upper is None and upper_c is None) or (
            item_upper is not None and upper_c is not None and math.isclose(float(item_upper), float(upper_c), rel_tol=0.0, abs_tol=1e-9)
        )
        if lower_ok and upper_ok:
            matches.append(bin_id)
    if len(matches) != 1:
        return None
    return matches[0]


def _replacement_bound_to_c(value: object, *, unit: str) -> float | None:
    if value is None:
        return None
    number = float(value)
    if unit == "C":
        return number
    if unit == "F":
        return (number - 32.0) * 5.0 / 9.0
    raise ValueError("replacement candidate bin unit must be C or F")


def _replacement_anchor_mu_c(replacement_bundle: object) -> float | None:
    """The soft-anchor point estimate μ (°C) the bundle was built around.

    Read from ``provenance_json.anchor_value_c`` (the deterministic IFS9 anchor value carried
    by legacy posterior rows and retained as provenance on current live posteriors). ``None``
    when absent so the floor is skipped (degrade, never crash)."""
    provenance = getattr(replacement_bundle, "provenance_json", None) or {}
    if not isinstance(provenance, Mapping):
        return None
    value = provenance.get("anchor_value_c")
    if value is None:
        return None
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def _replacement_predictive_sigma_c(replacement_bundle: object) -> float | None:
    """The fused posterior's predictive sigma (°C) from bayes_precision_fusion provenance.

    FIX A (direction law, 2026-06-10 Milan-24C incident): read from
    ``provenance_json.bayes_precision_fusion.predictive_sigma_c`` — the T2_BAYES fusion's own
    predictive sigma, NOT the settlement-floored sigma (the floored ~3.3C value
    would widen the direction-law band enough to re-admit the incident trade).
    ``None`` when absent so the law degrades to the 1-settlement-step threshold
    (strictly conservative).
    """
    provenance = getattr(replacement_bundle, "provenance_json", None) or {}
    if not isinstance(provenance, Mapping):
        return None
    fusion = provenance.get("bayes_precision_fusion")
    if not isinstance(fusion, Mapping):
        return None
    value = fusion.get("predictive_sigma_c")
    if value is None:
        return None
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def _replacement_yes_lcb_for_bin(
    replacement_bundle: object,
    *,
    bin_id: str,
    q_yes: float,
    settlement_floor_lcb: float | None = None,
) -> float:
    """Raw replacement YES q_lcb from the replacement bundle's certified bound.

    ``settlement_floor_lcb`` is an optional ONLY-LOWERS ceiling: when supplied the
    returned bound is ``min(raw, settlement_floor_lcb)`` (it can never raise the q_lcb);
    ``None`` (the default) returns the bundle value. Wave-2 item 6 (2026-06-12):
    the live caller always passes ``None`` — the settlement-σ-grounded q_lcb floor (a
    distinct, never-live correction) was deleted, so this param is currently inert.
    """
    def _apply_floor(raw: float) -> float:
        if settlement_floor_lcb is None:
            return raw
        return min(raw, float(settlement_floor_lcb))

    q_lcb = getattr(replacement_bundle, "q_lcb", None) or {}
    if isinstance(q_lcb, Mapping) and bin_id in q_lcb:
        return _apply_floor(min(max(float(q_lcb[bin_id]), 0.0), max(0.0, min(float(q_yes), 1.0))))
    return 0.0


def _replacement_yes_bootstrap_samples_for_bin(
    replacement_bundle: object,
    *,
    bin_id: str,
) -> tuple[float, ...]:
    provenance = getattr(replacement_bundle, "provenance_json", None) or {}
    if not isinstance(provenance, Mapping):
        return ()
    samples_by_bin = provenance.get("q_bootstrap_samples_by_bin")
    if not isinstance(samples_by_bin, Mapping):
        return ()
    raw_samples = samples_by_bin.get(bin_id)
    if not isinstance(raw_samples, (list, tuple)):
        return ()
    samples: list[float] = []
    for raw in raw_samples:
        try:
            value = float(raw)
        except (TypeError, ValueError):
            return ()
        if not math.isfinite(value):
            return ()
        samples.append(float(min(max(value, 0.0), 1.0)))
    return tuple(samples)


def _finite_sample_false_edge_rate(samples: tuple[float, ...], *, cost: float) -> float | None:
    if not samples:
        return None
    threshold = float(cost)
    false_edges = sum(1 for sample in samples if sample <= threshold)
    return float((false_edges + 1) / (len(samples) + 1))


def _replacement_no_lcb_for_bin(
    replacement_bundle: object,
    *,
    bin_id: str,
    q_yes: float,
) -> float:
    """Native-NO robust q_lcb for ``bin_id`` on the replacement_0_1 path (Hidden #3).

    bin-selection §4 (lines 154-166) / §9 Hidden #3: the NO robust lower bound is the
    lower tail of the per-sample complement ``1 - q_yes``, which equals ``1 - q_ucb_yes``
    — NOT ``1 - q_lcb_yes``. The replacement bundle exposes a per-bin ``q_ucb`` map, and
    the complement identity is exact, so ``q_lcb_no = 1 - q_ucb_yes`` directly. Clamp into
    ``[0, 1 - q_yes]`` so the NO lower bound never exceeds the NO point ``1 - q_yes``
    (the ProbabilityUncertainty / NativeSideCandidate invariant, Hidden #2 on the NO leg).

    Absent a bundle ``q_ucb`` there is no native NO authority — return ``0.0``
    (fail-closed). It is NEVER derived from the YES q_lcb (the point-complement the spec
    forbids).
    """
    q_ucb = getattr(replacement_bundle, "q_ucb", None) or {}
    q_point_no = float(min(max(1.0 - float(q_yes), 0.0), 1.0))
    if isinstance(q_ucb, Mapping) and bin_id in q_ucb:
        try:
            q_ucb_yes = float(min(max(float(q_ucb[bin_id]), 0.0), 1.0))
        except (TypeError, ValueError):
            return 0.0
        q_lcb_no = 1.0 - q_ucb_yes
        return float(min(max(q_lcb_no, 0.0), q_point_no))
    return 0.0


def _replacement_authority_probability_and_fdr_proof(
    *,
    event: OpportunityEvent,
    payload: dict[str, object],
    family,
    conn: sqlite3.Connection,
    native_costs: dict[tuple[str, str], tuple[dict[str, Any] | None, ExecutionPrice | None, float, float | None, str | None]],
    decision_time: datetime,
    promotion_evidence: ReplacementForecastPromotionEvidence | None = None,
    capital_objective_evidence: ReplacementForecastCapitalObjectiveEvidence | None = None,
    provenance_capture: dict[str, Any] | None = None,
) -> tuple[
    dict[str, float],
    dict[tuple[str, str], float],
    dict[tuple[str, str], float],
    dict[tuple[str, str], bool],
    dict[str, str],
] | None:
    if not _replacement_authority_enabled():
        return None
    # OPERATOR DIRECTIVE 2026-06-08 — INSERTION A promotion/capital-objective EVIDENCE
    # GATE REMOVED (paired with the runtime_policy.py Insertion-B removal). It was the
    # second copy of the circular "prove after-cost before trading" bureaucracy and was
    # the actual binding blocker on the live FORECAST_SNAPSHOT_READY path: with the live
    # evidence file it returned permitted=False (INSUFFICIENT_OFFICIAL_DAYS/ROWS,
    # Q_LCB_COVERAGE_TOO_LOW, NESTED_WALK_FORWARD_NOT_PASSED) → return None → BAYES_PRECISION_FUSION silently
    # degraded to the legacy canonical kernel and never traded live. Live authority is
    # now granted by the trade_authority flag (_replacement_authority_enabled, above).
    # The REAL forward risk controls remain enforced BELOW and are untouched: readiness
    # freshness (READINESS_MISSING raise), the bundle gate (BUNDLE_BLOCKED), the q_lcb
    # fused-center bootstrap bounds (must exist for live-eligible q modes),
    # the direction law (re-derived from argmax(BAYES_PRECISION_FUSION.q) per bin), fractional Kelly, the
    # after-cost cost floor, and RiskGuard. Overconfidence is bounded FORWARD by q_lcb +
    # fractional Kelly and judged by settlement, not by a pre-trade evidence checklist.
    import logging as _logging
    from src.calibration.qlcb_provenance import QlcbByDirection, _set_qlcb_provenance
    from src.data.replacement_forecast_bundle_reader import read_replacement_forecast_bundle
    from src.engine.replacement_forecast_hook_factory import _latest_replacement_readiness

    readiness = _latest_replacement_readiness(
        conn,
        city=str(family.city),
        target_date=str(family.target_date),
        temperature_metric=str(family.metric),
    )
    if readiness is None:
        raise ValueError("REPLACEMENT_0_1_LIVE_READINESS_MISSING")
    bundle_result = read_replacement_forecast_bundle(
        conn,
        baseline_bundle=None,
        readiness=readiness,
        city=str(family.city),
        target_date=str(family.target_date),
        temperature_metric=str(family.metric),
        decision_time=decision_time,
        require_baseline_bundle=False,
    )
    if not bundle_result.ok or bundle_result.bundle is None:
        raise ValueError(f"REPLACEMENT_0_1_LIVE_BUNDLE_BLOCKED:{bundle_result.reason_code}")
    replacement_bundle = bundle_result.bundle
    # DecisionProvenanceEnvelope (operator law 2026-06-11): record the SERVED bundle the moment it
    # is bound — BEFORE the q-mode / bounds gates below — so every rejection raised after the read
    # (q-mode ineligible, bounds missing, ...) still carries the exact data combination it
    # examined. Observability only; never read back into any gate.
    if provenance_capture is not None:
        provenance_capture["replacement_bundle"] = replacement_bundle
    raw_lag_reason = _replacement_live_input_lag_reason(
        conn,
        family=family,
        decision_time=decision_time,
        posterior_source_cycle_time=replacement_bundle.source_cycle_time,
    )
    if raw_lag_reason is not None:
        raise ValueError(f"REPLACEMENT_0_1_LIVE_INPUT_LAG:{raw_lag_reason}")
    # FIX 1 (2026-06-09) — q-mode live eligibility gate. Real submit is allowed ONLY when the
    # replacement posterior's q was built as a live Normal carrier
    # (FUSED_NORMAL_FULL/PARTIAL or ANCHOR_ONLY_CURRENT). Every other mode (soft-anchor fallback,
    # capture missing, fused-q build failed, or a legacy non-fused row without the key) is a
    # deterministic no-submit: the row sizes Kelly under a DIFFERENT probability regime than the
    # release evidence assumes. Raising here becomes a LIVE_INFERENCE_INPUTS_MISSING no-submit
    # receipt at the caller (data-class check; fail-closed).
    _q_mode_eligible, _q_mode = _replacement_q_mode_live_eligibility(replacement_bundle)
    if not _q_mode_eligible:
        raise ValueError(f"REPLACEMENT_Q_MODE_NOT_LIVE_ELIGIBLE#{_q_mode}")
    # PR#403 FIX (2026-06-09) — belt-and-braces bounds presence check. The materializer now
    # degrades FULL/PARTIAL to FUSED_NORMAL_BOUNDS_MISSING when bounds fail, so the q_mode gate
    # above already catches new materializations. This second check catches rows materialized
    # BEFORE the fix (which have FULL/PARTIAL mode but NULL q_lcb_json / q_ucb_json) and any
    # future code path that might set a live-eligible mode without writing bounds.
    #
    # Requirement: every live-eligible Normal carrier MUST carry BOTH q_lcb and q_ucb as non-empty
    # mappings AND q_lcb_basis must equal the fused-center bootstrap marker.
    # Absent/mismatched => reject with FUSED_NORMAL_BOUNDS_MISSING.
    #
    # NOTE: grandfathered rows (q_shape="fused_normal_direct", no mode key) are now rejected by the
    # FIRST gate above with FUSED_NORMAL_GRANDFATHER_REVOKED (operator directive 2026-06-10 P0).
    # The `_q_mode == "FUSED_NORMAL_GRANDFATHERED"` branch has been removed — it can never be
    # reached. The second gate still covers FULL/PARTIAL rows with absent bounds (pre-PR#403 rows).
    _prov_bounds_check = getattr(replacement_bundle, "provenance_json", None) or {}
    _q_shape_for_bounds = str(
        _prov_bounds_check.get("q_shape") if isinstance(_prov_bounds_check, Mapping) else ""
    )
    _needs_bounds = _q_mode in _REPLACEMENT_Q_MODE_LIVE_ELIGIBLE
    if _needs_bounds:
        _bundle_q_lcb = getattr(replacement_bundle, "q_lcb", None) or {}
        _bundle_q_ucb = getattr(replacement_bundle, "q_ucb", None) or {}
        _lcb_basis = (
            _prov_bounds_check.get("q_lcb_basis")
            if isinstance(_prov_bounds_check, Mapping)
            else None
        )
        _bounds_ok = (
            isinstance(_bundle_q_lcb, Mapping)
            and bool(_bundle_q_lcb)
            and isinstance(_bundle_q_ucb, Mapping)
            and bool(_bundle_q_ucb)
            and _lcb_basis == "fused_center_bootstrap_p05"
        )
        if not _bounds_ok:
            raise ValueError(
                f"REPLACEMENT_Q_MODE_NOT_LIVE_ELIGIBLE#FUSED_NORMAL_BOUNDS_MISSING"
                f":q_shape={_q_shape_for_bounds}:q_mode={_q_mode}"
                f":lcb_basis={_lcb_basis}"
            )
    q_by_condition: dict[str, float] = {}
    lcb_by_direction: QlcbByDirection = QlcbByDirection()
    p_values: dict[tuple[str, str], float] = {}
    prefilter: dict[tuple[str, str], bool] = {}
    q_map = replacement_bundle.q
    # Wave-2 item 6 (2026-06-12): the per-bin replacement q_lcb SETTLEMENT-σ-GROUNDED FLOOR
    # is DELETED, not activated. The live replacement q_lcb is the certified fused-center
    # bootstrap bound carried by the bundle; the q-mode/bounds gates above are the live
    # fail-closed checks.
    for candidate in family.candidates:
        condition_id = str(candidate.condition_id or "")
        bin_id = _candidate_replacement_bin_id(candidate, replacement_bundle)
        if not bin_id or bin_id not in q_map:
            raise ValueError(f"REPLACEMENT_0_1_LIVE_BIN_BINDING_MISSING:{condition_id}")
        q_yes = min(max(float(q_map[bin_id]), 0.0), 1.0)
        yes_lcb = _replacement_yes_lcb_for_bin(
            replacement_bundle, bin_id=bin_id, q_yes=q_yes, settlement_floor_lcb=None
        )
        yes_samples = _replacement_yes_bootstrap_samples_for_bin(
            replacement_bundle, bin_id=bin_id
        )
        q_by_condition[condition_id] = q_yes
        _set_qlcb_provenance(
            lcb_by_direction,
            (condition_id, "buy_yes"),
            yes_lcb,
            source="FORECAST_BOOTSTRAP",
        )
        # bin-selection S2 native-NO authority (Hidden #3, §4 lines 154-166): the NO
        # robust lower bound is the lower tail of the per-sample complement 1 - q_yes,
        # which equals 1 - q_ucb_yes. The replacement_0_1 bundle does not expose the YES
        # sample array (it reads a precomputed posterior), but it DOES carry the per-bin
        # q_ucb map — and the complement identity is exact, so q_lcb_no = 1 - q_ucb_yes
        # directly, NEVER 1 - q_lcb_yes (the point-complement the spec forbids). Clamp
        # under the NO point (1 - q_yes) so q_lcb_no <= q_point_no. Absent a bundle q_ucb
        # there is no native NO authority -> 0.0 (fail-closed; never a YES-complement).
        no_lcb = _replacement_no_lcb_for_bin(
            replacement_bundle, bin_id=bin_id, q_yes=q_yes
        )
        _set_qlcb_provenance(
            lcb_by_direction,
            (condition_id, "buy_no"),
            no_lcb,
            source="FORECAST_BOOTSTRAP",
        )
        yes_price = native_costs.get((condition_id, "buy_yes"), (None, None, 0.0, None, None))[1]
        yes_cost = float(yes_price.value) if yes_price is not None else 1.0
        yes_edge_lcb_positive = yes_price is not None and yes_lcb > yes_cost
        yes_bootstrap_p = (
            _finite_sample_false_edge_rate(yes_samples, cost=yes_cost)
            if yes_price is not None
            else None
        )
        p_values[(condition_id, "buy_yes")] = (
            yes_bootstrap_p
            if yes_bootstrap_p is not None
            else (0.0 if yes_edge_lcb_positive else 1.0)
        )
        prefilter[(condition_id, "buy_yes")] = bool(yes_edge_lcb_positive)
        # FIX (2026-06-10 funnel autopsy):
        no_price = native_costs.get((condition_id, "buy_no"), (None, None, 0.0, None, None))[1]
        no_cost = float(no_price.value) if no_price is not None else 1.0
        no_edge_lcb_positive = no_price is not None and no_lcb > no_cost
        no_bootstrap_samples = tuple(1.0 - sample for sample in yes_samples)
        no_bootstrap_p = (
            _finite_sample_false_edge_rate(no_bootstrap_samples, cost=no_cost)
            if no_price is not None
            else None
        )
        p_values[(condition_id, "buy_no")] = (
            no_bootstrap_p
            if no_bootstrap_p is not None
            else (0.0 if no_edge_lcb_positive else 1.0)
        )
        prefilter[(condition_id, "buy_no")] = bool(no_edge_lcb_positive)
    coverage_cache: dict = {}
    # K3 settlement-backward coverage is a live safety gate. It only ever lowers an
    # unlicensed q_lcb; INSUFFICIENT_DATA is a typed no-shrink verdict, while structural
    # coverage-authority faults fail closed instead of serving an unlicensed bound.
    _coverage_verdict_by_direction = _maybe_apply_settlement_coverage_to_lcb(
        family=family,
        forecast_conn=conn,
        lcb_by_direction=lcb_by_direction,
        coverage_cache=coverage_cache,
    )
    _coverage_status_by_direction: dict[tuple[str, str], str] = {
        key: str(getattr(verdict, "status"))
        for key, verdict in _coverage_verdict_by_direction.items()
    }
    payload["_edli_q_source"] = "replacement_0_1"
    return q_by_condition, lcb_by_direction, p_values, prefilter, {
        "probability_authority": "replacement_0_1",
        # Selected-leg coverage authority: every proof receives the verdict for its
        # own (condition_id, direction). A family-level representative verdict would
        # license or block unrelated sibling legs.
        "settlement_coverage_status_by_direction": _coverage_status_by_direction,
        "settlement_coverage_verdict_by_direction": dict(_coverage_verdict_by_direction),
        "replacement_bundle": replacement_bundle,
        "replacement_q_mode": _q_mode,
        # FIX A (direction law; 2026-06-10 Milan-24C incident): thread the fused
        # posterior center + predictive sigma (°C) to the proof-construction seam
        # so candidate admission can enforce buy_yes <=> bin ~= forecast. Read
        # UNCONDITIONALLY (not gated by the sigma-floor flag): the law needs the
        # center whenever fusion provenance carries one.
        "forecast_mu_c": _replacement_anchor_mu_c(replacement_bundle),
        "forecast_predictive_sigma_c": _replacement_predictive_sigma_c(replacement_bundle),
        "posterior_id": str(replacement_bundle.posterior_id),
        "replacement_product_id": replacement_bundle.product_id,
        "p_cal_vector_hash": _probability_vector_hash(
            q_by_condition[str(candidate.condition_id or "")]
            for candidate in family.candidates
        ),
        "p_live_vector_hash": _probability_vector_hash(
            q_by_condition[str(candidate.condition_id or "")]
            for candidate in family.candidates
        ),
    }


